                  <p className="text-xs font-bold text-slate-200">{t.description}</p>
                  <p className="text-[9px] text-slate-600 font-black uppercase">{t.category} • {new Date(t.date).toLocaleDateString('pt-BR')}</p>
                </div>
              </div>
              <p className={`text-sm font-black ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-300'}`}>
                {t.type === 'income' ? '+' : '-'} R$ {t.amount.toLocaleString()}
              </p>
            </div>
          ))}
          {transactions.length === 0 && (
            <div className="col-span-2 py-10 text-center text-slate-700 font-black uppercase text-[10px]">Nenhuma transação registrada.</div>
          )}
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4">
          {potes.map((pote) => (
            <div key={pote.id} className="bg-[#0a0c14] p-4 md:p-5 rounded-2xl md:rounded-3xl border border-white/5 hover:border-indigo-500/40 transition-all shadow-xl group">
               <div className="flex justify-between items-center mb-3">
                  <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest truncate">{pote.name}</span>
                  <span className="text-[8px] md:text-[9px] font-bold text-indigo-400 bg-indigo-500/10 px-1.5 py-0.5 rounded-lg">{pote.percentage}%</span>
               </div>
               <p className={`text-sm md:text-xl font-bold tracking-tighter ${pote.balance < 0 ? 'text-rose-500' : 'text-slate-200'}`}>
                 R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
               </p>
               <div className="mt-3 h-1 w-full bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-1000" style={{ width: `${Math.max(0, Math.min(100, (pote.balance / (totalBalance || 1)) * 100))}%` }}></div>
               </div>
            </div>
          ))}
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, ArrowUpCircle, ArrowDownCircle, X, Trash2, Edit2, Calendar, CreditCard, Tag, Filter, ArrowUpDown } from 'lucide-react';
import { Transaction, TransactionType, Jar } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

type SortOption = 'date-desc' | 'date-asc' | 'amount-desc' | 'amount-asc';

export default function Transactions({ transactions, potes, onAdd, onDelete, onEdit }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [sortOption, setSortOption] = useState<SortOption>('date-desc');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: 'Geral', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX'
  });

  const filteredTransactions = useMemo(() => {
    let result = transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === 'all' || t.type === typeFilter;
      const txDate = new Date(t.date).getTime();
      const matchesStartDate = !startDate || txDate >= new Date(startDate).getTime();
      const matchesEndDate = !endDate || txDate <= new Date(endDate).getTime();
      return matchesSearch && matchesType && matchesStartDate && matchesEndDate;
    });

    result.sort((a, b) => {
      switch (sortOption) {
        case 'date-desc': return new Date(b.date).getTime() - new Date(a.date).getTime();
        case 'date-asc': return new Date(a.date).getTime() - new Date(b.date).getTime();
        case 'amount-desc': return b.amount - a.amount;
        case 'amount-asc': return a.amount - b.amount;
        default: return 0;
      }
    });
    return result;
  }, [transactions, searchTerm, typeFilter, startDate, endDate, sortOption]);

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: type === 'income' ? 'Salário' : 'Consumo', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : '',
      paymentMethod: 'PIX'
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount) return;
    if (currentTx.type === 'expense' && !currentTx.poteId) {
       alert("Selecione um pote.");
       return;
    }
    if (modalType === 'add') onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    else if (modalType === 'edit') onEdit(currentTx as Transaction);
    setModalType(null);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 md:gap-4">
        <button 
          onClick={() => handleOpenAdd('income')}
          className="group flex items-center justify-center gap-3 py-5 md:py-6 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 rounded-2xl md:rounded-3xl hover:bg-emerald-500/20 transition-all font-black uppercase text-[10px] md:text-xs tracking-widest"
        >
          <Plus className="w-5 h-5" /> Entrada
        </button>
        <button 
          onClick={() => handleOpenAdd('expense')}
          className="group flex items-center justify-center gap-3 py-5 md:py-6 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-2xl md:rounded-3xl hover:bg-rose-500/20 transition-all font-black uppercase text-[10px] md:text-xs tracking-widest"
        >
          <Minus className="w-5 h-5" /> Despesa
        </button>
      </div>

      <div className="bg-slate-900/40 p-4 md:p-6 rounded-2xl md:rounded-3xl border border-white/5 space-y-4">
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="relative flex-1 w-full">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
            <input type="text" placeholder="Buscar..." className="w-full pl-11 pr-6 py-3 bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 text-sm outline-none" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
          <button onClick={() => setIsFilterExpanded(!isFilterExpanded)} className={`flex items-center gap-2 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-950/50 text-slate-400 border-white/5'}`}>
            <Filter className="w-4 h-4" /> Filtros
          </button>
        </div>

        {isFilterExpanded && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-4 border-t border-white/5 animate-in slide-in-from-top-2 duration-200">
            <input type="date" className="bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 p-2 text-xs" value={startDate} onChange={e=>setStartDate(e.target.value)} />
            <input type="date" className="bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 p-2 text-xs" value={endDate} onChange={e=>setEndDate(e.target.value)} />
            <select className="bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 p-2 text-xs" value={sortOption} onChange={e=>setSortOption(e.target.value as any)}>
               <option value="date-desc">Recentes</option>
               <option value="amount-desc">Maior Valor</option>
            </select>
          </div>
        )}
      </div>

      <div className="space-y-3">
        {filteredTransactions.map(t => (
          <div key={t.id} className="bg-[#0a0c14] p-4 rounded-2xl border border-white/5 flex flex-col gap-3 group animate-in fade-in duration-300">
            <div className="flex justify-between items-start">
              <div className="flex gap-3">
                <div className={`p-2 rounded-lg ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                </div>
                <div>
                  <p className="font-bold text-slate-200 text-sm">{t.description}</p>
                  <p className="text-[9px] text-slate-600 font-black uppercase">{t.category} • {new Date(t.date).toLocaleDateString('pt-BR')}</p>
                </div>
              </div>
              <p className={`font-black text-sm ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-200'}`}>
                R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
            </div>
            <div className="flex justify-between items-center border-t border-white/5 pt-3">
              <span className="text-[9px] font-black text-indigo-400 uppercase">
                {t.type === 'income' ? 'TAXA GERAL' : (potes.find(p => p.id === t.poteId)?.name || 'OUTRO')}
              </span>
              <div className="flex gap-2">
                <button onClick={() => handleOpenEdit(t)} className="p-2 text-slate-600 bg-slate-900 rounded-lg hover:text-indigo-400"><Edit2 className="w-3.5 h-3.5" /></button>
                <button onClick={() => onDelete(t.id)} className="p-2 text-rose-500/50 bg-rose-500/5 rounded-lg hover:text-rose-400"><Trash2 className="w-3.5 h-3.5" /></button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {modalType && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 md:p-4 bg-black/95 backdrop-blur-md overflow-y-auto">
          <div className="bg-[#111827] w-full h-full md:h-auto md:max-w-lg md:rounded-[2.5rem] p-8 border-white/10 flex flex-col">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-white uppercase tracking-tighter">{modalType === 'add' ? 'Novo Registro' : 'Editar'}</h3>
              <button onClick={() => setModalType(null)} className="p-2 bg-slate-900 rounded-full"><X className="w-6 h-6 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <input placeholder="Descrição" required className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-2xl text-white outline-none" value={currentTx.description} onChange={e => setCurrentTx({...currentTx, description: e.target.value})} />
              <input 
                type="number" 
                step="0.01" 
                inputMode="decimal" 
                placeholder="Valor R$ 0,00" 
                required 
                className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-2xl text-white outline-none" 
                value={currentTx.amount || ''} 
                onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} 
              />
              {currentTx.type === 'expense' && (
                  <select className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-2xl text-white outline-none" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    <option value="">Pote de Saída</option>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name} (R$ {p.balance.toLocaleString()})</option>)}
                  </select>
              )}
              <input type="date" className="w-full px-5 py-4 bg-slate-950 border border-slate-800 rounded-2xl text-white outline-none" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Confirmar Registro</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { BrainCircuit, Send, Loader2, Sparkles, Plus, Check } from 'lucide-react';
import { FinancialData, Transaction } from '../types';
import { getFinancialAdvice } from '../services/gemini';

interface Message {
  id: string;
  role: 'user' | 'ai';
  content: string;
  suggestedTransaction?: Partial<Transaction>;
}

export default function AIAdvisor({ data, onTransactionCommand }: { data: FinancialData, onTransactionCommand: (t: Transaction) => void }) {
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', role: 'ai', content: 'ZenOS Neural Link Ativo. Diga algo como: "Gastei 45 no jantar ontem" ou "Recebi 1200 extras". Como posso otimizar sua vida hoje?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = { id: Date.now().toString(), role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const advice = await getFinancialAdvice(data, input);

    // Process JSON commands from AI response
    let cleanContent = advice;
    let suggestedTx: Partial<Transaction> | undefined = undefined;

    try {
      const jsonMatch = advice.match(/\{[\s\S]*"action"\s*:\s*"ADD_TRANSACTION"[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0]);
        suggestedTx = parsed.transaction;
        cleanContent = advice.replace(jsonMatch[0], '').trim();
      }
    } catch (e) {
      console.warn("AI returned malformed JSON command");
    }

    const aiMessage: Message = { 
      id: (Date.now() + 1).toString(), 
      role: 'ai', 
      content: cleanContent || 'Entendido. Algo mais?',
      suggestedTransaction: suggestedTx
    };

    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);
  };

  const confirmTransaction = (msgId: string, tx: Partial<Transaction>) => {
    const fullTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: tx.description || 'Transação via IA',
      amount: tx.amount || 0,
      type: tx.type || 'expense',
      category: tx.category || 'Geral',
      date: tx.date || new Date().toISOString().split('T')[0],
      poteId: tx.type === 'expense' ? data.potes[0].id : undefined,
      paymentMethod: 'IA Context'
    };
    onTransactionCommand(fullTx);
    setMessages(prev => prev.map(m => m.id === msgId ? { ...m, suggestedTransaction: undefined } : m));
  };

  return (
    <div className="flex flex-col h-[calc(100vh-10rem)] md:h-[calc(100vh-12rem)] bg-[#0a0c14] rounded-[1.5rem] md:rounded-[3rem] border border-white/5 overflow-hidden shadow-2xl animate-in zoom-in duration-500">
      <div className="bg-indigo-600 p-6 md:p-8 text-white flex items-center justify-between border-b border-indigo-500/20">
        <div className="flex items-center gap-4">
          <div className="bg-white/10 p-2.5 rounded-xl backdrop-blur-md"><BrainCircuit className="w-6 h-6" /></div>
          <div>
            <h2 className="text-lg md:text-2xl font-black uppercase tracking-tighter">ZenOS AI Advisor</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></span>
              <span className="text-[8px] md:text-[10px] text-indigo-100/60 font-black uppercase tracking-widest">Neural Link Estável</span>
            </div>
          </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 bg-[#030712]/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`
              max-w-[90%] md:max-w-[85%] rounded-[1.5rem] p-4 md:p-6 text-xs md:text-sm leading-relaxed
              ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-[#111827] text-slate-300 rounded-tl-none border border-white/5'}
            `}>
              {msg.content}
            </div>

            {msg.suggestedTransaction && (
              <div className="mt-3 bg-emerald-500/10 border border-emerald-500/30 p-4 rounded-2xl w-[90%] animate-in slide-in-from-left-2">
                <p className="text-[9px] font-black text-emerald-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                  <Sparkles className="w-3 h-3" /> Intenção Detectada: Registrar {msg.suggestedTransaction.type === 'income' ? 'Ganho' : 'Gasto'}
                </p>
                <div className="flex justify-between items-center">
                   <div>
                      <p className="text-xs font-bold text-white">{msg.suggestedTransaction.description}</p>
                      <p className="text-[10px] text-slate-500">R$ {msg.suggestedTransaction.amount?.toLocaleString()} • {msg.suggestedTransaction.category}</p>
                   </div>
                   <button 
                    onClick={() => confirmTransaction(msg.id, msg.suggestedTransaction!)}
                    className="p-2 bg-emerald-500 text-emerald-950 rounded-xl hover:scale-110 active:scale-95 transition-all"
                   >
                    <Check className="w-4 h-4" />
                   </button>
                </div>
              </div>
            )}
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-[#111827] p-4 rounded-2xl flex items-center gap-3">
              <Loader2 className="w-4 h-4 text-indigo-500 animate-spin" />
              <span className="text-[9px] text-slate-600 font-black uppercase tracking-widest">Processando intenção...</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 md:p-6 bg-[#0a0c14] border-t border-white/5">
        <form onSubmit={handleSend} className="relative flex gap-2">
          <input 
            className="flex-1 pl-6 pr-4 py-4 bg-slate-900/60 border border-white/5 rounded-2xl text-white text-sm outline-none focus:ring-2 focus:ring-indigo-600 transition-all"
            placeholder="Diga algo como: Gastei 45 no café..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button type="submit" className="p-4 bg-indigo-600 text-white rounded-2xl shadow-lg hover:bg-indigo-500 active:scale-95 transition-all">
            <Send className="w-5 h-5" />
          </button>
        </form>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Receipt, Target, Wallet, BrainCircuit, Menu, X, Archive, 
  AlertCircle, CheckSquare, FileText, BookOpen, Plus, Sparkles
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Task, Note, JournalEntry, CalendarEvent, Budget, FinancialGoal } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Tasks from './components/Tasks';
import Notes from './components/Notes';
import Journal from './components/Journal';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Toast, { ToastType } from './components/Toast';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [tasks, setTasks] = useState<Task[]>(() => JSON.parse(localStorage.getItem('zen_tasks') || '[]'));
  const [notes, setNotes] = useState<Note[]>(() => JSON.parse(localStorage.getItem('zen_notes') || '[]'));
  const [journal, setJournal] = useState<JournalEntry[]>(() => JSON.parse(localStorage.getItem('zen_journal') || '[]'));
  const [events, setEvents] = useState<CalendarEvent[]>(() => JSON.parse(localStorage.getItem('zen_events') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_tasks', JSON.stringify(tasks));
    localStorage.setItem('zen_notes', JSON.stringify(notes));
    localStorage.setItem('zen_journal', JSON.stringify(journal));
    localStorage.setItem('zen_events', JSON.stringify(events));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [transactions, potes, debts, tasks, notes, journal, events, budgets, goals]);

  const processedPotes = useMemo(() => {
    return potes.map(pote => {
      let balance = 0;
      transactions.forEach(t => {
        if (t.type === 'income') {
          balance += t.amount * (pote.percentage / 100);
        } else if (t.type === 'expense' && t.poteId === pote.id) {
          balance -= t.amount;
        }
      });
      return { ...pote, balance };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, tasks, notes, journal, events, budgets, goals
  }), [transactions, processedPotes, debts, tasks, notes, journal, events, budgets, goals]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const navItems = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard },
    { id: 'transactions', label: 'Finanças', icon: Receipt },
    { id: 'potes', label: 'Potes', icon: Archive },
    { id: 'budgets', label: 'Orçamentos', icon: Target },
    { id: 'goals', label: 'Metas', icon: Target },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle },
    { id: 'tasks', label: 'Tarefas', icon: CheckSquare },
    { id: 'notes', label: 'Notas', icon: FileText },
    { id: 'journal', label: 'Diário', icon: BookOpen },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit },
  ];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans overflow-hidden select-none">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <button 
        onClick={() => { setView('transactions'); showToast("Crie um novo registro rápido", "info"); }}
        className="fixed bottom-6 right-6 z-[60] w-14 h-14 bg-indigo-600 text-white rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group safe-pb"
      >
        <Plus className="w-7 h-7 group-hover:rotate-90 transition-transform" />
      </button>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-[#0a0c14] border-r border-white/5 flex flex-col
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-slate-500" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-1 overflow-y-auto no-scrollbar">
          {navItems.map((item) => (
            <button 
              key={item.id} 
              onClick={() => { setView(item.id as AppView); setIsSidebarOpen(false); }} 
              className={`
                w-full flex items-center gap-4 px-4 py-3.5 rounded-2xl transition-all
                ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}
              `}
            >
              <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
              <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
            </button>
          ))}
        </nav>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#030712]">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-900/50 rounded-xl text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Patrimônio Líquido</span>
                <span className="text-xs font-black text-white">R$ {financialData.potes.reduce((a,b)=>a+b.balance,0).toLocaleString()}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <BrainCircuit className="w-5 h-5 text-indigo-400" />
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
              />
            )}
            {view === 'debts' && (
              <Debts debts={debts} potes={processedPotes} onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} onPay={handleDebtPayment} />
            )}
            {view === 'tasks' && <Tasks tasks={tasks} onUpdate={setTasks} />}
            {view === 'notes' && <Notes notes={notes} onUpdate={setNotes} />}
            {view === 'journal' && <Journal journal={journal} onUpdate={setJournal} />}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && <Goals goals={goals} onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} onUpdate={setGoals} />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div> {/* Espaçador para o FAB no mobile */}
        </div>
      </main>
    </div>
  );
}

import React, { useMemo } from 'react';
import { Wallet, TrendingUp, PieChart as PieChartIcon, BarChart3, Activity, ArrowRight, Plus } from 'lucide-react';
import { FinancialData, Transaction } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend 
} from 'recharts';

interface DashboardProps {
  data: FinancialData;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#06b6d4'];

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, potes, tasks, journal } = data;
  const totalBalance = potes.reduce((acc, p) => acc + p.balance, 0);

  const now = new Date();
  const monthIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === now.getMonth())
    .reduce((acc, t) => acc + t.amount, 0);

  const categoryData = useMemo(() => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const categories: Record<string, number> = {};
    expenses.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });
    return Object.entries(categories)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 6);
  }, [transactions]);

  const trendData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const monthIndex = d.getMonth();
      const year = d.getFullYear();
      const income = transactions
        .filter(t => t.type === 'income' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      const expense = transactions
        .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      last6Months.push({ name: months[monthIndex], Entradas: income, Saídas: expense });
    }
    return last6Months;
  }, [transactions]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-[#0f172a] border border-white/10 p-2 rounded-xl shadow-2xl backdrop-blur-md">
          <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-0.5">{payload[0].name || payload[0].dataKey}</p>
          <p className="text-xs font-black text-white">R$ {payload[0].value.toLocaleString()}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-4 md:space-y-6 animate-in fade-in duration-500">
      {/* Indicadores Financeiros Master */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 p-5 md:p-6 rounded-3xl shadow-xl relative overflow-hidden group border border-white/10">
           <div className="absolute -top-4 -right-4 p-8 opacity-10 group-hover:scale-125 transition-transform duration-700"><Wallet className="w-16 h-16 md:w-24" /></div>
           <span className="text-indigo-100/60 text-[9px] font-black uppercase tracking-[0.2em] block mb-1">Liquidez ZenOS</span>
           <p className={`text-2xl md:text-4xl font-black tracking-tighter ${totalBalance < 0 ? 'text-rose-400' : 'text-white'}`}>
             R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
           <div className="mt-3 flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></div>
              <span className="text-[8px] text-indigo-200/50 font-black uppercase tracking-widest">Motor Neural Online</span>
           </div>
        </div>

        <div className="bg-[#111827]/60 p-5 md:p-6 rounded-3xl border border-white/5 relative group overflow-hidden hover:border-emerald-500/20 transition-all flex flex-col justify-center">
           <div className="absolute -top-4 -right-4 p-8 opacity-5"><TrendingUp className="w-16 h-16 md:w-24" /></div>
           <div className="flex items-center gap-2 mb-2">
              <div className="p-1.5 bg-emerald-500/10 rounded-lg"><TrendingUp className="w-4 h-4 text-emerald-400" /></div>
              <span className="text-slate-500 text-[9px] font-black uppercase tracking-[0.2em]">Faturamento do Mês</span>
           </div>
           <p className="text-2xl md:text-4xl font-black text-emerald-400 tracking-tighter">
             R$ {monthIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-[#0a0c14] p-5 rounded-3xl border border-white/5 shadow-xl">
          <h3 className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center justify-between">
            <span className="flex items-center gap-2"><PieChartIcon className="w-3.5 h-3.5 text-indigo-400" /> Mix de Consumo</span>
          </h3>
          <div className="aspect-[4/3] sm:aspect-video lg:aspect-square max-h-[250px] w-full mx-auto">
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={categoryData} cx="50%" cy="50%" innerRadius="60%" outerRadius="80%" paddingAngle={4} dataKey="value">
                    {categoryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip content={<CustomTooltip />} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-700 text-[9px] font-black uppercase italic">Sem dados</div>
            )}
          </div>
        </div>

        <div className="bg-[#0a0c14] p-5 rounded-3xl border border-white/5 shadow-xl">
          <h3 className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
            <BarChart3 className="w-3.5 h-3.5 text-indigo-400" /> Fluxo Histórico
          </h3>
          <div className="aspect-[4/3] sm:aspect-video lg:aspect-square max-h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#475569', fontSize: 9, fontWeight: 900 }} />
                <YAxis hide />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(255,255,255,0.03)' }} />
                <Bar dataKey="Entradas" fill="#10b981" radius={[3, 3, 0, 0]} />
                <Bar dataKey="Saídas" fill="#f43f5e" radius={[3, 3, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="space-y-3">
        <h3 className="text-[9px] font-black text-slate-500 uppercase tracking-widest px-1 flex items-center gap-3">
          Atividade Recente <div className="h-px flex-1 bg-slate-800/50"></div>
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {transactions.slice(0, 4).map(t => (
            <div key={t.id} className="bg-[#0a0c14] p-3.5 rounded-2xl border border-white/5 flex items-center justify-between hover:bg-slate-900 transition-colors">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-xl ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                  {t.type === 'income' ? <TrendingUp className="w-3.5 h-3.5" /> : <Activity className="w-3.5 h-3.5" />}
                </div>
                <div className="min-w-0">
                  <p className="text-xs font-bold text-slate-200 truncate">{t.description}</p>
                  <p className="text-[8px] text-slate-600 font-black uppercase tracking-widest">{t.category}</p>
                </div>
              </div>
              <p className={`text-xs font-black ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-300'}`}>
                R$ {t.amount.toLocaleString()}
              </p>
            </div>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {potes.map((pote) => (
            <div key={pote.id} className="bg-[#0a0c14] p-4 rounded-2xl border border-white/5 hover:border-indigo-500/40 transition-all group">
               <div className="flex justify-between items-center mb-2">
                  <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest truncate">{pote.name}</span>
                  <span className="text-[8px] font-bold text-indigo-400 bg-indigo-500/10 px-1.5 py-0.5 rounded-lg">{pote.percentage}%</span>
               </div>
               <p className={`text-sm md:text-lg font-black tracking-tighter ${pote.balance < 0 ? 'text-rose-500' : 'text-slate-200'}`}>
                 R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
               </p>
               <div className="mt-2 h-1 w-full bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-700" style={{ width: `${Math.max(0, Math.min(100, (pote.balance / (totalBalance || 1)) * 100))}%` }}></div>
               </div>
            </div>
          ))}
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, X, Trash2, Edit2, Filter } from 'lucide-react';
import { Transaction, TransactionType, Jar } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

export default function Transactions({ transactions, potes, onAdd, onDelete, onEdit }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: 'Geral', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX'
  });

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === 'all' || t.type === typeFilter;
      return matchesSearch && matchesType;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, searchTerm, typeFilter]);

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: type === 'income' ? 'Receita' : 'Gasto', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : '',
      paymentMethod: 'PIX'
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount) return;
    if (modalType === 'add') onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    else if (modalType === 'edit') onEdit(currentTx as Transaction);
    setModalType(null);
  };

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-2 gap-3">
        <button onClick={() => handleOpenAdd('income')} className="flex items-center justify-center gap-2 py-4 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-emerald-500/20 active:scale-95 transition-all">
          <Plus className="w-4 h-4" /> Ganho
        </button>
        <button onClick={() => handleOpenAdd('expense')} className="flex items-center justify-center gap-2 py-4 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-rose-500/20 active:scale-95 transition-all">
          <Minus className="w-4 h-4" /> Gasto
        </button>
      </div>

      <div className="bg-slate-900/40 p-3.5 rounded-2xl border border-white/5 space-y-3">
        <div className="flex gap-3 items-center">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-600" />
            <input type="text" placeholder="Filtrar..." className="w-full pl-9 pr-4 py-2.5 bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 text-xs outline-none focus:ring-1 focus:ring-indigo-500" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
          <button onClick={() => setIsFilterExpanded(!isFilterExpanded)} className={`p-2.5 rounded-xl transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-950/50 text-slate-400 border-white/5'}`}>
            <Filter className="w-4 h-4" />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-2.5">
        {filteredTransactions.map(t => (
          <div key={t.id} className="bg-[#0a0c14] p-4 rounded-2xl border border-white/5 flex flex-col gap-2 group animate-in slide-in-from-bottom-2 duration-300">
            <div className="flex justify-between items-start">
              <div className="flex gap-3 min-w-0">
                <div className={`p-1.5 rounded-lg flex-shrink-0 ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                </div>
                <div className="min-w-0">
                  <p className="font-bold text-slate-200 text-xs truncate">{t.description}</p>
                  <p className="text-[8px] text-slate-600 font-black uppercase tracking-widest">{t.category} • {new Date(t.date).toLocaleDateString()}</p>
                </div>
              </div>
              <p className={`font-black text-xs whitespace-nowrap ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-200'}`}>
                R$ {t.amount.toLocaleString()}
              </p>
            </div>
            <div className="flex justify-between items-center border-t border-white/5 pt-2">
              <span className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">
                {t.type === 'income' ? 'RECEITA' : (potes.find(p => p.id === t.poteId)?.name || 'OUTRO')}
              </span>
              <div className="flex gap-1.5">
                <button onClick={() => handleOpenEdit(t)} className="p-2 text-slate-600 bg-slate-900/50 rounded-lg hover:text-indigo-400 transition-colors"><Edit2 className="w-3.5 h-3.5" /></button>
                <button onClick={() => onDelete(t.id)} className="p-2 text-rose-500/50 bg-rose-500/5 rounded-lg hover:text-rose-400 transition-colors"><Trash2 className="w-3.5 h-3.5" /></button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {modalType && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/95 backdrop-blur-sm">
          <div className="bg-[#111827] w-full sm:max-w-md rounded-t-[2.5rem] sm:rounded-[2rem] p-6 md:p-8 border-t border-x sm:border border-white/10 flex flex-col shadow-2xl animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-center mb-6">
