              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Valor R$</label>
                  <input type="number" step="0.01" inputMode="decimal" required className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.amount || ''} onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Data</label>
                  <input type="date" className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
                </div>
              </div>
              {currentTx.type === 'expense' && (
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Pote de Origem</label>
                  <select className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    <option value="">Selecione...</option>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name} (R$ {p.balance.toLocaleString()})</option>)}
                  </select>
                </div>
              )}
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-xl shadow-xl mt-4 active:scale-95 transition-all">Salvar Registro</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { BrainCircuit, Send, Loader2, Sparkles, Plus, Check } from 'lucide-react';
import { FinancialData, Transaction } from '../types';
import { getFinancialAdvice } from '../services/gemini';

interface Message {
  id: string;
  role: 'user' | 'ai';
  content: string;
  suggestedTransaction?: Partial<Transaction>;
}

export default function AIAdvisor({ data, onTransactionCommand }: { data: FinancialData, onTransactionCommand: (t: Transaction) => void }) {
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', role: 'ai', content: 'ZenOS Neural Link Ativo. Posso registrar seus gastos via texto ou dar insights sobre seu saldo de R$ ' + data.potes.reduce((a,b)=>a+b.balance,0).toLocaleString() }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = { id: Date.now().toString(), role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const advice = await getFinancialAdvice(data, input);

    let cleanContent = advice;
    let suggestedTx: Partial<Transaction> | undefined = undefined;

    try {
      const jsonMatch = advice.match(/\{[\s\S]*"action"\s*:\s*"ADD_TRANSACTION"[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0]);
        suggestedTx = parsed.transaction;
        cleanContent = advice.replace(jsonMatch[0], '').trim();
      }
    } catch (e) {
      console.warn("AI malformed command");
    }

    const aiMessage: Message = { 
      id: (Date.now() + 1).toString(), 
      role: 'ai', 
      content: cleanContent || 'Entendido. Algo mais?',
      suggestedTransaction: suggestedTx
    };

    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);
  };

  const confirmTransaction = (msgId: string, tx: Partial<Transaction>) => {
    const fullTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: tx.description || 'IA Log',
      amount: tx.amount || 0,
      type: tx.type || 'expense',
      category: tx.category || 'Geral',
      date: tx.date || new Date().toISOString().split('T')[0],
      poteId: tx.type === 'expense' ? data.potes[0].id : undefined,
      paymentMethod: 'ZenAI'
    };
    onTransactionCommand(fullTx);
    setMessages(prev => prev.map(m => m.id === msgId ? { ...m, suggestedTransaction: undefined } : m));
  };

  return (
    <div className="flex flex-col h-[calc(100vh-10rem)] bg-[#0a0c14] rounded-3xl border border-white/5 overflow-hidden shadow-2xl animate-in fade-in duration-500">
      <div className="bg-indigo-600 px-5 py-4 text-white flex items-center justify-between">
        <div className="flex items-center gap-3">
          <BrainCircuit className="w-5 h-5" />
          <h2 className="text-sm font-black uppercase tracking-widest">ZenAI Advisor</h2>
        </div>
        <div className="flex items-center gap-1.5">
          <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></span>
          <span className="text-[8px] font-black uppercase">Online</span>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-[#030712]/40 no-scrollbar">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`
              max-w-[85%] rounded-2xl p-3.5 text-xs leading-relaxed
              ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-[#111827] text-slate-300 rounded-tl-none border border-white/5 shadow-sm'}
            `}>
              {msg.content}
            </div>

            {msg.suggestedTransaction && (
              <div className="mt-2 bg-emerald-500/10 border border-emerald-500/20 p-3 rounded-xl w-[85%] animate-in slide-in-from-left-2">
                <p className="text-[8px] font-black text-emerald-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5">
                  <Sparkles className="w-3 h-3" /> Registrar {msg.suggestedTransaction.type === 'income' ? 'Ganho' : 'Gasto'}?
                </p>
                <div className="flex justify-between items-center">
                   <div className="min-w-0">
                      <p className="text-[10px] font-bold text-white truncate">{msg.suggestedTransaction.description}</p>
                      <p className="text-[9px] text-slate-500 font-black">R$ {msg.suggestedTransaction.amount?.toLocaleString()}</p>
                   </div>
                   <button 
                    onClick={() => confirmTransaction(msg.id, msg.suggestedTransaction!)}
                    className="p-1.5 bg-emerald-500 text-emerald-950 rounded-lg shadow-lg active:scale-90 transition-all"
                   >
                    <Check className="w-3.5 h-3.5" />
                   </button>
                </div>
              </div>
            )}
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-[#111827] px-3 py-2 rounded-xl flex items-center gap-2 border border-white/5">
              <Loader2 className="w-3 h-3 text-indigo-500 animate-spin" />
              <span className="text-[8px] text-slate-600 font-black uppercase tracking-widest">Processando...</span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-[#0a0c14] border-t border-white/5 safe-pb">
        <form onSubmit={handleSend} className="relative flex gap-2">
          <input 
            className="flex-1 pl-4 pr-4 py-3 bg-slate-900 border border-white/5 rounded-xl text-white text-xs outline-none focus:ring-1 focus:ring-indigo-600 transition-all"
            placeholder="Diga: Gastei 40 no mercado..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button type="submit" className="p-3 bg-indigo-600 text-white rounded-xl shadow-lg active:scale-95 transition-all">
            <Send className="w-4 h-4" />
          </button>
        </form>
      </div>
    </div>
  );
}

