                  <p className="text-[8px] text-slate-600 font-black uppercase tracking-widest">{t.category}</p>
                </div>
              </div>
              <p className={`text-xs font-black ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-300'}`}>
                R$ {t.amount.toLocaleString()}
              </p>
            </div>
          ))}
          {transactions.length === 0 && (
            <div className="col-span-full py-6 text-center text-slate-700 text-[8px] font-black uppercase italic tracking-widest">Vazio</div>
          )}
        </div>
      </div>

      {/* 4 e 5. Gráficos */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-[#0a0c14] p-5 rounded-3xl border border-white/5 shadow-xl">
          <h3 className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
            <PieChartIcon className="w-3.5 h-3.5 text-indigo-400" /> Consumo
          </h3>
          <div className="aspect-[4/3] sm:aspect-video lg:aspect-square max-h-[250px] w-full mx-auto">
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={categoryData} cx="50%" cy="50%" innerRadius="60%" outerRadius="80%" paddingAngle={4} dataKey="value">
                    {categoryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip content={<CustomTooltip />} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-700 text-[9px] font-black uppercase italic tracking-widest">Sem Dados</div>
