import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Receipt, Target, BrainCircuit, Menu, X, Archive, 
  AlertCircle, Plus, Settings as SettingsIcon
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Budget, FinancialGoal, Category } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Settings from './components/Settings';
import Toast, { ToastType } from './components/Toast';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const DEFAULT_CATEGORIES: Category[] = [
  { 
    id: 'c1', name: 'Moradia', type: 'expense', isDefault: true,
    subCategories: [{id: 's1', name: 'Aluguel'}, {id: 's2', name: 'Energia'}, {id: 's3', name: 'Internet'}, {id: 's4', name: 'Manutenção'}] 
  },
  { 
    id: 'c2', name: 'Alimentação', type: 'expense', isDefault: true,
    subCategories: [{id: 's5', name: 'Supermercado'}, {id: 's6', name: 'Restaurante'}, {id: 's7', name: 'Delivery'}] 
  },
  { 
    id: 'c3', name: 'Transporte', type: 'expense', isDefault: true,
    subCategories: [{id: 's8', name: 'Combustível'}, {id: 's9', name: 'Uber/Táxi'}, {id: 's10', name: 'Manutenção Veículo'}] 
  },
  { 
    id: 'c4', name: 'Saúde', type: 'expense', isDefault: true,
    subCategories: [{id: 's11', name: 'Farmácia'}, {id: 's12', name: 'Consultas'}, {id: 's13', name: 'Plano de Saúde'}] 
  },
  { 
    id: 'c5', name: 'Lazer', type: 'expense', isDefault: true,
    subCategories: [{id: 's14', name: 'Cinema/Streaming'}, {id: 's15', name: 'Viagem'}, {id: 's16', name: 'Hobbies'}] 
  },
  { 
    id: 'c6', name: 'Renda', type: 'income', isDefault: true,
    subCategories: [{id: 's17', name: 'Salário'}, {id: 's18', name: 'Freelance'}, {id: 's19', name: 'Dividendos'}] 
  }
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', subCategory: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', subCategory: 'Aluguel', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', subCategory: 'Supermercado', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
}

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  // Função para debitar do Pote quando um aporte em Meta é feito
  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense', // Sai do operacional/potes
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans overflow-hidden select-none">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <button 
        onClick={() => { setView('transactions'); showToast("Crie um novo registro rápido", "info"); }}
        className="fixed bottom-6 right-6 z-[60] w-14 h-14 bg-indigo-600 text-white rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group safe-pb"
      >
        <Plus className="w-7 h-7 group-hover:rotate-90 transition-transform" />
      </button>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-[#0a0c14] border-r border-white/5 flex flex-col
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-slate-500" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => (
            <div key={sectionName} className="space-y-1">
              <h4 className="px-4 text-[8px] font-black text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                {sectionName}
              </h4>
              <div className="space-y-1">
                {navItems.filter(item => item.section === sectionName).map((item) => (
                  <button 
                    key={item.id} 
                    onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                    className={`
                      w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                      ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}
                    `}
                  >
                    <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                    <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </nav>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#030712]">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-900/50 rounded-xl text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Patrimônio Líquido</span>
                <span className="text-xs font-black text-white">R$ {financialData.potes.reduce((a,b)=>a+b.balance,0).toLocaleString()}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <BrainCircuit className="w-5 h-5 text-indigo-400" />
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
              />
            )}
            {view === 'debts' && (
              <Debts debts={debts} potes={processedPotes} onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} onPay={handleDebtPayment} />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
              />
            )}
            {view === 'settings' && <Settings categories={categories} onUpdateCategories={setCategories} showToast={showToast} />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div> {/* Espaçador para o FAB no mobile */}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Category, SubCategory } from '../types';
import { Settings as SettingsIcon, Plus, Trash2, Edit2, Check, X, Tag } from 'lucide-react';

interface SettingsProps {
  categories: Category[];
  onUpdateCategories: (cats: Category[]) => void;
  showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
}

export default function Settings({ categories, onUpdateCategories, showToast }: SettingsProps) {
  const [activeTab, setActiveTab] = useState<'categories' | 'general'>('categories');
  const [newCatName, setNewCatName] = useState('');
  const [newCatType, setNewCatType] = useState<'income' | 'expense'>('expense');
  const [editingCatId, setEditingCatId] = useState<string | null>(null);
  const [newSubName, setNewSubName] = useState('');

  const handleAddCategory = () => {
    if (!newCatName.trim()) return;
    const newCat: Category = {
      id: Math.random().toString(36).substr(2, 9),
      name: newCatName,
      type: newCatType,
      subCategories: []
    };
    onUpdateCategories([...categories, newCat]);
    setNewCatName('');
    showToast('Categoria criada com sucesso!', 'success');
  };

  const handleDeleteCategory = (id: string) => {
    if (confirm('Tem certeza? Isso pode afetar registros históricos.')) {
      onUpdateCategories(categories.filter(c => c.id !== id));
      showToast('Categoria removida', 'info');
    }
  };

  const handleAddSubCategory = (catId: string) => {
    if (!newSubName.trim()) return;
    const updatedCats = categories.map(c => {
      if (c.id === catId) {
        return {
          ...c,
          subCategories: [...c.subCategories, { id: Math.random().toString(36).substr(2, 9), name: newSubName }]
        };
      }
      return c;
    });
    onUpdateCategories(updatedCats);
    setNewSubName('');
  };

  const handleDeleteSubCategory = (catId: string, subId: string) => {
    const updatedCats = categories.map(c => {
      if (c.id === catId) {
        return { ...c, subCategories: c.subCategories.filter(s => s.id !== subId) };
      }
      return c;
    });
    onUpdateCategories(updatedCats);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center gap-4 mb-6">
        <div className="bg-indigo-600 p-3 rounded-2xl shadow-lg shadow-indigo-600/20">
          <SettingsIcon className="w-6 h-6 text-white" />
        </div>
        <div>
           <h2 className="text-xl font-black text-white uppercase tracking-tighter">Ajustes do Sistema</h2>
           <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Personalize sua experiência</p>
        </div>
      </div>

      <div className="bg-[#0a0c14] border border-white/5 rounded-[2.5rem] overflow-hidden">
         <div className="flex border-b border-white/5">
            <button 
              onClick={() => setActiveTab('categories')}
              className={`flex-1 py-4 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'categories' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-200'}`}
            >
              Categorias
            </button>
            <button 
              onClick={() => setActiveTab('general')}
              className={`flex-1 py-4 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'general' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-200'}`}
            >
              Geral
            </button>
         </div>

         <div className="p-8">
            {activeTab === 'categories' && (
              <div className="space-y-8">
                {/* Add New Category */}
                <div className="bg-slate-900/50 p-6 rounded-3xl border border-white/5">
                   <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Nova Categoria</h3>
                   <div className="flex flex-col md:flex-row gap-4">
                      <input 
                        type="text" 
                        placeholder="Nome da categoria..."
                        className="flex-1 px-4 py-3 bg-[#030712] border border-slate-800 rounded-xl text-white outline-none focus:ring-1 focus:ring-indigo-500 text-sm"
                        value={newCatName}
                        onChange={e => setNewCatName(e.target.value)}
                      />
                      <select 
                        className="px-4 py-3 bg-[#030712] border border-slate-800 rounded-xl text-white outline-none focus:ring-1 focus:ring-indigo-500 text-sm"
                        value={newCatType}
                        onChange={e => setNewCatType(e.target.value as any)}
                      >
                        <option value="expense">Despesa</option>
                        <option value="income">Receita</option>
                      </select>
                      <button 
                        onClick={handleAddCategory}
                        className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black uppercase text-xs tracking-widest hover:bg-indigo-500 transition-all"
                      >
                        Criar
                      </button>
                   </div>
                </div>

                {/* List Categories */}
                <div className="space-y-4">
                   {categories.map(cat => (
                     <div key={cat.id} className="bg-[#111827]/40 rounded-3xl border border-white/5 overflow-hidden">
                        <div className="p-4 flex items-center justify-between bg-white/5">
                           <div className="flex items-center gap-3">
                              <span className={`w-2 h-2 rounded-full ${cat.type === 'income' ? 'bg-emerald-400' : 'bg-rose-400'}`}></span>
                              <h4 className="font-bold text-slate-200">{cat.name}</h4>
                              <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">{cat.type === 'income' ? 'Receita' : 'Despesa'}</span>
                           </div>
                           <div className="flex items-center gap-2">
                              <button onClick={() => setEditingCatId(editingCatId === cat.id ? null : cat.id)} className="p-2 text-slate-500 hover:text-indigo-400"><Tag className="w-4 h-4" /></button>
                              <button onClick={() => handleDeleteCategory(cat.id)} className="p-2 text-slate-500 hover:text-rose-500"><Trash2 className="w-4 h-4" /></button>
                           </div>
                        </div>

                        {/* Subcategories */}
                        {(editingCatId === cat.id) && (
                          <div className="p-4 bg-black/20 animate-in slide-in-from-top-2">
                             <div className="flex flex-wrap gap-2 mb-4">
                                {cat.subCategories.map(sub => (
                                  <div key={sub.id} className="bg-indigo-500/10 border border-indigo-500/20 px-3 py-1.5 rounded-lg flex items-center gap-2">
                                     <span className="text-xs text-indigo-300 font-bold">{sub.name}</span>
                                     <button onClick={() => handleDeleteSubCategory(cat.id, sub.id)} className="text-indigo-400 hover:text-rose-400"><X className="w-3 h-3" /></button>
                                  </div>
                                ))}
                             </div>
                             <div className="flex gap-2">
                                <input 
                                  placeholder="Nova subcategoria..."
                                  className="flex-1 px-3 py-2 bg-[#030712] border border-slate-800 rounded-lg text-white text-xs outline-none"
                                  value={newSubName}
                                  onChange={e => setNewSubName(e.target.value)}
                                  onKeyDown={e => e.key === 'Enter' && handleAddSubCategory(cat.id)}
                                />
                                <button onClick={() => handleAddSubCategory(cat.id)} className="p-2 bg-indigo-600 rounded-lg text-white"><Plus className="w-4 h-4" /></button>
                             </div>
                          </div>
                        )}
                     </div>
                   ))}
                </div>
              </div>
            )}

            {activeTab === 'general' && (
              <div className="text-center py-20 bg-slate-900/20 rounded-3xl border border-dashed border-white/10">
                <p className="text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Configurações gerais em breve</p>
              </div>
            )}
         </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { FinancialGoal, Jar } from '../types';
import { Target, Trophy, Calendar, Plus, X, ArrowUpRight, Wallet } from 'lucide-react';

interface GoalsProps {
  goals: FinancialGoal[];
  potes: Jar[];
  onAdd: (g: FinancialGoal) => void;
  onUpdate: (goals: FinancialGoal[]) => void;
  onDeposit: (amount: number, poteId: string, goalName: string) => void;
}

export default function Goals({ goals, potes, onAdd, onUpdate, onDeposit }: GoalsProps) {
  const [showAdd, setShowAdd] = useState(false);
  const [newGoal, setNewGoal] = useState({ name: '', targetAmount: 0, deadline: '' });

  const [depositModal, setDepositModal] = useState<{ goalId: string, goalName: string } | null>(null);
  const [depositAmount, setDepositAmount] = useState(0);
  const [selectedPoteId, setSelectedPoteId] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newGoal.name || newGoal.targetAmount <= 0) return;
    const goal: FinancialGoal = {
      id: Math.random().toString(36).substr(2, 9),
      name: newGoal.name,
      targetAmount: newGoal.targetAmount,
      currentAmount: 0,
      deadline: newGoal.deadline || new Date().toISOString().split('T')[0]
    };
    onAdd(goal);
    setNewGoal({ name: '', targetAmount: 0, deadline: '' });
    setShowAdd(false);
  };

  const handleDepositSubmit = () => {
    if (depositAmount <= 0 || !selectedPoteId || !depositModal) return;

    // Atualiza a meta
    onUpdate(goals.map(g => g.id === depositModal.goalId ? { ...g, currentAmount: g.currentAmount + depositAmount } : g));

    // Aciona a lógica de transação (débito do pote)
    onDeposit(depositAmount, selectedPoteId, depositModal.goalName);

    // Limpa estado
    setDepositModal(null);
    setDepositAmount(0);
    setSelectedPoteId('');
  };

  const removeGoal = (id: string) => {
    onUpdate(goals.filter(g => g.id !== id));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-white uppercase tracking-tighter">Grandes Sonhos</h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Acompanhe sua evolução financeira</p>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-4 h-4" /> Criar Meta
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {goals.map((goal) => {
          const progress = (goal.currentAmount / goal.targetAmount) * 100;
          const remaining = goal.targetAmount - goal.currentAmount;

          return (
            <div key={goal.id} className="bg-[#0a0c14] p-8 rounded-[2.5rem] border border-white/5 shadow-xl flex gap-6 group relative">
              <button 
                onClick={() => removeGoal(goal.id)}
                className="absolute top-6 right-6 opacity-0 group-hover:opacity-100 p-2 text-slate-700 hover:text-rose-500 transition-all"
              >
                <X className="w-5 h-5" />
              </button>

              <div className="hidden sm:flex flex-col items-center justify-center bg-indigo-600/10 w-24 rounded-[1.5rem] p-4 border border-indigo-600/20">
                <Trophy className="w-8 h-8 text-indigo-400 mb-2" />
                <span className="text-[10px] font-black text-indigo-400">{progress.toFixed(0)}%</span>
              </div>

              <div className="flex-1 space-y-4">
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-xl font-black text-white tracking-tight">{goal.name}</h3>
                    <div className="flex items-center gap-2 text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">
                      <Calendar className="w-3 h-3 text-indigo-400" />
                      {new Date(goal.deadline).toLocaleDateString('pt-BR')}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] text-slate-500 font-black uppercase">Faltam</p>
                    <p className="font-black text-rose-400 text-lg">R$ {remaining.toLocaleString()}</p>
                  </div>
                </div>

                <div className="space-y-2">
                  <div className="w-full bg-slate-900 h-3 rounded-full overflow-hidden">
                    <div 
                      className="bg-indigo-600 h-full transition-all duration-1000 ease-out"
                      style={{ width: `${Math.min(progress, 100)}%` }}
                    />
                  </div>
                  <div className="flex justify-between text-[10px] font-black uppercase tracking-widest">
                    <span className="text-slate-500">R$ {goal.currentAmount.toLocaleString()} acumulado</span>
                    <span className="text-slate-200">Alvo: R$ {goal.targetAmount.toLocaleString()}</span>
                  </div>
                </div>

                <div className="flex gap-2 pt-2">
                  <button 
                    onClick={() => setDepositModal({ goalId: goal.id, goalName: goal.name })}
                    className="flex-1 py-3 bg-white/5 text-slate-200 border border-white/10 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center gap-2"
                  >
                    <ArrowUpRight className="w-4 h-4" /> Realizar Aporte
                  </button>
                </div>
              </div>
            </div>
          );
        })}
        {goals.length === 0 && (
          <div className="lg:col-span-2 text-center py-20 bg-slate-900/20 rounded-3xl border border-dashed border-white/10">
            <p className="text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhuma meta ativa</p>
          </div>
        )}
      </div>

      {/* Modal Criar Meta */}
      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-white/10 shadow-2xl animate-in slide-in-from-bottom-4">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-white uppercase tracking-tighter">Novo Sonho</h3>
              <button onClick={() => setShowAdd(false)} className="p-2 hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-slate-500" /></button>
            </div>
            <form onSubmit={handleAdd} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Descrição do Sonho</label>
                <input required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.name} onChange={e => setNewGoal({...newGoal, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Meta Financeira R$</label>
                <input type="number" required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.targetAmount || ''} onChange={e => setNewGoal({...newGoal, targetAmount: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Prazo Estimado</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.deadline} onChange={e => setNewGoal({...newGoal, deadline: e.target.value})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Ativar Sonho</button>
            </form>
          </div>
        </div>
