      {/* Modal de Aporte */}
      {depositModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-white/10 shadow-2xl animate-in zoom-in-95">
             <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-lg font-black text-white uppercase tracking-tighter">Aportar na Meta</h3>
                  <p className="text-slate-500 text-[10px] uppercase font-bold">{depositModal.goalName}</p>
                </div>
                <button onClick={() => setDepositModal(null)} className="p-2 hover:bg-white/5 rounded-full"><X className="w-5 h-5 text-slate-500" /></button>
             </div>

             <div className="space-y-6">
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Valor do Aporte R$</label>
                   <input 
                      type="number" 
                      className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500 text-lg font-bold"
                      value={depositAmount || ''}
                      onChange={e => setDepositAmount(parseFloat(e.target.value))}
                      placeholder="0.00"
                   />
                </div>

                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Sair de qual Pote?</label>
                   <div className="grid grid-cols-1 gap-2">
                      {potes.map(p => (
                        <button 
                          key={p.id}
                          type="button"
                          onClick={() => setSelectedPoteId(p.id)}
                          className={`flex justify-between items-center p-3 rounded-xl border transition-all ${selectedPoteId === p.id ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-indigo-500/50'}`}
                        >
                          <span className="text-xs font-bold">{p.name}</span>
                          <span className="text-xs">R$ {p.balance.toLocaleString()}</span>
                        </button>
                      ))}
                   </div>
                </div>

                <button 
                  onClick={handleDepositSubmit}
                  className="w-full py-4 bg-emerald-500 text-emerald-950 font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl hover:bg-emerald-400 transition-all"
                >
                  Confirmar Aporte
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Search, Plus, Minus, X, Trash2, Edit2, Filter } from 'lucide-react';
import { Transaction, TransactionType, Jar, Category } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  categories: Category[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
}

export default function Transactions({ transactions, potes, categories, onAdd, onDelete, onEdit }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: '', subCategory: '', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX'
  });

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === 'all' || t.type === typeFilter;
      return matchesSearch && matchesType;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, searchTerm, typeFilter]);

  const availableCategories = useMemo(() => {
    return categories.filter(c => c.type === currentTx.type);
  }, [categories, currentTx.type]);

  const availableSubCategories = useMemo(() => {
    const cat = categories.find(c => c.name === currentTx.category);
    return cat ? cat.subCategories : [];
  }, [categories, currentTx.category]);

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: '', subCategory: '', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : '',
      paymentMethod: 'PIX'
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount || !currentTx.category) return;
    if (modalType === 'add') onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    else if (modalType === 'edit') onEdit(currentTx as Transaction);
    setModalType(null);
  };

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-2 gap-3">
        <button onClick={() => handleOpenAdd('income')} className="flex items-center justify-center gap-2 py-4 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-emerald-500/20 active:scale-95 transition-all">
          <Plus className="w-4 h-4" /> Ganho
        </button>
        <button onClick={() => handleOpenAdd('expense')} className="flex items-center justify-center gap-2 py-4 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-rose-500/20 active:scale-95 transition-all">
          <Minus className="w-4 h-4" /> Gasto
        </button>
      </div>

      <div className="bg-slate-900/40 p-3.5 rounded-2xl border border-white/5 space-y-3">
        <div className="flex gap-3 items-center">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-600" />
            <input type="text" placeholder="Filtrar..." className="w-full pl-9 pr-4 py-2.5 bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 text-xs outline-none focus:ring-1 focus:ring-indigo-500" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
          <button onClick={() => setIsFilterExpanded(!isFilterExpanded)} className={`p-2.5 rounded-xl transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-950/50 text-slate-400 border-white/5'}`}>
            <Filter className="w-4 h-4" />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-2.5">
        {filteredTransactions.map(t => (
          <div key={t.id} className="bg-[#0a0c14] p-4 rounded-2xl border border-white/5 flex flex-col gap-2 group animate-in slide-in-from-bottom-2 duration-300">
            <div className="flex justify-between items-start">
              <div className="flex gap-3 min-w-0">
                <div className={`p-1.5 rounded-lg flex-shrink-0 ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                </div>
                <div className="min-w-0">
                  <p className="font-bold text-slate-200 text-xs truncate">{t.description}</p>
                  <p className="text-[8px] text-slate-600 font-black uppercase tracking-widest">
                    {t.category} {t.subCategory && `• ${t.subCategory}`} • {new Date(t.date).toLocaleDateString()}
                  </p>
                </div>
              </div>
              <p className={`font-black text-xs whitespace-nowrap ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-200'}`}>
                R$ {t.amount.toLocaleString()}
              </p>
            </div>
            <div className="flex justify-between items-center border-t border-white/5 pt-2">
              <span className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">
                {t.type === 'income' ? 'RECEITA' : (potes.find(p => p.id === t.poteId)?.name || 'OUTRO')}
              </span>
              <div className="flex gap-1.5">
                <button onClick={() => handleOpenEdit(t)} className="p-2 text-slate-600 bg-slate-900/50 rounded-lg hover:text-indigo-400 transition-colors"><Edit2 className="w-3.5 h-3.5" /></button>
                <button onClick={() => onDelete(t.id)} className="p-2 text-rose-500/50 bg-rose-500/5 rounded-lg hover:text-rose-400 transition-colors"><Trash2 className="w-3.5 h-3.5" /></button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {modalType && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/95 backdrop-blur-sm">
          <div className="bg-[#111827] w-full sm:max-w-md rounded-t-[2.5rem] sm:rounded-[2rem] p-6 md:p-8 border-t border-x sm:border border-white/10 flex flex-col shadow-2xl animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-black text-white uppercase tracking-tighter">{modalType === 'add' ? 'Registrar' : 'Editar'}</h3>
              <button onClick={() => setModalType(null)} className="p-2 bg-slate-900 rounded-full"><X className="w-5 h-5 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Descrição</label>
                <input required className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none focus:ring-1 focus:ring-indigo-600 text-sm" value={currentTx.description} onChange={e => setCurrentTx({...currentTx, description: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Valor R$</label>
                  <input type="number" step="0.01" inputMode="decimal" required className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.amount || ''} onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Data</label>
                  <input type="date" className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
                </div>
              </div>

              {/* Category Selector */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Categoria</label>
                  <select 
                    required 
                    className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm"
                    value={currentTx.category}
                    onChange={e => setCurrentTx({...currentTx, category: e.target.value, subCategory: ''})}
                  >
                    <option value="">Selecione...</option>
                    {availableCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Subcategoria</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm"
                    value={currentTx.subCategory}
                    onChange={e => setCurrentTx({...currentTx, subCategory: e.target.value})}
                    disabled={availableSubCategories.length === 0}
                  >
                    <option value="">{availableSubCategories.length === 0 ? '-' : 'Selecione...'}</option>
                    {availableSubCategories.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                  </select>
                </div>
              </div>

              {currentTx.type === 'expense' && (
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Pote de Origem</label>
                  <select className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    <option value="">Selecione...</option>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name} (R$ {p.balance.toLocaleString()})</option>)}
                  </select>
                </div>
              )}
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-xl shadow-xl mt-4 active:scale-95 transition-all">Salvar Registro</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Budget, Transaction, Category } from '../types';
import { AlertCircle, Plus, X, BarChart3, TrendingDown } from 'lucide-react';

interface BudgetsProps {
  budgets: Budget[];
  transactions: Transaction[];
  categories: Category[];
  onUpdate: (b: Budget[]) => void;
}

export default function Budgets({ budgets, transactions, categories, onUpdate }: BudgetsProps) {
  const [isAdding, setIsAdding] = useState(false);
  const [newBudget, setNewBudget] = useState({ category: '', limit: 0 });

  const expenseCategories = useMemo(() => categories.filter(c => c.type === 'expense'), [categories]);

  const categorySpending = useMemo(() => {
    const map: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.type === 'expense') {
        map[t.category] = (map[t.category] || 0) + t.amount;
      }
    });
    return map;
  }, [transactions]);

  const processedBudgets = useMemo(() => {
    return budgets.map(b => ({
      ...b,
      spent: categorySpending[b.category] || 0
    }));
  }, [budgets, categorySpending]);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newBudget.category || newBudget.limit <= 0) return;
    const budget: Budget = {
      id: Math.random().toString(36).substr(2, 9),
      category: newBudget.category,
      limit: newBudget.limit,
      spent: 0
    };
    onUpdate([...budgets, budget]);
    setNewBudget({ category: '', limit: 0 });
    setIsAdding(false);
  };

  const updateLimit = (id: string, newLimit: number) => {
    onUpdate(budgets.map(b => b.id === id ? { ...b, limit: newLimit } : b));
  };

  const removeBudget = (id: string) => {
    onUpdate(budgets.filter(b => b.id !== id));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-white uppercase tracking-tighter">Limites de Consumo</h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Acompanhe seus orçamentos mensais</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-4 h-4" /> Novo Orçamento
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {processedBudgets.map((budget) => {
          const percentage = (budget.spent / budget.limit) * 100;
          const isOver = percentage > 100;
          const isNear = percentage > 85 && !isOver;

          return (
            <div key={budget.id} className="bg-[#0a0c14] p-6 rounded-[2rem] border border-white/5 shadow-xl flex flex-col group relative">
              <button 
                onClick={() => removeBudget(budget.id)}
                className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 p-2 text-slate-700 hover:text-rose-500 transition-all"
              >
                <X className="w-4 h-4" />
              </button>

              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-xl ${isOver ? 'bg-rose-500/10 text-rose-400' : 'bg-indigo-500/10 text-indigo-400'}`}>
                    <BarChart3 className="w-4 h-4" />
                  </div>
                  <h3 className="font-bold text-slate-200 text-sm uppercase tracking-wider">{budget.category}</h3>
                </div>
                {isOver && <AlertCircle className="w-5 h-5 text-rose-500 animate-pulse" />}
              </div>

              <div className="flex justify-between text-[10px] font-black uppercase tracking-widest mb-2">
                <span className="text-slate-500">Gasto: R$ {budget.spent.toLocaleString()}</span>
                <span className="text-slate-200">Limite: R$ {budget.limit.toLocaleString()}</span>
              </div>

              <div className="w-full bg-slate-900 h-2 rounded-full overflow-hidden mb-4">
                <div 
                  className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500' : isNear ? 'bg-amber-500' : 'bg-indigo-500'}`}
                  style={{ width: `${Math.min(percentage, 100)}%` }}
                />
              </div>

              <div className="mt-auto pt-4 flex justify-between items-center border-t border-white/5">
                <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg ${isOver ? 'bg-rose-500/10 text-rose-500' : isNear ? 'bg-amber-500/10 text-amber-500' : 'bg-emerald-500/10 text-emerald-500'}`}>
                  {isOver ? 'Limite Excedido' : `${(100 - percentage).toFixed(0)}% restante`}
                </span>
                <button 
                  onClick={() => updateLimit(budget.id, budget.limit + 500)}
                  className="text-indigo-400 text-[9px] font-black uppercase tracking-widest hover:text-indigo-300 transition-colors"
                >
                  + R$ 500
                </button>
              </div>
            </div>
          );
        })}
        {processedBudgets.length === 0 && (
          <div className="md:col-span-2 lg:col-span-3 text-center py-20 bg-slate-900/20 rounded-3xl border border-dashed border-white/10">
            <p className="text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhum limite definido</p>
          </div>
        )}
      </div>

      {isAdding && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-md">
          <div className="bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-white uppercase tracking-tighter">Novo Limite</h3>
              <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-slate-500" /></button>
            </div>
            <form onSubmit={handleAdd} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Categoria</label>
                <select 
                  required 
                  className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={newBudget.category}
                  onChange={e => setNewBudget({...newBudget, category: e.target.value})}
                >
                  <option value="">Selecione...</option>
                  {expenseCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Limite Mensal R$</label>
                <input type="number" required className="w-full px-5 py-4 bg-slate-900 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newBudget.limit || ''} onChange={e => setNewBudget({...newBudget, limit: parseFloat(e.target.value)})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Confirmar</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

