];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', subCategory: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', subCategory: 'Aluguel', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', subCategory: 'Supermercado', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
}

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // States for Quick Entry (Fab)
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null); // Limpa o preenchimento automático após salvar
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  // --- Handlers para Câmera e Microfone ---

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    showToast("Analisando imagem...", "info");

    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);

      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; // Reset input
  };

  const handleMicClick = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
    // Não fecha o FAB imediatamente se estiver começando a gravar
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");

          const result = await analyzeAudioCommand(base64Audio);

          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast("Comando de voz entendido!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        // Parar tracks
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };


  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  return (
    <div className="min-h-screen flex bg-[#030712] text-slate-100 font-sans overflow-hidden select-none">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* Input de arquivo escondido para câmera */}
      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {/* Overlay de Processamento */}
      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
          <p className="text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* Floating Action Button Group */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button 
              onClick={handleCameraClick}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button 
              onClick={handleMicClick}
              className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}
            >
              {isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}
            </button>
            <button 
              onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Receipt className="w-5 h-5" />
            </button>
          </div>
        )}

        <button 
          onClick={() => {
             if (isRecording) {
                stopRecording();
             } else {
                setIsFabOpen(!isFabOpen);
             }
          }}
          className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}
        >
          {isRecording ? (
             <div className="w-4 h-4 bg-white rounded-sm animate-spin" />
          ) : (
             <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />
          )}
        </button>
      </div>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-[#0a0c14] border-r border-white/5 flex flex-col
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-slate-500" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => (
            <div key={sectionName} className="space-y-1">
              <h4 className="px-4 text-[8px] font-black text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                {sectionName}
              </h4>
              <div className="space-y-1">
                {navItems.filter(item => item.section === sectionName).map((item) => (
                  <button 
                    key={item.id} 
                    onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                    className={`
                      w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                      ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-slate-500 hover:text-slate-200 hover:bg-slate-800/40'}
                    `}
                  >
                    <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                    <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </nav>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#030712]">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-900/50 rounded-xl text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Patrimônio Líquido</span>
                <span className="text-xs font-black text-white">R$ {financialData.potes.reduce((a,b)=>a+b.balance,0).toLocaleString()}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <BrainCircuit className="w-5 h-5 text-indigo-400" />
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts debts={debts} potes={processedPotes} onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} onPay={handleDebtPayment} />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
              />
            )}
            {view === 'settings' && <Settings categories={categories} onUpdateCategories={setCategories} showToast={showToast} />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div> {/* Espaçador para o FAB no mobile */}
        </div>
      </main>
    </div>
  );
}

import React, { useMemo } from 'react';
import { Wallet, TrendingUp, Plus, PieChart as PieChartIcon, BarChart3, Activity } from 'lucide-react';
import { FinancialData } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid 
} from 'recharts';

interface DashboardProps {
  data: FinancialData;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#06b6d4'];

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, potes } = data;
  const totalBalance = potes.reduce((acc, p) => acc + p.balance, 0);

  const now = new Date();
  const monthIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === now.getMonth())
    .reduce((acc, t) => acc + t.amount, 0);

  const categoryData = useMemo(() => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const categories: Record<string, number> = {};
    expenses.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });
    return Object.entries(categories)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 6);
  }, [transactions]);

  const trendData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const monthIndex = d.getMonth();
      const year = d.getFullYear();
      const income = transactions
        .filter(t => t.type === 'income' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      const expense = transactions
        .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      last6Months.push({ name: months[monthIndex], Entradas: income, Saídas: expense });
    }
    return last6Months;
  }, [transactions]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-[#0f172a] border border-white/10 p-2 rounded-xl shadow-2xl backdrop-blur-md">
          <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-0.5">{payload[0].name || payload[0].dataKey}</p>
          <p className="text-xs font-black text-white">R$ {payload[0].value.toLocaleString()}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-10">

      {/* 1. Saldo */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 p-5 md:p-6 rounded-3xl shadow-xl relative overflow-hidden group border border-white/10">
           <div className="absolute -top-4 -right-4 p-8 opacity-10 group-hover:scale-125 transition-transform duration-700"><Wallet className="w-16 h-16 md:w-24" /></div>
           <span className="text-indigo-100/60 text-[9px] font-black uppercase tracking-[0.2em] block mb-1">Saldo</span>
           <p className={`text-2xl md:text-4xl font-black tracking-tighter ${totalBalance < 0 ? 'text-rose-400' : 'text-white'}`}>
             R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
           <div className="mt-3 flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></div>
              <span className="text-[8px] text-indigo-200/50 font-black uppercase tracking-widest">Ativo</span>
           </div>
        </div>

        <div className="bg-[#111827]/60 p-5 md:p-6 rounded-3xl border border-white/5 relative group overflow-hidden flex flex-col justify-center">
           <div className="absolute -top-4 -right-4 p-8 opacity-5"><TrendingUp className="w-16 h-16 md:w-24" /></div>
           <div className="flex items-center gap-2 mb-2">
              <div className="p-1.5 bg-emerald-500/10 rounded-lg"><TrendingUp className="w-4 h-4 text-emerald-400" /></div>
              <span className="text-slate-500 text-[9px] font-black uppercase tracking-[0.2em]">Ganhos</span>
           </div>
           <p className="text-2xl md:text-4xl font-black text-emerald-400 tracking-tighter">
             R$ {monthIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
        </div>
      </div>

      {/* 2. Potes */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {potes.map((pote) => (
            <div key={pote.id} className="bg-[#0a0c14] p-4 rounded-2xl border border-white/5 hover:border-indigo-500/40 transition-all group">
               <div className="flex justify-between items-center mb-2">
                  <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest truncate">{pote.name}</span>
                  <span className="text-[8px] font-bold text-indigo-400 bg-indigo-500/10 px-1.5 py-0.5 rounded-lg">{pote.percentage}%</span>
               </div>
               <p className={`text-sm md:text-lg font-black tracking-tighter ${pote.balance < 0 ? 'text-rose-500' : 'text-slate-200'}`}>
                 R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
               </p>
               <div className="mt-2 h-1 w-full bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-700" style={{ width: `${Math.max(0, Math.min(100, (pote.balance / (totalBalance || 1)) * 100))}%` }}></div>
               </div>
            </div>
          ))}
      </div>

      {/* 3. Atividades */}
      <div className="space-y-3">
        <h3 className="text-[9px] font-black text-slate-500 uppercase tracking-widest px-1 flex items-center gap-3">
          Atividades <div className="h-px flex-1 bg-slate-800/50"></div>
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {transactions.slice(0, 4).map(t => (
            <div key={t.id} className="bg-[#0a0c14] p-3.5 rounded-2xl border border-white/5 flex items-center justify-between hover:bg-slate-900 transition-colors">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-xl ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-3.5 h-3.5" /> : <Activity className="w-3.5 h-3.5" />}
                </div>
                <div className="min-w-0">
                  <p className="text-xs font-bold text-slate-200 truncate">{t.description}</p>
                  <p className="text-[8px] text-slate-600 font-black uppercase tracking-widest">{t.category}</p>
