                  <Pie data={categoryData} cx="50%" cy="50%" innerRadius="60%" outerRadius="80%" paddingAngle={4} dataKey="value">
                    {categoryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip content={<CustomTooltip />} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-700 text-[9px] font-black uppercase italic tracking-widest">Sem Dados</div>
            )}
          </div>
        </div>

        <div className="bg-[#0a0c14] p-5 rounded-3xl border border-white/5 shadow-xl">
          <h3 className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
            <BarChart3 className="w-3.5 h-3.5 text-indigo-400" /> Histórico
          </h3>
          <div className="h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#475569', fontSize: 9, fontWeight: 900 }} />
                <YAxis hide />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(255,255,255,0.03)' }} />
                <Bar dataKey="Entradas" fill="#10b981" radius={[3, 3, 0, 0]} />
                <Bar dataKey="Saídas" fill="#f43f5e" radius={[3, 3, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

    </div>
  );
}

import { GoogleGenAI } from "@google/genai";
import { FinancialData } from "../types";

export const getFinancialAdvice = async (data: FinancialData, userQuery: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contextSummary = {
    balance: data.transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0) - 
             data.transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0),
    debtsCount: data.debts.filter(d => d.status !== 'paid').length,
    potes: data.potes.map(p => `${p.name}: R$ ${p.balance.toLocaleString('pt-BR')}`).join(', '),
    categories: Array.from(new Set(data.transactions.map(t => t.category)))
  };

  const systemInstruction = `
    Você é o ZenOS Master Assistant, um assistente financeiro de elite.

    ESTADO ATUAL:
    - Saldo: R$ ${contextSummary.balance}
    - Potes: ${contextSummary.potes}
    - Categorias conhecidas: ${contextSummary.categories.join(', ')}

    COMANDOS ESPECIAIS:
    Se o usuário pedir para registrar um gasto ou entrada (ex: "gastei 50 com café" ou "recebi 2000 de bônus"), você deve responder normalmente mas incluir no FINAL da resposta um bloco JSON exatamente com este formato para que o sistema processe:
    {
      "action": "ADD_TRANSACTION",
      "transaction": {
        "description": "string",
        "amount": number,
        "type": "income" | "expense",
        "category": "string",
        "date": "YYYY-MM-DD"
      }
    }

    DIRETRIZES:
    - Seja conciso e executivo.
    - Se for um gasto, tente associar a uma categoria existente: ${contextSummary.categories.join(', ')}.
    - Use Markdown.
    - Responda em Português (Brasil).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: userQuery,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.2, // Baixa temperatura para extração de dados mais precisa
      },
    });

    return response.text;
  } catch (error) {
    console.error("ZenOS AI Error:", error);
    return "Falha na conexão neural. Tente novamente.";
  }
};

// Nova função para analisar Imagens (Cupons Fiscais)
export const analyzeReceipt = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: `Analise este cupom fiscal ou imagem financeira. Extraia os dados para criar uma transação.
             Identifique se é: Mercado, Padaria, Posto de Gasolina, Farmácia, Restaurante, etc.
             Retorne APENAS um JSON (sem markdown code block) neste formato:
             {
               "description": "Nome do Estabelecimento ou Resumo",
               "amount": 0.00,
               "date": "YYYY-MM-DD",
               "category": "Categoria Sugerida (Ex: Alimentação, Transporte, Saúde)",
               "type": "expense"
             }`
          }
        ]
      },
      config: {
        temperature: 0.1,
      }
    });

    const text = response.text || "{}";
    const cleanJson = text.replace(/```json|```/g, '').trim();
    return JSON.parse(cleanJson);
  } catch (error) {
    console.error("Receipt Analysis Error:", error);
    return null;
  }
};

// Nova função para analisar Áudio (Comandos de Voz Rápidos)
export const analyzeAudioCommand = async (base64Audio: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
