        parts: [
          { inlineData: { mimeType: 'audio/mp3', data: base64Audio } }, 
          { text: `Ouça este comando de voz financeiro. Extraia a intenção de transação.
             REGRAS ESTRITAS DE TIPO:
             - Se contiver "Gastei", "Comprei", "Paguei", "Saiu" -> type: "expense"
             - Se contiver "Recebi", "Ganhei", "Entrou", "Depósito" -> type: "income"

             Retorne APENAS um JSON (sem markdown code block) neste formato:
             {
               "description": "Descrição curta (ex: Almoço, Uber, Salário)",
               "amount": 0.00,
               "date": "YYYY-MM-DD" (use hoje se não especificado),
               "category": "Categoria Sugerida",
               "type": "income" | "expense"
             }`
          }
        ]
      }
