const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', subCategory: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', subCategory: 'Aluguel', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', subCategory: 'Supermercado', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
}

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');


  // States for Quick Entry (Fab)
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null); // Limpa o preenchimento automático após salvar
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  // --- Handlers para Câmera e Microfone ---

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    showToast("Analisando imagem...", "info");

    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);

      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; // Reset input
  };

  const handleMicClick = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
    // Não fecha o FAB imediatamente se estiver começando a gravar
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");

          const result = await analyzeAudioCommand(base64Audio);

          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        // Parar tracks
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };


  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  return (
    <div className="min-h-screen flex bg-gray-50 dark:bg-[#030712] text-slate-900 dark:text-slate-100 font-sans overflow-hidden select-none transition-colors duration-300">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* Input de arquivo escondido para câmera */}
      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {/* Overlay de Processamento */}
      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
          <p className="text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* Floating Action Button Group */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button 
              onClick={handleCameraClick}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button 
              onClick={handleMicClick}
              className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}
            >
              {isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}
            </button>
            <button 
              onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Receipt className="w-5 h-5" />
            </button>
          </div>
        )}

        <button 
          onClick={() => {
             if (isRecording) {
                stopRecording();
             } else {
                setIsFabOpen(!isFabOpen);
             }
          }}
          className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}
        >
          {isRecording ? (
             <div className="w-4 h-4 bg-white rounded-sm animate-spin" />
          ) : (
             <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />
          )}
        </button>
      </div>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-white dark:bg-[#0a0c14] border-r border-slate-200 dark:border-white/5 flex flex-col shadow-2xl lg:shadow-none
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter text-slate-800 dark:text-white">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-slate-500" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => (
            <div key={sectionName} className="space-y-1">
              <h4 className="px-4 text-[8px] font-black text-slate-400 dark:text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                {sectionName}
              </h4>
              <div className="space-y-1">
                {navItems.filter(item => item.section === sectionName).map((item) => (
                  <button 
                    key={item.id} 
                    onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                    className={`
                      w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                      ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800/40'}
                    `}
                  >
                    <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                    <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </nav>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-gray-50 dark:bg-[#030712] transition-colors duration-300">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between bg-white/70 dark:bg-[#0f172a]/70 border-b border-slate-200 dark:border-white/5">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-slate-800 dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Patrimônio Líquido</span>
                <span className="text-xs font-black text-slate-900 dark:text-white">R$ {financialData.potes.reduce((a,b)=>a+b.balance,0).toLocaleString()}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <BrainCircuit className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts debts={debts} potes={processedPotes} onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} onPay={handleDebtPayment} />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={setCategories} 
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
              />
            )}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div> {/* Espaçador para o FAB no mobile */}
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Category, SubCategory } from '../types';
import { Settings as SettingsIcon, Plus, Trash2, Edit2, Check, X, Tag, Moon, Sun, Monitor } from 'lucide-react';

interface SettingsProps {
  categories: Category[];
  onUpdateCategories: (cats: Category[]) => void;
  showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
  currentTheme?: 'dark' | 'light';
  toggleTheme?: () => void;
}

export default function Settings({ categories, onUpdateCategories, showToast, currentTheme, toggleTheme }: SettingsProps) {
  const [activeTab, setActiveTab] = useState<'categories' | 'appearance'>('categories');
  const [newCatName, setNewCatName] = useState('');
  const [newCatType, setNewCatType] = useState<'income' | 'expense'>('expense');
  const [editingCatId, setEditingCatId] = useState<string | null>(null);
  const [newSubName, setNewSubName] = useState('');

  const handleAddCategory = () => {
    if (!newCatName.trim()) return;
    const newCat: Category = {
      id: Math.random().toString(36).substr(2, 9),
      name: newCatName,
      type: newCatType,
      subCategories: []
    };
    onUpdateCategories([...categories, newCat]);
    setNewCatName('');
    showToast('Categoria criada com sucesso!', 'success');
  };

  const handleDeleteCategory = (id: string) => {
    if (confirm('Tem certeza? Isso pode afetar registros históricos.')) {
      onUpdateCategories(categories.filter(c => c.id !== id));
      showToast('Categoria removida', 'info');
    }
  };

  const handleAddSubCategory = (catId: string) => {
    if (!newSubName.trim()) return;
    const updatedCats = categories.map(c => {
      if (c.id === catId) {
        return {
          ...c,
          subCategories: [...c.subCategories, { id: Math.random().toString(36).substr(2, 9), name: newSubName }]
        };
      }
      return c;
    });
    onUpdateCategories(updatedCats);
    setNewSubName('');
  };

  const handleDeleteSubCategory = (catId: string, subId: string) => {
    const updatedCats = categories.map(c => {
      if (c.id === catId) {
        return { ...c, subCategories: c.subCategories.filter(s => s.id !== subId) };
      }
      return c;
    });
    onUpdateCategories(updatedCats);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center gap-4 mb-6">
        <div className="bg-indigo-600 p-3 rounded-2xl shadow-lg shadow-indigo-600/20">
          <SettingsIcon className="w-6 h-6 text-white" />
        </div>
        <div>
           <h2 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Ajustes do Sistema</h2>
           <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Personalize sua experiência</p>
        </div>
      </div>

      <div className="bg-white dark:bg-[#0a0c14] border border-slate-200 dark:border-white/5 rounded-[2.5rem] overflow-hidden shadow-xl dark:shadow-none">
         <div className="flex border-b border-slate-200 dark:border-white/5">
            <button 
              onClick={() => setActiveTab('categories')}
              className={`flex-1 py-4 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'categories' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              Categorias
            </button>
            <button 
              onClick={() => setActiveTab('appearance')}
              className={`flex-1 py-4 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'appearance' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              Aparência
            </button>
         </div>

         <div className="p-8">
            {activeTab === 'categories' && (
              <div className="space-y-8">
                {/* Add New Category */}
                <div className="bg-slate-50 dark:bg-slate-900/50 p-6 rounded-3xl border border-slate-200 dark:border-white/5">
                   <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Nova Categoria</h3>
                   <div className="flex flex-col md:flex-row gap-4">
                      <input 
                        type="text" 
                        placeholder="Nome da categoria..."
                        className="flex-1 px-4 py-3 bg-white dark:bg-[#030712] border border-slate-200 dark:border-slate-800 rounded-xl text-slate-900 dark:text-white outline-none focus:ring-1 focus:ring-indigo-500 text-sm"
                        value={newCatName}
                        onChange={e => setNewCatName(e.target.value)}
                      />
                      <select 
                        className="px-4 py-3 bg-white dark:bg-[#030712] border border-slate-200 dark:border-slate-800 rounded-xl text-slate-900 dark:text-white outline-none focus:ring-1 focus:ring-indigo-500 text-sm"
                        value={newCatType}
                        onChange={e => setNewCatType(e.target.value as any)}
                      >
                        <option value="expense">Despesa</option>
                        <option value="income">Receita</option>
                      </select>
                      <button 
                        onClick={handleAddCategory}
                        className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black uppercase text-xs tracking-widest hover:bg-indigo-500 transition-all"
                      >
                        Criar
                      </button>
                   </div>
                </div>

                {/* List Categories */}
                <div className="space-y-4">
                   {categories.map(cat => (
                     <div key={cat.id} className="bg-slate-50 dark:bg-[#111827]/40 rounded-3xl border border-slate-200 dark:border-white/5 overflow-hidden">
                        <div className="p-4 flex items-center justify-between bg-white/50 dark:bg-white/5">
                           <div className="flex items-center gap-3">
                              <span className={`w-2 h-2 rounded-full ${cat.type === 'income' ? 'bg-emerald-400' : 'bg-rose-400'}`}></span>
                              <h4 className="font-bold text-slate-700 dark:text-slate-200">{cat.name}</h4>
                              <span className="text-[9px] font-black uppercase tracking-widest text-slate-500 dark:text-slate-600">{cat.type === 'income' ? 'Receita' : 'Despesa'}</span>
                           </div>
                           <div className="flex items-center gap-2">
                              <button onClick={() => setEditingCatId(editingCatId === cat.id ? null : cat.id)} className="p-2 text-slate-500 hover:text-indigo-400"><Tag className="w-4 h-4" /></button>
                              <button onClick={() => handleDeleteCategory(cat.id)} className="p-2 text-slate-500 hover:text-rose-500"><Trash2 className="w-4 h-4" /></button>
                           </div>
                        </div>

                        {/* Subcategories */}
                        {(editingCatId === cat.id) && (
                          <div className="p-4 bg-slate-100 dark:bg-black/20 animate-in slide-in-from-top-2">
                             <div className="flex flex-wrap gap-2 mb-4">
                                {cat.subCategories.map(sub => (
                                  <div key={sub.id} className="bg-indigo-500/10 border border-indigo-500/20 px-3 py-1.5 rounded-lg flex items-center gap-2">
                                     <span className="text-xs text-indigo-600 dark:text-indigo-300 font-bold">{sub.name}</span>
                                     <button onClick={() => handleDeleteSubCategory(cat.id, sub.id)} className="text-indigo-400 hover:text-rose-400"><X className="w-3 h-3" /></button>
                                  </div>
                                ))}
                             </div>
                             <div className="flex gap-2">
                                <input 
                                  placeholder="Nova subcategoria..."
                                  className="flex-1 px-3 py-2 bg-white dark:bg-[#030712] border border-slate-200 dark:border-slate-800 rounded-lg text-slate-900 dark:text-white text-xs outline-none"
                                  value={newSubName}
                                  onChange={e => setNewSubName(e.target.value)}
                                  onKeyDown={e => e.key === 'Enter' && handleAddSubCategory(cat.id)}
                                />
                                <button onClick={() => handleAddSubCategory(cat.id)} className="p-2 bg-indigo-600 rounded-lg text-white"><Plus className="w-4 h-4" /></button>
                             </div>
                          </div>
                        )}
                     </div>
                   ))}
                </div>
              </div>
            )}

            {activeTab === 'appearance' && (
              <div className="space-y-6">
                 <div className="bg-slate-50 dark:bg-slate-900/50 p-6 rounded-3xl border border-slate-200 dark:border-white/5 flex items-center justify-between">
                    <div className="flex items-center gap-4">
                       <div className="p-3 bg-indigo-500/10 rounded-2xl">
                          {currentTheme === 'dark' ? <Moon className="w-6 h-6 text-indigo-400" /> : <Sun className="w-6 h-6 text-amber-500" />}
                       </div>
                       <div>
                          <h3 className="text-sm font-bold text-slate-900 dark:text-white">Modo Escuro</h3>
                          <p className="text-xs text-slate-500 dark:text-slate-400">Alternar entre tema claro e escuro</p>
                       </div>
                    </div>

                    <button 
                      onClick={toggleTheme}
                      className={`
                        relative inline-flex h-8 w-14 items-center rounded-full transition-colors duration-300
                        ${currentTheme === 'dark' ? 'bg-indigo-600' : 'bg-slate-300'}
                      `}
                    >
                      <span className={`
                        inline-block h-6 w-6 transform rounded-full bg-white transition-transform duration-300 shadow-md
                        ${currentTheme === 'dark' ? 'translate-x-7' : 'translate-x-1'}
                      `} />
                    </button>
                 </div>
              </div>
            )}
         </div>
      </div>
    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { Search, Plus, Minus, X, Trash2, Edit2, Filter } from 'lucide-react';
import { Transaction, TransactionType, Jar, Category } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  categories: Category[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
  preFilledData?: Partial<Transaction> | null;
}

export default function Transactions({ transactions, potes, categories, onAdd, onDelete, onEdit, preFilledData }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: '', subCategory: '', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX'
  });

  // Effect para abrir o modal quando dados pré-preenchidos (IA) chegarem
  useEffect(() => {
    if (preFilledData) {
      setCurrentTx({
        ...currentTx,
        ...preFilledData,
        // Garante que se a IA mandou uma categoria que existe, use-a. Se não, string vazia.
        category: categories.some(c => c.name === preFilledData.category) ? preFilledData.category : '',
        poteId: preFilledData.type === 'expense' && potes.length > 0 ? potes[0].id : ''
      });
      setModalType('add');
    }
  }, [preFilledData, categories, potes]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === 'all' || t.type === typeFilter;
      return matchesSearch && matchesType;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, searchTerm, typeFilter]);

  const availableCategories = useMemo(() => {
    return categories.filter(c => c.type === currentTx.type);
  }, [categories, currentTx.type]);

  const availableSubCategories = useMemo(() => {
    const cat = categories.find(c => c.name === currentTx.category);
    return cat ? cat.subCategories : [];
  }, [categories, currentTx.category]);

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: '', subCategory: '', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : '',
      paymentMethod: 'PIX'
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount || !currentTx.category) return;
    if (modalType === 'add') onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    else if (modalType === 'edit') onEdit(currentTx as Transaction);
    setModalType(null);
  };

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-2 gap-3">
        <button onClick={() => handleOpenAdd('income')} className="flex items-center justify-center gap-2 py-4 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-emerald-500/20 active:scale-95 transition-all">
          <Plus className="w-4 h-4" /> Ganho
        </button>
        <button onClick={() => handleOpenAdd('expense')} className="flex items-center justify-center gap-2 py-4 bg-rose-500/10 border border-rose-500/20 text-rose-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-rose-500/20 active:scale-95 transition-all">
          <Minus className="w-4 h-4" /> Gasto
        </button>
      </div>

      <div className="bg-slate-900/40 p-3.5 rounded-2xl border border-white/5 space-y-3">
        <div className="flex gap-3 items-center">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-600" />
            <input type="text" placeholder="Filtrar..." className="w-full pl-9 pr-4 py-2.5 bg-slate-950/50 border border-white/5 rounded-xl text-slate-200 text-xs outline-none focus:ring-1 focus:ring-indigo-500" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
          <button onClick={() => setIsFilterExpanded(!isFilterExpanded)} className={`p-2.5 rounded-xl transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-950/50 text-slate-400 border-white/5'}`}>
            <Filter className="w-4 h-4" />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-2.5">
        {filteredTransactions.map(t => (
          <div key={t.id} className="bg-[#0a0c14] p-4 rounded-2xl border border-white/5 flex flex-col gap-2 group animate-in slide-in-from-bottom-2 duration-300">
            <div className="flex justify-between items-start">
              <div className="flex gap-3 min-w-0">
                <div className={`p-1.5 rounded-lg flex-shrink-0 ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                </div>
                <div className="min-w-0">
                  <p className="font-bold text-slate-200 text-xs truncate">{t.description}</p>
                  <p className="text-[8px] text-slate-600 font-black uppercase tracking-widest">
                    {t.category} {t.subCategory && `• ${t.subCategory}`} • {new Date(t.date).toLocaleDateString()}
                  </p>
                </div>
              </div>
              <p className={`font-black text-xs whitespace-nowrap ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-200'}`}>
                R$ {t.amount.toLocaleString()}
              </p>
            </div>
            <div className="flex justify-between items-center border-t border-white/5 pt-2">
              <span className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">
                {t.type === 'income' ? 'RECEITA' : (potes.find(p => p.id === t.poteId)?.name || 'OUTRO')}
              </span>
              <div className="flex gap-1.5">
                <button onClick={() => handleOpenEdit(t)} className="p-2 text-slate-600 bg-slate-900/50 rounded-lg hover:text-indigo-400 transition-colors"><Edit2 className="w-3.5 h-3.5" /></button>
                <button onClick={() => onDelete(t.id)} className="p-2 text-rose-500/50 bg-rose-500/5 rounded-lg hover:text-rose-400 transition-colors"><Trash2 className="w-3.5 h-3.5" /></button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {modalType && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/95 backdrop-blur-sm">
          <div className={`
             bg-[#111827] w-full sm:max-w-md rounded-t-[2.5rem] sm:rounded-[2rem] p-6 md:p-8 border-t border-x sm:border flex flex-col shadow-2xl animate-in slide-in-from-bottom duration-300
             ${currentTx.type === 'income' ? 'border-emerald-500/30' : 'border-rose-500/30'}
          `}>
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center gap-3">
                 <div className={`p-2 rounded-xl ${currentTx.type === 'income' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                    {currentTx.type === 'income' ? <Plus className="w-5 h-5" /> : <Minus className="w-5 h-5" />}
                 </div>
                 <h3 className="text-lg font-black text-white uppercase tracking-tighter">
                    {modalType === 'add' ? 'Registrar' : 'Editar'} {currentTx.type === 'income' ? 'Ganho' : 'Gasto'}
                 </h3>
              </div>
              <button onClick={() => setModalType(null)} className="p-2 bg-slate-900 rounded-full"><X className="w-5 h-5 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Descrição</label>
                <input required className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none focus:ring-1 focus:ring-indigo-600 text-sm" value={currentTx.description} onChange={e => setCurrentTx({...currentTx, description: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Valor R$</label>
                  <input type="number" step="0.01" inputMode="decimal" required className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.amount || ''} onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Data</label>
                  <input type="date" className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
                </div>
              </div>

              {/* Category Selector */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Categoria</label>
                  <select 
                    required 
                    className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm"
                    value={currentTx.category}
                    onChange={e => setCurrentTx({...currentTx, category: e.target.value, subCategory: ''})}
                  >
                    <option value="">Selecione...</option>
                    {availableCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                    {/* Fallback option if category doesn't match predefined ones */}
                    {currentTx.category && !availableCategories.some(c => c.name === currentTx.category) && (
                       <option value={currentTx.category}>{currentTx.category} (Sugerida)</option>
                    )}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Subcategoria</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm"
                    value={currentTx.subCategory}
                    onChange={e => setCurrentTx({...currentTx, subCategory: e.target.value})}
                    disabled={availableSubCategories.length === 0}
                  >
                    <option value="">{availableSubCategories.length === 0 ? '-' : 'Selecione...'}</option>
                    {availableSubCategories.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                  </select>
                </div>
              </div>

              {currentTx.type === 'expense' && (
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Pote de Origem</label>
                  <select className="w-full px-4 py-3 bg-slate-950 border border-slate-800 rounded-xl text-white outline-none text-sm" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    <option value="">Selecione...</option>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name} (R$ {p.balance.toLocaleString()})</option>)}
                  </select>
                </div>
              )}
              <button 
                type="submit" 
                className={`w-full py-4 text-white font-black uppercase text-xs tracking-widest rounded-xl shadow-xl mt-4 active:scale-95 transition-all
                  ${currentTx.type === 'income' ? 'bg-emerald-600 hover:bg-emerald-500' : 'bg-rose-600 hover:bg-rose-500'}
                `}
              >
                Confirmar {currentTx.type === 'income' ? 'Entrada' : 'Saída'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Receipt, Target, BrainCircuit, Menu, X, Archive, 
  AlertCircle, Plus, Settings as SettingsIcon, Camera, Mic, Loader2, StopCircle
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Budget, FinancialGoal, Category } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Settings from './components/Settings';
import Toast, { ToastType } from './components/Toast';
import { analyzeReceipt, analyzeAudioCommand } from './services/gemini';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const DEFAULT_CATEGORIES: Category[] = [
  { 
    id: 'c1', name: 'Moradia', type: 'expense', isDefault: true,
    subCategories: [{id: 's1', name: 'Aluguel'}, {id: 's2', name: 'Energia'}, {id: 's3', name: 'Internet'}, {id: 's4', name: 'Manutenção'}] 
  },
  { 
    id: 'c2', name: 'Alimentação', type: 'expense', isDefault: true,
    subCategories: [{id: 's5', name: 'Supermercado'}, {id: 's6', name: 'Restaurante'}, {id: 's7', name: 'Delivery'}] 
  },
  { 
    id: 'c3', name: 'Transporte', type: 'expense', isDefault: true,
    subCategories: [{id: 's8', name: 'Combustível'}, {id: 's9', name: 'Uber/Táxi'}, {id: 's10', name: 'Manutenção Veículo'}] 
  },
  { 
    id: 'c4', name: 'Saúde', type: 'expense', isDefault: true,
    subCategories: [{id: 's11', name: 'Farmácia'}, {id: 's12', name: 'Consultas'}, {id: 's13', name: 'Plano de Saúde'}] 
  },
  { 
    id: 'c5', name: 'Lazer', type: 'expense', isDefault: true,
    subCategories: [{id: 's14', name: 'Cinema/Streaming'}, {id: 's15', name: 'Viagem'}, {id: 's16', name: 'Hobbies'}] 
  },
  { 
    id: 'c6', name: 'Renda', type: 'income', isDefault: true,
    subCategories: [{id: 's17', name: 'Salário'}, {id: 's18', name: 'Freelance'}, {id: 's19', name: 'Dividendos'}] 
  }
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', subCategory: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', subCategory: 'Aluguel', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', subCategory: 'Supermercado', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
}

export default function App() {
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');


  // States for Quick Entry (Fab)
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null); // Limpa o preenchimento automático após salvar
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  // --- Handlers para Câmera e Microfone ---

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    showToast("Analisando imagem...", "info");

    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);

      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; // Reset input
  };

  const handleMicClick = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
    // Não fecha o FAB imediatamente se estiver começando a gravar
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");

          const result = await analyzeAudioCommand(base64Audio);

          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        // Parar tracks
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };


  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  return (
    <div className="min-h-screen flex bg-[#F8F9FA] dark:bg-[#030712] text-[#212529] dark:text-slate-100 font-sans overflow-hidden select-none transition-colors duration-300">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* Input de arquivo escondido para câmera */}
      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {/* Overlay de Processamento */}
      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-white/80 dark:bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          <p className="text-[#212529] dark:text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* Floating Action Button Group */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button 
              onClick={handleCameraClick}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button 
              onClick={handleMicClick}
              className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}
            >
              {isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}
            </button>
            <button 
              onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Receipt className="w-5 h-5" />
            </button>
          </div>
        )}

        <button 
          onClick={() => {
             if (isRecording) {
                stopRecording();
             } else {
                setIsFabOpen(!isFabOpen);
             }
          }}
          className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}
        >
          {isRecording ? (
             <div className="w-4 h-4 bg-white rounded-sm animate-spin" />
          ) : (
             <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />
          )}
        </button>
      </div>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-white dark:bg-[#0a0c14] border-r border-slate-200 dark:border-white/5 flex flex-col shadow-2xl lg:shadow-none
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter text-[#212529] dark:text-white">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-[#6C757D]" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => (
            <div key={sectionName} className="space-y-1">
              <h4 className="px-4 text-[8px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                {sectionName}
              </h4>
              <div className="space-y-1">
                {navItems.filter(item => item.section === sectionName).map((item) => (
                  <button 
                    key={item.id} 
                    onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                    className={`
                      w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                      ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800/40'}
                    `}
                  >
                    <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                    <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </nav>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#F8F9FA] dark:bg-[#030712] transition-colors duration-300">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-[#212529] dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest">Patrimônio Líquido</span>
                <span className="text-xs font-black text-[#212529] dark:text-white">R$ {financialData.potes.reduce((a,b)=>a+b.balance,0).toLocaleString()}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <BrainCircuit className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts debts={debts} potes={processedPotes} onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} onPay={handleDebtPayment} />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={setCategories} 
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
              />
            )}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div> {/* Espaçador para o FAB no mobile */}
        </div>
      </main>
    </div>
  );
}

import React, { useMemo } from 'react';
import { Wallet, TrendingUp, Plus, PieChart as PieChartIcon, BarChart3, Activity } from 'lucide-react';
import { FinancialData } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid 
} from 'recharts';

interface DashboardProps {
  data: FinancialData;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#06b6d4'];

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, potes } = data;
  const totalBalance = potes.reduce((acc, p) => acc + p.balance, 0);

  const now = new Date();
  const monthIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === now.getMonth())
    .reduce((acc, t) => acc + t.amount, 0);

  const categoryData = useMemo(() => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const categories: Record<string, number> = {};
    expenses.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });
    return Object.entries(categories)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 6);
  }, [transactions]);

  const trendData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const monthIndex = d.getMonth();
      const year = d.getFullYear();
      const income = transactions
        .filter(t => t.type === 'income' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      const expense = transactions
        .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      last6Months.push({ name: months[monthIndex], Entradas: income, Saídas: expense });
    }
    return last6Months;
  }, [transactions]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white dark:bg-[#0f172a] border border-slate-200 dark:border-white/10 p-2 rounded-xl shadow-2xl backdrop-blur-md">
          <p className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-0.5">{payload[0].name || payload[0].dataKey}</p>
          <p className="text-xs font-black text-[#212529] dark:text-white">R$ {payload[0].value.toLocaleString()}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-10">

      {/* 1. Saldo */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 p-5 md:p-6 rounded-3xl shadow-xl relative overflow-hidden group border border-white/10">
           <div className="absolute -top-4 -right-4 p-8 opacity-10 group-hover:scale-125 transition-transform duration-700"><Wallet className="w-16 h-16 md:w-24 text-white" /></div>
           <span className="text-indigo-100/60 text-[9px] font-black uppercase tracking-[0.2em] block mb-1">Saldo</span>
           <p className={`text-2xl md:text-4xl font-black tracking-tighter ${totalBalance < 0 ? 'text-rose-400' : 'text-white'}`}>
             R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
           <div className="mt-3 flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></div>
              <span className="text-[8px] text-indigo-200/50 font-black uppercase tracking-widest">Ativo</span>
           </div>
        </div>

        <div className="bg-white dark:bg-[#111827]/60 p-5 md:p-6 rounded-3xl border border-slate-200 dark:border-white/5 relative group overflow-hidden flex flex-col justify-center shadow-sm dark:shadow-none">
           <div className="absolute -top-4 -right-4 p-8 opacity-5"><TrendingUp className="w-16 h-16 md:w-24 text-[#212529] dark:text-white" /></div>
           <div className="flex items-center gap-2 mb-2">
              <div className="p-1.5 bg-emerald-500/10 rounded-lg"><TrendingUp className="w-4 h-4 text-emerald-600 dark:text-emerald-400" /></div>
              <span className="text-[#6C757D] dark:text-slate-500 text-[9px] font-black uppercase tracking-[0.2em]">Ganhos</span>
           </div>
           <p className="text-2xl md:text-4xl font-black text-emerald-600 dark:text-emerald-400 tracking-tighter">
             R$ {monthIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
        </div>
      </div>

      {/* 2. Potes */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {potes.map((pote) => (
            <div key={pote.id} className="bg-white dark:bg-[#0a0c14] p-4 rounded-2xl border border-slate-200 dark:border-white/5 hover:border-indigo-500/40 transition-all group shadow-sm dark:shadow-none">
               <div className="flex justify-between items-center mb-2">
                  <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest truncate">{pote.name}</span>
                  <span className="text-[8px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-500/10 px-1.5 py-0.5 rounded-lg">{pote.percentage}%</span>
               </div>
               <p className={`text-sm md:text-lg font-black tracking-tighter ${pote.balance < 0 ? 'text-rose-500' : 'text-[#212529] dark:text-slate-200'}`}>
                 R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
               </p>
               <div className="mt-2 h-1 w-full bg-slate-100 dark:bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-700" style={{ width: `${Math.max(0, Math.min(100, (pote.balance / (totalBalance || 1)) * 100))}%` }}></div>
               </div>
            </div>
          ))}
      </div>

      {/* 3. Atividades */}
      <div className="space-y-3">
        <h3 className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest px-1 flex items-center gap-3">
          Atividades <div className="h-px flex-1 bg-slate-200 dark:bg-slate-800/50"></div>
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {transactions.slice(0, 4).map(t => (
            <div key={t.id} className="bg-white dark:bg-[#0a0c14] p-3.5 rounded-2xl border border-slate-200 dark:border-white/5 flex items-center justify-between hover:bg-slate-50 dark:hover:bg-slate-900 transition-colors shadow-sm dark:shadow-none">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-xl ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : 'bg-rose-500/10 text-rose-600 dark:text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-3.5 h-3.5" /> : <Activity className="w-3.5 h-3.5" />}
                </div>
                <div className="min-w-0">
                  <p className="text-xs font-bold text-[#212529] dark:text-slate-200 truncate">{t.description}</p>
                  <p className="text-[8px] text-[#6C757D] dark:text-slate-600 font-black uppercase tracking-widest">{t.category}</p>
                </div>
              </div>
              <p className={`text-xs font-black ${t.type === 'income' ? 'text-emerald-600 dark:text-emerald-400' : 'text-[#212529] dark:text-slate-300'}`}>
                R$ {t.amount.toLocaleString()}
              </p>
            </div>
          ))}
          {transactions.length === 0 && (
            <div className="col-span-full py-6 text-center text-[#6C757D] dark:text-slate-700 text-[8px] font-black uppercase italic tracking-widest">Vazio</div>
          )}
        </div>
      </div>

      {/* 4 e 5. Gráficos */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-white dark:bg-[#0a0c14] p-5 rounded-3xl border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none">
          <h3 className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
            <PieChartIcon className="w-3.5 h-3.5 text-indigo-500 dark:text-indigo-400" /> Consumo
          </h3>
          <div className="h-[250px] w-full mx-auto">
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={categoryData} cx="50%" cy="50%" innerRadius="60%" outerRadius="80%" paddingAngle={4} dataKey="value">
                    {categoryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip content={<CustomTooltip />} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-[#6C757D] dark:text-slate-700 text-[9px] font-black uppercase italic tracking-widest">Sem Dados</div>
            )}
          </div>
        </div>

        <div className="bg-white dark:bg-[#0a0c14] p-5 rounded-3xl border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none">
          <h3 className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
            <BarChart3 className="w-3.5 h-3.5 text-indigo-500 dark:text-indigo-400" /> Histórico
          </h3>
          <div className="h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" className="dark:stroke-slate-800" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 9, fontWeight: 900 }} />
                <YAxis hide />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(99, 102, 241, 0.1)' }} />
                <Bar dataKey="Entradas" fill="#10b981" radius={[3, 3, 0, 0]} />
                <Bar dataKey="Saídas" fill="#f43f5e" radius={[3, 3, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { Search, Plus, Minus, X, Trash2, Edit2, Filter } from 'lucide-react';
import { Transaction, TransactionType, Jar, Category } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  categories: Category[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
  preFilledData?: Partial<Transaction> | null;
}

export default function Transactions({ transactions, potes, categories, onAdd, onDelete, onEdit, preFilledData }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [isFilterExpanded, setIsFilterExpanded] = useState(false);
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: '', subCategory: '', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX'
  });

  // Effect para abrir o modal quando dados pré-preenchidos (IA) chegarem
  useEffect(() => {
    if (preFilledData) {
      setCurrentTx({
        ...currentTx,
        ...preFilledData,
        // Garante que se a IA mandou uma categoria que existe, use-a. Se não, string vazia.
        category: categories.some(c => c.name === preFilledData.category) ? preFilledData.category : '',
        poteId: preFilledData.type === 'expense' && potes.length > 0 ? potes[0].id : ''
      });
      setModalType('add');
    }
  }, [preFilledData, categories, potes]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === 'all' || t.type === typeFilter;
      return matchesSearch && matchesType;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, searchTerm, typeFilter]);

  const availableCategories = useMemo(() => {
    return categories.filter(c => c.type === currentTx.type);
  }, [categories, currentTx.type]);

  const availableSubCategories = useMemo(() => {
    const cat = categories.find(c => c.name === currentTx.category);
    return cat ? cat.subCategories : [];
  }, [categories, currentTx.category]);

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: '', subCategory: '', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : '',
      paymentMethod: 'PIX'
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount || !currentTx.category) return;
    if (modalType === 'add') onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    else if (modalType === 'edit') onEdit(currentTx as Transaction);
    setModalType(null);
  };

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-2 gap-3">
        <button onClick={() => handleOpenAdd('income')} className="flex items-center justify-center gap-2 py-4 bg-emerald-500/10 border border-emerald-500/20 text-emerald-600 dark:text-emerald-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-emerald-500/20 active:scale-95 transition-all">
          <Plus className="w-4 h-4" /> Ganho
        </button>
        <button onClick={() => handleOpenAdd('expense')} className="flex items-center justify-center gap-2 py-4 bg-rose-500/10 border border-rose-500/20 text-rose-600 dark:text-rose-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-rose-500/20 active:scale-95 transition-all">
          <Minus className="w-4 h-4" /> Gasto
        </button>
      </div>

      <div className="bg-white dark:bg-slate-900/40 p-3.5 rounded-2xl border border-slate-200 dark:border-white/5 space-y-3 shadow-sm dark:shadow-none">
        <div className="flex gap-3 items-center">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500 dark:text-slate-600" />
            <input type="text" placeholder="Filtrar..." className="w-full pl-9 pr-4 py-2.5 bg-slate-100 dark:bg-slate-950/50 border border-slate-200 dark:border-white/5 rounded-xl text-[#212529] dark:text-slate-200 text-xs outline-none focus:ring-1 focus:ring-indigo-500" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
          <button onClick={() => setIsFilterExpanded(!isFilterExpanded)} className={`p-2.5 rounded-xl transition-all border ${isFilterExpanded ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-100 dark:bg-slate-950/50 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-white/5'}`}>
            <Filter className="w-4 h-4" />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-2.5">
        {filteredTransactions.map(t => (
          <div key={t.id} className="bg-white dark:bg-[#0a0c14] p-4 rounded-2xl border border-slate-200 dark:border-white/5 flex flex-col gap-2 group animate-in slide-in-from-bottom-2 duration-300 shadow-sm dark:shadow-none">
            <div className="flex justify-between items-start">
              <div className="flex gap-3 min-w-0">
                <div className={`p-1.5 rounded-lg flex-shrink-0 ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : 'bg-rose-500/10 text-rose-600 dark:text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                </div>
                <div className="min-w-0">
                  <p className="font-bold text-[#212529] dark:text-slate-200 text-xs truncate">{t.description}</p>
                  <p className="text-[8px] text-[#6C757D] dark:text-slate-600 font-black uppercase tracking-widest">
                    {t.category} {t.subCategory && `• ${t.subCategory}`} • {new Date(t.date).toLocaleDateString()}
                  </p>
                </div>
              </div>
              <p className={`font-black text-xs whitespace-nowrap ${t.type === 'income' ? 'text-emerald-600 dark:text-emerald-400' : 'text-[#212529] dark:text-slate-200'}`}>
                R$ {t.amount.toLocaleString()}
              </p>
            </div>
            <div className="flex justify-between items-center border-t border-slate-100 dark:border-white/5 pt-2">
              <span className="text-[8px] font-black text-indigo-500 dark:text-indigo-400 uppercase tracking-widest">
                {t.type === 'income' ? 'RECEITA' : (potes.find(p => p.id === t.poteId)?.name || 'OUTRO')}
              </span>
              <div className="flex gap-1.5">
                <button onClick={() => handleOpenEdit(t)} className="p-2 text-[#6C757D] dark:text-slate-600 bg-slate-100 dark:bg-slate-900/50 rounded-lg hover:text-indigo-500 dark:hover:text-indigo-400 transition-colors"><Edit2 className="w-3.5 h-3.5" /></button>
                <button onClick={() => onDelete(t.id)} className="p-2 text-rose-500/50 bg-rose-500/5 rounded-lg hover:text-rose-600 dark:hover:text-rose-400 transition-colors"><Trash2 className="w-3.5 h-3.5" /></button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {modalType && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/50 dark:bg-black/95 backdrop-blur-sm">
          <div className={`
             bg-white dark:bg-[#111827] w-full sm:max-w-md rounded-t-[2.5rem] sm:rounded-[2rem] p-6 md:p-8 border-t border-x sm:border flex flex-col shadow-2xl animate-in slide-in-from-bottom duration-300
             ${currentTx.type === 'income' ? 'border-emerald-500/30' : 'border-rose-500/30'}
          `}>
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center gap-3">
                 <div className={`p-2 rounded-xl ${currentTx.type === 'income' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : 'bg-rose-500/10 text-rose-600 dark:text-rose-400'}`}>
                    {currentTx.type === 'income' ? <Plus className="w-5 h-5" /> : <Minus className="w-5 h-5" />}
                 </div>
                 <h3 className="text-lg font-black text-[#212529] dark:text-white uppercase tracking-tighter">
                    {modalType === 'add' ? 'Registrar' : 'Editar'} {currentTx.type === 'income' ? 'Ganho' : 'Gasto'}
                 </h3>
              </div>
              <button onClick={() => setModalType(null)} className="p-2 bg-slate-100 dark:bg-slate-900 rounded-full"><X className="w-5 h-5 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Descrição</label>
                <input required className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none focus:ring-1 focus:ring-indigo-600 text-sm" value={currentTx.description} onChange={e => setCurrentTx({...currentTx, description: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Valor R$</label>
                  <input type="number" step="0.01" inputMode="decimal" required className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm" value={currentTx.amount || ''} onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Data</label>
                  <input type="date" className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
                </div>
              </div>

              {/* Category Selector */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Categoria</label>
                  <select 
                    required 
                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm"
                    value={currentTx.category}
                    onChange={e => setCurrentTx({...currentTx, category: e.target.value, subCategory: ''})}
                  >
                    <option value="">Selecione...</option>
                    {availableCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                    {currentTx.category && !availableCategories.some(c => c.name === currentTx.category) && (
                       <option value={currentTx.category}>{currentTx.category} (Sugerida)</option>
                    )}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Subcategoria</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm"
                    value={currentTx.subCategory}
                    onChange={e => setCurrentTx({...currentTx, subCategory: e.target.value})}
                    disabled={availableSubCategories.length === 0}
                  >
                    <option value="">{availableSubCategories.length === 0 ? '-' : 'Selecione...'}</option>
                    {availableSubCategories.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                  </select>
                </div>
              </div>

              {currentTx.type === 'expense' && (
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Pote de Origem</label>
                  <select className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    <option value="">Selecione...</option>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name} (R$ {p.balance.toLocaleString()})</option>)}
                  </select>
                </div>
              )}
              <button 
                type="submit" 
                className={`w-full py-4 text-white font-black uppercase text-xs tracking-widest rounded-xl shadow-xl mt-4 active:scale-95 transition-all
                  ${currentTx.type === 'income' ? 'bg-emerald-600 hover:bg-emerald-500' : 'bg-rose-600 hover:bg-rose-500'}
                `}
              >
                Confirmar {currentTx.type === 'income' ? 'Entrada' : 'Saída'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { Jar } from '../types';
import { Plus, Trash2, Edit2, Archive, X, Save, Settings } from 'lucide-react';

interface PotesProps {
  potes: Jar[];
  onUpdate: (potes: Jar[]) => void;
}

export default function Potes({ potes, onUpdate }: PotesProps) {
  const [showModal, setShowModal] = useState<'add' | 'edit' | null>(null);
  const [currentPote, setCurrentPote] = useState<Partial<Jar>>({ name: '', percentage: 0 });

  const totalPercentage = potes.reduce((acc, p) => acc + p.percentage, 0);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const otherPotes = showModal === 'edit' ? potes.filter(p => p.id !== currentPote.id) : potes;
    const currentTotal = otherPotes.reduce((acc, p) => acc + p.percentage, 0);

    if (currentTotal + (currentPote.percentage || 0) > 100) { 
      alert("ERRO: A soma total das porcentagens não pode exceder 100%!"); 
      return; 
    }

    if (showModal === 'add') {
      const pote: Jar = { 
        id: Math.random().toString(36).substr(2, 9), 
        name: currentPote.name || 'Novo Pote', 
        percentage: currentPote.percentage || 0, 
        balance: 0 
      };
      onUpdate([...potes, pote]);
    } else {
      onUpdate(potes.map(p => p.id === currentPote.id ? { ...p, ...currentPote } as Jar : p));
    }
    setShowModal(null);
  };

  return (
    <div className="space-y-8">
      {/* Resumo da Estrutura */}
      <div className="bg-white dark:bg-[#0a0c14] p-8 rounded-[2.5rem] border border-slate-200 dark:border-white/5 flex flex-col md:flex-row items-center justify-between gap-6 shadow-2xl dark:shadow-none">
        <div className="flex items-center gap-5">
           <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-600/20">
              <Settings className="w-8 h-8 text-indigo-600 dark:text-indigo-400" />
           </div>
           <div>
              <h2 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Arquitetura de Rateio</h2>
              <p className="text-[#6C757D] dark:text-slate-500 text-[11px] font-bold uppercase tracking-[0.2em] mt-1">
                Alocação: <span className={`px-2 py-0.5 rounded-lg ${totalPercentage > 100 ? 'bg-rose-500/20 text-rose-600 dark:text-rose-400' : 'bg-indigo-500/10 text-indigo-600 dark:text-indigo-400'}`}>{totalPercentage}% / 100%</span>
              </p>
           </div>
        </div>
        <button 
          onClick={() => { setCurrentPote({ name: '', percentage: 0 }); setShowModal('add'); }}
          className="w-full md:w-auto flex items-center justify-center gap-3 px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-5 h-5" /> Adicionar Pote
        </button>
      </div>

      {/* Grid de Potes Editáveis */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {potes.map((pote) => (
          <div key={pote.id} className="bg-white dark:bg-[#111827]/40 p-6 rounded-[2rem] border border-slate-200 dark:border-white/5 group relative overflow-hidden transition-all hover:border-indigo-500/30 shadow-sm dark:shadow-none">
            <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
              <button onClick={() => { setCurrentPote(pote); setShowModal('edit'); }} className="p-2 text-[#6C757D] dark:text-slate-600 hover:text-indigo-500 dark:hover:text-indigo-400 hover:bg-slate-100 dark:hover:bg-white/5 rounded-xl"><Edit2 className="w-4 h-4" /></button>
              <button onClick={() => { if(confirm(`Excluir ${pote.name}? As transações vinculadas perderão a referência de pote.`)) onUpdate(potes.filter(p => p.id !== pote.id)) }} className="p-2 text-[#6C757D] dark:text-slate-600 hover:text-rose-500 hover:bg-slate-100 dark:hover:bg-white/5 rounded-xl"><Trash2 className="w-4 h-4" /></button>
            </div>

            <div className="bg-indigo-500/10 w-12 h-12 flex items-center justify-center rounded-2xl border border-indigo-500/20 mb-6">
              <Archive className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
            </div>

            <h3 className="text-lg font-black text-[#212529] dark:text-white mb-1 tracking-tight truncate pr-10">{pote.name}</h3>
            <span className="text-[10px] font-black text-indigo-600/80 dark:text-indigo-500/80 uppercase tracking-widest block mb-4">Rateio: {pote.percentage}%</span>

            <div className="pt-4 border-t border-slate-100 dark:border-white/5">
              <p className="text-[9px] text-[#6C757D] dark:text-slate-600 uppercase font-black tracking-widest mb-1">Saldo Atual (Live)</p>
              <p className={`text-2xl font-black tracking-tighter ${pote.balance >= 0 ? 'text-[#212529] dark:text-slate-200' : 'text-rose-500'}`}>
                R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
            </div>
          </div>
        ))}
      </div>

      {/* Modal de Configuração de Pote */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/95 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Configurar Pote</h3>
              <button onClick={() => setShowModal(null)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-full"><X className="w-5 h-5 text-[#6C757D] dark:text-slate-600" /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-6">
