}

import React, { useState } from 'react';
import { FinancialGoal, Jar } from '../types';
import { Target, Trophy, Calendar, Plus, X, ArrowUpRight, Wallet } from 'lucide-react';

interface GoalsProps {
  goals: FinancialGoal[];
  potes: Jar[];
  onAdd: (g: FinancialGoal) => void;
  onUpdate: (goals: FinancialGoal[]) => void;
  onDeposit: (amount: number, poteId: string, goalName: string) => void;
}

export default function Goals({ goals, potes, onAdd, onUpdate, onDeposit }: GoalsProps) {
  const [showAdd, setShowAdd] = useState(false);
  const [newGoal, setNewGoal] = useState({ name: '', targetAmount: 0, deadline: '' });

  const [depositModal, setDepositModal] = useState<{ goalId: string, goalName: string } | null>(null);
  const [depositAmount, setDepositAmount] = useState(0);
  const [selectedPoteId, setSelectedPoteId] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newGoal.name || newGoal.targetAmount <= 0) return;
    const goal: FinancialGoal = {
      id: Math.random().toString(36).substr(2, 9),
      name: newGoal.name,
      targetAmount: newGoal.targetAmount,
      currentAmount: 0,
      deadline: newGoal.deadline || new Date().toISOString().split('T')[0]
    };
    onAdd(goal);
    setNewGoal({ name: '', targetAmount: 0, deadline: '' });
    setShowAdd(false);
  };

  const handleDepositSubmit = () => {
    if (depositAmount <= 0 || !selectedPoteId || !depositModal) return;

    // Atualiza a meta
    onUpdate(goals.map(g => g.id === depositModal.goalId ? { ...g, currentAmount: g.currentAmount + depositAmount } : g));

    // Aciona a lógica de transação (débito do pote)
    onDeposit(depositAmount, selectedPoteId, depositModal.goalName);

    // Limpa estado
    setDepositModal(null);
    setDepositAmount(0);
    setSelectedPoteId('');
  };

  const removeGoal = (id: string) => {
    onUpdate(goals.filter(g => g.id !== id));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Grandes Sonhos</h2>
          <p className="text-[#6C757D] dark:text-slate-500 text-xs font-bold uppercase tracking-widest">Acompanhe sua evolução financeira</p>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-4 h-4" /> Criar Meta
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {goals.map((goal) => {
          const progress = (goal.currentAmount / goal.targetAmount) * 100;
          const remaining = goal.targetAmount - goal.currentAmount;

          return (
            <div key={goal.id} className="bg-white dark:bg-[#0a0c14] p-8 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none flex gap-6 group relative">
              <button 
                onClick={() => removeGoal(goal.id)}
                className="absolute top-6 right-6 opacity-0 group-hover:opacity-100 p-2 text-[#6C757D] dark:text-slate-700 hover:text-rose-500 transition-all"
              >
                <X className="w-5 h-5" />
              </button>

              <div className="hidden sm:flex flex-col items-center justify-center bg-indigo-600/10 w-24 rounded-[1.5rem] p-4 border border-indigo-600/20">
                <Trophy className="w-8 h-8 text-indigo-600 dark:text-indigo-400 mb-2" />
                <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400">{progress.toFixed(0)}%</span>
              </div>

              <div className="flex-1 space-y-4">
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-xl font-black text-[#212529] dark:text-white tracking-tight">{goal.name}</h3>
                    <div className="flex items-center gap-2 text-[#6C757D] dark:text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">
                      <Calendar className="w-3 h-3 text-indigo-500 dark:text-indigo-400" />
                      {new Date(goal.deadline).toLocaleDateString('pt-BR')}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase">Faltam</p>
                    <p className="font-black text-rose-500 dark:text-rose-400 text-lg">R$ {remaining.toLocaleString()}</p>
                  </div>
                </div>

                <div className="space-y-2">
                  <div className="w-full bg-slate-100 dark:bg-slate-900 h-3 rounded-full overflow-hidden">
                    <div 
                      className="bg-indigo-600 h-full transition-all duration-1000 ease-out"
                      style={{ width: `${Math.min(progress, 100)}%` }}
                    />
                  </div>
                  <div className="flex justify-between text-[10px] font-black uppercase tracking-widest">
                    <span className="text-[#6C757D] dark:text-slate-500">R$ {goal.currentAmount.toLocaleString()} acumulado</span>
                    <span className="text-[#212529] dark:text-slate-200">Alvo: R$ {goal.targetAmount.toLocaleString()}</span>
                  </div>
                </div>

                <div className="flex gap-2 pt-2">
                  <button 
                    onClick={() => setDepositModal({ goalId: goal.id, goalName: goal.name })}
                    className="flex-1 py-3 bg-slate-50 dark:bg-white/5 text-[#212529] dark:text-slate-200 border border-slate-200 dark:border-white/10 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 hover:text-white hover:border-indigo-600 transition-all flex items-center justify-center gap-2"
                  >
                    <ArrowUpRight className="w-4 h-4" /> Realizar Aporte
                  </button>
                </div>
              </div>
            </div>
          );
        })}
        {goals.length === 0 && (
          <div className="lg:col-span-2 text-center py-20 bg-slate-100 dark:bg-slate-900/20 rounded-3xl border border-dashed border-slate-300 dark:border-white/10">
            <p className="text-[#6C757D] dark:text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhuma meta ativa</p>
          </div>
        )}
      </div>

      {/* Modal Criar Meta */}
      {showAdd && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/90 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl animate-in slide-in-from-bottom-4">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Novo Sonho</h3>
              <button onClick={() => setShowAdd(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-[#6C757D] dark:text-slate-500" /></button>
            </div>
            <form onSubmit={handleAdd} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Descrição do Sonho</label>
                <input required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.name} onChange={e => setNewGoal({...newGoal, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Meta Financeira R$</label>
                <input type="number" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.targetAmount || ''} onChange={e => setNewGoal({...newGoal, targetAmount: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Prazo Estimado</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newGoal.deadline} onChange={e => setNewGoal({...newGoal, deadline: e.target.value})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Ativar Sonho</button>
            </form>
          </div>
        </div>
      )}

      {/* Modal de Aporte */}
      {depositModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/90 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl animate-in zoom-in-95">
             <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-lg font-black text-[#212529] dark:text-white uppercase tracking-tighter">Aportar na Meta</h3>
                  <p className="text-[#6C757D] dark:text-slate-500 text-[10px] uppercase font-bold">{depositModal.goalName}</p>
                </div>
                <button onClick={() => setDepositModal(null)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-full"><X className="w-5 h-5 text-[#6C757D] dark:text-slate-500" /></button>
             </div>

             <div className="space-y-6">
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Valor do Aporte R$</label>
                   <input 
                      type="number" 
                      className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500 text-lg font-bold"
                      value={depositAmount || ''}
                      onChange={e => setDepositAmount(parseFloat(e.target.value))}
                      placeholder="0.00"
                   />
                </div>

                <div className="space-y-2">
                   <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Sair de qual Pote?</label>
                   <div className="grid grid-cols-1 gap-2">
                      {potes.map(p => (
                        <button 
                          key={p.id}
                          type="button"
                          onClick={() => setSelectedPoteId(p.id)}
                          className={`flex justify-between items-center p-3 rounded-xl border transition-all ${selectedPoteId === p.id ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-[#6C757D] dark:text-slate-400 hover:border-indigo-500/50'}`}
                        >
                          <span className="text-xs font-bold">{p.name}</span>
                          <span className="text-xs">R$ {p.balance.toLocaleString()}</span>
                        </button>
                      ))}
                   </div>
                </div>

                <button 
                  onClick={handleDepositSubmit}
                  className="w-full py-4 bg-emerald-500 text-emerald-950 font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl hover:bg-emerald-400 transition-all"
                >
                  Confirmar Aporte
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useMemo } from 'react';
import { Wallet, TrendingUp, Plus, PieChart as PieChartIcon, BarChart3, Activity } from 'lucide-react';
import { FinancialData } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid 
} from 'recharts';

interface DashboardProps {
  data: FinancialData;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#06b6d4'];

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, potes } = data;
  const totalBalance = potes.reduce((acc, p) => acc + p.balance, 0);

  const now = new Date();
  const monthIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === now.getMonth())
    .reduce((acc, t) => acc + t.amount, 0);

  const categoryData = useMemo(() => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const categories: Record<string, number> = {};
    expenses.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });
    return Object.entries(categories)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 6);
  }, [transactions]);

  const trendData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const monthIndex = d.getMonth();
      const year = d.getFullYear();
      const income = transactions
        .filter(t => t.type === 'income' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      const expense = transactions
        .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      last6Months.push({ name: months[monthIndex], Entradas: income, Saídas: expense });
    }
    return last6Months;
  }, [transactions]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white dark:bg-[#0f172a] border border-slate-200 dark:border-white/10 p-2 rounded-xl shadow-2xl backdrop-blur-md">
          <p className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-0.5">{payload[0].name || payload[0].dataKey}</p>
          <p className="text-xs font-black text-[#212529] dark:text-white">R$ {payload[0].value.toLocaleString()}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-10">

      {/* 1. Saldo */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 p-5 md:p-6 rounded-3xl shadow-xl relative overflow-hidden group border border-white/10">
           <div className="absolute -top-4 -right-4 p-8 opacity-10 group-hover:scale-125 transition-transform duration-700"><Wallet className="w-16 h-16 md:w-24 text-white" /></div>
           <span className="text-indigo-100/60 text-[9px] font-black uppercase tracking-[0.2em] block mb-1">Saldo</span>
           <p className={`text-2xl md:text-4xl font-black tracking-tighter ${totalBalance < 0 ? 'text-rose-400' : 'text-white'}`}>
             R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
           <div className="mt-3 flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></div>
              <span className="text-[8px] text-indigo-200/50 font-black uppercase tracking-widest">Ativo</span>
           </div>
        </div>

        <div className="bg-white dark:bg-[#111827]/60 p-5 md:p-6 rounded-3xl border border-slate-200 dark:border-white/5 relative group overflow-hidden flex flex-col justify-center shadow-sm dark:shadow-none">
           <div className="absolute -top-4 -right-4 p-8 opacity-5"><TrendingUp className="w-16 h-16 md:w-24 text-[#212529] dark:text-white" /></div>
           <div className="flex items-center gap-2 mb-2">
              <div className="p-1.5 bg-emerald-500/10 rounded-lg"><TrendingUp className="w-4 h-4 text-emerald-600 dark:text-emerald-400" /></div>
              <span className="text-[#6C757D] dark:text-slate-500 text-[9px] font-black uppercase tracking-[0.2em]">Ganhos</span>
           </div>
           <p className="text-2xl md:text-4xl font-black text-emerald-600 dark:text-emerald-400 tracking-tighter">
             R$ {monthIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
        </div>
      </div>

      {/* 2. Potes */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {potes.map((pote) => (
