              </>
            )}
            {mode === 'register' && (
              <button onClick={() => setMode('login')} className="text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:underline">Já tem conta? Entrar.</button>
            )}
            {mode === 'forgot' && (
              <button onClick={() => setMode('login')} className="text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:underline">Voltar para o login</button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

