import React, { useState, useMemo } from 'react';
import { Jar, Transaction } from '../types';
import { Plus, Trash2, Edit2, Archive, X, Save, Settings, Calendar } from 'lucide-react';

interface PotesProps {
  potes: Jar[];
  transactions: Transaction[];
  onUpdate: (potes: Jar[]) => void;
}

export default function Potes({ potes, transactions, onUpdate }: PotesProps) {
  const [showModal, setShowModal] = useState<'add' | 'edit' | null>(null);
  const [currentPote, setCurrentPote] = useState<Partial<Jar>>({ name: '', percentage: 0 });
  const [dateRange, setDateRange] = useState({ start: '', end: '' });

  const totalPercentage = potes.reduce((acc, p) => acc + p.percentage, 0);

  // Calcula o saldo do período se datas forem selecionadas
  const periodBalances = useMemo(() => {
    if (!dateRange.start && !dateRange.end) return null;

    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      const txDate = t.date;
      const afterStart = !dateRange.start || txDate >= dateRange.start;
      const beforeEnd = !dateRange.end || txDate <= dateRange.end;

      if (afterStart && beforeEnd) {
        if (t.type === 'income') {
          totalIncome += t.amount;
        } else if (t.type === 'expense' && t.poteId) {
          expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
        }
      }
    });

    return potes.reduce((acc, pote) => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      acc[pote.id] = allocatedIncome - expenses;
      return acc;
    }, {} as Record<string, number>);

  }, [transactions, potes, dateRange]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const otherPotes = showModal === 'edit' ? potes.filter(p => p.id !== currentPote.id) : potes;
    const currentTotal = otherPotes.reduce((acc, p) => acc + p.percentage, 0);

    if (currentTotal + (currentPote.percentage || 0) > 100) { 
      alert("ERRO: A soma total das porcentagens não pode exceder 100%!"); 
      return; 
    }

    if (showModal === 'add') {
      const pote: Jar = { 
        id: Math.random().toString(36).substr(2, 9), 
        name: currentPote.name || 'Novo Pote', 
        percentage: currentPote.percentage || 0, 
        balance: 0 
      };
      onUpdate([...potes, pote]);
    } else {
      onUpdate(potes.map(p => p.id === currentPote.id ? { ...p, ...currentPote } as Jar : p));
    }
    setShowModal(null);
  };

  return (
    <div className="space-y-8">
      {/* Resumo da Estrutura */}
      <div className="bg-white dark:bg-[#0a0c14] p-8 rounded-[2.5rem] border border-slate-200 dark:border-white/5 flex flex-col xl:flex-row items-start xl:items-center justify-between gap-6 shadow-2xl dark:shadow-none">
        <div className="flex flex-col md:flex-row items-start md:items-center gap-5 w-full xl:w-auto">
           <div className="flex items-center gap-5">
             <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-600/20">
                <Settings className="w-8 h-8 text-indigo-600 dark:text-indigo-400" />
             </div>
             <div>
                <h2 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Arquitetura de Rateio</h2>
                <p className="text-[#6C757D] dark:text-slate-500 text-[11px] font-bold uppercase tracking-[0.2em] mt-1">
                  Alocação: <span className={`px-2 py-0.5 rounded-lg ${totalPercentage > 100 ? 'bg-rose-500/20 text-rose-600 dark:text-rose-400' : 'bg-indigo-500/10 text-indigo-600 dark:text-indigo-400'}`}>{totalPercentage}% / 100%</span>
                </p>
             </div>
           </div>

           {/* Date Filter in Potes */}
           <div className="flex items-center gap-2 mt-4 md:mt-0 bg-slate-50 dark:bg-slate-900/50 p-2 rounded-2xl border border-slate-200 dark:border-white/5">
              <div className="relative">
                 <input 
                   type="date" 
                   className="pl-3 pr-2 py-2 bg-transparent text-[#212529] dark:text-slate-200 text-[10px] outline-none font-bold uppercase w-28"
                   value={dateRange.start}
                   onChange={e => setDateRange({...dateRange, start: e.target.value})}
                 />
              </div>
              <span className="text-slate-400 text-xs">-</span>
              <div className="relative">
                 <input 
                   type="date" 
                   className="pl-2 pr-2 py-2 bg-transparent text-[#212529] dark:text-slate-200 text-[10px] outline-none font-bold uppercase w-28"
                   value={dateRange.end}
                   onChange={e => setDateRange({...dateRange, end: e.target.value})}
                 />
              </div>
              {(dateRange.start || dateRange.end) && (
                <button 
                  onClick={() => setDateRange({start: '', end: ''})}
                  className="p-1.5 bg-slate-200 dark:bg-slate-800 rounded-lg text-slate-500 hover:text-rose-500"
                >
                  <X className="w-3 h-3" />
                </button>
              )}
           </div>
        </div>

        <button 
          onClick={() => { setCurrentPote({ name: '', percentage: 0 }); setShowModal('add'); }}
          className="w-full xl:w-auto flex items-center justify-center gap-3 px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-5 h-5" /> Adicionar Pote
        </button>
      </div>

      {/* Grid de Potes Editáveis */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {potes.map((pote) => {
          const displayBalance = periodBalances ? periodBalances[pote.id] : pote.balance;
          const isPeriodView = !!periodBalances;

          return (
            <div key={pote.id} className="bg-white dark:bg-[#111827]/40 p-6 rounded-[2rem] border border-slate-200 dark:border-white/5 group relative overflow-hidden transition-all hover:border-indigo-500/30 shadow-sm dark:shadow-none">
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                <button onClick={() => { setCurrentPote(pote); setShowModal('edit'); }} className="p-2 text-[#6C757D] dark:text-slate-600 hover:text-indigo-500 dark:hover:text-indigo-400 hover:bg-slate-100 dark:hover:bg-white/5 rounded-xl"><Edit2 className="w-4 h-4" /></button>
                <button onClick={() => { if(confirm(`Excluir ${pote.name}? As transações vinculadas perderão a referência de pote.`)) onUpdate(potes.filter(p => p.id !== pote.id)) }} className="p-2 text-[#6C757D] dark:text-slate-600 hover:text-rose-500 hover:bg-slate-100 dark:hover:bg-white/5 rounded-xl"><Trash2 className="w-4 h-4" /></button>
              </div>

              <div className="bg-indigo-500/10 w-12 h-12 flex items-center justify-center rounded-2xl border border-indigo-500/20 mb-6">
                <Archive className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
              </div>

              <h3 className="text-lg font-black text-[#212529] dark:text-white mb-1 tracking-tight truncate pr-10">{pote.name}</h3>
              <span className="text-[10px] font-black text-indigo-600/80 dark:text-indigo-500/80 uppercase tracking-widest block mb-4">Rateio: {pote.percentage}%</span>

              <div className="pt-4 border-t border-slate-100 dark:border-white/5">
                <p className="text-[9px] text-[#6C757D] dark:text-slate-600 uppercase font-black tracking-widest mb-1">
                  {isPeriodView ? 'Fluxo do Período' : 'Saldo Acumulado'}
                </p>
                <p className={`text-2xl font-black tracking-tighter ${displayBalance >= 0 ? 'text-[#212529] dark:text-slate-200' : 'text-rose-500'}`}>
                  R$ {displayBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </p>
              </div>
            </div>
          );
        })}
      </div>

      {/* Modal de Configuração de Pote */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/95 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Configurar Pote</h3>
              <button onClick={() => setShowModal(null)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-full"><X className="w-5 h-5 text-[#6C757D] dark:text-slate-600" /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Identificação</label>
                <input type="text" required className="w-full px-5 py-4 bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm text-[#212529] dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentPote.name} onChange={e => setCurrentPote({...currentPote, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Percentual de Entrada (%)</label>
                <div className="relative">
                  <input type="number" required min="0" max="100" className="w-full px-5 py-4 bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-sm text-[#212529] dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none" value={currentPote.percentage || ''} onChange={e => setCurrentPote({...currentPote, percentage: parseInt(e.target.value) || 0})} />
                  <span className="absolute right-5 top-1/2 -translate-y-1/2 text-[#6C757D] dark:text-slate-600 font-black">%</span>
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(null)} className="flex-1 py-4 text-[#6C757D] dark:text-slate-600 font-black uppercase text-xs tracking-widest hover:text-[#212529] dark:hover:text-white transition-colors">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-indigo-500 shadow-xl transition-all">
                  Confirmar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Budget, Transaction, Category } from '../types';
import { AlertCircle, Plus, X, BarChart3, Edit2, Calendar, TrendingUp } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';

interface BudgetsProps {
  budgets: Budget[];
  transactions: Transaction[];
  categories: Category[];
  onUpdate: (b: Budget[]) => void;
}

export default function Budgets({ budgets, transactions, categories, onUpdate }: BudgetsProps) {
  const [modalMode, setModalMode] = useState<'add' | 'edit' | 'view' | null>(null);
  const [selectedBudget, setSelectedBudget] = useState<Budget | null>(null);

  // State para formulário (Add/Edit)
  const [formData, setFormData] = useState({ id: '', category: '', limit: 0 });

  // State para filtro do gráfico (View)
  const [graphDateRange, setGraphDateRange] = useState({
    start: new Date(new Date().setMonth(new Date().getMonth() - 5)).toISOString().split('T')[0], // 6 meses atrás
    end: new Date().toISOString().split('T')[0]
  });

  const expenseCategories = useMemo(() => categories.filter(c => c.type === 'expense'), [categories]);

  // Calcula gastos do mês atual para exibir nos cards
  const currentMonthSpending = useMemo(() => {
    const now = new Date();
    const map: Record<string, number> = {};
    transactions.forEach(t => {
      const tDate = new Date(t.date);
      if (t.type === 'expense' && tDate.getMonth() === now.getMonth() && tDate.getFullYear() === now.getFullYear()) {
        map[t.category] = (map[t.category] || 0) + t.amount;
      }
    });
    return map;
  }, [transactions]);

  const processedBudgets = useMemo(() => {
    return budgets.map(b => ({
      ...b,
      spent: currentMonthSpending[b.category] || 0
    }));
  }, [budgets, currentMonthSpending]);

  // Gera dados históricos para o gráfico do orçamento selecionado
  const historyData = useMemo(() => {
    if (!selectedBudget) return [];

    const data = [];
    const start = new Date(graphDateRange.start);
    const end = new Date(graphDateRange.end);

    // Itera mês a mês dentro do range
    let current = new Date(start);
    current.setDate(1); // Garante início do mês

    while (current <= end) {
        const monthIdx = current.getMonth();
        const year = current.getFullYear();
        const label = current.toLocaleDateString('pt-BR', { month: 'short', year: '2-digit' });

        const total = transactions
            .filter(t => {
                const tDate = new Date(t.date);
                return t.category === selectedBudget.category && 
                       t.type === 'expense' &&
                       tDate.getMonth() === monthIdx &&
                       tDate.getFullYear() === year;
            })
            .reduce((acc, t) => acc + t.amount, 0);

        data.push({ name: label, Gasto: total, Limite: selectedBudget.limit });
        current.setMonth(current.getMonth() + 1);
    }
    return data;
  }, [selectedBudget, transactions, graphDateRange]);

  const handleOpenAdd = () => {
    setFormData({ id: '', category: '', limit: 0 });
    setModalMode('add');
  };

  const handleOpenEdit = (e: React.MouseEvent, budget: Budget) => {
    e.stopPropagation();
    setFormData({ id: budget.id, category: budget.category, limit: budget.limit });
    setModalMode('edit');
  };

  const handleOpenView = (budget: Budget) => {
    setSelectedBudget(budget);
    setModalMode('view');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.category || formData.limit <= 0) return;

    if (modalMode === 'add') {
      const newB: Budget = {
        id: Math.random().toString(36).substr(2, 9),
        category: formData.category,
        limit: formData.limit,
        spent: 0
      };
      onUpdate([...budgets, newB]);
    } else if (modalMode === 'edit') {
      onUpdate(budgets.map(b => b.id === formData.id ? { ...b, category: formData.category, limit: formData.limit } : b));
    }
    setModalMode(null);
  };

  const removeBudget = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if(confirm("Remover este orçamento?")) {
        onUpdate(budgets.filter(b => b.id !== id));
    }
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white dark:bg-[#1e293b] p-3 rounded-xl shadow-xl border border-slate-200 dark:border-white/10">
          <p className="text-xs font-bold text-slate-500 mb-1">{label}</p>
          <p className="text-sm font-black text-indigo-500">Gasto: R$ {payload[0].value.toLocaleString()}</p>
          <p className="text-[10px] font-bold text-slate-400">Limite: R$ {payload[1]?.value.toLocaleString()}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Limites de Consumo</h2>
          <p className="text-[#6C757D] dark:text-slate-500 text-xs font-bold uppercase tracking-widest">Toque em um card para ver detalhes</p>
        </div>
        <button 
          onClick={handleOpenAdd}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-4 h-4" /> Novo Orçamento
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {processedBudgets.map((budget) => {
          const percentage = (budget.spent / budget.limit) * 100;
          const isOver = percentage > 100;
          const isNear = percentage > 85 && !isOver;

          return (
            <div 
                key={budget.id} 
                onClick={() => handleOpenView(budget)}
                className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2rem] border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none flex flex-col group relative cursor-pointer hover:border-indigo-500/30 transition-all"
            >
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button 
                    onClick={(e) => handleOpenEdit(e, budget)}
                    className="p-2 text-[#6C757D] dark:text-slate-700 hover:text-indigo-500 bg-slate-100 dark:bg-white/5 rounded-full"
                  >
                    <Edit2 className="w-3.5 h-3.5" />
                  </button>
                  <button 
                    onClick={(e) => removeBudget(e, budget.id)}
                    className="p-2 text-[#6C757D] dark:text-slate-700 hover:text-rose-500 bg-slate-100 dark:bg-white/5 rounded-full"
                  >
                    <X className="w-3.5 h-3.5" />
                  </button>
              </div>

              <div className="flex justify-between items-start mb-6">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-xl ${isOver ? 'bg-rose-500/10 text-rose-600 dark:text-rose-400' : 'bg-indigo-500/10 text-indigo-600 dark:text-indigo-400'}`}>
                    <BarChart3 className="w-4 h-4" />
                  </div>
                  <h3 className="font-bold text-[#212529] dark:text-slate-200 text-sm uppercase tracking-wider">{budget.category}</h3>
                </div>
                {isOver && <AlertCircle className="w-5 h-5 text-rose-500 animate-pulse" />}
              </div>

              <div className="flex justify-between text-[10px] font-black uppercase tracking-widest mb-2">
                <span className="text-[#6C757D] dark:text-slate-500">Gasto: R$ {budget.spent.toLocaleString()}</span>
                <span className="text-[#212529] dark:text-slate-200">Limite: R$ {budget.limit.toLocaleString()}</span>
              </div>

              <div className="w-full bg-slate-100 dark:bg-slate-900 h-2 rounded-full overflow-hidden mb-4">
                <div 
                  className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500' : isNear ? 'bg-amber-500' : 'bg-indigo-500'}`}
                  style={{ width: `${Math.min(percentage, 100)}%` }}
                />
              </div>

              <div className="mt-auto pt-4 flex justify-between items-center border-t border-slate-100 dark:border-white/5">
                <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg ${isOver ? 'bg-rose-500/10 text-rose-600 dark:text-rose-500' : isNear ? 'bg-amber-500/10 text-amber-600 dark:text-amber-500' : 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-500'}`}>
                  {isOver ? 'Limite Excedido' : `${Math.max(0, 100 - percentage).toFixed(0)}% restante`}
                </span>
                <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest flex items-center gap-1">
                    Ver detalhes <TrendingUp className="w-3 h-3" />
                </span>
              </div>
            </div>
          );
        })}
        {processedBudgets.length === 0 && (
          <div className="md:col-span-2 lg:col-span-3 text-center py-20 bg-slate-100 dark:bg-slate-900/20 rounded-3xl border border-dashed border-slate-300 dark:border-white/10">
            <p className="text-[#6C757D] dark:text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhum limite definido</p>
          </div>
        )}
      </div>

      {/* Modal Add/Edit */}
      {(modalMode === 'add' || modalMode === 'edit') && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/90 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">
                {modalMode === 'add' ? 'Novo Limite' : 'Editar Limite'}
              </h3>
              <button onClick={() => setModalMode(null)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-[#6C757D] dark:text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Categoria</label>
                <select 
                  required 
                  className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={formData.category}
                  onChange={e => setFormData({...formData, category: e.target.value})}
                >
                  <option value="">Selecione...</option>
                  {expenseCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Limite Mensal R$</label>
                <input type="number" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={formData.limit || ''} onChange={e => setFormData({...formData, limit: parseFloat(e.target.value)})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Salvar</button>
            </form>
          </div>
        </div>
      )}

      {/* Modal View Details (Graph) */}
      {modalMode === 'view' && selectedBudget && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 dark:bg-black/90 backdrop-blur-md">
            <div className="bg-white dark:bg-[#0f172a] rounded-[2.5rem] w-full max-w-3xl p-6 md:p-8 border border-slate-200 dark:border-white/10 shadow-2xl animate-in zoom-in-95 flex flex-col max-h-[90vh]">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <h3 className="text-2xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">{selectedBudget.category}</h3>
                        <p className="text-[#6C757D] dark:text-slate-500 text-xs font-bold uppercase tracking-widest">Análise de Consumo</p>
                    </div>
                    <button onClick={() => setModalMode(null)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-[#6C757D] dark:text-slate-500" /></button>
                </div>

                {/* Date Filter */}
                <div className="flex flex-wrap gap-2 items-center mb-6 bg-slate-50 dark:bg-slate-900/50 p-3 rounded-2xl">
                    <Calendar className="w-4 h-4 text-slate-500 ml-2" />
                    <input 
                        type="date" 
                        value={graphDateRange.start} 
                        onChange={e => setGraphDateRange({...graphDateRange, start: e.target.value})}
                        className="bg-transparent text-xs font-bold text-slate-700 dark:text-slate-300 outline-none"
                    />
                    <span className="text-slate-400">-</span>
                    <input 
                        type="date" 
                        value={graphDateRange.end} 
                        onChange={e => setGraphDateRange({...graphDateRange, end: e.target.value})}
                        className="bg-transparent text-xs font-bold text-slate-700 dark:text-slate-300 outline-none"
                    />
                </div>

                <div className="flex-1 w-full min-h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={historyData} margin={{ top: 20, right: 30, left: 0, bottom: 5 }}>
                            <CartesianGrid strokeDasharray="3 3" stroke="#334155" opacity={0.1} vertical={false} />
                            <XAxis dataKey="name" tick={{fontSize: 10, fill: '#64748b'}} axisLine={false} tickLine={false} />
                            <YAxis tick={{fontSize: 10, fill: '#64748b'}} axisLine={false} tickLine={false} />
                            <Tooltip content={<CustomTooltip />} cursor={{fill: 'rgba(99, 102, 241, 0.1)'}} />
                            <Bar dataKey="Gasto" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={40} />
                            {/* Linha de referência visual para o limite poderia ser adicionada aqui se desejado */}
                        </BarChart>
                    </ResponsiveContainer>
                </div>
            </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { Debt, Jar } from '../types';
import { Plus, CheckCircle2, AlertTriangle, Calendar, CreditCard, ChevronRight, DollarSign, X, LayoutList, Grip, Clock } from 'lucide-react';

interface DebtsProps {
  debts: Debt[];
  potes: Jar[];
  onAdd: (d: Debt) => void;
  onUpdate: (d: Debt) => void;
  onPay: (d: Debt, amount: number, poteId: string) => void;
}

export default function Debts({ debts, potes, onAdd, onUpdate, onPay }: DebtsProps) {
  const [showAddModal, setShowAddModal] = useState(false);
  const [viewMode, setViewMode] = useState<'simple' | 'detailed'>('simple');
  const [inputType, setInputType] = useState<'total' | 'installment'>('total');

  const [paymentModal, setPaymentModal] = useState<{ debt: Debt | null, amount: number, poteId: string }>({ 
    debt: null, 
    amount: 0, 
    poteId: '' 
  });

  const [newDebt, setNewDebt] = useState<{
    name: string;
    valueInput: number; // Pode ser total ou parcela
    dueDate: string;
    category: string;
    installments: number;
  }>({
    name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1
  });

  const totalDebt = debts.filter(d => d.status !== 'paid').reduce((acc, d) => acc + d.remainingAmount, 0);

  // Ordenação: Vencidos primeiro, depois por data de vencimento
  const sortedDebts = [...debts].sort((a, b) => {
    if (a.status === 'paid' && b.status !== 'paid') return 1;
    if (a.status !== 'paid' && b.status === 'paid') return -1;
    return new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime();
  });

  const handleOpenPayment = (debt: Debt) => {
    let suggestedAmount = debt.remainingAmount;
    if (debt.installments && debt.installments > 0) {
        suggestedAmount = debt.totalAmount / debt.installments;
        if(suggestedAmount > debt.remainingAmount) suggestedAmount = debt.remainingAmount;
    }

    setPaymentModal({
      debt,
      amount: parseFloat(suggestedAmount.toFixed(2)),
      poteId: potes.length > 0 ? potes[0].id : ''
    });
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDebt.name || !newDebt.valueInput) return;

    let totalAmount = 0;
    if (inputType === 'total') {
        totalAmount = newDebt.valueInput;
    } else {
        totalAmount = newDebt.valueInput * (newDebt.installments || 1);
    }

    onAdd({
      id: Math.random().toString(36).substr(2, 9),
      name: newDebt.name,
      totalAmount: totalAmount,
      remainingAmount: totalAmount,
      dueDate: newDebt.dueDate,
      category: newDebt.category,
      installments: newDebt.installments,
      status: 'active',
      currentInstallment: 0
    });

    setNewDebt({ name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1 });
    setShowAddModal(false);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-rose-500/10 border border-rose-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-rose-600 dark:text-rose-400 uppercase tracking-widest block mb-2">Total em Aberto</span>
          <p className="text-3xl font-black text-rose-600 dark:text-white tracking-tighter">R$ {totalDebt.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
        </div>
        <div className="bg-emerald-500/10 border border-emerald-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest block mb-2">Dívidas Quitadas</span>
          <p className="text-3xl font-black text-emerald-600 dark:text-white tracking-tighter">{debts.filter(d => d.status === 'paid').length}</p>
        </div>
        <div className="flex items-center justify-center">
            <button 
              onClick={() => setShowAddModal(true)}
              className="w-full h-full flex items-center justify-center gap-3 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/10"
            >
              <Plus className="w-5 h-5" /> Nova Dívida
            </button>
        </div>
      </div>

      <div className="flex justify-between items-center">
        <h3 className="text-[11px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-[0.2em] flex items-center gap-3">
          Compromissos <div className="h-px w-10 bg-slate-200 dark:bg-slate-800"></div>
        </h3>
        <div className="flex gap-1 bg-slate-100 dark:bg-slate-900/50 p-1 rounded-xl">
            <button 
                onClick={() => setViewMode('simple')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'simple' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                title="Vista Simples"
            >
                <LayoutList className="w-4 h-4" />
            </button>
            <button 
                onClick={() => setViewMode('detailed')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'detailed' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                title="Vista Detalhada"
            >
                <Grip className="w-4 h-4" />
            </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          {sortedDebts.map(debt => {
            const progress = (1 - (debt.remainingAmount / debt.totalAmount)) * 100;
            const paidAmount = debt.totalAmount - debt.remainingAmount;
            const installmentValue = debt.installments && debt.installments > 0 ? (debt.totalAmount / debt.installments) : 0;
            const paidInstallmentsApprox = debt.installments ? Math.floor(paidAmount / (installmentValue || 1)) : 0;

            const isOverdue = debt.status !== 'paid' && new Date(debt.dueDate) < new Date(new Date().setHours(0,0,0,0));

            return (
              <div key={debt.id} className={`bg-white dark:bg-[#111827]/60 backdrop-blur-md border ${isOverdue ? 'border-rose-500/30 dark:border-rose-500/30' : 'border-slate-200 dark:border-white/5'} rounded-3xl p-6 group hover:border-indigo-500/30 transition-all shadow-sm dark:shadow-none`}>
                <div className="flex justify-between items-start mb-4">
                  <div className="flex items-center gap-4">
                    <div className={`p-3 rounded-2xl ${debt.status === 'paid' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : isOverdue ? 'bg-rose-500/20 text-rose-600 animate-pulse' : 'bg-indigo-500/10 text-indigo-600 dark:text-indigo-400'}`}>
                      {debt.status === 'paid' ? <CheckCircle2 /> : isOverdue ? <AlertTriangle /> : <Clock />}
                    </div>
                    <div>
                      <h4 className="font-bold text-[#212529] dark:text-white text-lg tracking-tight">{debt.name}</h4>
                      <div className="flex gap-2 items-center">
                          {isOverdue && <span className="text-[9px] bg-rose-500 text-white px-2 py-0.5 rounded font-black uppercase">Vencido</span>}
                          {viewMode === 'detailed' && <span className="text-[10px] text-[#6C757D] dark:text-slate-500 font-black uppercase tracking-widest">{debt.category}</span>}
                      </div>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`text-xs font-bold uppercase tracking-widest mb-1 ${isOverdue ? 'text-rose-500' : 'text-[#6C757D] dark:text-slate-500'}`}>Vencimento</p>
                    <div className={`flex items-center justify-end gap-2 text-sm font-bold ${isOverdue ? 'text-rose-600' : 'text-[#212529] dark:text-slate-200'}`}>
                      <Calendar className="w-4 h-4" />
                      {new Date(debt.dueDate).toLocaleDateString('pt-BR')}
                    </div>
                  </div>
                </div>

                {viewMode === 'detailed' && (
                    <div className="grid grid-cols-2 gap-4 mb-6">
                        <div className="bg-slate-50 dark:bg-slate-900/40 p-3 rounded-2xl border border-slate-200 dark:border-white/5">
                            <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block mb-1">Valor Total</span>
                            <span className="text-sm font-bold text-[#212529] dark:text-slate-300">R$ {debt.totalAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </div>
                        <div className="bg-slate-50 dark:bg-slate-900/40 p-3 rounded-2xl border border-slate-200 dark:border-white/5">
                            <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block mb-1">Restante</span>
                            <span className="text-sm font-bold text-rose-500 dark:text-rose-400">R$ {debt.remainingAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </div>
                    </div>
                )}

                {viewMode === 'simple' && (
                     <div className="flex justify-between items-center mb-6 px-2">
                        <div>
                             <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block">Parcela Est.</span>
                             <span className="text-sm font-bold text-[#212529] dark:text-slate-300">R$ {installmentValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </div>
                        <div className="text-right">
                             <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block">Restante</span>
                             <span className="text-sm font-bold text-rose-500 dark:text-rose-400">R$ {debt.remainingAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </div>
                     </div>
                )}

                {viewMode === 'detailed' && (
                    <div className="space-y-2 mb-6">
                    <div className="flex justify-between items-center text-[10px] font-black uppercase text-[#6C757D] dark:text-slate-500 tracking-widest">
                        <span>Progresso ({Math.min(paidInstallmentsApprox, debt.installments || 1)}/{debt.installments})</span>
                        <span className="text-indigo-600 dark:text-indigo-400">{progress.toFixed(0)}%</span>
                    </div>
                    <div className="h-2 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${progress}%` }}></div>
                    </div>
                    </div>
                )}

                {debt.status !== 'paid' && (
                  <button 
                    onClick={() => handleOpenPayment(debt)}
                    className="w-full flex items-center justify-center gap-2 py-3 bg-slate-100 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl text-[11px] font-black uppercase tracking-widest text-[#212529] dark:text-slate-300 hover:bg-indigo-600 hover:text-white hover:border-indigo-600 transition-all"
                  >
                    <DollarSign className="w-4 h-4" /> Amortizar
                  </button>
                )}
              </div>
            );
          })}
          {debts.length === 0 && (
            <div className="lg:col-span-2 text-center py-20 bg-slate-100 dark:bg-slate-900/20 rounded-3xl border border-dashed border-slate-300 dark:border-white/10">
              <p className="text-[#6C757D] dark:text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhum compromisso pendente</p>
            </div>
          )}
      </div>

      {/* Total Discreto */}
      <div className="flex justify-end pt-4 border-t border-slate-100 dark:border-white/5">
         <p className="text-xs text-slate-400 font-medium">
            Total Devedor Geral: R$ {totalDebt.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
         </p>
      </div>

      {/* Modal de Pagamento */}
      {paymentModal.debt && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/80 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-3xl w-full max-w-sm p-8 border border-slate-200 dark:border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-[#212529] dark:text-white tracking-tight">Amortizar {paymentModal.debt.name}</h3>
              <button onClick={() => setPaymentModal({ debt: null, amount: 0, poteId: '' })}><X className="text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-white" /></button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Valor do Pagamento</label>
                <input 
                  type="number" 
                  step="0.01"
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.amount}
                  onChange={(e) => setPaymentModal({ ...paymentModal, amount: parseFloat(e.target.value) || 0 })}
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Pote de Origem</label>
                <select 
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.poteId}
                  onChange={(e) => setPaymentModal({ ...paymentModal, poteId: e.target.value })}
                >
                  <option value="">Selecione...</option>
                  {potes.map(p => <option key={p.id} value={p.id}>{p.name} (Saldo: R$ {p.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })})</option>)}
                </select>
              </div>
              <button 
                onClick={() => {
                  if (paymentModal.debt && paymentModal.amount > 0 && paymentModal.poteId) {
                    onPay(paymentModal.debt, paymentModal.amount, paymentModal.poteId);
                    setPaymentModal({ debt: null, amount: 0, poteId: '' });
                  } else {
                    alert("Preencha todos os campos corretamente.");
                  }
                }}
                className="w-full py-4 bg-emerald-500 text-emerald-950 font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-emerald-400 transition-all shadow-xl"
              >
                Confirmar Pagamento
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Nova Dívida */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/80 backdrop-blur-md">
           <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Registrar Dívida</h3>
              <button onClick={() => setShowAddModal(false)}><X className="text-[#6C757D] dark:text-slate-600" /></button>
            </div>
            <form onSubmit={handleAddSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Descrição</label>
                <input required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.name} onChange={e => setNewDebt({...newDebt, name: e.target.value})} />
              </div>

              {/* Toggle Input Type */}
              <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1 rounded-xl">
                 <button 
                   type="button" 
                   onClick={() => setInputType('total')}
                   className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${inputType === 'total' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
                 >
                   Valor Total
                 </button>
                 <button 
                   type="button" 
                   onClick={() => setInputType('installment')}
                   className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${inputType === 'installment' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
                 >
                   Valor da Parcela
                 </button>
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">
                        {inputType === 'total' ? 'Total R$' : 'Parcela R$'}
                    </label>
                    <input type="number" step="0.01" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.valueInput || ''} onChange={e => setNewDebt({...newDebt, valueInput: parseFloat(e.target.value)})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Qtd. Parcelas</label>
                    <input type="number" min="1" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.installments || 1} onChange={e => setNewDebt({...newDebt, installments: parseInt(e.target.value)})} />
                  </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Vencimento</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.dueDate} onChange={e => setNewDebt({...newDebt, dueDate: e.target.value})} />
              </div>

              <div className="bg-indigo-50 dark:bg-indigo-500/10 p-3 rounded-xl text-center">
                 <p className="text-[10px] uppercase text-indigo-400 font-bold mb-1">Resumo do Registro</p>
                 <p className="text-indigo-600 dark:text-indigo-300 font-bold text-sm">
                    {inputType === 'total' 
                        ? `${newDebt.installments}x de R$ ${(newDebt.valueInput / (newDebt.installments || 1)).toFixed(2)}`
                        : `Total de R$ ${(newDebt.valueInput * (newDebt.installments || 1)).toFixed(2)}`
                    }
                 </p>
              </div>

              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Salvar Compromisso</button>
            </form>
           </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Receipt, Target, BrainCircuit, Menu, X, Archive, 
  AlertCircle, Plus, Settings as SettingsIcon, Camera, Mic, Loader2, StopCircle, LogOut, Shield
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Budget, FinancialGoal, Category, User } from './types';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Settings from './components/Settings';
import AdminPanel from './components/AdminPanel';
import Auth from './components/Auth';
import Toast, { ToastType } from './components/Toast';
import { analyzeReceipt, analyzeAudioCommand } from './services/gemini';
import { initializeAuth, getCurrentUser, logout } from './services/auth';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const DEFAULT_CATEGORIES: Category[] = [
  { 
    id: 'c1', name: 'Moradia', type: 'expense', isDefault: true,
    subCategories: [{id: 's1', name: 'Aluguel'}, {id: 's2', name: 'Energia'}, {id: 's3', name: 'Internet'}, {id: 's4', name: 'Manutenção'}] 
  },
  { 
    id: 'c2', name: 'Alimentação', type: 'expense', isDefault: true,
    subCategories: [{id: 's5', name: 'Supermercado'}, {id: 's6', name: 'Restaurante'}, {id: 's7', name: 'Delivery'}] 
  },
  { 
    id: 'c3', name: 'Transporte', type: 'expense', isDefault: true,
    subCategories: [{id: 's8', name: 'Combustível'}, {id: 's9', name: 'Uber/Táxi'}, {id: 's10', name: 'Manutenção Veículo'}] 
  },
  { 
    id: 'c4', name: 'Saúde', type: 'expense', isDefault: true,
    subCategories: [{id: 's11', name: 'Farmácia'}, {id: 's12', name: 'Consultas'}, {id: 's13', name: 'Plano de Saúde'}] 
  },
  { 
    id: 'c5', name: 'Lazer', type: 'expense', isDefault: true,
    subCategories: [{id: 's14', name: 'Cinema/Streaming'}, {id: 's15', name: 'Viagem'}, {id: 's16', name: 'Hobbies'}] 
  },
  { 
    id: 'c6', name: 'Renda', type: 'income', isDefault: true,
    subCategories: [{id: 's17', name: 'Salário'}, {id: 's18', name: 'Freelance'}, {id: 's19', name: 'Dividendos'}] 
  }
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', subCategory: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', subCategory: 'Aluguel', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', subCategory: 'Supermercado', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
  adminOnly?: boolean;
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // Initialize Auth
  useEffect(() => {
    initializeAuth();
    const currentUser = getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }
  }, []);

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // States for Quick Entry (Fab)
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = () => {
    logout();
    setUser(null);
    setView('dashboard');
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null); 
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  const handleGoalEdit = (updatedGoal: FinancialGoal) => {
    setGoals(goals.map(g => g.id === updatedGoal.id ? updatedGoal : g));
    showToast("Meta atualizada com sucesso!");
  };

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    showToast("Analisando imagem...", "info");

    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);

      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; 
  };

  const handleMicClick = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");

          const result = await analyzeAudioCommand(base64Audio);

          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };

  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'admin', label: 'Admin', icon: Shield, section: 'SISTEMA', adminOnly: true },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  if (!user) {
    return (
      <>
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        <Auth onLoginSuccess={handleLoginSuccess} />
      </>
    );
  }

  return (
    <div className="min-h-screen flex bg-[#F8F9FA] dark:bg-[#030712] text-[#212529] dark:text-slate-100 font-sans overflow-hidden select-none transition-colors duration-300">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-white/80 dark:bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          <p className="text-[#212529] dark:text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* Floating Action Button */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button 
              onClick={handleCameraClick}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button 
              onClick={handleMicClick}
              className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}
            >
              {isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}
            </button>
            <button 
              onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Receipt className="w-5 h-5" />
            </button>
          </div>
        )}

        <button 
          onClick={() => {
             if (isRecording) {
                stopRecording();
             } else {
                setIsFabOpen(!isFabOpen);
             }
          }}
          className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}
        >
          {isRecording ? (
             <div className="w-4 h-4 bg-white rounded-sm animate-spin" />
          ) : (
             <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />
          )}
        </button>
      </div>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-white dark:bg-[#0a0c14] border-r border-slate-200 dark:border-white/5 flex flex-col shadow-2xl lg:shadow-none
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter text-[#212529] dark:text-white">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-[#6C757D]" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => {
             const items = navItems.filter(item => item.section === sectionName && (!item.adminOnly || user.role === 'admin'));
             if (items.length === 0) return null;

             return (
              <div key={sectionName} className="space-y-1">
                <h4 className="px-4 text-[8px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                  {sectionName}
                </h4>
                <div className="space-y-1">
                  {items.map((item) => (
                    <button 
                      key={item.id} 
                      onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                      className={`
                        w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                        ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800/40'}
                      `}
                    >
                      <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                      <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </nav>

        <div className="p-4 border-t border-slate-200 dark:border-white/5">
          <button 
            onClick={handleLogout}
            className="w-full flex items-center gap-4 px-4 py-3 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all"
          >
            <LogOut className="w-5 h-5" />
            <span className="font-bold text-sm lg:hidden xl:block">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#F8F9FA] dark:bg-[#030712] transition-colors duration-300">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-[#212529] dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest">Usuário</span>
                <span className="text-xs font-black text-[#212529] dark:text-white truncate max-w-[100px]">{user.name}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <span className="font-black text-indigo-600 dark:text-indigo-400">{user.name.charAt(0)}</span>
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} 
                onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} // Usado para update
                onEdit={(d) => { setDebts(debts.map(item => item.id === d.id ? d : item)); showToast("Dívida atualizada!"); }} // Usado para edição completa
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
                onEdit={handleGoalEdit}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={setCategories} 
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Debt, Jar } from '../types';
import { Plus, CheckCircle2, AlertTriangle, Calendar, CreditCard, ChevronRight, DollarSign, X, LayoutList, Grip, Clock, Edit2 } from 'lucide-react';

interface DebtsProps {
  debts: Debt[];
  potes: Jar[];
  onAdd: (d: Debt) => void;
  onUpdate: (d: Debt) => void;
  onPay: (d: Debt, amount: number, poteId: string) => void;
  onEdit?: (d: Debt) => void;
}

export default function Debts({ debts, potes, onAdd, onUpdate, onPay, onEdit }: DebtsProps) {
  const [showAddModal, setShowAddModal] = useState(false);
  const [viewMode, setViewMode] = useState<'simple' | 'detailed'>('simple');
  const [inputType, setInputType] = useState<'total' | 'installment'>('total');
  const [isEditing, setIsEditing] = useState(false);

  const [paymentModal, setPaymentModal] = useState<{ debt: Debt | null, amount: number, poteId: string }>({ 
    debt: null, 
    amount: 0, 
    poteId: '' 
  });

  const [newDebt, setNewDebt] = useState<{
    id?: string;
    name: string;
    valueInput: number; // Pode ser total ou parcela
    dueDate: string;
    category: string;
    installments: number;
    remainingAmount?: number;
    status?: 'active' | 'paid' | 'overdue';
  }>({
    name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1
  });

  const totalDebt = debts.filter(d => d.status !== 'paid').reduce((acc, d) => acc + d.remainingAmount, 0);

  // Ordenação: Vencidos primeiro, depois por data de vencimento
  const sortedDebts = [...debts].sort((a, b) => {
    if (a.status === 'paid' && b.status !== 'paid') return 1;
    if (a.status !== 'paid' && b.status === 'paid') return -1;
    return new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime();
  });

  const handleOpenPayment = (debt: Debt) => {
    let suggestedAmount = debt.remainingAmount;
    if (debt.installments && debt.installments > 0) {
        suggestedAmount = debt.totalAmount / debt.installments;
        if(suggestedAmount > debt.remainingAmount) suggestedAmount = debt.remainingAmount;
    }

    setPaymentModal({
      debt,
      amount: parseFloat(suggestedAmount.toFixed(2)),
      poteId: potes.length > 0 ? potes[0].id : ''
    });
  };

  const handleOpenEdit = (debt: Debt) => {
    setIsEditing(true);
    setInputType('total'); // Padrão ao editar
    setNewDebt({
      id: debt.id,
      name: debt.name,
      valueInput: debt.totalAmount, // Carrega o valor total
      dueDate: debt.dueDate,
      category: debt.category,
      installments: debt.installments || 1,
      remainingAmount: debt.remainingAmount,
      status: debt.status
    });
    setShowAddModal(true);
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDebt.name || !newDebt.valueInput) return;

    let totalAmount = 0;
    if (inputType === 'total') {
        totalAmount = newDebt.valueInput;
    } else {
        totalAmount = newDebt.valueInput * (newDebt.installments || 1);
    }

    const debtData: Debt = {
      id: isEditing && newDebt.id ? newDebt.id : Math.random().toString(36).substr(2, 9),
      name: newDebt.name,
      totalAmount: totalAmount,
      // Se editando, mantém o restante proporcional ou ajusta? 
      // Simplificação: Se valor total mudou, ajusta o restante pela diferença. Se nova dívida, restante = total.
      remainingAmount: isEditing ? (newDebt.remainingAmount ?? totalAmount) : totalAmount, 
      dueDate: newDebt.dueDate,
      category: newDebt.category,
      installments: newDebt.installments,
      status: newDebt.status || 'active',
      currentInstallment: 0
    };

    // Ajuste fino para edição de valor: Se o usuário mudar o valor total na edição, recalcula o restante?
    // Vamos assumir que se é edição, atualiza o totalAmount e se o novo total for maior que o antigo, a diferença vai pro remaining.
    if (isEditing && onEdit) {
        // Recalcular remainingAmount se o total mudou
        if (isEditing && newDebt.id) {
            const original = debts.find(d => d.id === newDebt.id);
            if (original && original.totalAmount !== totalAmount) {
                 const diff = totalAmount - original.totalAmount;
                 debtData.remainingAmount = Math.max(0, original.remainingAmount + diff);
            }
        }
        onEdit(debtData);
    } else {
        onAdd(debtData);
    }

    setNewDebt({ name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1 });
    setShowAddModal(false);
    setIsEditing(false);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-rose-500/10 border border-rose-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-rose-600 dark:text-rose-400 uppercase tracking-widest block mb-2">Total em Aberto</span>
          <p className="text-3xl font-black text-rose-600 dark:text-white tracking-tighter">R$ {totalDebt.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
        </div>
        <div className="bg-emerald-500/10 border border-emerald-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest block mb-2">Dívidas Quitadas</span>
          <p className="text-3xl font-black text-emerald-600 dark:text-white tracking-tighter">{debts.filter(d => d.status === 'paid').length}</p>
        </div>
        <div className="flex items-center justify-center">
            <button 
              onClick={() => {
                setIsEditing(false);
                setNewDebt({ name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1 });
                setShowAddModal(true);
              }}
              className="w-full h-full flex items-center justify-center gap-3 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/10"
            >
              <Plus className="w-5 h-5" /> Nova Dívida
            </button>
        </div>
      </div>

      <div className="flex justify-between items-center">
        <h3 className="text-[11px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-[0.2em] flex items-center gap-3">
          Compromissos <div className="h-px w-10 bg-slate-200 dark:bg-slate-800"></div>
        </h3>
        <div className="flex gap-1 bg-slate-100 dark:bg-slate-900/50 p-1 rounded-xl">
            <button 
                onClick={() => setViewMode('simple')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'simple' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                title="Vista Simples"
            >
                <LayoutList className="w-4 h-4" />
            </button>
            <button 
                onClick={() => setViewMode('detailed')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'detailed' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                title="Vista Detalhada"
            >
                <Grip className="w-4 h-4" />
            </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          {sortedDebts.map(debt => {
            const progress = (1 - (debt.remainingAmount / debt.totalAmount)) * 100;
            const paidAmount = debt.totalAmount - debt.remainingAmount;
            const installmentValue = debt.installments && debt.installments > 0 ? (debt.totalAmount / debt.installments) : 0;
            const paidInstallmentsApprox = debt.installments ? Math.floor(paidAmount / (installmentValue || 1)) : 0;

            const isOverdue = debt.status !== 'paid' && new Date(debt.dueDate) < new Date(new Date().setHours(0,0,0,0));

            return (
              <div key={debt.id} className={`bg-white dark:bg-[#111827]/60 backdrop-blur-md border ${isOverdue ? 'border-rose-500/30 dark:border-rose-500/30' : 'border-slate-200 dark:border-white/5'} rounded-3xl p-6 group hover:border-indigo-500/30 transition-all shadow-sm dark:shadow-none relative`}>
                <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-all z-10">
                   <button 
                     onClick={() => handleOpenEdit(debt)}
                     className="p-2 bg-slate-100 dark:bg-slate-900/50 rounded-full hover:bg-indigo-500 hover:text-white transition-colors text-slate-500"
                   >
                     <Edit2 className="w-4 h-4" />
                   </button>
                </div>

                <div className="flex justify-between items-start mb-4">
                  <div className="flex items-center gap-4">
                    <div className={`p-3 rounded-2xl ${debt.status === 'paid' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : isOverdue ? 'bg-rose-500/20 text-rose-600 animate-pulse' : 'bg-indigo-500/10 text-indigo-600 dark:text-indigo-400'}`}>
                      {debt.status === 'paid' ? <CheckCircle2 /> : isOverdue ? <AlertTriangle /> : <Clock />}
                    </div>
                    <div>
                      <h4 className="font-bold text-[#212529] dark:text-white text-lg tracking-tight">{debt.name}</h4>
                      <div className="flex gap-2 items-center">
                          {isOverdue && <span className="text-[9px] bg-rose-500 text-white px-2 py-0.5 rounded font-black uppercase">Vencido</span>}
                          {viewMode === 'detailed' && <span className="text-[10px] text-[#6C757D] dark:text-slate-500 font-black uppercase tracking-widest">{debt.category}</span>}
                      </div>
                    </div>
                  </div>
                  <div className="text-right pr-8 lg:pr-0">
                    <p className={`text-xs font-bold uppercase tracking-widest mb-1 ${isOverdue ? 'text-rose-500' : 'text-[#6C757D] dark:text-slate-500'}`}>Vencimento</p>
                    <div className={`flex items-center justify-end gap-2 text-sm font-bold ${isOverdue ? 'text-rose-600' : 'text-[#212529] dark:text-slate-200'}`}>
                      <Calendar className="w-4 h-4" />
                      {new Date(debt.dueDate).toLocaleDateString('pt-BR')}
                    </div>
                  </div>
                </div>

                {viewMode === 'detailed' && (
                    <div className="grid grid-cols-2 gap-4 mb-6">
                        <div className="bg-slate-50 dark:bg-slate-900/40 p-3 rounded-2xl border border-slate-200 dark:border-white/5">
                            <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block mb-1">Valor Total</span>
                            <span className="text-sm font-bold text-[#212529] dark:text-slate-300">R$ {debt.totalAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </div>
                        <div className="bg-slate-50 dark:bg-slate-900/40 p-3 rounded-2xl border border-slate-200 dark:border-white/5">
                            <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block mb-1">Restante</span>
                            <span className="text-sm font-bold text-rose-500 dark:text-rose-400">R$ {debt.remainingAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </div>
                    </div>
                )}

                {viewMode === 'simple' && (
                     <div className="flex justify-between items-center mb-6 px-2">
                        <div>
                             <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block">Parcela Est.</span>
                             <span className="text-sm font-bold text-[#212529] dark:text-slate-300">R$ {installmentValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </div>
                        <div className="text-right">
                             <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block">Restante</span>
                             <span className="text-sm font-bold text-rose-500 dark:text-rose-400">R$ {debt.remainingAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </div>
                     </div>
                )}

                {viewMode === 'detailed' && (
                    <div className="space-y-2 mb-6">
                    <div className="flex justify-between items-center text-[10px] font-black uppercase text-[#6C757D] dark:text-slate-500 tracking-widest">
                        <span>Progresso ({Math.min(paidInstallmentsApprox, debt.installments || 1)}/{debt.installments})</span>
                        <span className="text-indigo-600 dark:text-indigo-400">{progress.toFixed(0)}%</span>
                    </div>
                    <div className="h-2 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${progress}%` }}></div>
                    </div>
                    </div>
                )}

                {debt.status !== 'paid' && (
                  <button 
                    onClick={() => handleOpenPayment(debt)}
                    className="w-full flex items-center justify-center gap-2 py-3 bg-slate-100 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl text-[11px] font-black uppercase tracking-widest text-[#212529] dark:text-slate-300 hover:bg-indigo-600 hover:text-white hover:border-indigo-600 transition-all"
                  >
                    <DollarSign className="w-4 h-4" /> Amortizar
                  </button>
                )}
              </div>
            );
          })}
          {debts.length === 0 && (
            <div className="lg:col-span-2 text-center py-20 bg-slate-100 dark:bg-slate-900/20 rounded-3xl border border-dashed border-slate-300 dark:border-white/10">
              <p className="text-[#6C757D] dark:text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhum compromisso pendente</p>
            </div>
          )}
      </div>

      {/* Total Discreto */}
      <div className="flex justify-end pt-4 border-t border-slate-100 dark:border-white/5">
         <p className="text-xs text-slate-400 font-medium">
            Total Devedor Geral: R$ {totalDebt.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
         </p>
      </div>

      {/* Modal de Pagamento */}
      {paymentModal.debt && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/80 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-3xl w-full max-w-sm p-8 border border-slate-200 dark:border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-[#212529] dark:text-white tracking-tight">Amortizar {paymentModal.debt.name}</h3>
              <button onClick={() => setPaymentModal({ debt: null, amount: 0, poteId: '' })}><X className="text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-white" /></button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Valor do Pagamento</label>
                <input 
                  type="number" 
                  step="0.01"
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.amount}
                  onChange={(e) => setPaymentModal({ ...paymentModal, amount: parseFloat(e.target.value) || 0 })}
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Pote de Origem</label>
                <select 
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.poteId}
                  onChange={(e) => setPaymentModal({ ...paymentModal, poteId: e.target.value })}
                >
                  <option value="">Selecione...</option>
                  {potes.map(p => <option key={p.id} value={p.id}>{p.name} (Saldo: R$ {p.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })})</option>)}
                </select>
              </div>
              <button 
                onClick={() => {
                  if (paymentModal.debt && paymentModal.amount > 0 && paymentModal.poteId) {
                    onPay(paymentModal.debt, paymentModal.amount, paymentModal.poteId);
                    setPaymentModal({ debt: null, amount: 0, poteId: '' });
                  } else {
                    alert("Preencha todos os campos corretamente.");
                  }
                }}
                className="w-full py-4 bg-emerald-500 text-emerald-950 font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-emerald-400 transition-all shadow-xl"
              >
                Confirmar Pagamento
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Nova/Editar Dívida */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/80 backdrop-blur-md">
           <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">
                {isEditing ? 'Editar Dívida' : 'Registrar Dívida'}
              </h3>
              <button onClick={() => setShowAddModal(false)}><X className="text-[#6C757D] dark:text-slate-600" /></button>
            </div>
            <form onSubmit={handleAddSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Descrição</label>
                <input required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.name} onChange={e => setNewDebt({...newDebt, name: e.target.value})} />
              </div>

              {/* Toggle Input Type - Only if not editing (simplicity) or allow toggle */}
              <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1 rounded-xl">
                 <button 
                   type="button" 
                   onClick={() => setInputType('total')}
                   className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${inputType === 'total' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
                 >
                   Valor Total
                 </button>
                 <button 
                   type="button" 
                   onClick={() => setInputType('installment')}
                   className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${inputType === 'installment' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
                 >
                   Valor da Parcela
                 </button>
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">
                        {inputType === 'total' ? 'Total R$' : 'Parcela R$'}
                    </label>
                    <input type="number" step="0.01" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.valueInput || ''} onChange={e => setNewDebt({...newDebt, valueInput: parseFloat(e.target.value)})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Qtd. Parcelas</label>
                    <input type="number" min="1" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.installments || 1} onChange={e => setNewDebt({...newDebt, installments: parseInt(e.target.value)})} />
                  </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Vencimento</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.dueDate} onChange={e => setNewDebt({...newDebt, dueDate: e.target.value})} />
              </div>

              <div className="bg-indigo-50 dark:bg-indigo-500/10 p-3 rounded-xl text-center">
                 <p className="text-[10px] uppercase text-indigo-400 font-bold mb-1">Resumo do Registro</p>
                 <p className="text-indigo-600 dark:text-indigo-300 font-bold text-sm">
                    {inputType === 'total' 
                        ? `${newDebt.installments}x de R$ ${(newDebt.valueInput / (newDebt.installments || 1)).toFixed(2)}`
                        : `Total de R$ ${(newDebt.valueInput * (newDebt.installments || 1)).toFixed(2)}`
                    }
                 </p>
              </div>

              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">
                 {isEditing ? 'Atualizar Dívida' : 'Salvar Compromisso'}
              </button>
            </form>
           </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { FinancialGoal, Jar } from '../types';
import { Target, Trophy, Calendar, Plus, X, ArrowUpRight, Wallet, Edit2, TrendingUp } from 'lucide-react';

interface GoalsProps {
  goals: FinancialGoal[];
  potes: Jar[];
  onAdd: (g: FinancialGoal) => void;
  onUpdate: (goals: FinancialGoal[]) => void;
  onDeposit: (amount: number, poteId: string, goalName: string) => void;
  onEdit?: (g: FinancialGoal) => void;
}

export default function Goals({ goals, potes, onAdd, onUpdate, onDeposit, onEdit }: GoalsProps) {
  const [showAdd, setShowAdd] = useState(false);
  const [editingGoal, setEditingGoal] = useState<FinancialGoal | null>(null);
  const [newGoal, setNewGoal] = useState({ name: '', targetAmount: 0, deadline: '' });

  const [depositModal, setDepositModal] = useState<{ goalId: string, goalName: string } | null>(null);
  const [depositAmount, setDepositAmount] = useState(0);
  const [selectedPoteId, setSelectedPoteId] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newGoal.name || newGoal.targetAmount <= 0) return;
    const goal: FinancialGoal = {
      id: Math.random().toString(36).substr(2, 9),
      name: newGoal.name,
      targetAmount: newGoal.targetAmount,
      currentAmount: 0,
      deadline: newGoal.deadline || new Date().toISOString().split('T')[0]
    };
    onAdd(goal);
    setNewGoal({ name: '', targetAmount: 0, deadline: '' });
    setShowAdd(false);
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if(editingGoal && onEdit) {
        onEdit(editingGoal);
        setEditingGoal(null);
    }
  };

  const handleDepositSubmit = () => {
    if (depositAmount <= 0 || !selectedPoteId || !depositModal) return;

    // Atualiza a meta
    onUpdate(goals.map(g => g.id === depositModal.goalId ? { ...g, currentAmount: g.currentAmount + depositAmount } : g));

    // Aciona a lógica de transação (débito do pote)
    onDeposit(depositAmount, selectedPoteId, depositModal.goalName);

    // Limpa estado
    setDepositModal(null);
    setDepositAmount(0);
    setSelectedPoteId('');
  };

  const removeGoal = (id: string) => {
    if(confirm('Deseja realmente remover esta meta?')) {
        onUpdate(goals.filter(g => g.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Grandes Sonhos</h2>
          <p className="text-[#6C757D] dark:text-slate-500 text-xs font-bold uppercase tracking-widest">Acompanhe sua evolução financeira</p>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20"
        >
          <Plus className="w-4 h-4" /> Criar Meta
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {goals.map((goal) => {
          const progress = (goal.currentAmount / goal.targetAmount) * 100;
          const remaining = Math.max(0, goal.targetAmount - goal.currentAmount);

          // Cálculo de Depósito Diário Recomendado
          const today = new Date();
          const deadlineDate = new Date(goal.deadline);

          // Diferença em dias (evitar divisão por zero se for hoje)
          const diffTime = deadlineDate.getTime() - today.getTime();
          const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

          let dailyRecommendation = 0;
          if (remaining > 0 && diffDays > 0) {
            dailyRecommendation = remaining / diffDays;
          }

          return (
            <div key={goal.id} className="bg-white dark:bg-[#0a0c14] p-8 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none flex gap-6 group relative overflow-hidden">
              <div className="absolute top-6 right-6 opacity-0 group-hover:opacity-100 flex gap-2 transition-all z-10">
                <button 
                    onClick={() => setEditingGoal(goal)}
                    className="p-2 text-[#6C757D] dark:text-slate-700 hover:text-indigo-500 transition-all bg-white dark:bg-black/20 rounded-full"
                >
                    <Edit2 className="w-4 h-4" />
                </button>
                <button 
                    onClick={() => removeGoal(goal.id)}
                    className="p-2 text-[#6C757D] dark:text-slate-700 hover:text-rose-500 transition-all bg-white dark:bg-black/20 rounded-full"
                >
                    <X className="w-5 h-5" />
                </button>
              </div>

              <div className="hidden sm:flex flex-col items-center justify-center bg-indigo-600/10 w-24 rounded-[1.5rem] p-4 border border-indigo-600/20">
                <Trophy className="w-8 h-8 text-indigo-600 dark:text-indigo-400 mb-2" />
                <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400">{progress.toFixed(0)}%</span>
              </div>

              <div className="flex-1 space-y-4">
