                {/* Recomendação Diária */}
                {dailyRecommendation > 0 && (
                   <div className="bg-emerald-500/10 border border-emerald-500/20 p-2 rounded-xl flex items-center justify-center gap-2">
                      <TrendingUp className="w-4 h-4 text-emerald-500" />
