            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">Editar Sonho</h3>
              <button onClick={() => setEditingGoal(null)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-[#6C757D] dark:text-slate-500" /></button>
            </div>
            <form onSubmit={handleEditSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Descrição</label>
                <input required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={editingGoal.name} onChange={e => setEditingGoal({...editingGoal, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Meta R$</label>
                <input type="number" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={editingGoal.targetAmount} onChange={e => setEditingGoal({...editingGoal, targetAmount: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Prazo</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={editingGoal.deadline} onChange={e => setEditingGoal({...editingGoal, deadline: e.target.value})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">Salvar Alterações</button>
