                      {potes.map(p => (
                        <button 
                          key={p.id}
                          type="button"
                          onClick={() => setSelectedPoteId(p.id)}
                          className={`flex justify-between items-center p-3 rounded-xl border transition-all ${selectedPoteId === p.id ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-[#6C757D] dark:text-slate-400 hover:border-indigo-500/50'}`}
                        >
                          <span className="text-xs font-bold">{p.name}</span>
                          <span className="text-xs">R$ {p.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        </button>
                      ))}
                   </div>
                </div>

                <button 
                  onClick={handleDepositSubmit}
