interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
  adminOnly?: boolean;
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // Initialize Auth
  useEffect(() => {
    initializeAuth();
    const currentUser = getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }
  }, []);

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // States for Quick Entry (Fab)
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = () => {
    logout();
    setUser(null);
    setView('dashboard');
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null); 
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string, date: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: date || new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  const handleGoalEdit = (updatedGoal: FinancialGoal) => {
    setGoals(goals.map(g => g.id === updatedGoal.id ? updatedGoal : g));
    showToast("Meta atualizada com sucesso!");
  };

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    showToast("Analisando imagem...", "info");

    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);

      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; 
  };

  const handleMicClick = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");

          const result = await analyzeAudioCommand(base64Audio);

          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };

  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Início', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'admin', label: 'Admin', icon: Shield, section: 'SISTEMA', adminOnly: true },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  if (!user) {
    return (
      <>
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        <Auth onLoginSuccess={handleLoginSuccess} />
      </>
    );
  }

  return (
    <div className="min-h-screen flex bg-[#F8F9FA] dark:bg-[#030712] text-[#212529] dark:text-slate-100 font-sans overflow-hidden select-none transition-colors duration-300">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-white/80 dark:bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          <p className="text-[#212529] dark:text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* Floating Action Button */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button 
              onClick={handleCameraClick}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button 
              onClick={handleMicClick}
              className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}
            >
              {isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}
            </button>
            <button 
              onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Receipt className="w-5 h-5" />
            </button>
          </div>
        )}

        <button 
          onClick={() => {
             if (isRecording) {
                stopRecording();
             } else {
                setIsFabOpen(!isFabOpen);
             }
          }}
          className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}
        >
          {isRecording ? (
             <div className="w-4 h-4 bg-white rounded-sm animate-spin" />
          ) : (
             <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />
          )}
        </button>
      </div>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-white dark:bg-[#0a0c14] border-r border-slate-200 dark:border-white/5 flex flex-col shadow-2xl lg:shadow-none
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter text-[#212529] dark:text-white">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-[#6C757D]" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => {
             const items = navItems.filter(item => item.section === sectionName && (!item.adminOnly || user.role === 'admin'));
             if (items.length === 0) return null;

             return (
              <div key={sectionName} className="space-y-1">
                <h4 className="px-4 text-[8px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                  {sectionName}
                </h4>
                <div className="space-y-1">
                  {items.map((item) => (
                    <button 
                      key={item.id} 
                      onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                      className={`
                        w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                        ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800/40'}
                      `}
                    >
                      <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                      <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </nav>

        <div className="p-4 border-t border-slate-200 dark:border-white/5">
          <button 
            onClick={handleLogout}
            className="w-full flex items-center gap-4 px-4 py-3 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all"
          >
            <LogOut className="w-5 h-5" />
            <span className="font-bold text-sm lg:hidden xl:block">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#F8F9FA] dark:bg-[#030712] transition-colors duration-300">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-[#212529] dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest">Usuário</span>
                <span className="text-xs font-black text-[#212529] dark:text-white truncate max-w-[100px]">{user.name}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <span className="font-black text-indigo-600 dark:text-indigo-400">{user.name.charAt(0)}</span>
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} 
                onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} // Usado para update
                onEdit={(d) => { setDebts(debts.map(item => item.id === d.id ? d : item)); showToast("Dívida atualizada!"); }} // Usado para edição completa
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
                onEdit={handleGoalEdit}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={setCategories} 
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Debt, Jar } from '../types';
import { Plus, CheckCircle2, AlertTriangle, Calendar, ChevronLeft, ChevronRight, DollarSign, X, Edit2, Clock, AlertCircle } from 'lucide-react';

interface DebtsProps {
  debts: Debt[];
  potes: Jar[];
  onAdd: (d: Debt) => void;
  onUpdate: (d: Debt) => void;
  onPay: (d: Debt, amount: number, poteId: string, date: string) => void;
  onEdit?: (d: Debt) => void;
}

// Interface auxiliar para renderização
interface InstallmentItem {
  debt: Debt;
  installmentNumber: number;
  totalInstallments: number;
  date: Date;
  amount: number;
  status: 'paid' | 'overdue' | 'pending';
  originalDebtId: string;
}

export default function Debts({ debts, potes, onAdd, onUpdate, onPay, onEdit }: DebtsProps) {
  const [showAddModal, setShowAddModal] = useState(false);
  const [inputType, setInputType] = useState<'total' | 'installment'>('total');
  const [isEditing, setIsEditing] = useState(false);

  // Navegação de Mês
  const [currentMonth, setCurrentMonth] = useState(new Date());

  const [paymentModal, setPaymentModal] = useState<{ debt: Debt | null, amount: number, poteId: string, date: string }>({ 
    debt: null, 
    amount: 0, 
    poteId: '',
    date: new Date().toISOString().split('T')[0]
  });

  const [newDebt, setNewDebt] = useState<{
    id?: string;
    name: string;
    valueInput: number;
    dueDate: string;
    category: string;
    installments: number;
    remainingAmount?: number;
    status?: 'active' | 'paid' | 'overdue';
  }>({
    name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1
  });

  // Totais Globais
  const totalDebt = debts.filter(d => d.status !== 'paid').reduce((acc, d) => acc + d.remainingAmount, 0);

  const changeMonth = (delta: number) => {
    const newDate = new Date(currentMonth);
    newDate.setMonth(newDate.getMonth() + delta);
    setCurrentMonth(newDate);
  };

  const monthLabel = currentMonth.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

  // Lógica principal: Projetar parcelas e filtrar
  const displayItems = useMemo(() => {
    const items: InstallmentItem[] = [];
    const viewMonth = currentMonth.getMonth();
    const viewYear = currentMonth.getFullYear();

    // Verifica se estamos visualizando o mês atual (para lógica de mostrar atrasados)
    const today = new Date();
    today.setHours(0,0,0,0);
    const isCurrentViewMonth = viewMonth === today.getMonth() && viewYear === today.getFullYear();

    debts.forEach(debt => {
      // Valor da parcela
      const installmentValue = debt.totalAmount / (debt.installments || 1);

      // Quantas parcelas já foram "totalmente pagas" baseado no valor amortizado
      const paidAmount = debt.totalAmount - debt.remainingAmount;
      // Pequena margem de erro para floats
      const paidInstallmentsCount = Math.floor((paidAmount + 0.01) / installmentValue);

      // Gera todas as parcelas virtuais
      for (let i = 0; i < (debt.installments || 1); i++) {
        const installmentDate = new Date(debt.dueDate);
        // Adiciona meses à data inicial
        installmentDate.setMonth(installmentDate.getMonth() + i);
        // Ajusta para ultimo dia do mês se necessário (ex: 31 jan -> 28 fev)
        // (Lógica simplificada de Date do JS já faz o rollover, mas mantemos simples)
        installmentDate.setHours(0,0,0,0);

        let status: 'paid' | 'overdue' | 'pending' = 'pending';

        // 1. Verifica se está paga
        if (i < paidInstallmentsCount) {
          status = 'paid';
        } 
        // 2. Se não paga, verifica se está vencida
        else if (installmentDate < today) {
          status = 'overdue';
        }
        // 3. Se não, é pendente (futuro ou hoje)
        else {
          status = 'pending';
        }

        // Lógica de Exibição (Filtro)
        const isInstallmentMonth = installmentDate.getMonth() === viewMonth && installmentDate.getFullYear() === viewYear;

        // MOSTRAR SE:
        // A) É a parcela do mês selecionado
        // B) OU Se estamos vendo o mês ATUAL e essa parcela é antiga e está ATRASADA (Vencida)
        if (isInstallmentMonth || (isCurrentViewMonth && status === 'overdue' && debt.status !== 'paid')) {
          items.push({
            debt: debt,
            installmentNumber: i + 1,
            totalInstallments: debt.installments || 1,
            date: installmentDate,
            amount: installmentValue,
            status: status,
            originalDebtId: debt.id
          });
        }
      }
    });

    // Ordenar: Vencidos primeiro, depois por data
    return items.sort((a, b) => {
      if (a.status === 'overdue' && b.status !== 'overdue') return -1;
      if (a.status !== 'overdue' && b.status === 'overdue') return 1;
      return a.date.getTime() - b.date.getTime();
    });

  }, [debts, currentMonth]);

  // Cálculos do Mês
  const monthSummary = useMemo(() => {
    let due = 0;
    let paid = 0;
    displayItems.forEach(item => {
        if (item.status === 'paid') {
            paid += item.amount;
        } else {
            due += item.amount;
        }
    });
    return { due, paid };
  }, [displayItems]);


  // Handlers
  const handleOpenPayment = (item: InstallmentItem) => {
    // Sugere pagar o valor dessa parcela específica
    // Mas limita ao que falta pagar da dívida total
    const amountToPay = Math.min(item.amount, item.debt.remainingAmount);

    setPaymentModal({
      debt: item.debt,
      amount: parseFloat(amountToPay.toFixed(2)),
      poteId: potes.length > 0 ? potes[0].id : '',
      date: new Date().toISOString().split('T')[0]
    });
  };

  const handleOpenEdit = (debt: Debt) => {
    setIsEditing(true);
    setInputType('total');
    setNewDebt({
      id: debt.id,
      name: debt.name,
      valueInput: debt.totalAmount,
      dueDate: debt.dueDate,
      category: debt.category,
      installments: debt.installments || 1,
      remainingAmount: debt.remainingAmount,
      status: debt.status
    });
    setShowAddModal(true);
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDebt.name || !newDebt.valueInput) return;

    let totalAmount = 0;
    if (inputType === 'total') {
        totalAmount = newDebt.valueInput;
    } else {
        totalAmount = newDebt.valueInput * (newDebt.installments || 1);
    }

    const debtData: Debt = {
      id: isEditing && newDebt.id ? newDebt.id : Math.random().toString(36).substr(2, 9),
      name: newDebt.name,
      totalAmount: totalAmount,
      remainingAmount: isEditing ? (newDebt.remainingAmount ?? totalAmount) : totalAmount, 
      dueDate: newDebt.dueDate,
      category: newDebt.category,
      installments: newDebt.installments,
      status: newDebt.status || 'active',
      currentInstallment: 0
    };

    if (isEditing && onEdit) {
        if (isEditing && newDebt.id) {
            const original = debts.find(d => d.id === newDebt.id);
            if (original && original.totalAmount !== totalAmount) {
                 const diff = totalAmount - original.totalAmount;
                 debtData.remainingAmount = Math.max(0, original.remainingAmount + diff);
            }
        }
        onEdit(debtData);
    } else {
        onAdd(debtData);
    }

    setNewDebt({ name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1 });
    setShowAddModal(false);
    setIsEditing(false);
  };

  return (
    <div className="space-y-6">
      {/* Resumo Global */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {/* Card 1: Saldo Devedor Total (Todos) */}
        <div className="bg-rose-500/10 border border-rose-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-rose-600 dark:text-rose-400 uppercase tracking-widest block mb-2">Saldo Devedor Total</span>
          <p className="text-3xl font-black text-rose-600 dark:text-white tracking-tighter">R$ {totalDebt.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
        </div>

        {/* Card 2: À Pagar do Mês (Somente Mês Selecionado) */}
        <div className="bg-amber-500/10 border border-amber-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest block mb-2">À Pagar ({monthLabel})</span>
          <p className="text-3xl font-black text-amber-600 dark:text-white tracking-tighter">R$ {monthSummary.due.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
        </div>

        {/* Card 3: Pago no Mês */}
        <div className="bg-emerald-500/10 border border-emerald-500/20 p-6 rounded-3xl relative overflow-hidden group">
          <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest block mb-2">Pago ({monthLabel})</span>
          <p className="text-3xl font-black text-emerald-600 dark:text-white tracking-tighter">R$ {monthSummary.paid.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>

          <button 
              onClick={() => {
                setIsEditing(false);
                setNewDebt({ name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1 });
                setShowAddModal(true);
              }}
              className="absolute top-4 right-4 p-2 bg-emerald-500 text-white rounded-xl shadow-lg hover:bg-emerald-600 transition-all opacity-0 group-hover:opacity-100"
              title="Nova Dívida"
            >
              <Plus className="w-5 h-5" />
            </button>
        </div>
      </div>

      <div className="flex flex-col gap-4">
         <div className="flex items-center justify-between">
            <h3 className="text-[11px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-[0.2em]">
            Parcelas do Mês
            </h3>

            {/* Seletor de Mês */}
            <div className="flex items-center bg-slate-100 dark:bg-slate-900/50 p-1.5 rounded-xl border border-slate-200 dark:border-white/5">
                <button onClick={() => changeMonth(-1)} className="p-1.5 hover:bg-white dark:hover:bg-white/10 rounded-lg transition-colors">
                    <ChevronLeft className="w-4 h-4 text-slate-500" />
                </button>
                <span className="text-xs font-black uppercase tracking-widest text-[#212529] dark:text-white px-3 min-w-[120px] text-center">
                    {monthLabel}
                </span>
                <button onClick={() => changeMonth(1)} className="p-1.5 hover:bg-white dark:hover:bg-white/10 rounded-lg transition-colors">
                    <ChevronRight className="w-4 h-4 text-slate-500" />
                </button>
            </div>
         </div>

         <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            {displayItems.map((item, index) => {
              // Configuração de Cores baseada no status
              let statusConfig = {
                 bg: 'bg-white dark:bg-[#111827]/60',
                 border: 'border-slate-200 dark:border-white/5',
                 iconBg: 'bg-indigo-500/10',
                 iconColor: 'text-indigo-600 dark:text-indigo-400',
                 icon: Clock,
                 label: 'A Vencer',
                 labelColor: 'text-amber-500' // Laranja para pendente/futuro
              };

              if (item.status === 'overdue') {
                 statusConfig = {
                    bg: 'bg-rose-50 dark:bg-rose-900/10',
                    border: 'border-rose-200 dark:border-rose-500/30',
                    iconBg: 'bg-rose-500/20',
                    iconColor: 'text-rose-600 dark:text-rose-400',
                    icon: AlertTriangle,
                    label: 'Vencido',
                    labelColor: 'text-rose-600' // Vermelho
                 };
              } else if (item.status === 'paid') {
                 statusConfig = {
                    bg: 'bg-emerald-50 dark:bg-emerald-900/10',
                    border: 'border-emerald-200 dark:border-emerald-500/30',
                    iconBg: 'bg-emerald-500/20',
                    iconColor: 'text-emerald-600 dark:text-emerald-400',
                    icon: CheckCircle2,
                    label: 'Pago',
                    labelColor: 'text-emerald-600' // Verde
                 };
              }

              // Se pendente (não pago, não vencido), garantir cor Laranja
              if (item.status === 'pending') {
                  statusConfig.iconBg = 'bg-amber-500/10';
                  statusConfig.iconColor = 'text-amber-600 dark:text-amber-400';
                  statusConfig.label = 'A Vencer';
                  statusConfig.labelColor = 'text-amber-600 dark:text-amber-400';
                  statusConfig.border = 'border-amber-200 dark:border-amber-500/30';
              }

              return (
                <div key={`${item.originalDebtId}-${item.installmentNumber}-${index}`} className={`${statusConfig.bg} backdrop-blur-md border ${statusConfig.border} rounded-3xl p-6 relative group transition-all shadow-sm`}>

                  {/* Botão Editar (Apenas na dívida pai, mas acessível aqui) */}
                  <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-all z-10">
                     <button 
                       onClick={() => handleOpenEdit(item.debt)}
                       className="p-2 bg-white/50 dark:bg-black/20 rounded-full hover:bg-indigo-500 hover:text-white transition-colors text-slate-500"
                     >
                       <Edit2 className="w-4 h-4" />
                     </button>
                  </div>

                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center gap-4">
                      <div className={`p-3 rounded-2xl ${statusConfig.iconBg} ${statusConfig.iconColor}`}>
                        <statusConfig.icon />
                      </div>
                      <div>
                        <h4 className="font-bold text-[#212529] dark:text-white text-lg tracking-tight">{item.debt.name}</h4>
                        <div className="flex gap-2 items-center mt-1">
                            <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded-md ${statusConfig.labelColor} bg-white/50 dark:bg-black/20`}>
                                {statusConfig.label}
                            </span>
                            <span className="text-[10px] text-[#6C757D] dark:text-slate-500 font-bold uppercase tracking-widest">
                                {item.installmentNumber}/{item.totalInstallments}
                            </span>
                        </div>
                      </div>
                    </div>
                    <div className="text-right pr-8 lg:pr-0">
                      <p className="text-xs font-bold uppercase tracking-widest mb-1 text-[#6C757D] dark:text-slate-500">Vencimento</p>
                      <div className={`flex items-center justify-end gap-2 text-sm font-bold ${statusConfig.labelColor}`}>
                        <Calendar className="w-4 h-4" />
                        {item.date.toLocaleDateString('pt-BR')}
                      </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4 mb-4">
                      <div className="bg-white/50 dark:bg-black/20 p-3 rounded-2xl">
                          <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block mb-1">Parcela</span>
                          <span className="text-sm font-bold text-[#212529] dark:text-slate-200">
                             R$ {item.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                          </span>
                      </div>
                      <div className="bg-white/50 dark:bg-black/20 p-3 rounded-2xl">
                          <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block mb-1">Restante Total</span>
                          <span className="text-sm font-bold text-[#212529] dark:text-slate-200">
                             R$ {item.debt.remainingAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                          </span>
                      </div>
                  </div>

                  {item.status !== 'paid' && (
                    <button 
                      onClick={() => handleOpenPayment(item)}
                      className="w-full flex items-center justify-center gap-2 py-3 bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl text-[11px] font-black uppercase tracking-widest text-[#212529] dark:text-slate-300 hover:bg-indigo-600 hover:text-white hover:border-indigo-600 transition-all shadow-sm"
                    >
                      <DollarSign className="w-4 h-4" /> Pagar Parcela
                    </button>
                  )}
                </div>
              );
            })}

            {displayItems.length === 0 && (
              <div className="lg:col-span-2 text-center py-16 bg-slate-100 dark:bg-slate-900/20 rounded-3xl border border-dashed border-slate-300 dark:border-white/10">
                <div className="flex justify-center mb-3">
                    <CheckCircle2 className="w-10 h-10 text-emerald-500/50" />
                </div>
                <p className="text-[#6C757D] dark:text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhuma parcela pendente em {monthLabel}</p>
              </div>
            )}
         </div>
      </div>

      {/* Modal de Pagamento */}
      {paymentModal.debt && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/80 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-3xl w-full max-w-sm p-8 border border-slate-200 dark:border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-[#212529] dark:text-white tracking-tight">Amortizar {paymentModal.debt.name}</h3>
              <button onClick={() => setPaymentModal({ debt: null, amount: 0, poteId: '', date: '' })}><X className="text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-white" /></button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Valor do Pagamento</label>
                <input 
                  type="number" 
                  step="0.01"
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.amount}
                  onChange={(e) => setPaymentModal({ ...paymentModal, amount: parseFloat(e.target.value) || 0 })}
                />
              </div>
              <div>
                 <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Data do Pagamento</label>
                 <input 
                   type="date" 
                   className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                   value={paymentModal.date}
                   onChange={(e) => setPaymentModal({ ...paymentModal, date: e.target.value })}
                 />
              </div>
              <div>
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Pote de Origem</label>
                <select 
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.poteId}
                  onChange={(e) => setPaymentModal({ ...paymentModal, poteId: e.target.value })}
                >
                  <option value="">Selecione...</option>
                  {potes.map(p => <option key={p.id} value={p.id}>{p.name} (Saldo: R$ {p.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })})</option>)}
                </select>
              </div>
              <button 
                onClick={() => {
                  if (paymentModal.debt && paymentModal.amount > 0 && paymentModal.poteId && paymentModal.date) {
                    onPay(paymentModal.debt, paymentModal.amount, paymentModal.poteId, paymentModal.date);
                    setPaymentModal({ debt: null, amount: 0, poteId: '', date: '' });
                  } else {
                    alert("Preencha todos os campos corretamente.");
                  }
                }}
                className="w-full py-4 bg-emerald-500 text-emerald-950 font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-emerald-400 transition-all shadow-xl"
              >
                Confirmar Pagamento
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Nova/Editar Dívida */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/80 backdrop-blur-md">
           <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">
                {isEditing ? 'Editar Dívida' : 'Registrar Dívida'}
              </h3>
              <button onClick={() => setShowAddModal(false)}><X className="text-[#6C757D] dark:text-slate-600" /></button>
            </div>
            <form onSubmit={handleAddSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Descrição</label>
                <input required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.name} onChange={e => setNewDebt({...newDebt, name: e.target.value})} />
              </div>

              {/* Toggle Input Type - Only if not editing (simplicity) or allow toggle */}
              <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1 rounded-xl">
                 <button 
                   type="button" 
                   onClick={() => setInputType('total')}
                   className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${inputType === 'total' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
                 >
                   Valor Total
                 </button>
                 <button 
                   type="button" 
                   onClick={() => setInputType('installment')}
                   className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${inputType === 'installment' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
                 >
                   Valor da Parcela
                 </button>
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">
                        {inputType === 'total' ? 'Total R$' : 'Parcela R$'}
                    </label>
                    <input type="number" step="0.01" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.valueInput || ''} onChange={e => setNewDebt({...newDebt, valueInput: parseFloat(e.target.value)})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Qtd. Parcelas</label>
                    <input type="number" min="1" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.installments || 1} onChange={e => setNewDebt({...newDebt, installments: parseInt(e.target.value)})} />
                  </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Vencimento (1ª Parc)</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.dueDate} onChange={e => setNewDebt({...newDebt, dueDate: e.target.value})} />
              </div>

              <div className="bg-indigo-50 dark:bg-indigo-500/10 p-3 rounded-xl text-center">
                 <p className="text-[10px] uppercase text-indigo-400 font-bold mb-1">Resumo do Registro</p>
                 <p className="text-indigo-600 dark:text-indigo-300 font-bold text-sm">
                    {inputType === 'total' 
                        ? `${newDebt.installments}x de R$ ${(newDebt.valueInput / (newDebt.installments || 1)).toFixed(2)}`
                        : `Total de R$ ${(newDebt.valueInput * (newDebt.installments || 1)).toFixed(2)}`
                    }
                 </p>
              </div>

              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">
                 {isEditing ? 'Atualizar Dívida' : 'Salvar Compromisso'}
              </button>
            </form>
           </div>
        </div>
      )}
    </div>
  );
}

export type TransactionType = 'income' | 'expense';

export interface SubCategory {
  id: string;
  name: string;
}

export interface Category {
  id: string;
  name: string;
  type: TransactionType;
  subCategories: SubCategory[];
  isDefault?: boolean;
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  category: string;
  subCategory?: string;
  date: string;
  type: TransactionType;
  poteId?: string;
  paymentMethod?: string;
  isRecurring?: boolean;
}

export interface Debt {
  id: string;
  name: string;
  totalAmount: number;
  remainingAmount: number;
  dueDate: string;
  category: string;
  status: 'active' | 'paid' | 'overdue';
  installments?: number; // Total de parcelas
  currentInstallment?: number; // Parcela atual (calculada ou manual)
}

export interface Jar {
  id: string;
  name: string;
  percentage: number;
  balance: number;
}

export interface Budget {
  id: string;
  category: string;
  limit: number;
  spent: number;
}

export interface FinancialGoal {
  id: string;
  name: string;
  targetAmount: number;
  currentAmount: number;
  deadline: string;
}

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  priority: 'low' | 'medium' | 'high';
  dueDate: string;
  tags: string[];
}

export interface Note {
  id: string;
  title: string;
  content: string;
  date: string;
  tags: string[];
}

export interface JournalEntry {
  id: string;
  content: string;
  mood: string;
  date: string;
}

// Auth Types
export interface User {
  id: string;
  email: string;
  password: string; // Em produção real, isso seria um hash
  name: string;
  role: 'admin' | 'user';
  status: 'active' | 'blocked';
  createdAt: string;
}

export interface FinancialData {
  transactions: Transaction[];
  budgets: Budget[];
  goals: FinancialGoal[];
  potes: Jar[];
  debts: Debt[];
  categories: Category[];
  tasks?: Task[];
  notes?: Note[];
  journal?: JournalEntry[];
}

export type AppView = 'dashboard' | 'wallet' | 'transactions' | 'debts' | 'potes' | 'advisor' | 'goals' | 'budgets' | 'settings' | 'tasks' | 'notes' | 'journal' | 'admin';

import React, { useState, useMemo } from 'react';
import { FinancialData } from '../types';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  BarChart, Bar, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { Calendar, TrendingUp, TrendingDown, DollarSign, Target, AlertTriangle, Filter, Wallet } from 'lucide-react';

interface AnalyticsDashboardProps {
  data: FinancialData;
}

export default function AnalyticsDashboard({ data }: AnalyticsDashboardProps) {
  const [dateRange, setDateRange] = useState<{ type: 'month' | 'year' | 'all', value: string }>({ type: 'year', value: new Date().getFullYear().toString() });

  // --- FILTRAGEM DE DADOS ---
  const filteredTransactions = useMemo(() => {
    return data.transactions.filter(t => {
      const d = new Date(t.date);
      const now = new Date();

      if (dateRange.type === 'month') {
        // value format: "YYYY-MM"
        return t.date.startsWith(dateRange.value);
      } else if (dateRange.type === 'year') {
        return d.getFullYear().toString() === dateRange.value;
      }
      return true; // All
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [data.transactions, dateRange]);

  // --- KPIs GERAIS (Baseado no filtro) ---
  const kpis = useMemo(() => {
    const income = filteredTransactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = filteredTransactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    const balance = income - expense;
    const savingsRate = income > 0 ? ((income - expense) / income) * 100 : 0;

    return { income, expense, balance, savingsRate };
  }, [filteredTransactions]);

  // --- DADOS PARA GRÁFICO DE EVOLUÇÃO (AREA CHART) ---
  const evolutionData = useMemo(() => {
    const grouped: Record<string, { name: string, Receitas: number, Despesas: number }> = {};

    filteredTransactions.forEach(t => {
      // Se filtro for anual, agrupa por mês. Se mensal, agrupa por dia.
      const dateKey = dateRange.type === 'month' 
        ? new Date(t.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })
        : new Date(t.date).toLocaleDateString('pt-BR', { month: 'short' });

      if (!grouped[dateKey]) grouped[dateKey] = { name: dateKey, Receitas: 0, Despesas: 0 };

      if (t.type === 'income') grouped[dateKey].Receitas += t.amount;
      else grouped[dateKey].Despesas += t.amount;
    });

    // Se estiver vazio, gera placeholder
    if (Object.keys(grouped).length === 0) return [];

    return Object.values(grouped);
  }, [filteredTransactions, dateRange]);

  // --- ORÇAMENTOS (STATUS) ---
  const budgetStatus = useMemo(() => {
    // Calcular gasto REAL dentro do período filtrado para cada categoria de orçamento
    const spendingByCategory: Record<string, number> = {};
    filteredTransactions.filter(t => t.type === 'expense').forEach(t => {
      spendingByCategory[t.category] = (spendingByCategory[t.category] || 0) + t.amount;
    });

    return data.budgets.map(b => ({
      name: b.category,
      limit: b.limit,
      spent: spendingByCategory[b.category] || 0,
      percentage: Math.min(100, ((spendingByCategory[b.category] || 0) / b.limit) * 100)
    }));
  }, [data.budgets, filteredTransactions]);

  // --- METAS ---
  const goalStats = useMemo(() => {
    return data.goals.map(g => ({
      name: g.name,
      current: g.currentAmount,
      target: g.targetAmount,
      percentage: (g.currentAmount / g.targetAmount) * 100
    }));
  }, [data.goals]);

  // --- DÍVIDAS ---
  const debtStats = useMemo(() => {
    const total = data.debts.reduce((acc, d) => acc + d.totalAmount, 0);
    const remaining = data.debts.reduce((acc, d) => acc + d.remainingAmount, 0);
    const paid = total - remaining;

    return [
      { name: 'Pago', value: paid },
      { name: 'Pendente', value: remaining }
    ];
  }, [data.debts]);

  const COLORS_DEBT = ['#10b981', '#f43f5e'];

  // --- HANDLERS ---
  const handleFilterChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
     const val = e.target.value;
     if (val === 'all') setDateRange({ type: 'all', value: '' });
     else if (val.includes('-')) setDateRange({ type: 'month', value: val });
     else setDateRange({ type: 'year', value: val });
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white dark:bg-[#1e293b] p-3 rounded-xl shadow-xl border border-slate-200 dark:border-white/10">
          <p className="text-xs font-bold text-slate-500 mb-2">{label}</p>
          {payload.map((p: any) => (
            <p key={p.name} className="text-xs font-black flex items-center gap-2" style={{ color: p.color }}>
              <span>{p.name}:</span>
              <span>R$ {p.value.toLocaleString()}</span>
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in duration-500">

      {/* HEADER E FILTROS */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white dark:bg-[#111827]/60 p-6 rounded-[2rem] border border-slate-200 dark:border-white/5 shadow-sm">
         <div>
            <h2 className="text-2xl font-black text-[#212529] dark:text-white uppercase tracking-tighter flex items-center gap-3">
              <TrendingUp className="w-6 h-6 text-indigo-600" /> Visão Geral
            </h2>
            <p className="text-[#6C757D] dark:text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">
              Inteligência Financeira Consolidada
            </p>
         </div>

         <div className="flex items-center gap-3 bg-slate-100 dark:bg-black/20 p-2 rounded-2xl">
            <Filter className="w-4 h-4 text-slate-500 ml-2" />
            <select 
              className="bg-transparent text-sm font-bold text-slate-700 dark:text-slate-200 outline-none p-2"
              onChange={handleFilterChange}
              value={dateRange.type === 'all' ? 'all' : dateRange.value}
            >
               <option value={new Date().getFullYear().toString()}>Este Ano ({new Date().getFullYear()})</option>
               <option value={(new Date().getFullYear() - 1).toString()}>Ano Passado ({new Date().getFullYear() - 1})</option>
               <option value={new Date().toISOString().slice(0, 7)}>Este Mês</option>
               <option value="all">Todo o Período</option>
            </select>
         </div>
      </div>

      {/* KPI CARDS */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
         <div className="bg-emerald-500/10 border border-emerald-500/20 p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-2">
               <div className="p-1.5 bg-emerald-500/20 rounded-lg"><TrendingUp className="w-4 h-4 text-emerald-600 dark:text-emerald-400" /></div>
               <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest">Receitas</span>
            </div>
            <p className="text-2xl font-black text-emerald-600 dark:text-white tracking-tighter">R$ {kpis.income.toLocaleString()}</p>
         </div>
         <div className="bg-rose-500/10 border border-rose-500/20 p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-2">
               <div className="p-1.5 bg-rose-500/20 rounded-lg"><TrendingDown className="w-4 h-4 text-rose-600 dark:text-rose-400" /></div>
               <span className="text-[10px] font-black text-rose-600 dark:text-rose-400 uppercase tracking-widest">Despesas</span>
            </div>
            <p className="text-2xl font-black text-rose-600 dark:text-white tracking-tighter">R$ {kpis.expense.toLocaleString()}</p>
         </div>
         <div className="bg-indigo-500/10 border border-indigo-500/20 p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-2">
               <div className="p-1.5 bg-indigo-500/20 rounded-lg"><DollarSign className="w-4 h-4 text-indigo-600 dark:text-indigo-400" /></div>
               <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">Resultado</span>
            </div>
            <p className={`text-2xl font-black tracking-tighter ${kpis.balance >= 0 ? 'text-indigo-600 dark:text-white' : 'text-rose-500'}`}>
              R$ {kpis.balance.toLocaleString()}
            </p>
         </div>
         <div className="bg-amber-500/10 border border-amber-500/20 p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-2">
               <div className="p-1.5 bg-amber-500/20 rounded-lg"><Wallet className="w-4 h-4 text-amber-600 dark:text-amber-400" /></div>
               <span className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest">Economia</span>
            </div>
            <p className="text-2xl font-black text-amber-600 dark:text-white tracking-tighter">{kpis.savingsRate.toFixed(1)}%</p>
         </div>
      </div>

      {/* GRÁFICO PRINCIPAL: FLUXO DE CAIXA */}
      <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none">
         <h3 className="text-sm font-black text-[#212529] dark:text-white uppercase tracking-widest mb-6 flex items-center gap-2">
            <Calendar className="w-4 h-4 text-indigo-500" /> Evolução Financeira
         </h3>
         <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
               <AreaChart data={evolutionData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                  <defs>
                     <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                     </linearGradient>
                     <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#f43f5e" stopOpacity={0}/>
                     </linearGradient>
                  </defs>
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} />
                  <YAxis hide />
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" opacity={0.1} />
                  <Tooltip content={<CustomTooltip />} />
                  <Area type="monotone" dataKey="Receitas" stroke="#10b981" fillOpacity={1} fill="url(#colorIncome)" strokeWidth={3} />
                  <Area type="monotone" dataKey="Despesas" stroke="#f43f5e" fillOpacity={1} fill="url(#colorExpense)" strokeWidth={3} />
               </AreaChart>
            </ResponsiveContainer>
         </div>
      </div>

      {/* GRID INFERIOR: DETALHES */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

         {/* ORÇAMENTOS */}
         <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-lg dark:shadow-none">
            <h3 className="text-xs font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-4">Orçamentos (Período)</h3>
            <div className="space-y-4 max-h-[250px] overflow-y-auto no-scrollbar">
               {budgetStatus.map((b, idx) => (
                  <div key={idx} className="space-y-1">
                     <div className="flex justify-between text-[10px] font-bold uppercase">
                        <span className="text-[#212529] dark:text-white">{b.name}</span>
                        <span className={`${b.percentage > 100 ? 'text-rose-500' : 'text-indigo-500'}`}>{b.percentage.toFixed(0)}%</span>
                     </div>
                     <div className="h-2 w-full bg-slate-100 dark:bg-slate-900 rounded-full overflow-hidden">
                        <div className={`h-full ${b.percentage > 100 ? 'bg-rose-500' : 'bg-indigo-500'}`} style={{ width: `${b.percentage}%` }}></div>
                     </div>
                     <p className="text-[9px] text-slate-400 text-right">R$ {b.spent.toLocaleString()} / {b.limit.toLocaleString()}</p>
                  </div>
               ))}
               {budgetStatus.length === 0 && <p className="text-xs text-slate-500 italic">Sem orçamentos definidos.</p>}
            </div>
         </div>

         {/* DÍVIDAS (PIE) */}
         <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-lg dark:shadow-none flex flex-col items-center justify-center">
            <h3 className="text-xs font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-2 w-full text-left">Saúde da Dívida</h3>
            <div className="w-full h-[200px] relative">
               <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                     <Pie data={debtStats} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                        {debtStats.map((entry, index) => (
                           <Cell key={`cell-${index}`} fill={COLORS_DEBT[index % COLORS_DEBT.length]} />
                        ))}
                     </Pie>
                     <Tooltip />
                  </PieChart>
               </ResponsiveContainer>
               <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center">
                  <p className="text-[10px] text-slate-400 uppercase font-black">Total</p>
                  <p className="text-sm font-black text-[#212529] dark:text-white">R$ {(debtStats[0].value + debtStats[1].value).toLocaleString()}</p>
               </div>
            </div>
            <div className="flex gap-4 mt-2">
               <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-emerald-500"></div><span className="text-[10px] text-slate-500 font-bold uppercase">Pago</span></div>
               <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-rose-500"></div><span className="text-[10px] text-slate-500 font-bold uppercase">Aberto</span></div>
            </div>
         </div>

         {/* METAS */}
         <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-lg dark:shadow-none">
            <h3 className="text-xs font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-4">Metas Ativas</h3>
            <div className="space-y-4 max-h-[250px] overflow-y-auto no-scrollbar">
               {goalStats.map((g, idx) => (
                  <div key={idx} className="flex items-center gap-3">
                     <div className="relative w-10 h-10 flex-shrink-0">
                        <svg className="w-full h-full" viewBox="0 0 36 36">
                           <path className="text-slate-100 dark:text-slate-800" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="4" />
                           <path className="text-amber-500" strokeDasharray={`${g.percentage}, 100`} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="4" />
                        </svg>
                        <div className="absolute inset-0 flex items-center justify-center">
                           <Target className="w-4 h-4 text-amber-500" />
                        </div>
                     </div>
                     <div className="flex-1 min-w-0">
                        <p className="text-xs font-bold text-[#212529] dark:text-white truncate">{g.name}</p>
                        <p className="text-[9px] text-slate-500 uppercase font-black">R$ {g.current.toLocaleString()} / {g.target.toLocaleString()}</p>
                     </div>
                  </div>
               ))}
               {goalStats.length === 0 && <p className="text-xs text-slate-500 italic">Nenhuma meta ativa.</p>}
            </div>
         </div>

      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Receipt, Target, BrainCircuit, Menu, X, Archive, 
  AlertCircle, Plus, Settings as SettingsIcon, Camera, Mic, Loader2, StopCircle, LogOut, Shield, Wallet
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Budget, FinancialGoal, Category, User } from './types';
import Dashboard from './components/Dashboard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Settings from './components/Settings';
import AdminPanel from './components/AdminPanel';
import Auth from './components/Auth';
import Toast, { ToastType } from './components/Toast';
import { analyzeReceipt, analyzeAudioCommand } from './services/gemini';
import { initializeAuth, getCurrentUser, logout } from './services/auth';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const DEFAULT_CATEGORIES: Category[] = [
  { 
    id: 'c1', name: 'Moradia', type: 'expense', isDefault: true,
    subCategories: [{id: 's1', name: 'Aluguel'}, {id: 's2', name: 'Energia'}, {id: 's3', name: 'Internet'}, {id: 's4', name: 'Manutenção'}] 
  },
  { 
    id: 'c2', name: 'Alimentação', type: 'expense', isDefault: true,
    subCategories: [{id: 's5', name: 'Supermercado'}, {id: 's6', name: 'Restaurante'}, {id: 's7', name: 'Delivery'}] 
  },
  { 
    id: 'c3', name: 'Transporte', type: 'expense', isDefault: true,
    subCategories: [{id: 's8', name: 'Combustível'}, {id: 's9', name: 'Uber/Táxi'}, {id: 's10', name: 'Manutenção Veículo'}] 
  },
  { 
    id: 'c4', name: 'Saúde', type: 'expense', isDefault: true,
    subCategories: [{id: 's11', name: 'Farmácia'}, {id: 's12', name: 'Consultas'}, {id: 's13', name: 'Plano de Saúde'}] 
  },
  { 
    id: 'c5', name: 'Lazer', type: 'expense', isDefault: true,
    subCategories: [{id: 's14', name: 'Cinema/Streaming'}, {id: 's15', name: 'Viagem'}, {id: 's16', name: 'Hobbies'}] 
  },
  { 
    id: 'c6', name: 'Renda', type: 'income', isDefault: true,
    subCategories: [{id: 's17', name: 'Salário'}, {id: 's18', name: 'Freelance'}, {id: 's19', name: 'Dividendos'}] 
  }
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', subCategory: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', subCategory: 'Aluguel', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', subCategory: 'Supermercado', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
  adminOnly?: boolean;
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // Initialize Auth
  useEffect(() => {
    initializeAuth();
    const currentUser = getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }
  }, []);

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // States for Quick Entry (Fab)
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = () => {
    logout();
    setUser(null);
    setView('dashboard');
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null); 
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string, date: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: date || new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  const handleGoalEdit = (updatedGoal: FinancialGoal) => {
    setGoals(goals.map(g => g.id === updatedGoal.id ? updatedGoal : g));
    showToast("Meta atualizada com sucesso!");
  };

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    showToast("Analisando imagem...", "info");

    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);

      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; 
  };

  const handleMicClick = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");

          const result = await analyzeAudioCommand(base64Audio);

          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };

  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'wallet', label: 'Carteira', icon: Wallet, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'admin', label: 'Admin', icon: Shield, section: 'SISTEMA', adminOnly: true },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  if (!user) {
    return (
      <>
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        <Auth onLoginSuccess={handleLoginSuccess} />
      </>
    );
  }

  return (
    <div className="min-h-screen flex bg-[#F8F9FA] dark:bg-[#030712] text-[#212529] dark:text-slate-100 font-sans overflow-hidden select-none transition-colors duration-300">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-white/80 dark:bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          <p className="text-[#212529] dark:text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* Floating Action Button */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button 
              onClick={handleCameraClick}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button 
              onClick={handleMicClick}
              className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}
            >
              {isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}
            </button>
            <button 
              onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Receipt className="w-5 h-5" />
            </button>
          </div>
        )}

        <button 
          onClick={() => {
             if (isRecording) {
                stopRecording();
             } else {
                setIsFabOpen(!isFabOpen);
             }
          }}
          className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}
        >
          {isRecording ? (
             <div className="w-4 h-4 bg-white rounded-sm animate-spin" />
          ) : (
             <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />
          )}
        </button>
      </div>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-white dark:bg-[#0a0c14] border-r border-slate-200 dark:border-white/5 flex flex-col shadow-2xl lg:shadow-none
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter text-[#212529] dark:text-white">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-[#6C757D]" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => {
             const items = navItems.filter(item => item.section === sectionName && (!item.adminOnly || user.role === 'admin'));
             if (items.length === 0) return null;

             return (
              <div key={sectionName} className="space-y-1">
                <h4 className="px-4 text-[8px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                  {sectionName}
                </h4>
                <div className="space-y-1">
                  {items.map((item) => (
                    <button 
                      key={item.id} 
                      onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                      className={`
                        w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                        ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800/40'}
                      `}
                    >
                      <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                      <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </nav>

        <div className="p-4 border-t border-slate-200 dark:border-white/5">
          <button 
            onClick={handleLogout}
            className="w-full flex items-center gap-4 px-4 py-3 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all"
          >
            <LogOut className="w-5 h-5" />
            <span className="font-bold text-sm lg:hidden xl:block">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#F8F9FA] dark:bg-[#030712] transition-colors duration-300">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-[#212529] dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest">Usuário</span>
                <span className="text-xs font-black text-[#212529] dark:text-white truncate max-w-[100px]">{user.name}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <span className="font-black text-indigo-600 dark:text-indigo-400">{user.name.charAt(0)}</span>
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <AnalyticsDashboard data={financialData} />}
            {view === 'wallet' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} 
                onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} // Usado para update
                onEdit={(d) => { setDebts(debts.map(item => item.id === d.id ? d : item)); showToast("Dívida atualizada!"); }} // Usado para edição completa
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
                onEdit={handleGoalEdit}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={setCategories} 
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Receipt, Target, BrainCircuit, Menu, X, Archive, 
  AlertCircle, Plus, Settings as SettingsIcon, Camera, Mic, Loader2, StopCircle, LogOut, Shield, Wallet
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Budget, FinancialGoal, Category, User } from './types';
import Dashboard from './components/Dashboard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Settings from './components/Settings';
import AdminPanel from './components/AdminPanel';
import Auth from './components/Auth';
import Toast, { ToastType } from './components/Toast';
import { analyzeReceipt, analyzeAudioCommand } from './services/gemini';
import { initializeAuth, getCurrentUser, logout } from './services/auth';

const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const DEFAULT_CATEGORIES: Category[] = [
  { 
    id: 'c1', name: 'Moradia', type: 'expense', isDefault: true,
    subCategories: [{id: 's1', name: 'Aluguel'}, {id: 's2', name: 'Energia'}, {id: 's3', name: 'Internet'}, {id: 's4', name: 'Manutenção'}] 
  },
  { 
    id: 'c2', name: 'Alimentação', type: 'expense', isDefault: true,
    subCategories: [{id: 's5', name: 'Supermercado'}, {id: 's6', name: 'Restaurante'}, {id: 's7', name: 'Delivery'}] 
  },
  { 
    id: 'c3', name: 'Transporte', type: 'expense', isDefault: true,
    subCategories: [{id: 's8', name: 'Combustível'}, {id: 's9', name: 'Uber/Táxi'}, {id: 's10', name: 'Manutenção Veículo'}] 
  },
  { 
    id: 'c4', name: 'Saúde', type: 'expense', isDefault: true,
    subCategories: [{id: 's11', name: 'Farmácia'}, {id: 's12', name: 'Consultas'}, {id: 's13', name: 'Plano de Saúde'}] 
  },
  { 
    id: 'c5', name: 'Lazer', type: 'expense', isDefault: true,
    subCategories: [{id: 's14', name: 'Cinema/Streaming'}, {id: 's15', name: 'Viagem'}, {id: 's16', name: 'Hobbies'}] 
  },
  { 
    id: 'c6', name: 'Renda', type: 'income', isDefault: true,
    subCategories: [{id: 's17', name: 'Salário'}, {id: 's18', name: 'Freelance'}, {id: 's19', name: 'Dividendos'}] 
  }
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', subCategory: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', subCategory: 'Aluguel', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', subCategory: 'Supermercado', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
  adminOnly?: boolean;
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // Initialize Auth
  useEffect(() => {
    initializeAuth();
    const currentUser = getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }
  }, []);

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // States for Quick Entry (Fab)
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = () => {
    logout();
    setUser(null);
    setView('dashboard');
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null); 
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string, date: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: date || new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  const handleGoalEdit = (updatedGoal: FinancialGoal) => {
    setGoals(goals.map(g => g.id === updatedGoal.id ? updatedGoal : g));
    showToast("Meta atualizada com sucesso!");
  };

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    showToast("Analisando imagem...", "info");

    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);

      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; 
  };

  const handleMicClick = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");

          const result = await analyzeAudioCommand(base64Audio);

          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };

  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'wallet', label: 'Carteira', icon: Wallet, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'admin', label: 'Admin', icon: Shield, section: 'SISTEMA', adminOnly: true },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  if (!user) {
    return (
      <>
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        <Auth onLoginSuccess={handleLoginSuccess} />
      </>
    );
  }

  return (
    <div className="min-h-screen flex bg-[#F8F9FA] dark:bg-[#030712] text-[#212529] dark:text-slate-100 font-sans overflow-hidden select-none transition-colors duration-300">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-white/80 dark:bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          <p className="text-[#212529] dark:text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* Floating Action Button */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button 
              onClick={handleCameraClick}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button 
              onClick={handleMicClick}
              className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}
            >
              {isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}
            </button>
            <button 
              onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Receipt className="w-5 h-5" />
            </button>
          </div>
        )}

        <button 
          onClick={() => {
             if (isRecording) {
                stopRecording();
             } else {
                setIsFabOpen(!isFabOpen);
             }
          }}
          className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}
        >
          {isRecording ? (
             <div className="w-4 h-4 bg-white rounded-sm animate-spin" />
          ) : (
             <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />
          )}
        </button>
      </div>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-white dark:bg-[#0a0c14] border-r border-slate-200 dark:border-white/5 flex flex-col shadow-2xl lg:shadow-none
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter text-[#212529] dark:text-white">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-[#6C757D]" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => {
             const items = navItems.filter(item => item.section === sectionName && (!item.adminOnly || user.role === 'admin'));
             if (items.length === 0) return null;

             return (
              <div key={sectionName} className="space-y-1">
                <h4 className="px-4 text-[8px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                  {sectionName}
                </h4>
                <div className="space-y-1">
                  {items.map((item) => (
                    <button 
                      key={item.id} 
                      onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                      className={`
                        w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                        ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800/40'}
                      `}
                    >
                      <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                      <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </nav>

        <div className="p-4 border-t border-slate-200 dark:border-white/5">
          <button 
            onClick={handleLogout}
            className="w-full flex items-center gap-4 px-4 py-3 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all"
          >
            <LogOut className="w-5 h-5" />
            <span className="font-bold text-sm lg:hidden xl:block">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#F8F9FA] dark:bg-[#030712] transition-colors duration-300">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-[#212529] dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest">Usuário</span>
                <span className="text-xs font-black text-[#212529] dark:text-white truncate max-w-[100px]">{user.name}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <span className="font-black text-indigo-600 dark:text-indigo-400">{user.name.charAt(0)}</span>
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <AnalyticsDashboard data={financialData} />}
            {view === 'wallet' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                transactions={transactions}
                onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} 
                onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} // Usado para update
                onEdit={(d) => { setDebts(debts.map(item => item.id === d.id ? d : item)); showToast("Dívida atualizada!"); }} // Usado para edição completa
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
                onEdit={handleGoalEdit}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={setCategories} 
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Debt, Jar, Transaction } from '../types';
import { Plus, CheckCircle2, AlertTriangle, Calendar, ChevronLeft, ChevronRight, DollarSign, X, Edit2, Clock, AlertCircle } from 'lucide-react';

interface DebtsProps {
  debts: Debt[];
  potes: Jar[];
  transactions?: Transaction[];
  onAdd: (d: Debt) => void;
  onUpdate: (d: Debt) => void;
  onPay: (d: Debt, amount: number, poteId: string, date: string) => void;
  onEdit?: (d: Debt) => void;
}

// Interface auxiliar para renderização
interface InstallmentItem {
  debt: Debt;
  installmentNumber: number;
  totalInstallments: number;
  date: Date;
  amount: number;
  status: 'paid' | 'overdue' | 'pending';
  originalDebtId: string;
}

export default function Debts({ debts, potes, transactions = [], onAdd, onUpdate, onPay, onEdit }: DebtsProps) {
  const [showAddModal, setShowAddModal] = useState(false);
  const [inputType, setInputType] = useState<'total' | 'installment'>('total');
  const [isEditing, setIsEditing] = useState(false);

  // Navegação de Mês
  const [currentMonth, setCurrentMonth] = useState(new Date());

  const [paymentModal, setPaymentModal] = useState<{ debt: Debt | null, amount: number, poteId: string, date: string }>({ 
    debt: null, 
    amount: 0, 
    poteId: '',
    date: new Date().toISOString().split('T')[0]
  });

  const [newDebt, setNewDebt] = useState<{
    id?: string;
    name: string;
    valueInput: number;
    dueDate: string;
    category: string;
    installments: number;
    remainingAmount?: number;
    status?: 'active' | 'paid' | 'overdue';
  }>({
    name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1
  });

  // Totais Globais
  const totalDebt = debts.filter(d => d.status !== 'paid').reduce((acc, d) => acc + d.remainingAmount, 0);

  const changeMonth = (delta: number) => {
    const newDate = new Date(currentMonth);
    newDate.setMonth(newDate.getMonth() + delta);
    setCurrentMonth(newDate);
  };

  const monthLabel = currentMonth.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

  // Lógica principal: Projetar parcelas e filtrar
  const displayItems = useMemo(() => {
    const items: InstallmentItem[] = [];
    const viewMonth = currentMonth.getMonth();
    const viewYear = currentMonth.getFullYear();

    // Verifica se estamos visualizando o mês atual (para lógica de mostrar atrasados)
    const today = new Date();
    today.setHours(0,0,0,0);
    const isCurrentViewMonth = viewMonth === today.getMonth() && viewYear === today.getFullYear();

    debts.forEach(debt => {
      // Valor da parcela
      const installmentValue = debt.totalAmount / (debt.installments || 1);

      // Quantas parcelas já foram "totalmente pagas" baseado no valor amortizado
      const paidAmount = debt.totalAmount - debt.remainingAmount;
      // Pequena margem de erro para floats
      const paidInstallmentsCount = Math.floor((paidAmount + 0.01) / installmentValue);

      // Gera todas as parcelas virtuais
      for (let i = 0; i < (debt.installments || 1); i++) {
        const installmentDate = new Date(debt.dueDate);
        // Adiciona meses à data inicial
        installmentDate.setMonth(installmentDate.getMonth() + i);
        // Ajusta para ultimo dia do mês se necessário (ex: 31 jan -> 28 fev)
        // (Lógica simplificada de Date do JS já faz o rollover, mas mantemos simples)
        installmentDate.setHours(0,0,0,0);

        let status: 'paid' | 'overdue' | 'pending' = 'pending';

        // 1. Verifica se está paga
        if (i < paidInstallmentsCount) {
          status = 'paid';
        } 
        // 2. Se não paga, verifica se está vencida
        else if (installmentDate < today) {
          status = 'overdue';
        }
        // 3. Se não, é pendente (futuro ou hoje)
        else {
          status = 'pending';
        }

        // Lógica de Exibição (Filtro)
        const isInstallmentMonth = installmentDate.getMonth() === viewMonth && installmentDate.getFullYear() === viewYear;

        // MOSTRAR SE:
        // A) É a parcela do mês selecionado
        // B) OU Se estamos vendo o mês ATUAL e essa parcela é antiga e está ATRASADA (Vencida)
        if (isInstallmentMonth || (isCurrentViewMonth && status === 'overdue' && debt.status !== 'paid')) {
          items.push({
            debt: debt,
            installmentNumber: i + 1,
            totalInstallments: debt.installments || 1,
            date: installmentDate,
            amount: installmentValue,
            status: status,
            originalDebtId: debt.id
          });
        }
      }
    });

    // Ordenar: Vencidos primeiro, depois por data
    return items.sort((a, b) => {
      if (a.status === 'overdue' && b.status !== 'overdue') return -1;
      if (a.status !== 'overdue' && b.status === 'overdue') return 1;
      return a.date.getTime() - b.date.getTime();
    });

  }, [debts, currentMonth]);

  // Cálculos do Mês
  const monthSummary = useMemo(() => {
    let due = 0;
    let paid = 0;
    displayItems.forEach(item => {
        if (item.status === 'paid') {
            paid += item.amount;
        } else {
            due += item.amount;
        }
    });
    return { due, paid };
  }, [displayItems]);


  // Handlers
  const handleOpenPayment = (item: InstallmentItem) => {
    // Sugere pagar o valor dessa parcela específica
    // Mas limita ao que falta pagar da dívida total
    const amountToPay = Math.min(item.amount, item.debt.remainingAmount);

    setPaymentModal({
      debt: item.debt,
      amount: parseFloat(amountToPay.toFixed(2)),
      poteId: potes.length > 0 ? potes[0].id : '',
      date: new Date().toISOString().split('T')[0]
    });
  };

  const handleOpenEdit = (debt: Debt) => {
    setIsEditing(true);
    setInputType('total');
    setNewDebt({
      id: debt.id,
      name: debt.name,
      valueInput: debt.totalAmount,
      dueDate: debt.dueDate,
      category: debt.category,
      installments: debt.installments || 1,
      remainingAmount: debt.remainingAmount,
      status: debt.status
    });
    setShowAddModal(true);
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDebt.name || !newDebt.valueInput) return;

    let totalAmount = 0;
    if (inputType === 'total') {
        totalAmount = newDebt.valueInput;
    } else {
        totalAmount = newDebt.valueInput * (newDebt.installments || 1);
    }

    const debtData: Debt = {
      id: isEditing && newDebt.id ? newDebt.id : Math.random().toString(36).substr(2, 9),
      name: newDebt.name,
      totalAmount: totalAmount,
      remainingAmount: isEditing ? (newDebt.remainingAmount ?? totalAmount) : totalAmount, 
      dueDate: newDebt.dueDate,
      category: newDebt.category,
      installments: newDebt.installments,
      status: newDebt.status || 'active',
      currentInstallment: 0
    };

    if (isEditing && onEdit) {
        if (isEditing && newDebt.id) {
            const original = debts.find(d => d.id === newDebt.id);
            if (original && original.totalAmount !== totalAmount) {
                 const diff = totalAmount - original.totalAmount;
                 debtData.remainingAmount = Math.max(0, original.remainingAmount + diff);
            }
        }
        onEdit(debtData);
    } else {
        onAdd(debtData);
    }

    setNewDebt({ name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1 });
    setShowAddModal(false);
    setIsEditing(false);
  };

  // Helper para buscar data do pagamento
  const getPaymentDate = (debt: Debt) => {
    if (transactions.length === 0) return null;
    // Tenta encontrar uma transação de pagamento recente para esta dívida
    const payment = transactions
        .filter(t => t.category === 'Dívidas' && t.description.toLowerCase().includes(debt.name.toLowerCase()))
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0];

    return payment ? new Date(payment.date).toLocaleDateString('pt-BR') : null;
  };

  return (
    <div className="space-y-6">
      {/* Resumo Global Reformulado */}
      <div className="grid grid-cols-2 gap-4">
        {/* Card 1: À Pagar do Mês */}
        <div className="bg-amber-500/10 border border-amber-500/20 p-6 rounded-3xl">
          <span className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest block mb-2">À Pagar ({monthLabel})</span>
          <p className="text-3xl font-black text-amber-600 dark:text-white tracking-tighter">R$ {monthSummary.due.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
        </div>

        {/* Card 2: Pago no Mês */}
        <div className="bg-emerald-500/10 border border-emerald-500/20 p-6 rounded-3xl relative overflow-hidden group">
          <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest block mb-2">Pago ({monthLabel})</span>
          <p className="text-3xl font-black text-emerald-600 dark:text-white tracking-tighter">R$ {monthSummary.paid.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>

          <button 
              onClick={() => {
                setIsEditing(false);
                setNewDebt({ name: '', valueInput: 0, dueDate: new Date().toISOString().split('T')[0], category: 'Outros', installments: 1 });
                setShowAddModal(true);
              }}
              className="absolute top-4 right-4 p-2 bg-emerald-500 text-white rounded-xl shadow-lg hover:bg-emerald-600 transition-all opacity-0 group-hover:opacity-100"
              title="Nova Dívida"
            >
              <Plus className="w-5 h-5" />
            </button>
        </div>
      </div>

      <div className="flex flex-col gap-4">
         <div className="flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex flex-col">
                <h3 className="text-[11px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-[0.2em]">
                Parcelas do Mês
                </h3>
                <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
                    Saldo Total Devedor: R$ {totalDebt.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </span>
            </div>

            {/* Seletor de Mês */}
            <div className="flex items-center bg-slate-100 dark:bg-slate-900/50 p-1.5 rounded-xl border border-slate-200 dark:border-white/5">
                <button onClick={() => changeMonth(-1)} className="p-1.5 hover:bg-white dark:hover:bg-white/10 rounded-lg transition-colors">
                    <ChevronLeft className="w-4 h-4 text-slate-500" />
                </button>
                <span className="text-xs font-black uppercase tracking-widest text-[#212529] dark:text-white px-3 min-w-[120px] text-center">
                    {monthLabel}
                </span>
                <button onClick={() => changeMonth(1)} className="p-1.5 hover:bg-white dark:hover:bg-white/10 rounded-lg transition-colors">
                    <ChevronRight className="w-4 h-4 text-slate-500" />
                </button>
            </div>
         </div>

         <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            {displayItems.map((item, index) => {
              // Configuração de Cores baseada no status
              let statusConfig = {
                 bg: 'bg-white dark:bg-[#111827]/60',
                 border: 'border-slate-200 dark:border-white/5',
                 iconBg: 'bg-indigo-500/10',
                 iconColor: 'text-indigo-600 dark:text-indigo-400',
                 icon: Clock,
                 label: 'A Vencer',
                 labelColor: 'text-amber-500'
              };

              let paymentDateDisplay = null;

              if (item.status === 'overdue') {
                 statusConfig = {
                    bg: 'bg-rose-50 dark:bg-rose-900/10',
                    border: 'border-rose-200 dark:border-rose-500/30',
                    iconBg: 'bg-rose-500/20',
                    iconColor: 'text-rose-600 dark:text-rose-400',
                    icon: AlertTriangle,
                    label: 'Vencido',
                    labelColor: 'text-rose-600' // Vermelho
                 };
              } else if (item.status === 'paid') {
                 statusConfig = {
                    bg: 'bg-emerald-50 dark:bg-emerald-900/10',
                    border: 'border-emerald-200 dark:border-emerald-500/30',
                    iconBg: 'bg-emerald-500/20',
                    iconColor: 'text-emerald-600 dark:text-emerald-400',
                    icon: CheckCircle2,
                    label: 'Pago',
                    labelColor: 'text-emerald-600' // Verde
                 };
                 paymentDateDisplay = getPaymentDate(item.debt);
              }

              // Se pendente (não pago, não vencido), garantir cor Laranja
              if (item.status === 'pending') {
                  statusConfig.iconBg = 'bg-amber-500/10';
                  statusConfig.iconColor = 'text-amber-600 dark:text-amber-400';
                  statusConfig.label = 'A Vencer';
                  statusConfig.labelColor = 'text-amber-600 dark:text-amber-400';
                  statusConfig.border = 'border-amber-200 dark:border-amber-500/30';
              }

              return (
                <div key={`${item.originalDebtId}-${item.installmentNumber}-${index}`} className={`${statusConfig.bg} backdrop-blur-md border ${statusConfig.border} rounded-3xl p-6 relative group transition-all shadow-sm`}>

                  {/* Botão Editar (Apenas na dívida pai, mas acessível aqui) */}
                  <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-all z-10">
                     <button 
                       onClick={() => handleOpenEdit(item.debt)}
                       className="p-2 bg-white/50 dark:bg-black/20 rounded-full hover:bg-indigo-500 hover:text-white transition-colors text-slate-500"
                     >
                       <Edit2 className="w-4 h-4" />
                     </button>
                  </div>

                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center gap-4">
                      <div className={`p-3 rounded-2xl ${statusConfig.iconBg} ${statusConfig.iconColor}`}>
                        <statusConfig.icon />
                      </div>
                      <div>
                        <h4 className="font-bold text-[#212529] dark:text-white text-lg tracking-tight">{item.debt.name}</h4>
                        <div className="flex gap-2 items-center mt-1">
                            <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded-md ${statusConfig.labelColor} bg-white/50 dark:bg-black/20`}>
                                {statusConfig.label}
                            </span>
                            <span className="text-[10px] text-[#6C757D] dark:text-slate-500 font-bold uppercase tracking-widest">
                                {item.installmentNumber}/{item.totalInstallments}
                            </span>
                        </div>
                      </div>
                    </div>
                    <div className="text-right pr-8 lg:pr-0">
                      <p className="text-xs font-bold uppercase tracking-widest mb-1 text-[#6C757D] dark:text-slate-500">
                        {item.status === 'paid' && paymentDateDisplay ? 'Pago em' : 'Vencimento'}
                      </p>
                      <div className={`flex items-center justify-end gap-2 text-sm font-bold ${statusConfig.labelColor}`}>
                        <Calendar className="w-4 h-4" />
                        {item.status === 'paid' && paymentDateDisplay 
                           ? paymentDateDisplay 
                           : item.date.toLocaleDateString('pt-BR')
                        }
                      </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4 mb-4">
                      <div className="bg-white/50 dark:bg-black/20 p-3 rounded-2xl">
                          <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block mb-1">Parcela</span>
                          <span className="text-sm font-bold text-[#212529] dark:text-slate-200">
                             R$ {item.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                          </span>
                      </div>
                      <div className="bg-white/50 dark:bg-black/20 p-3 rounded-2xl">
                          <span className="text-[9px] text-[#6C757D] dark:text-slate-500 font-black uppercase block mb-1">Restante Total</span>
                          <span className="text-sm font-bold text-[#212529] dark:text-slate-200">
                             R$ {item.debt.remainingAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                          </span>
                      </div>
                  </div>

                  {item.status !== 'paid' && (
                    <button 
                      onClick={() => handleOpenPayment(item)}
                      className="w-full flex items-center justify-center gap-2 py-3 bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl text-[11px] font-black uppercase tracking-widest text-[#212529] dark:text-slate-300 hover:bg-indigo-600 hover:text-white hover:border-indigo-600 transition-all shadow-sm"
                    >
                      <DollarSign className="w-4 h-4" /> Pagar Parcela
                    </button>
                  )}
                </div>
              );
            })}

            {displayItems.length === 0 && (
              <div className="lg:col-span-2 text-center py-16 bg-slate-100 dark:bg-slate-900/20 rounded-3xl border border-dashed border-slate-300 dark:border-white/10">
                <div className="flex justify-center mb-3">
                    <CheckCircle2 className="w-10 h-10 text-emerald-500/50" />
                </div>
                <p className="text-[#6C757D] dark:text-slate-600 font-black uppercase text-xs tracking-[0.2em]">Nenhuma parcela pendente em {monthLabel}</p>
              </div>
            )}
         </div>
      </div>

      {/* Modal de Pagamento */}
      {paymentModal.debt && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/80 backdrop-blur-md">
          <div className="bg-white dark:bg-[#1e293b] rounded-3xl w-full max-w-sm p-8 border border-slate-200 dark:border-white/10 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-[#212529] dark:text-white tracking-tight">Amortizar {paymentModal.debt.name}</h3>
              <button onClick={() => setPaymentModal({ debt: null, amount: 0, poteId: '', date: '' })}><X className="text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-white" /></button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Valor do Pagamento</label>
                <input 
                  type="number" 
                  step="0.01"
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.amount}
                  onChange={(e) => setPaymentModal({ ...paymentModal, amount: parseFloat(e.target.value) || 0 })}
                />
              </div>
              <div>
                 <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Data do Pagamento</label>
                 <input 
                   type="date" 
                   className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                   value={paymentModal.date}
                   onChange={(e) => setPaymentModal({ ...paymentModal, date: e.target.value })}
                 />
              </div>
              <div>
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest block mb-2">Pote de Origem</label>
                <select 
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500"
                  value={paymentModal.poteId}
                  onChange={(e) => setPaymentModal({ ...paymentModal, poteId: e.target.value })}
                >
                  <option value="">Selecione...</option>
                  {potes.map(p => <option key={p.id} value={p.id}>{p.name} (Saldo: R$ {p.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })})</option>)}
                </select>
              </div>
              <button 
                onClick={() => {
                  if (paymentModal.debt && paymentModal.amount > 0 && paymentModal.poteId && paymentModal.date) {
                    onPay(paymentModal.debt, paymentModal.amount, paymentModal.poteId, paymentModal.date);
                    setPaymentModal({ debt: null, amount: 0, poteId: '', date: '' });
                  } else {
                    alert("Preencha todos os campos corretamente.");
                  }
                }}
                className="w-full py-4 bg-emerald-500 text-emerald-950 font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-emerald-400 transition-all shadow-xl"
              >
                Confirmar Pagamento
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Nova/Editar Dívida */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 dark:bg-black/80 backdrop-blur-md">
           <div className="bg-white dark:bg-[#1e293b] rounded-[2.5rem] w-full max-w-sm p-10 border border-slate-200 dark:border-white/10 shadow-2xl animate-in zoom-in-95">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">
                {isEditing ? 'Editar Dívida' : 'Registrar Dívida'}
              </h3>
              <button onClick={() => setShowAddModal(false)}><X className="text-[#6C757D] dark:text-slate-600" /></button>
            </div>
            <form onSubmit={handleAddSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Descrição</label>
                <input required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.name} onChange={e => setNewDebt({...newDebt, name: e.target.value})} />
              </div>

              {/* Toggle Input Type - Only if not editing (simplicity) or allow toggle */}
              <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1 rounded-xl">
                 <button 
                   type="button" 
                   onClick={() => setInputType('total')}
                   className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${inputType === 'total' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
                 >
                   Valor Total
                 </button>
                 <button 
                   type="button" 
                   onClick={() => setInputType('installment')}
                   className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${inputType === 'installment' ? 'bg-white dark:bg-white/10 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
                 >
                   Valor da Parcela
                 </button>
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">
                        {inputType === 'total' ? 'Total R$' : 'Parcela R$'}
                    </label>
                    <input type="number" step="0.01" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.valueInput || ''} onChange={e => setNewDebt({...newDebt, valueInput: parseFloat(e.target.value)})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Qtd. Parcelas</label>
                    <input type="number" min="1" required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.installments || 1} onChange={e => setNewDebt({...newDebt, installments: parseInt(e.target.value)})} />
                  </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-widest ml-1">Vencimento (1ª Parc)</label>
                <input type="date" className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500" value={newDebt.dueDate} onChange={e => setNewDebt({...newDebt, dueDate: e.target.value})} />
              </div>

              <div className="bg-indigo-50 dark:bg-indigo-500/10 p-3 rounded-xl text-center">
                 <p className="text-[10px] uppercase text-indigo-400 font-bold mb-1">Resumo do Registro</p>
                 <p className="text-indigo-600 dark:text-indigo-300 font-bold text-sm">
                    {inputType === 'total' 
                        ? `${newDebt.installments}x de R$ ${(newDebt.valueInput / (newDebt.installments || 1)).toFixed(2)}`
                        : `Total de R$ ${(newDebt.valueInput * (newDebt.installments || 1)).toFixed(2)}`
                    }
                 </p>
              </div>

              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl">
                 {isEditing ? 'Atualizar Dívida' : 'Salvar Compromisso'}
              </button>
            </form>
           </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { FinancialData, FinancialGoal } from '../types';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  BarChart, Bar, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { Calendar, TrendingUp, TrendingDown, DollarSign, Target, AlertTriangle, Filter, Wallet, X, ArrowUpRight } from 'lucide-react';

interface AnalyticsDashboardProps {
  data: FinancialData;
}

export default function AnalyticsDashboard({ data }: AnalyticsDashboardProps) {
  const [dateRange, setDateRange] = useState<{ type: 'month' | 'year' | 'all', value: string }>({ type: 'year', value: new Date().getFullYear().toString() });
  const [selectedGoal, setSelectedGoal] = useState<FinancialGoal | null>(null);

  // --- FILTRAGEM DE DADOS ---
  const filteredTransactions = useMemo(() => {
    return data.transactions.filter(t => {
      const d = new Date(t.date);
      const now = new Date();

      if (dateRange.type === 'month') {
        // value format: "YYYY-MM"
        return t.date.startsWith(dateRange.value);
      } else if (dateRange.type === 'year') {
        return d.getFullYear().toString() === dateRange.value;
      }
      return true; // All
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [data.transactions, dateRange]);

  // --- KPIs GERAIS (Baseado no filtro) ---
  const kpis = useMemo(() => {
    const income = filteredTransactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = filteredTransactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    const balance = income - expense;
    const savingsRate = income > 0 ? ((income - expense) / income) * 100 : 0;

    return { income, expense, balance, savingsRate };
  }, [filteredTransactions]);

  // --- DADOS PARA GRÁFICO DE EVOLUÇÃO (AREA CHART) ---
  const evolutionData = useMemo(() => {
    const grouped: Record<string, { name: string, Receitas: number, Despesas: number }> = {};

    filteredTransactions.forEach(t => {
      // Se filtro for anual, agrupa por mês. Se mensal, agrupa por dia.
      const dateKey = dateRange.type === 'month' 
        ? new Date(t.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })
        : new Date(t.date).toLocaleDateString('pt-BR', { month: 'short' });

      if (!grouped[dateKey]) grouped[dateKey] = { name: dateKey, Receitas: 0, Despesas: 0 };

      if (t.type === 'income') grouped[dateKey].Receitas += t.amount;
      else grouped[dateKey].Despesas += t.amount;
    });

    // Se estiver vazio, gera placeholder
    if (Object.keys(grouped).length === 0) return [];

    return Object.values(grouped);
  }, [filteredTransactions, dateRange]);

  // --- ORÇAMENTOS (STATUS) ---
  const budgetStatus = useMemo(() => {
    // Calcular gasto REAL dentro do período filtrado para cada categoria de orçamento
    const spendingByCategory: Record<string, number> = {};
    filteredTransactions.filter(t => t.type === 'expense').forEach(t => {
      spendingByCategory[t.category] = (spendingByCategory[t.category] || 0) + t.amount;
    });

    return data.budgets.map(b => ({
      name: b.category,
      limit: b.limit,
      spent: spendingByCategory[b.category] || 0,
      percentage: Math.min(100, ((spendingByCategory[b.category] || 0) / b.limit) * 100)
    }));
  }, [data.budgets, filteredTransactions]);

  // --- METAS ---
  const goalStats = useMemo(() => {
    return data.goals.map(g => ({
      ...g,
      percentage: (g.currentAmount / g.targetAmount) * 100
    }));
  }, [data.goals]);

  // --- HISTÓRICO DE APORTES (Para o modal de meta selecionada) ---
  const goalHistory = useMemo(() => {
    if (!selectedGoal) return [];
    // Busca transações que sejam do tipo Investimento ou tenham a descrição/subcategoria da meta
    return data.transactions
        .filter(t => 
            (t.subCategory === 'Meta' && t.description.includes(selectedGoal.name)) || 
            (t.category === 'Investimento' && t.description.includes(selectedGoal.name))
        )
        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [selectedGoal, data.transactions]);


  // --- DÍVIDAS ---
  const debtStats = useMemo(() => {
    const total = data.debts.reduce((acc, d) => acc + d.totalAmount, 0);
    const remaining = data.debts.reduce((acc, d) => acc + d.remainingAmount, 0);
    const paid = total - remaining;

    return [
      { name: 'Pago', value: paid },
      { name: 'Pendente', value: remaining }
    ];
  }, [data.debts]);

  const COLORS_DEBT = ['#10b981', '#f43f5e'];

  // --- HANDLERS ---
  const handleFilterChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
     const val = e.target.value;
     if (val === 'all') setDateRange({ type: 'all', value: '' });
     else if (val.includes('-')) setDateRange({ type: 'month', value: val });
     else setDateRange({ type: 'year', value: val });
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white dark:bg-[#1e293b] p-3 rounded-xl shadow-xl border border-slate-200 dark:border-white/10">
          <p className="text-xs font-bold text-slate-500 mb-2">{label}</p>
          {payload.map((p: any) => (
            <p key={p.name} className="text-xs font-black flex items-center gap-2" style={{ color: p.color }}>
              <span>{p.name}:</span>
              <span>R$ {p.value.toLocaleString()}</span>
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in duration-500">

      {/* HEADER E FILTROS */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white dark:bg-[#111827]/60 p-6 rounded-[2rem] border border-slate-200 dark:border-white/5 shadow-sm">
         <div>
            <h2 className="text-2xl font-black text-[#212529] dark:text-white uppercase tracking-tighter flex items-center gap-3">
              <TrendingUp className="w-6 h-6 text-indigo-600" /> Visão Geral
            </h2>
            <p className="text-[#6C757D] dark:text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">
              Inteligência Financeira Consolidada
            </p>
         </div>

         <div className="flex items-center gap-3 bg-slate-100 dark:bg-black/20 p-2 rounded-2xl">
            <Filter className="w-4 h-4 text-slate-500 ml-2" />
            <select 
              className="bg-transparent text-sm font-bold text-slate-700 dark:text-slate-200 outline-none p-2"
              onChange={handleFilterChange}
              value={dateRange.type === 'all' ? 'all' : dateRange.value}
            >
               <option value={new Date().getFullYear().toString()}>Este Ano ({new Date().getFullYear()})</option>
               <option value={(new Date().getFullYear() - 1).toString()}>Ano Passado ({new Date().getFullYear() - 1})</option>
               <option value={new Date().toISOString().slice(0, 7)}>Este Mês</option>
               <option value="all">Todo o Período</option>
            </select>
         </div>
      </div>

      {/* KPI CARDS */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
         <div className="bg-emerald-500/10 border border-emerald-500/20 p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-2">
               <div className="p-1.5 bg-emerald-500/20 rounded-lg"><TrendingUp className="w-4 h-4 text-emerald-600 dark:text-emerald-400" /></div>
               <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest">Receitas</span>
            </div>
            <p className="text-2xl font-black text-emerald-600 dark:text-white tracking-tighter">R$ {kpis.income.toLocaleString()}</p>
         </div>
         <div className="bg-rose-500/10 border border-rose-500/20 p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-2">
               <div className="p-1.5 bg-rose-500/20 rounded-lg"><TrendingDown className="w-4 h-4 text-rose-600 dark:text-rose-400" /></div>
               <span className="text-[10px] font-black text-rose-600 dark:text-rose-400 uppercase tracking-widest">Despesas</span>
            </div>
            <p className="text-2xl font-black text-rose-600 dark:text-white tracking-tighter">R$ {kpis.expense.toLocaleString()}</p>
         </div>
         <div className="bg-indigo-500/10 border border-indigo-500/20 p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-2">
               <div className="p-1.5 bg-indigo-500/20 rounded-lg"><DollarSign className="w-4 h-4 text-indigo-600 dark:text-indigo-400" /></div>
               <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">Resultado</span>
            </div>
            <p className={`text-2xl font-black tracking-tighter ${kpis.balance >= 0 ? 'text-indigo-600 dark:text-white' : 'text-rose-500'}`}>
              R$ {kpis.balance.toLocaleString()}
            </p>
         </div>
         <div className="bg-amber-500/10 border border-amber-500/20 p-6 rounded-3xl">
            <div className="flex items-center gap-2 mb-2">
               <div className="p-1.5 bg-amber-500/20 rounded-lg"><Wallet className="w-4 h-4 text-amber-600 dark:text-amber-400" /></div>
               <span className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest">Economia</span>
            </div>
            <p className="text-2xl font-black text-amber-600 dark:text-white tracking-tighter">{kpis.savingsRate.toFixed(1)}%</p>
         </div>
      </div>

      {/* GRÁFICO PRINCIPAL: FLUXO DE CAIXA */}
      <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none">
         <h3 className="text-sm font-black text-[#212529] dark:text-white uppercase tracking-widest mb-6 flex items-center gap-2">
            <Calendar className="w-4 h-4 text-indigo-500" /> Evolução Financeira
         </h3>
         <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
               <AreaChart data={evolutionData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                  <defs>
                     <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                     </linearGradient>
                     <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#f43f5e" stopOpacity={0}/>
                     </linearGradient>
                  </defs>
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} />
                  <YAxis hide />
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" opacity={0.1} />
                  <Tooltip content={<CustomTooltip />} />
                  <Area type="monotone" dataKey="Receitas" stroke="#10b981" fillOpacity={1} fill="url(#colorIncome)" strokeWidth={3} />
                  <Area type="monotone" dataKey="Despesas" stroke="#f43f5e" fillOpacity={1} fill="url(#colorExpense)" strokeWidth={3} />
               </AreaChart>
            </ResponsiveContainer>
         </div>
      </div>

      {/* GRID INFERIOR: DETALHES */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

         {/* ORÇAMENTOS */}
         <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-lg dark:shadow-none">
            <h3 className="text-xs font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-4">Orçamentos (Período)</h3>
            <div className="space-y-4 max-h-[250px] overflow-y-auto no-scrollbar">
               {budgetStatus.map((b, idx) => (
                  <div key={idx} className="space-y-1">
                     <div className="flex justify-between text-[10px] font-bold uppercase">
                        <span className="text-[#212529] dark:text-white">{b.name}</span>
                        <span className={`${b.percentage > 100 ? 'text-rose-500' : 'text-indigo-500'}`}>{b.percentage.toFixed(0)}%</span>
                     </div>
                     <div className="h-2 w-full bg-slate-100 dark:bg-slate-900 rounded-full overflow-hidden">
                        <div className={`h-full ${b.percentage > 100 ? 'bg-rose-500' : 'bg-indigo-500'}`} style={{ width: `${b.percentage}%` }}></div>
                     </div>
                     <p className="text-[9px] text-slate-400 text-right">R$ {b.spent.toLocaleString()} / {b.limit.toLocaleString()}</p>
                  </div>
               ))}
               {budgetStatus.length === 0 && <p className="text-xs text-slate-500 italic">Sem orçamentos definidos.</p>}
            </div>
         </div>

         {/* DÍVIDAS (PIE) */}
         <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-lg dark:shadow-none flex flex-col items-center justify-center">
            <h3 className="text-xs font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-2 w-full text-left">Saúde da Dívida</h3>
            <div className="w-full h-[200px] relative">
               <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                     <Pie data={debtStats} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                        {debtStats.map((entry, index) => (
                           <Cell key={`cell-${index}`} fill={COLORS_DEBT[index % COLORS_DEBT.length]} />
                        ))}
                     </Pie>
                     <Tooltip />
                  </PieChart>
               </ResponsiveContainer>
               <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center">
                  <p className="text-[10px] text-slate-400 uppercase font-black">Total</p>
                  <p className="text-sm font-black text-[#212529] dark:text-white">R$ {(debtStats[0].value + debtStats[1].value).toLocaleString()}</p>
               </div>
            </div>
            <div className="flex gap-4 mt-2">
               <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-emerald-500"></div><span className="text-[10px] text-slate-500 font-bold uppercase">Pago</span></div>
               <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-rose-500"></div><span className="text-[10px] text-slate-500 font-bold uppercase">Aberto</span></div>
            </div>
         </div>

         {/* METAS */}
         <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-[2.5rem] border border-slate-200 dark:border-white/5 shadow-lg dark:shadow-none">
            <h3 className="text-xs font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-4">Metas Ativas</h3>
            <div className="space-y-4 max-h-[250px] overflow-y-auto no-scrollbar">
               {goalStats.map((g, idx) => (
                  <button 
                    key={idx} 
                    onClick={() => setSelectedGoal(g)}
                    className="flex items-center gap-3 w-full text-left hover:bg-slate-50 dark:hover:bg-white/5 p-2 rounded-xl transition-all group"
                  >
                     <div className="relative w-10 h-10 flex-shrink-0">
                        <svg className="w-full h-full" viewBox="0 0 36 36">
                           <path className="text-slate-100 dark:text-slate-800" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="4" />
                           <path className="text-amber-500" strokeDasharray={`${g.percentage}, 100`} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="currentColor" strokeWidth="4" />
                        </svg>
                        <div className="absolute inset-0 flex items-center justify-center">
                           <Target className="w-4 h-4 text-amber-500" />
                        </div>
                     </div>
                     <div className="flex-1 min-w-0">
                        <p className="text-xs font-bold text-[#212529] dark:text-white truncate group-hover:text-indigo-500 transition-colors">{g.name}</p>
                        <p className="text-[9px] text-slate-500 uppercase font-black">R$ {g.currentAmount.toLocaleString()} / {g.targetAmount.toLocaleString()}</p>
                     </div>
                     <ArrowUpRight className="w-4 h-4 text-slate-300 opacity-0 group-hover:opacity-100 transition-all" />
                  </button>
               ))}
               {goalStats.length === 0 && <p className="text-xs text-slate-500 italic">Nenhuma meta ativa.</p>}
            </div>
         </div>
      </div>

      {/* Modal de Detalhes da Meta */}
      {selectedGoal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 dark:bg-black/90 backdrop-blur-md">
            <div className="bg-white dark:bg-[#0f172a] rounded-[2.5rem] w-full max-w-lg p-8 border border-slate-200 dark:border-white/10 shadow-2xl animate-in zoom-in-95 flex flex-col max-h-[80vh]">
                <div className="flex justify-between items-center mb-6">
                   <div>
                       <h3 className="text-xl font-black text-[#212529] dark:text-white uppercase tracking-tighter">{selectedGoal.name}</h3>
                       <p className="text-[#6C757D] dark:text-slate-500 text-[10px] font-bold uppercase tracking-widest">Histórico de Aportes</p>
                   </div>
                   <button onClick={() => setSelectedGoal(null)} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-full"><X className="w-6 h-6 text-[#6C757D] dark:text-slate-500" /></button>
                </div>

                <div className="flex-1 overflow-y-auto space-y-3 pr-2">
                    {goalHistory.length > 0 ? (
                        goalHistory.map(t => (
                            <div key={t.id} className="flex justify-between items-center p-4 bg-slate-50 dark:bg-white/5 rounded-2xl border border-slate-100 dark:border-white/5">
                                <div className="flex items-center gap-3">
                                    <div className="p-2 bg-emerald-500/10 rounded-xl text-emerald-500">
                                        <TrendingUp className="w-4 h-4" />
                                    </div>
                                    <div>
                                        <p className="text-xs font-bold text-[#212529] dark:text-white">{new Date(t.date).toLocaleDateString()}</p>
                                        <p className="text-[9px] text-slate-400 font-black uppercase">Aporte</p>
                                    </div>
                                </div>
                                <span className="font-black text-emerald-500">+ R$ {t.amount.toLocaleString()}</span>
                            </div>
                        ))
                    ) : (
                        <div className="text-center py-10 text-slate-400 text-xs italic">Nenhum aporte registrado ainda.</div>
                    )}
                </div>

                <div className="mt-6 pt-6 border-t border-slate-200 dark:border-white/10">
                    <div className="flex justify-between items-center">
                        <span className="text-xs font-black uppercase text-slate-500">Total Acumulado</span>
                        <span className="text-lg font-black text-indigo-500">R$ {selectedGoal.currentAmount.toLocaleString()}</span>
                    </div>
                </div>
            </div>
        </div>
      )}

    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { Search, Plus, Minus, X, Trash2, Edit2, Calendar, SearchX, ChevronLeft, ChevronRight, Filter } from 'lucide-react';
import { Transaction, TransactionType, Jar, Category } from '../types';

interface TransactionsProps {
  transactions: Transaction[];
  potes: Jar[];
  categories: Category[];
  onAdd: (t: Transaction) => void;
  onDelete: (id: string) => void;
  onEdit: (t: Transaction) => void;
  preFilledData?: Partial<Transaction> | null;
}

export default function Transactions({ transactions, potes, categories, onAdd, onDelete, onEdit, preFilledData }: TransactionsProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState<'all' | TransactionType>('all');
  const [modalType, setModalType] = useState<'add' | 'edit' | null>(null);

  // Date Filters - Default to Current Month
  const [currentMonth, setCurrentMonth] = useState(new Date());

  const [dateRange, setDateRange] = useState({ 
    start: new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0], 
    end: new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0).toISOString().split('T')[0] 
  });

  const [currentTx, setCurrentTx] = useState<Partial<Transaction>>({
    description: '', amount: 0, category: '', subCategory: '', type: 'expense', date: new Date().toISOString().split('T')[0],
    poteId: potes.length > 0 ? potes[0].id : '', paymentMethod: 'PIX'
  });

  // Effect para abrir o modal quando dados pré-preenchidos (IA) chegarem
  useEffect(() => {
    if (preFilledData) {
      setCurrentTx({
        ...currentTx,
        ...preFilledData,
        // Garante que se a IA mandou uma categoria que existe, use-a. Se não, string vazia.
        category: categories.some(c => c.name === preFilledData.category) ? preFilledData.category : '',
        poteId: preFilledData.type === 'expense' && potes.length > 0 ? potes[0].id : ''
      });
      setModalType('add');
    }
  }, [preFilledData, categories, potes]);

  // Atualiza o range de datas quando o mês selecionado muda
  useEffect(() => {
    const start = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1).toISOString().split('T')[0];
    const end = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0).toISOString().split('T')[0];
    setDateRange({ start, end });
  }, [currentMonth]);

  const changeMonth = (delta: number) => {
    const newDate = new Date(currentMonth);
    newDate.setMonth(newDate.getMonth() + delta);
    setCurrentMonth(newDate);
  };

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            t.category.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === 'all' || t.type === typeFilter;

      const txDate = t.date; // YYYY-MM-DD
      const afterStart = !dateRange.start || txDate >= dateRange.start;
      const beforeEnd = !dateRange.end || txDate <= dateRange.end;

      return matchesSearch && matchesType && afterStart && beforeEnd;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, searchTerm, typeFilter, dateRange]);

  const availableCategories = useMemo(() => {
    return categories.filter(c => c.type === currentTx.type);
  }, [categories, currentTx.type]);

  const availableSubCategories = useMemo(() => {
    const cat = categories.find(c => c.name === currentTx.category);
    return cat ? cat.subCategories : [];
  }, [categories, currentTx.category]);

  const handleOpenAdd = (type: TransactionType) => {
    setCurrentTx({
      description: '', amount: 0, category: '', subCategory: '', type,
      date: new Date().toISOString().split('T')[0],
      poteId: type === 'expense' && potes.length > 0 ? potes[0].id : '',
      paymentMethod: 'PIX'
    });
    setModalType('add');
  };

  const handleOpenEdit = (t: Transaction) => {
    setCurrentTx(t);
    setModalType('edit');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentTx.description || !currentTx.amount || !currentTx.category) return;
    if (modalType === 'add') onAdd({ ...currentTx as Transaction, id: Math.random().toString(36).substr(2, 9) });
    else if (modalType === 'edit') onEdit(currentTx as Transaction);
    setModalType(null);
  };

  const monthLabel = currentMonth.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

  return (
    <div className="space-y-4">
      {/* Botões de Ação Rápida */}
      <div className="grid grid-cols-2 gap-3">
        <button onClick={() => handleOpenAdd('income')} className="flex items-center justify-center gap-2 py-4 bg-emerald-500/10 border border-emerald-500/20 text-emerald-600 dark:text-emerald-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-emerald-500/20 active:scale-95 transition-all">
          <Plus className="w-4 h-4" /> Ganho
        </button>
        <button onClick={() => handleOpenAdd('expense')} className="flex items-center justify-center gap-2 py-4 bg-rose-500/10 border border-rose-500/20 text-rose-600 dark:text-rose-400 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-rose-500/20 active:scale-95 transition-all">
          <Minus className="w-4 h-4" /> Gasto
        </button>
      </div>

      <div className="bg-white dark:bg-slate-900/40 p-3.5 rounded-2xl border border-slate-200 dark:border-white/5 space-y-3 shadow-sm dark:shadow-none">

        {/* Month Selector */}
        <div className="flex items-center justify-between bg-slate-100 dark:bg-slate-950/50 p-2 rounded-xl mb-2">
            <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-white dark:hover:bg-white/10 rounded-lg transition-colors">
                <ChevronLeft className="w-4 h-4 text-slate-500" />
            </button>
            <span className="text-sm font-black uppercase tracking-widest text-[#212529] dark:text-white">
                {monthLabel}
            </span>
            <button onClick={() => changeMonth(1)} className="p-2 hover:bg-white dark:hover:bg-white/10 rounded-lg transition-colors">
                <ChevronRight className="w-4 h-4 text-slate-500" />
            </button>
        </div>

        {/* Filtros de Tipo */}
        <div className="flex gap-2 p-1 bg-slate-100 dark:bg-slate-950/50 rounded-xl">
           <button 
             onClick={() => setTypeFilter('all')}
             className={`flex-1 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${typeFilter === 'all' ? 'bg-white dark:bg-slate-800 text-indigo-500 shadow-sm' : 'text-slate-400'}`}
           >
             Todos
           </button>
           <button 
             onClick={() => setTypeFilter('income')}
             className={`flex-1 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${typeFilter === 'income' ? 'bg-white dark:bg-slate-800 text-emerald-500 shadow-sm' : 'text-slate-400'}`}
           >
             Ganhos
           </button>
           <button 
             onClick={() => setTypeFilter('expense')}
             className={`flex-1 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${typeFilter === 'expense' ? 'bg-white dark:bg-slate-800 text-rose-500 shadow-sm' : 'text-slate-400'}`}
           >
             Gastos
           </button>
        </div>

        <div className="flex flex-wrap gap-3 items-center">
          <div className="relative flex-1 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500 dark:text-slate-600" />
            <input type="text" placeholder="Filtrar por nome..." className="w-full pl-9 pr-4 py-2.5 bg-slate-100 dark:bg-slate-950/50 border border-slate-200 dark:border-white/5 rounded-xl text-[#212529] dark:text-slate-200 text-xs outline-none focus:ring-1 focus:ring-indigo-500" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>

          <div className="flex items-center gap-2">
            <div className="relative hidden sm:block">
               <Calendar className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400" />
               <input 
                 type="date" 
                 className="pl-8 pr-2 py-2.5 bg-slate-100 dark:bg-slate-950/50 border border-slate-200 dark:border-white/5 rounded-xl text-[#212529] dark:text-slate-200 text-[10px] outline-none font-bold uppercase w-32"
                 value={dateRange.start}
                 onChange={e => setDateRange({...dateRange, start: e.target.value})}
               />
            </div>
            <span className="text-slate-400 text-xs font-bold hidden sm:block">-</span>
            <div className="relative hidden sm:block">
               <Calendar className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400" />
               <input 
                 type="date" 
                 className="pl-8 pr-2 py-2.5 bg-slate-100 dark:bg-slate-950/50 border border-slate-200 dark:border-white/5 rounded-xl text-[#212529] dark:text-slate-200 text-[10px] outline-none font-bold uppercase w-32"
                 value={dateRange.end}
                 onChange={e => setDateRange({...dateRange, end: e.target.value})}
               />
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-2.5">
        {filteredTransactions.map(t => (
          <div key={t.id} className="bg-white dark:bg-[#0a0c14] p-4 rounded-2xl border border-slate-200 dark:border-white/5 flex flex-col gap-2 group animate-in slide-in-from-bottom-2 duration-300 shadow-sm dark:shadow-none">
            <div className="flex justify-between items-start">
              <div className="flex gap-3 min-w-0">
                <div className={`p-1.5 rounded-lg flex-shrink-0 ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : 'bg-rose-500/10 text-rose-600 dark:text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                </div>
                <div className="min-w-0">
                  <p className="font-bold text-[#212529] dark:text-slate-200 text-xs truncate">{t.description}</p>
                  <p className="text-[8px] text-[#6C757D] dark:text-slate-600 font-black uppercase tracking-widest">
                    {t.category} {t.subCategory && `• ${t.subCategory}`} • {new Date(t.date).toLocaleDateString()}
                  </p>
                </div>
              </div>
              <p className={`font-black text-xs whitespace-nowrap ${t.type === 'income' ? 'text-emerald-600 dark:text-emerald-400' : 'text-[#212529] dark:text-slate-200'}`}>
                R$ {t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
              </p>
            </div>
            <div className="flex justify-between items-center border-t border-slate-100 dark:border-white/5 pt-2">
              <span className="text-[8px] font-black text-indigo-500 dark:text-indigo-400 uppercase tracking-widest">
                {t.type === 'income' ? 'RECEITA' : (potes.find(p => p.id === t.poteId)?.name || 'OUTRO')}
              </span>
              <div className="flex gap-1.5">
                <button onClick={() => handleOpenEdit(t)} className="p-2 text-[#6C757D] dark:text-slate-600 bg-slate-100 dark:bg-slate-900/50 rounded-lg hover:text-indigo-500 dark:hover:text-indigo-400 transition-colors"><Edit2 className="w-3.5 h-3.5" /></button>
                <button onClick={() => onDelete(t.id)} className="p-2 text-rose-500/50 bg-rose-500/5 rounded-lg hover:text-rose-600 dark:hover:text-rose-400 transition-colors"><Trash2 className="w-3.5 h-3.5" /></button>
              </div>
            </div>
          </div>
        ))}
        {filteredTransactions.length === 0 && (
          <div className="col-span-full flex flex-col items-center justify-center py-16 px-4 bg-slate-50 dark:bg-slate-900/20 border border-dashed border-slate-200 dark:border-white/10 rounded-3xl animate-in fade-in zoom-in-95">
            <div className="p-4 bg-white dark:bg-white/5 rounded-full mb-4 shadow-sm">
               <SearchX className="w-8 h-8 text-slate-400 dark:text-slate-500" />
            </div>
            <p className="text-sm font-bold text-slate-600 dark:text-slate-400">Nenhuma transação encontrada</p>
            <p className="text-[10px] text-slate-400 dark:text-slate-500 uppercase font-black tracking-widest mt-1 text-center">
               Para o filtro selecionado
            </p>
          </div>
        )}
      </div>

      {modalType && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/50 dark:bg-black/95 backdrop-blur-sm">
          <div className={`
             bg-white dark:bg-[#111827] w-full sm:max-w-md rounded-t-[2.5rem] sm:rounded-[2rem] p-6 md:p-8 border-t border-x sm:border flex flex-col shadow-2xl animate-in slide-in-from-bottom duration-300
             ${currentTx.type === 'income' ? 'border-emerald-500/30' : 'border-rose-500/30'}
          `}>
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center gap-3">
                 <div className={`p-2 rounded-xl ${currentTx.type === 'income' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : 'bg-rose-500/10 text-rose-600 dark:text-rose-400'}`}>
                    {currentTx.type === 'income' ? <Plus className="w-5 h-5" /> : <Minus className="w-5 h-5" />}
                 </div>
                 <h3 className="text-lg font-black text-[#212529] dark:text-white uppercase tracking-tighter">
                    {modalType === 'add' ? 'Registrar' : 'Editar'} {currentTx.type === 'income' ? 'Ganho' : 'Gasto'}
                 </h3>
              </div>
              <button onClick={() => setModalType(null)} className="p-2 bg-slate-100 dark:bg-slate-900 rounded-full"><X className="w-5 h-5 text-slate-500" /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Descrição</label>
                <input required className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none focus:ring-1 focus:ring-indigo-600 text-sm" value={currentTx.description} onChange={e => setCurrentTx({...currentTx, description: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Valor R$</label>
                  <input type="number" step="0.01" inputMode="decimal" required className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm" value={currentTx.amount || ''} onChange={e => setCurrentTx({...currentTx, amount: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Data</label>
                  <input type="date" className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm" value={currentTx.date} onChange={e => setCurrentTx({...currentTx, date: e.target.value})} />
                </div>
              </div>

              {/* Category Selector */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Categoria</label>
                  <select 
                    required 
                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm"
                    value={currentTx.category}
                    onChange={e => setCurrentTx({...currentTx, category: e.target.value, subCategory: ''})}
                  >
                    <option value="">Selecione...</option>
                    {availableCategories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                    {currentTx.category && !availableCategories.some(c => c.name === currentTx.category) && (
                       <option value={currentTx.category}>{currentTx.category} (Sugerida)</option>
                    )}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Subcategoria</label>
                  <select 
                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm"
                    value={currentTx.subCategory}
                    onChange={e => setCurrentTx({...currentTx, subCategory: e.target.value})}
                    disabled={availableSubCategories.length === 0}
                  >
                    <option value="">{availableSubCategories.length === 0 ? '-' : 'Selecione...'}</option>
                    {availableSubCategories.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                  </select>
                </div>
              </div>

              {currentTx.type === 'expense' && (
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-1">Pote de Origem</label>
                  <select className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-[#212529] dark:text-white outline-none text-sm" value={currentTx.poteId} onChange={e => setCurrentTx({...currentTx, poteId: e.target.value})}>
                    <option value="">Selecione...</option>
                    {potes.map(p => <option key={p.id} value={p.id}>{p.name} (R$ {p.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })})</option>)}
                  </select>
                </div>
              )}
              <button 
                type="submit" 
                className={`w-full py-4 text-white font-black uppercase text-xs tracking-widest rounded-xl shadow-xl mt-4 active:scale-95 transition-all
                  ${currentTx.type === 'income' ? 'bg-emerald-600 hover:bg-emerald-500' : 'bg-rose-600 hover:bg-rose-500'}
                `}
              >
                Confirmar {currentTx.type === 'income' ? 'Entrada' : 'Saída'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useMemo } from 'react';
import { Wallet, TrendingUp, Plus, PieChart as PieChartIcon, BarChart3, Activity, AlertTriangle, CheckCircle2 } from 'lucide-react';
import { FinancialData } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid 
} from 'recharts';

interface DashboardProps {
  data: FinancialData;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#06b6d4'];

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, potes, debts } = data;
  const totalBalance = potes.reduce((acc, p) => acc + p.balance, 0);

  const now = new Date();
  const currentMonthIdx = now.getMonth();
  const currentYear = now.getFullYear();

  const monthIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === currentMonthIdx)
    .reduce((acc, t) => acc + t.amount, 0);

  // Cálculo de Dívidas do Mês (Pagamento vs Aberto)
  const debtSummary = useMemo(() => {
    let due = 0;
    let paid = 0;

    debts.forEach(debt => {
      const installmentValue = debt.totalAmount / (debt.installments || 1);

      // Projeção simples para ver se tem parcela neste mês
      for (let i = 0; i < (debt.installments || 1); i++) {
         const installmentDate = new Date(debt.dueDate);
         installmentDate.setMonth(installmentDate.getMonth() + i);
         installmentDate.setHours(0,0,0,0);

         if (installmentDate.getMonth() === currentMonthIdx && installmentDate.getFullYear() === currentYear) {
            // Verificar se esta parcela específica foi "paga" baseado no montante total pago
            const amountPaid = debt.totalAmount - debt.remainingAmount;
            const installmentsPaidCount = Math.floor((amountPaid + 0.01) / installmentValue);

            if (i < installmentsPaidCount) {
               paid += installmentValue;
            } else {
               due += installmentValue;
            }
         }
      }
    });
    return { due, paid };
  }, [debts, currentMonthIdx, currentYear]);

  const categoryData = useMemo(() => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const categories: Record<string, number> = {};
    expenses.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });
    return Object.entries(categories)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 6);
  }, [transactions]);

  const trendData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const monthIndex = d.getMonth();
      const year = d.getFullYear();
      const income = transactions
        .filter(t => t.type === 'income' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      const expense = transactions
        .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      last6Months.push({ name: months[monthIndex], Entradas: income, Saídas: expense });
    }
    return last6Months;
  }, [transactions]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white dark:bg-[#0f172a] border border-slate-200 dark:border-white/10 p-2 rounded-xl shadow-2xl backdrop-blur-md">
          <p className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-0.5">{payload[0].name || payload[0].dataKey}</p>
          <p className="text-xs font-black text-[#212529] dark:text-white">R$ {payload[0].value.toLocaleString()}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-10">

      {/* 1. Saldo */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 p-5 md:p-6 rounded-3xl shadow-xl relative overflow-hidden group border border-white/10">
           <div className="absolute -top-4 -right-4 p-8 opacity-10 group-hover:scale-125 transition-transform duration-700"><Wallet className="w-16 h-16 md:w-24 text-white" /></div>
           <span className="text-indigo-100/60 text-[9px] font-black uppercase tracking-[0.2em] block mb-1">Saldo</span>
           <p className={`text-2xl md:text-4xl font-black tracking-tighter ${totalBalance < 0 ? 'text-rose-400' : 'text-white'}`}>
             R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
           <div className="mt-3 flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></div>
              <span className="text-[8px] text-indigo-200/50 font-black uppercase tracking-widest">Ativo</span>
           </div>
        </div>

        <div className="bg-white dark:bg-[#111827]/60 p-5 md:p-6 rounded-3xl border border-slate-200 dark:border-white/5 relative group overflow-hidden flex flex-col justify-center shadow-sm dark:shadow-none">
           <div className="absolute -top-4 -right-4 p-8 opacity-5"><TrendingUp className="w-16 h-16 md:w-24 text-[#212529] dark:text-white" /></div>
           <div className="flex items-center gap-2 mb-2">
              <div className="p-1.5 bg-emerald-500/10 rounded-lg"><TrendingUp className="w-4 h-4 text-emerald-600 dark:text-emerald-400" /></div>
              <span className="text-[#6C757D] dark:text-slate-500 text-[9px] font-black uppercase tracking-[0.2em]">Ganhos</span>
           </div>
           <p className="text-2xl md:text-4xl font-black text-emerald-600 dark:text-emerald-400 tracking-tighter">
             R$ {monthIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
        </div>
      </div>

      {/* 1.5 Dívidas do Mês (Novo) */}
      <div className="bg-slate-50 dark:bg-slate-900/40 p-5 rounded-3xl border border-slate-200 dark:border-white/5">
        <h3 className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-4">
           Compromissos do Mês
        </h3>
        <div className="grid grid-cols-2 gap-4">
            <div className="bg-rose-500/10 rounded-2xl p-4 border border-rose-500/20">
               <div className="flex items-center gap-2 mb-1">
                  <AlertTriangle className="w-3.5 h-3.5 text-rose-500" />
                  <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest">À Vencer</span>
               </div>
               <p className="text-lg font-black text-rose-500 dark:text-rose-400">R$ {debtSummary.due.toLocaleString()}</p>
            </div>
            <div className="bg-emerald-500/10 rounded-2xl p-4 border border-emerald-500/20">
               <div className="flex items-center gap-2 mb-1">
                  <CheckCircle2 className="w-3.5 h-3.5 text-emerald-500" />
                  <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Pago</span>
               </div>
               <p className="text-lg font-black text-emerald-500 dark:text-emerald-400">R$ {debtSummary.paid.toLocaleString()}</p>
            </div>
        </div>
      </div>

      {/* 2. Potes */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {potes.map((pote) => (
            <div key={pote.id} className="bg-white dark:bg-[#0a0c14] p-4 rounded-2xl border border-slate-200 dark:border-white/5 hover:border-indigo-500/40 transition-all group shadow-sm dark:shadow-none">
               <div className="flex justify-between items-center mb-2">
                  <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest truncate">{pote.name}</span>
                  <span className="text-[8px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-500/10 px-1.5 py-0.5 rounded-lg">{pote.percentage}%</span>
               </div>
               <p className={`text-sm md:text-lg font-black tracking-tighter ${pote.balance < 0 ? 'text-rose-500' : 'text-[#212529] dark:text-slate-200'}`}>
                 R$ {pote.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
               </p>
               <div className="mt-2 h-1 w-full bg-slate-100 dark:bg-slate-900 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-700" style={{ width: `${Math.max(0, Math.min(100, (pote.balance / (totalBalance || 1)) * 100))}%` }}></div>
               </div>
            </div>
          ))}
      </div>

      {/* 3. Atividades */}
      <div className="space-y-3">
        <h3 className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest px-1 flex items-center gap-3">
          Atividades <div className="h-px flex-1 bg-slate-200 dark:bg-slate-800/50"></div>
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {transactions.slice(0, 4).map(t => (
            <div key={t.id} className="bg-white dark:bg-[#0a0c14] p-3.5 rounded-2xl border border-slate-200 dark:border-white/5 flex items-center justify-between hover:bg-slate-50 dark:hover:bg-slate-900 transition-colors shadow-sm dark:shadow-none">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-xl ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : 'bg-rose-500/10 text-rose-600 dark:text-rose-400'}`}>
                  {t.type === 'income' ? <Plus className="w-3.5 h-3.5" /> : <Activity className="w-3.5 h-3.5" />}
                </div>
                <div className="min-w-0">
                  <p className="text-xs font-bold text-[#212529] dark:text-slate-200 truncate">{t.description}</p>
                  <p className="text-[8px] text-[#6C757D] dark:text-slate-600 font-black uppercase tracking-widest">{t.category}</p>
                </div>
              </div>
              <p className={`text-xs font-black ${t.type === 'income' ? 'text-emerald-600 dark:text-emerald-400' : 'text-[#212529] dark:text-slate-300'}`}>
                R$ {t.amount.toLocaleString()}
              </p>
            </div>
          ))}
          {transactions.length === 0 && (
            <div className="col-span-full py-6 text-center text-[#6C757D] dark:text-slate-700 text-[8px] font-black uppercase italic tracking-widest">Vazio</div>
          )}
        </div>
      </div>

      {/* 4 e 5. Gráficos */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-white dark:bg-[#0a0c14] p-5 rounded-3xl border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none">
          <h3 className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
            <PieChartIcon className="w-3.5 h-3.5 text-indigo-500 dark:text-indigo-400" /> Consumo
          </h3>
          <div className="h-[250px] w-full min-w-0 mx-auto">
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={0}>
                <PieChart>
                  <Pie data={categoryData} cx="50%" cy="50%" innerRadius="60%" outerRadius="80%" paddingAngle={4} dataKey="value">
                    {categoryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip content={<CustomTooltip />} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-[#6C757D] dark:text-slate-700 text-[9px] font-black uppercase italic tracking-widest">Sem Dados</div>
            )}
          </div>
        </div>

        <div className="bg-white dark:bg-[#0a0c14] p-5 rounded-3xl border border-slate-200 dark:border-white/5 shadow-xl dark:shadow-none">
          <h3 className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
            <BarChart3 className="w-3.5 h-3.5 text-indigo-500 dark:text-indigo-400" /> Histórico
          </h3>
          <div className="h-[250px] w-full min-w-0">
            <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={0}>
              <BarChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" className="dark:stroke-slate-800" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 9, fontWeight: 900 }} />
                <YAxis hide />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(99, 102, 241, 0.1)' }} />
                <Bar dataKey="Entradas" fill="#10b981" radius={[3, 3, 0, 0]} />
                <Bar dataKey="Saídas" fill="#f43f5e" radius={[3, 3, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

    </div>
  );
}

import { GoogleGenAI } from "@google/genai";
import { FinancialData } from "../types";

export const getFinancialAdvice = async (data: FinancialData, userQuery: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const contextSummary = {
    balance: data.transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0) - 
             data.transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0),
    debtsCount: data.debts.filter(d => d.status !== 'paid').length,
    potes: data.potes.map(p => `${p.name}: R$ ${p.balance.toLocaleString('pt-BR')}`).join(', '),
    categories: Array.from(new Set(data.transactions.map(t => t.category)))
  };

  const systemInstruction = `
    Você é o ZenOS Master Assistant, um assistente financeiro de elite.

    ESTADO ATUAL:
    - Saldo: R$ ${contextSummary.balance}
    - Potes: ${contextSummary.potes}
    - Categorias conhecidas: ${contextSummary.categories.join(', ')}

    COMANDOS ESPECIAIS:
    Se o usuário pedir para registrar um gasto ou entrada (ex: "gastei 50 com café" ou "recebi 2000 de bônus"), você deve responder normalmente mas incluir no FINAL da resposta um bloco JSON exatamente com este formato para que o sistema processe:
    {
      "action": "ADD_TRANSACTION",
      "transaction": {
        "description": "string",
        "amount": number,
        "type": "income" | "expense",
        "category": "string",
        "date": "YYYY-MM-DD"
      }
    }

    DIRETRIZES:
    - Seja conciso e executivo.
    - Se for um gasto, tente associar a uma categoria existente: ${contextSummary.categories.join(', ')}.
    - Use Markdown.
    - Responda em Português (Brasil).
  `;

  try {
    // Usando Gemini 3 Flash para respostas mais rápidas e otimizadas para o tier gratuito
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userQuery,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.4, 
      },
    });

    return response.text;
  } catch (error) {
    console.error("ZenOS AI Error:", error);
    return "Falha na conexão neural. Verifique se sua chave de API é válida.";
  }
};

// Nova função para analisar Imagens (Cupons Fiscais)
export const analyzeReceipt = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // Gemini 3 Flash suporta entrada multimodal e é mais rápido
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: `Analise este cupom fiscal ou imagem financeira. Extraia os dados para criar uma transação.
             Identifique se é: Mercado, Padaria, Posto de Gasolina, Farmácia, Restaurante, etc.
             Retorne os dados.`
          }
        ]
      },
      config: {
        temperature: 0.1,
        responseMimeType: 'application/json',
        responseSchema: {
           type: 'OBJECT',
           properties: {
             description: { type: 'STRING' },
             amount: { type: 'NUMBER' },
             date: { type: 'STRING' },
             category: { type: 'STRING' },
             type: { type: 'STRING' }
           }
        }
      }
    });

    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (error) {
    console.error("Receipt Analysis Error:", error);
    return null;
  }
};

