          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-[#212529] dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest">Usuário</span>
                <span className="text-xs font-black text-[#212529] dark:text-white truncate max-w-[100px]">{user.name}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <span className="font-black text-indigo-600 dark:text-indigo-400">{user.name.charAt(0)}</span>
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <AnalyticsDashboard data={financialData} />}
            {view === 'wallet' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                transactions={transactions}
                onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} 
                onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} // Usado para update
                onEdit={(d) => { setDebts(debts.map(item => item.id === d.id ? d : item)); showToast("Dívida atualizada!"); }} // Usado para edição completa
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
                onEdit={handleGoalEdit}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={setCategories} 
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { getUsers, updateUserStatus, activateSubscription } from '../services/auth';
import { Shield, Search, UserCheck, UserX, Trash2, Crown, Clock } from 'lucide-react';

export default function AdminPanel() {
  const [users, setUsers] = useState<User[]>([]);
  const [search, setSearch] = useState('');

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = () => {
    setUsers(getUsers());
  };

  const handleToggleStatus = (userId: string, currentStatus: 'active' | 'blocked') => {
    const newStatus = currentStatus === 'active' ? 'blocked' : 'active';
    if (updateUserStatus(userId, newStatus)) {
      loadUsers();
    } else {
      alert("Não é possível alterar o status deste usuário (pode ser um admin).");
    }
  };

  const handleActivateSubscription = (userId: string) => {
    if (activateSubscription(userId)) {
        loadUsers();
        alert("Assinatura ativada manualmente com sucesso.");
    }
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(search.toLowerCase()) || 
    u.email.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in">
      <div className="bg-indigo-600 rounded-[2.5rem] p-8 text-white flex flex-col md:flex-row justify-between items-center gap-6 shadow-2xl">
        <div className="flex items-center gap-4">
          <div className="p-4 bg-white/20 rounded-2xl backdrop-blur-md">
            <Shield className="w-8 h-8 text-white" />
          </div>
          <div>
            <h2 className="text-2xl font-black uppercase tracking-tighter">Portal Admin</h2>
            <p className="text-indigo-200 text-xs font-bold uppercase tracking-widest">Controle de Usuários e Assinaturas</p>
          </div>
        </div>
        <div className="relative w-full md:w-64">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-indigo-200" />
          <input 
            placeholder="Buscar usuário..." 
            className="w-full pl-10 pr-4 py-3 bg-white/10 border border-white/20 rounded-xl text-white placeholder:text-indigo-200 outline-none focus:bg-white/20 transition-all text-sm"
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white dark:bg-[#111827]/60 border border-slate-200 dark:border-white/5 rounded-[2.5rem] overflow-hidden shadow-xl">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-slate-50 dark:bg-black/20 border-b border-slate-200 dark:border-white/5">
              <tr>
                <th className="px-6 py-4 text-left text-[10px] font-black uppercase tracking-widest text-[#6C757D] dark:text-slate-500">Usuário</th>
                <th className="px-6 py-4 text-left text-[10px] font-black uppercase tracking-widest text-[#6C757D] dark:text-slate-500">Role</th>
                <th className="px-6 py-4 text-left text-[10px] font-black uppercase tracking-widest text-[#6C757D] dark:text-slate-500">Status</th>
                <th className="px-6 py-4 text-left text-[10px] font-black uppercase tracking-widest text-[#6C757D] dark:text-slate-500">Assinatura</th>
                <th className="px-6 py-4 text-right text-[10px] font-black uppercase tracking-widest text-[#6C757D] dark:text-slate-500">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-white/5">
              {filteredUsers.map(u => (
                <tr key={u.id} className="hover:bg-slate-50 dark:hover:bg-white/5 transition-colors">
                  <td className="px-6 py-4">
                    <div>
                      <p className="font-bold text-[#212529] dark:text-white text-sm">{u.name}</p>
                      <p className="text-xs text-[#6C757D] dark:text-slate-500">{u.email}</p>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${u.role === 'admin' ? 'bg-indigo-500/10 text-indigo-500' : 'bg-slate-500/10 text-slate-500'}`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${u.status === 'active' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
                      {u.status === 'active' ? 'Ativo' : 'Bloqueado'}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                     <div className="flex items-center gap-2">
                        {u.subscriptionStatus === 'active' ? (
                            <span className="flex items-center gap-1 px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest bg-emerald-500/10 text-emerald-500">
                                <Crown className="w-3 h-3" /> Premium
                            </span>
                        ) : u.subscriptionStatus === 'trial' ? (
                            <div className="flex flex-col">
                                <span className="flex items-center gap-1 px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest bg-amber-500/10 text-amber-500">
                                    <Clock className="w-3 h-3" /> Trial
                                </span>
                                <span className="text-[9px] text-slate-400 mt-1">Exp: {new Date(u.trialEndsAt).toLocaleDateString()}</span>
                            </div>
                        ) : (
                            <span className="flex items-center gap-1 px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest bg-rose-500/10 text-rose-500">
                                Expirado
                            </span>
                        )}
                     </div>
                  </td>
                  <td className="px-6 py-4 text-right flex items-center justify-end gap-2">
                    {u.role !== 'admin' && (
                      <>
                         {u.subscriptionStatus !== 'active' && (
                            <button 
                                onClick={() => handleActivateSubscription(u.id)}
                                className="p-2 bg-indigo-500/10 text-indigo-500 hover:bg-indigo-500 hover:text-white rounded-xl transition-all"
                                title="Ativar Premium Manualmente"
                            >
                                <Crown className="w-4 h-4" />
                            </button>
                         )}
                         <button 
                            onClick={() => handleToggleStatus(u.id, u.status)}
                            className={`p-2 rounded-xl transition-all ${u.status === 'active' ? 'bg-rose-500/10 text-rose-500 hover:bg-rose-500 hover:text-white' : 'bg-emerald-500/10 text-emerald-500 hover:bg-emerald-500 hover:text-white'}`}
                            title={u.status === 'active' ? 'Bloquear Acesso' : 'Liberar Acesso'}
                         >
                            {u.status === 'active' ? <UserX className="w-4 h-4" /> : <UserCheck className="w-4 h-4" />}
                         </button>
                      </>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export type TransactionType = 'income' | 'expense';

export interface SubCategory {
  id: string;
  name: string;
}

export interface Category {
  id: string;
  name: string;
  type: TransactionType;
  subCategories: SubCategory[];
  isDefault?: boolean;
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  category: string;
  subCategory?: string;
  date: string;
  type: TransactionType;
  poteId?: string;
  paymentMethod?: string;
  isRecurring?: boolean;
}

export interface Debt {
  id: string;
  name: string;
  totalAmount: number;
  remainingAmount: number;
  dueDate: string;
  category: string;
  status: 'active' | 'paid' | 'overdue';
  installments?: number; // Total de parcelas
  currentInstallment?: number; // Parcela atual (calculada ou manual)
}

export interface Jar {
  id: string;
  name: string;
  percentage: number;
  balance: number;
}

export interface Budget {
  id: string;
  category: string;
  limit: number;
  spent: number;
}

export interface FinancialGoal {
  id: string;
  name: string;
  targetAmount: number;
  currentAmount: number;
  deadline: string;
}

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  priority: 'low' | 'medium' | 'high';
  dueDate: string;
  tags: string[];
}

export interface Note {
  id: string;
  title: string;
  content: string;
  date: string;
  tags: string[];
}

export interface JournalEntry {
  id: string;
  content: string;
  mood: string;
  date: string;
}

// Auth Types
export interface User {
  id: string;
  email: string;
  password: string; // Em produção real, isso seria um hash
  name: string;
  role: 'admin' | 'user';
  status: 'active' | 'blocked';
  subscriptionStatus: 'trial' | 'active' | 'expired'; // Novo campo
  trialEndsAt: string; // Novo campo ISO Date
  createdAt: string;
}

export interface FinancialData {
  transactions: Transaction[];
  budgets: Budget[];
  goals: FinancialGoal[];
  potes: Jar[];
  debts: Debt[];
  categories: Category[];
  tasks?: Task[];
  notes?: Note[];
  journal?: JournalEntry[];
}

export type AppView = 'dashboard' | 'wallet' | 'transactions' | 'debts' | 'potes' | 'advisor' | 'goals' | 'budgets' | 'settings' | 'tasks' | 'notes' | 'journal' | 'admin';

