export const getUsers = (): User[] => {
  const stored = localStorage.getItem(USERS_KEY);
  return stored ? JSON.parse(stored) : [];
};

export const saveUser = (user: User) => {
  const users = getUsers();
  // Se usuário já existe, atualiza
  const existingIndex = users.findIndex(u => u.id === user.id);

  if (existingIndex >= 0) {
    users[existingIndex] = user;
  } else {
    users.push(user);
  }

  localStorage.setItem(USERS_KEY, JSON.stringify(users));

  // Se for o usuário logado atual, atualiza a sessão também
  const currentUser = getCurrentUser();
  if (currentUser && currentUser.id === user.id) {
    localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(user));
  }
};

export const login = (email: string, password: string): { success: boolean, user?: User, message?: string } => {
  const users = getUsers();
  const user = users.find(u => u.email.toLowerCase() === email.toLowerCase() && u.password === password);

  if (!user) {
    return { success: false, message: 'Credenciais inválidas.' };
  }

  if (user.status === 'blocked') {
    return { success: false, message: 'Conta bloqueada pelo administrador.' };
  }

  // Verifica validade da assinatura no login
  checkSubscriptionValidity(user);

  localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(user));
  return { success: true, user };
};

export const logout = () => {
  localStorage.removeItem(CURRENT_USER_KEY);
};

export const getCurrentUser = (): User | null => {
  const stored = localStorage.getItem(CURRENT_USER_KEY);
  if (!stored) return null;

  const user = JSON.parse(stored);
  // Revalidar status ao pegar usuário (caso o tempo tenha passado durante uso)
  return checkSubscriptionValidity(user);
};

// Função auxiliar para verificar e atualizar status de trial
const checkSubscriptionValidity = (user: User): User => {
  // Se já está ativo ou é admin, ignora
  if (user.subscriptionStatus === 'active' || user.role === 'admin') return user;

  const now = new Date();
  const trialEnd = new Date(user.trialEndsAt);

  if (now > trialEnd && user.subscriptionStatus === 'trial') {
    const updatedUser = { ...user, subscriptionStatus: 'expired' as const };
    // Atualiza no banco local sem recursão
    const users = getUsers();
    const idx = users.findIndex(u => u.id === user.id);
    if (idx >= 0) {
      users[idx] = updatedUser;
      localStorage.setItem(USERS_KEY, JSON.stringify(users));
    }
    return updatedUser;
  }

  return user;
};

export const register = (name: string, email: string, password: string): { success: boolean, message?: string } => {
  const users = getUsers();
  if (users.some(u => u.email.toLowerCase() === email.toLowerCase())) {
    return { success: false, message: 'E-mail já cadastrado.' };
  }

  // Define 7 dias de trial a partir de agora
  const trialDate = new Date();
  trialDate.setDate(trialDate.getDate() + 7);

  const newUser: User = {
    id: Math.random().toString(36).substr(2, 9),
    name,
    email,
    password,
    role: 'user',
    status: 'active',
    subscriptionStatus: 'trial',
    trialEndsAt: trialDate.toISOString(),
    createdAt: new Date().toISOString()
  };

  saveUser(newUser);
  return { success: true };
};

export const updateUserStatus = (userId: string, status: 'active' | 'blocked') => {
    const users = getUsers();
    const userIndex = users.findIndex(u => u.id === userId);
    if (userIndex >= 0 && users[userIndex].role !== 'admin') {
        users[userIndex].status = status;
        localStorage.setItem(USERS_KEY, JSON.stringify(users));
        return true;
    }
    return false;
}

// Ativação de Assinatura (Simulação de Pagamento)
export const activateSubscription = (userId: string) => {
    const users = getUsers();
    const userIndex = users.findIndex(u => u.id === userId);

    if (userIndex >= 0) {
        users[userIndex].subscriptionStatus = 'active';
        localStorage.setItem(USERS_KEY, JSON.stringify(users));

        // Atualiza sessão se for o usuário atual
        const currentUser = getCurrentUser();
        if (currentUser && currentUser.id === userId) {
            currentUser.subscriptionStatus = 'active';
            localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(currentUser));
        }
        return true;
    }
    return false;
};

import React, { useState } from 'react';
import { BrainCircuit, Lock, Mail, User as UserIcon, ArrowRight, Loader2, Star } from 'lucide-react';
import { login, register } from '../services/auth';
import { User } from '../types';

interface AuthProps {
  onLoginSuccess: (user: User) => void;
}

type AuthMode = 'login' | 'register' | 'forgot';

export default function Auth({ onLoginSuccess }: AuthProps) {
  const [mode, setMode] = useState<AuthMode>('login');
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setLoading(true);

    // Simulação de delay de rede
    await new Promise(r => setTimeout(r, 800));

    if (mode === 'login') {
      const result = login(formData.email, formData.password);
      if (result.success && result.user) {
        onLoginSuccess(result.user);
      } else {
        setError(result.message || 'Erro ao entrar.');
      }
    } else if (mode === 'register') {
      const result = register(formData.name, formData.email, formData.password);
      if (result.success) {
        setSuccess('Conta criada com 7 dias grátis! Faça login.');
        setMode('login');
        setFormData({ ...formData, password: '' });
      } else {
        setError(result.message || 'Erro ao criar conta.');
      }
    } else if (mode === 'forgot') {
      // Simulação de recuperação
      setSuccess(`Um link de recuperação foi enviado para ${formData.email} (Simulado). A senha do Admin é Edm1986@`);
    }

    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-[#030712] flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white dark:bg-[#111827] rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200 dark:border-white/5 animate-in zoom-in-95 duration-500">

        <div className="bg-indigo-600 p-8 text-center relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-full bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20"></div>
          <div className="relative z-10 flex flex-col items-center">
            <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md mb-4 shadow-xl">
              <BrainCircuit className="w-8 h-8 text-white" />
            </div>
            <h1 className="text-2xl font-black text-white uppercase tracking-tighter">ZenOS Finance</h1>
            <p className="text-indigo-200 text-xs font-bold uppercase tracking-widest mt-2">Sistema Operacional Financeiro</p>
          </div>
        </div>

        <div className="p-8">
          <h2 className="text-xl font-bold text-[#212529] dark:text-white text-center mb-6">
            {mode === 'login' && 'Acessar Sistema'}
            {mode === 'register' && 'Criar Nova Conta'}
            {mode === 'forgot' && 'Recuperar Acesso'}
          </h2>

          {mode === 'register' && (
            <div className="mb-6 p-4 bg-amber-500/10 border border-amber-500/20 rounded-2xl flex items-center gap-3">
              <div className="p-2 bg-amber-500 text-white rounded-full">
                <Star className="w-4 h-4" fill="currentColor" />
              </div>
              <div>
                <p className="text-xs font-black uppercase text-amber-600 dark:text-amber-500 tracking-wide">Comece Grátis</p>
                <p className="text-[10px] text-slate-500 dark:text-slate-400">7 dias de acesso total. Depois apenas R$ 9,90/mês.</p>
              </div>
            </div>
          )}

          {error && <div className="mb-4 p-3 bg-rose-500/10 border border-rose-500/20 rounded-xl text-rose-500 text-xs font-bold text-center">{error}</div>}
          {success && <div className="mb-4 p-3 bg-emerald-500/10 border border-emerald-500/20 rounded-xl text-emerald-500 text-xs font-bold text-center">{success}</div>}

          <form onSubmit={handleSubmit} className="space-y-4">

            {mode === 'register' && (
              <div className="space-y-1">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-2">Nome Completo</label>
                <div className="relative">
                  <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                  <input 
                    type="text" 
                    required 
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
                    placeholder="Seu nome"
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                  />
                </div>
              </div>
            )}

            <div className="space-y-1">
              <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-2">E-mail</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                <input 
                  type="email" 
                  required 
                  className="w-full pl-12 pr-4 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
                  placeholder="seu@email.com"
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                />
              </div>
            </div>

            {mode !== 'forgot' && (
              <div className="space-y-1">
                <label className="text-[10px] font-black text-[#6C757D] dark:text-slate-500 uppercase ml-2">Senha</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                  <input 
                    type="password" 
                    required 
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[#212529] dark:text-white outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
                    placeholder="••••••••"
                    value={formData.password}
                    onChange={e => setFormData({...formData, password: e.target.value})}
                  />
                </div>
              </div>
            )}

            <button 
              type="submit" 
              disabled={loading}
              className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl hover:bg-indigo-500 transition-all flex items-center justify-center gap-2 mt-6"
            >
              {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <ArrowRight className="w-4 h-4" />}
              {mode === 'login' ? 'Entrar' : mode === 'register' ? 'Criar Conta' : 'Enviar Link'}
            </button>
          </form>

          <div className="mt-8 flex flex-col gap-3 text-center">
            {mode === 'login' && (
              <>
                <button onClick={() => setMode('forgot')} className="text-xs text-[#6C757D] dark:text-slate-500 hover:text-indigo-500 transition-colors">Esqueceu a senha?</button>
                <button onClick={() => setMode('register')} className="text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:underline">Não tem conta? Crie agora.</button>
              </>
            )}
            {mode === 'register' && (
              <button onClick={() => setMode('login')} className="text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:underline">Já tem conta? Entrar.</button>
            )}
            {mode === 'forgot' && (
              <button onClick={() => setMode('login')} className="text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:underline">Voltar para o login</button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

