import { PlanConfig, PaymentRecord } from '../types';

const PLAN_KEY = 'zen_plan_config';
const PAYMENTS_KEY = 'zen_payments_db';

const DEFAULT_PLAN: PlanConfig = {
  id: 'premium_monthly',
  name: 'ZenOS Premium',
  price: 9.90,
  features: ['Inteligência Artificial Ilimitada', 'Gestão de Dívidas e Metas', 'Leitura de Cupons por IA'],
  mercadoPagoPublicKey: 'TEST-5e4d2a1b-3c4d-5e6f-7g8h-9i0j1k2l3m4n',
  paymentLink: '' // Vazio por padrão
};

export const getPlanConfig = (): PlanConfig => {
  const stored = localStorage.getItem(PLAN_KEY);
  return stored ? JSON.parse(stored) : DEFAULT_PLAN;
};

export const updatePlanConfig = (config: PlanConfig) => {
  localStorage.setItem(PLAN_KEY, JSON.stringify(config));
};

export const getPayments = (): PaymentRecord[] => {
  const stored = localStorage.getItem(PAYMENTS_KEY);
  return stored ? JSON.parse(stored) : [];
};

export const registerPayment = (payment: PaymentRecord) => {
  const payments = getPayments();
  // Evita duplicidade simples baseada no ID se já existir
  if (payments.some(p => p.id === payment.id)) return;

  payments.unshift(payment); // Adiciona no topo
  localStorage.setItem(PAYMENTS_KEY, JSON.stringify(payments));
};

// Gera a URL de Checkout (Real ou Simulada)
export const createMercadoPagoPreference = async (plan: PlanConfig, userId: string) => {
  // 1. MODO REAL (Se o admin configurou um Link de Pagamento)
  if (plan.paymentLink && plan.paymentLink.startsWith('http')) {
     // Retorna o link direto configurado no painel do MP
     // O admin deve configurar o "Back URL" no painel do MP para redirecionar de volta para o app
     return {
        preferenceId: 'static_link',
        initPoint: plan.paymentLink
     };
  }

  // 2. MODO SIMULAÇÃO (Sem backend, para testes)
  await new Promise(r => setTimeout(r, 1500)); // Delay para sensação de processamento

  const currentUrl = window.location.href.split('?')[0];

  // Simula o comportamento do Mercado Pago redirecionando de volta com params
  return {
    preferenceId: `pref_${Math.random().toString(36).substr(2, 9)}`,
    initPoint: `${currentUrl}?status=approved&collection_status=approved&payment_id=${Math.random().toString().slice(2,10)}&external_reference=${userId}`
  };
};

