                          <p className="text-[9px] text-slate-500 leading-relaxed">
                             Cole aqui o link gerado no seu painel do Mercado Pago. 
                             <br/><strong className="text-emerald-500">Importante:</strong> Configure as "Back URLs" (URLs de retorno) no Mercado Pago para apontar para este app.
                          </p>
                       </div>
                    </div>

                    <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl hover:bg-indigo-500 transition-all flex items-center justify-center gap-2">
                        <Save className="w-4 h-4" /> Salvar Configurações
                    </button>
                </form>
             </div>

             <div className="bg-indigo-500/10 p-8 rounded-[2.5rem] border border-indigo-500/20 flex flex-col items-center justify-center text-center">
                 <CreditCard className="w-16 h-16 text-indigo-500 mb-4" />
                 <h3 className="text-xl font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-tighter">Preview do Plano</h3>
                 <p className="text-slate-500 dark:text-slate-400 text-sm mb-6 max-w-xs">
                     É assim que o usuário verá o plano na tela de pagamento.
                 </p>

                 <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-3xl shadow-2xl w-full max-w-xs transform rotate-2">
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Assinatura</span>
                        <Crown className="w-5 h-5 text-amber-500" />
                    </div>
                    <h4 className="text-xl font-black text-[#212529] dark:text-white mb-1">{planConfig.name}</h4>
                    <p className="text-3xl font-black text-indigo-600 dark:text-indigo-400 tracking-tighter">
                        R$ {planConfig.price.toFixed(2)}<span className="text-xs text-slate-400 font-bold">/mês</span>
                    </p>
                 </div>

                 {planConfig.paymentLink ? (
                    <div className="mt-6 flex items-center gap-2 text-[10px] font-bold text-emerald-600 dark:text-emerald-400 bg-emerald-500/10 px-3 py-1 rounded-full">
                       <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                       Link Real Ativo
                    </div>
                 ) : (
                    <div className="mt-6 flex items-center gap-2 text-[10px] font-bold text-amber-600 dark:text-amber-400 bg-amber-500/10 px-3 py-1 rounded-full">
                       <div className="w-2 h-2 rounded-full bg-amber-500"></div>
                       Modo Simulação
                    </div>
                 )}
             </div>
          </div>
      )}

      {/* TAB: FINANCEIRO */}
      {activeTab === 'financial' && (
          <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="bg-emerald-500/10 p-6 rounded-3xl border border-emerald-500/20">
                      <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest block mb-2">Receita Total</span>
                      <p className="text-3xl font-black text-emerald-600 dark:text-white tracking-tighter">R$ {totalRevenue.toFixed(2)}</p>
                  </div>
                  <div className="bg-indigo-500/10 p-6 rounded-3xl border border-indigo-500/20">
                      <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest block mb-2">Vendas Totais</span>
                      <p className="text-3xl font-black text-indigo-600 dark:text-white tracking-tighter">{payments.length}</p>
                  </div>
                  <div className="bg-amber-500/10 p-6 rounded-3xl border border-amber-500/20">
                      <span className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest block mb-2">Ticket Médio</span>
                      <p className="text-3xl font-black text-amber-600 dark:text-white tracking-tighter">
                          R$ {payments.length > 0 ? (totalRevenue / payments.length).toFixed(2) : '0.00'}
                      </p>
                  </div>
              </div>

              <div className="bg-white dark:bg-[#111827]/60 border border-slate-200 dark:border-white/5 rounded-[2.5rem] overflow-hidden shadow-xl">
                  <div className="p-6 border-b border-slate-200 dark:border-white/5 flex items-center gap-2">
                     <BarChart3 className="w-5 h-5 text-slate-500" />
                     <h3 className="text-sm font-black text-[#212529] dark:text-white uppercase tracking-widest">Histórico de Transações</h3>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-slate-50 dark:bg-black/20">
                            <tr>
                                <th className="px-6 py-4 text-left text-[9px] font-black uppercase text-slate-500">Data</th>
                                <th className="px-6 py-4 text-left text-[9px] font-black uppercase text-slate-500">Cliente</th>
                                <th className="px-6 py-4 text-left text-[9px] font-black uppercase text-slate-500">Método</th>
                                <th className="px-6 py-4 text-left text-[9px] font-black uppercase text-slate-500">Status</th>
                                <th className="px-6 py-4 text-right text-[9px] font-black uppercase text-slate-500">Valor</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-white/5">
                            {payments.map(p => (
                                <tr key={p.id} className="hover:bg-slate-50 dark:hover:bg-white/5">
                                    <td className="px-6 py-4 text-xs font-bold text-slate-600 dark:text-slate-400">
                                        {new Date(p.date).toLocaleDateString()}
                                    </td>
                                    <td className="px-6 py-4 text-xs font-bold text-[#212529] dark:text-white">
                                        {p.userName}
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className="px-2 py-1 rounded-lg bg-slate-100 dark:bg-white/10 text-[10px] font-black uppercase tracking-widest text-slate-500">
                                            {p.method === 'credit_card' ? 'Cartão' : p.method === 'pix' ? 'Pix' : 'Boleto'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${p.status === 'approved' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-amber-500/10 text-amber-500'}`}>
                                            {p.status === 'approved' ? 'Aprovado' : p.status}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-right text-xs font-black text-[#212529] dark:text-white">
                                        R$ {p.amount.toFixed(2)}
                                    </td>
                                </tr>
                            ))}
                            {payments.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="px-6 py-8 text-center text-xs text-slate-400 italic">Nenhuma transação registrada.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Receipt, Target, BrainCircuit, Menu, X, Archive, 
  AlertCircle, Plus, Settings as SettingsIcon, Camera, Mic, Loader2, StopCircle, LogOut, Shield, Wallet, Lock, Crown, Check, CreditCard
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Budget, FinancialGoal, Category, User } from './types';
import Dashboard from './components/Dashboard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Settings from './components/Settings';
import AdminPanel from './components/AdminPanel';
import Auth from './components/Auth';
import Toast, { ToastType } from './components/Toast';
import { analyzeReceipt, analyzeAudioCommand } from './services/gemini';
import { initializeAuth, getCurrentUser, logout, activateSubscription } from './services/auth';
import { getPlanConfig, registerPayment, createMercadoPagoPreference } from './services/billing.ts';

const INITIAL_POTES: Jar[] = [
