    subCategories: [{id: 's1', name: 'Aluguel'}, {id: 's2', name: 'Energia'}, {id: 's3', name: 'Internet'}, {id: 's4', name: 'Manutenção'}] 
  },
  { 
    id: 'c2', name: 'Alimentação', type: 'expense', isDefault: true,
    subCategories: [{id: 's5', name: 'Supermercado'}, {id: 's6', name: 'Restaurante'}, {id: 's7', name: 'Delivery'}] 
  },
  { 
    id: 'c3', name: 'Transporte', type: 'expense', isDefault: true,
    subCategories: [{id: 's8', name: 'Combustível'}, {id: 's9', name: 'Uber/Táxi'}, {id: 's10', name: 'Manutenção Veículo'}] 
  },
  { 
    id: 'c4', name: 'Saúde', type: 'expense', isDefault: true,
    subCategories: [{id: 's11', name: 'Farmácia'}, {id: 's12', name: 'Consultas'}, {id: 's13', name: 'Plano de Saúde'}] 
  },
  { 
    id: 'c5', name: 'Lazer', type: 'expense', isDefault: true,
    subCategories: [{id: 's14', name: 'Cinema/Streaming'}, {id: 's15', name: 'Viagem'}, {id: 's16', name: 'Hobbies'}] 
  },
  { 
    id: 'c6', name: 'Renda', type: 'income', isDefault: true,
    subCategories: [{id: 's17', name: 'Salário'}, {id: 's18', name: 'Freelance'}, {id: 's19', name: 'Dividendos'}] 
  }
];

const SEED_TRANSACTIONS: Transaction[] = [
  { id: 't1', description: 'Salário Mensal', amount: 5000, category: 'Renda', subCategory: 'Salário', date: new Date().toISOString().split('T')[0], type: 'income', paymentMethod: 'Transferência' },
  { id: 't2', description: 'Aluguel Central', amount: 1200, category: 'Moradia', subCategory: 'Aluguel', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '2', paymentMethod: 'Boleto' },
  { id: 't3', description: 'Supermercado Gourmet', amount: 450, category: 'Alimentação', subCategory: 'Supermercado', date: new Date().toISOString().split('T')[0], type: 'expense', poteId: '1', paymentMethod: 'Cartão Crédito' },
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
  adminOnly?: boolean;
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // States for Subscription Paywall
  const [isProcessingPayment, setIsProcessingPayment] = useState(false);
  const [verifyingPayment, setVerifyingPayment] = useState(false);

  // Initialize Auth & Check Payment Callback
  useEffect(() => {
    initializeAuth();
    const currentUser = getCurrentUser();

    if (currentUser) {
      setUser(currentUser);

      // CHECK PAYMENT CALLBACK
      const params = new URLSearchParams(window.location.search);

      // Suporte para parametros de simulação (status, payment_id)
      // E parâmetros reais do Mercado Pago (collection_status, collection_id)
      const status = params.get('status') || params.get('collection_status');
      const paymentId = params.get('payment_id') || params.get('collection_id');

      if (status === 'approved' && paymentId) {
         setVerifyingPayment(true);

         // Simula verificação no backend
         setTimeout(() => {
            const plan = getPlanConfig();
            activateSubscription(currentUser.id);

            registerPayment({
               id: paymentId,
               userId: currentUser.id,
               userName: currentUser.name,
               amount: plan.price,
               date: new Date().toISOString(),
               status: 'approved',
               method: 'credit_card', // Em prod, viria do webhook
               planName: plan.name
            });

            // Atualiza estado local
            setUser(prev => prev ? ({ ...prev, subscriptionStatus: 'active' }) : null);
            setVerifyingPayment(false);

            // Limpa URL
            window.history.replaceState({}, document.title, window.location.pathname);

            showToast("Pagamento Confirmado! Assinatura Ativa.", "success");
         }, 1500);
      } else if (status === 'failure' || status === 'null' || status === 'rejected') {
         showToast("O pagamento não foi concluído.", "error");
         window.history.replaceState({}, document.title, window.location.pathname);
      }
    }
  }, []);

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // States for Quick Entry (Fab)
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('zen_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('zen_transactions');
    return saved ? JSON.parse(saved) : SEED_TRANSACTIONS;
  });

  const [potes, setPotes] = useState<Jar[]>(() => {
    const saved = localStorage.getItem('zen_potes');
    return saved ? JSON.parse(saved) : INITIAL_POTES;
  });

  const [debts, setDebts] = useState<Debt[]>(() => JSON.parse(localStorage.getItem('zen_debts') || '[]'));
  const [budgets, setBudgets] = useState<Budget[]>(() => JSON.parse(localStorage.getItem('zen_budgets') || '[]'));
  const [goals, setGoals] = useState<FinancialGoal[]>(() => JSON.parse(localStorage.getItem('zen_goals') || '[]'));

  useEffect(() => {
    localStorage.setItem('zen_categories', JSON.stringify(categories));
    localStorage.setItem('zen_transactions', JSON.stringify(transactions));
    localStorage.setItem('zen_potes', JSON.stringify(potes));
    localStorage.setItem('zen_debts', JSON.stringify(debts));
    localStorage.setItem('zen_budgets', JSON.stringify(budgets));
    localStorage.setItem('zen_goals', JSON.stringify(goals));
  }, [categories, transactions, potes, debts, budgets, goals]);

  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = () => {
    logout();
    setUser(null);
    setView('dashboard');
  };

  const handleMercadoPagoCheckout = async () => {
     if (!user) return;
     const plan = getPlanConfig();
     setIsProcessingPayment(true);

     try {
       // 1. Obtém o link (seja real ou simulado)
       const { initPoint } = await createMercadoPagoPreference(plan, user.id);

       // 2. REDIRECIONA o usuário para o Mercado Pago
       window.location.href = initPoint;

     } catch (error) {
       console.error("Erro no checkout", error);
       showToast("Erro ao iniciar pagamento.", "error");
       setIsProcessingPayment(false);
     }
  };

  const handleAddTransaction = (t: Transaction) => {
    setTransactions([t, ...transactions]);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null); 
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string, date: string) => {
    setDebts(prev => prev.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    }));

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: date || new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  const handleGoalEdit = (updatedGoal: FinancialGoal) => {
    setGoals(goals.map(g => g.id === updatedGoal.id ? updatedGoal : g));
    showToast("Meta atualizada com sucesso!");
  };

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    showToast("Analisando imagem...", "info");

    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);

      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; 
  };

  const handleMicClick = async () => {
    if (isRecording) {
      stopRecording();
    } else {
      startRecording();
    }
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");

          const result = await analyzeAudioCommand(base64Audio);

          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };

  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'wallet', label: 'Carteira', icon: Wallet, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'admin', label: 'Admin', icon: Shield, section: 'SISTEMA', adminOnly: true },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  // --- TELA DE CARREGAMENTO/VERIFICAÇÃO DE PAGAMENTO ---
  if (verifyingPayment) {
     return (
        <div className="min-h-screen bg-slate-50 dark:bg-[#030712] flex items-center justify-center flex-col gap-6 text-[#212529] dark:text-white p-6">
           <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
           <div className="text-center">
              <h2 className="text-xl font-black uppercase tracking-tighter">Confirmando Assinatura</h2>
              <p className="text-slate-500 text-sm mt-2">Aguardando confirmação do Mercado Pago...</p>
           </div>
        </div>
     );
  }

  if (!user) {
    return (
      <>
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        <Auth onLoginSuccess={handleLoginSuccess} />
      </>
    );
  }

  // --- LOGICA DE BLOQUEIO DE ASSINATURA ---
  const isExpired = user.subscriptionStatus === 'expired';

  if (isExpired) {
    const plan = getPlanConfig();

    return (
       <div className="min-h-screen bg-slate-50 dark:bg-[#030712] flex items-center justify-center p-6 text-[#212529] dark:text-white">
          <div className="bg-white dark:bg-[#111827] rounded-[2.5rem] w-full max-w-md p-8 border border-slate-200 dark:border-white/5 shadow-2xl relative overflow-hidden">

             {/* Background Effects */}
             <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-rose-500 via-purple-500 to-indigo-500"></div>
             <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-600/20 blur-3xl rounded-full pointer-events-none"></div>

             <div className="flex flex-col items-center text-center space-y-6">
                <div className="w-20 h-20 bg-rose-500/10 rounded-full flex items-center justify-center mb-2 animate-bounce">
                   <Lock className="w-10 h-10 text-rose-500" />
                </div>

                <div>
                   <h2 className="text-2xl font-black uppercase tracking-tighter mb-2">Período de Teste Encerrado</h2>
                   <p className="text-slate-500 text-sm">Esperamos que você tenha aproveitado os 7 dias gratuitos do ZenOS Finance. Para continuar organizando sua vida financeira, ative o plano premium.</p>
                </div>

                <div className="w-full bg-slate-50 dark:bg-black/20 rounded-2xl p-6 border border-slate-200 dark:border-white/5">
                   <div className="flex justify-between items-center mb-4">
                      <span className="text-sm font-bold text-slate-600 dark:text-slate-400 uppercase tracking-widest">{plan.name}</span>
                      <span className="text-2xl font-black text-indigo-600 dark:text-indigo-400">R$ {plan.price.toFixed(2)}<span className="text-xs text-slate-400">/mês</span></span>
                   </div>
                   <ul className="space-y-3 text-left">
                      {plan.features.map((feat, idx) => (
                        <li key={idx} className="flex items-center gap-2 text-xs font-bold text-slate-600 dark:text-slate-300"><Check className="w-4 h-4 text-emerald-500" /> {feat}</li>
                      ))}
                   </ul>
                </div>

                {/* Botão de Checkout Mercado Pago */}
                <button 
                  onClick={handleMercadoPagoCheckout}
                  disabled={isProcessingPayment}
                  className="w-full py-4 bg-[#009EE3] text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl hover:bg-[#008ED0] transition-all flex items-center justify-center gap-2 relative overflow-hidden group"
                >
                  <div className="absolute inset-0 w-full h-full bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:animate-[shimmer_1.5s_infinite]"></div>
                  {isProcessingPayment ? <Loader2 className="w-5 h-5 animate-spin" /> : <CreditCard className="w-5 h-5" />}
                  {isProcessingPayment ? 'Redirecionando...' : 'Pagar com Mercado Pago'}
                </button>
                <p className="text-[9px] text-slate-400">Você será redirecionado para o ambiente seguro do Mercado Pago.</p>

                <button onClick={handleLogout} className="text-xs text-slate-400 hover:text-rose-500 transition-colors">
                   Sair da conta
                </button>
             </div>
          </div>
          {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
       </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-[#F8F9FA] dark:bg-[#030712] text-[#212529] dark:text-slate-100 font-sans overflow-hidden select-none transition-colors duration-300">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <input 
        type="file" 
        accept="image/*" 
        capture="environment" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-white/80 dark:bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          <p className="text-[#212529] dark:text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* Floating Action Button */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button 
              onClick={handleCameraClick}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Camera className="w-5 h-5" />
            </button>
            <button 
              onClick={handleMicClick}
              className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}
            >
              {isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}
            </button>
            <button 
              onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }}
              className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
            >
              <Receipt className="w-5 h-5" />
            </button>
          </div>
        )}

        <button 
          onClick={() => {
             if (isRecording) {
                stopRecording();
             } else {
                setIsFabOpen(!isFabOpen);
             }
          }}
          className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}
        >
          {isRecording ? (
             <div className="w-4 h-4 bg-white rounded-sm animate-spin" />
          ) : (
             <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />
          )}
        </button>
      </div>

      <div 
        className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsSidebarOpen(false)}
      />

      <aside className={`
        fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300
        ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'}
        bg-white dark:bg-[#0a0c14] border-r border-slate-200 dark:border-white/5 flex flex-col shadow-2xl lg:shadow-none
      `}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter text-[#212529] dark:text-white">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-[#6C757D]" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>

        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => {
             const items = navItems.filter(item => item.section === sectionName && (!item.adminOnly || user.role === 'admin'));
             if (items.length === 0) return null;

             return (
              <div key={sectionName} className="space-y-1">
                <h4 className="px-4 text-[8px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">
                  {sectionName}
                </h4>
                <div className="space-y-1">
                  {items.map((item) => (
                    <button 
                      key={item.id} 
                      onClick={() => { setView(item.id); setIsSidebarOpen(false); }} 
                      className={`
                        w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all
                        ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800/40'}
                      `}
                    >
                      <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                      <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </nav>

        {/* Subscription Status Indicator */}
        <div className="px-4 py-2">
            <div className={`p-4 rounded-2xl border ${user.subscriptionStatus === 'trial' ? 'bg-amber-500/10 border-amber-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
                <p className={`text-[9px] font-black uppercase tracking-widest mb-1 ${user.subscriptionStatus === 'trial' ? 'text-amber-500' : 'text-emerald-500'}`}>
                    {user.subscriptionStatus === 'trial' ? 'Período de Teste' : 'Assinatura Ativa'}
                </p>
                {user.subscriptionStatus === 'trial' && (
                    <p className="text-xs text-slate-500 dark:text-slate-400">
                        Expira em: {new Date(user.trialEndsAt).toLocaleDateString()}
                    </p>
                )}
            </div>
        </div>

        <div className="p-4 border-t border-slate-200 dark:border-white/5">
          <button 
            onClick={handleLogout}
            className="w-full flex items-center gap-4 px-4 py-3 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all"
          >
            <LogOut className="w-5 h-5" />
            <span className="font-bold text-sm lg:hidden xl:block">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#F8F9FA] dark:bg-[#030712] transition-colors duration-300">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-[#212529] dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest">Usuário</span>
                <span className="text-xs font-black text-[#212529] dark:text-white truncate max-w-[100px]">{user.name}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <span className="font-black text-indigo-600 dark:text-indigo-400">{user.name.charAt(0)}</span>
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <AnalyticsDashboard data={financialData} />}
            {view === 'wallet' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => { setTransactions(transactions.filter(t => t.id !== id)); showToast("Registro excluído", "info"); }}
                onEdit={(updated) => { setTransactions(transactions.map(t => t.id === updated.id ? updated : t)); showToast("Alterações salvas!"); }}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                transactions={transactions}
                onAdd={(d) => { setDebts([...debts, d]); showToast("Dívida registrada"); }} 
                onUpdate={(d) => setDebts(debts.map(item => item.id === d.id ? d : item))} // Usado para update
                onEdit={(d) => { setDebts(debts.map(item => item.id === d.id ? d : item)); showToast("Dívida atualizada!"); }} // Usado para edição completa
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(updatedPotes) => {
                  const clean = updatedPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  setPotes(clean as Jar[]);
                  showToast("Arquitetura atualizada");
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => { setBudgets(b); showToast("Orçamentos salvos"); }} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => { setGoals([...goals, g]); showToast("Meta criada!"); }} 
                onUpdate={setGoals} 
                onDeposit={handleGoalDeposit}
                onEdit={handleGoalEdit}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={setCategories} 
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
                user={user}
                onSubscribe={handleMercadoPagoCheckout}
                isProcessingSubscription={isProcessingPayment}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Category, User } from '../types';
import { getPlanConfig } from '../services/billing';
import { Settings as SettingsIcon, Plus, Trash2, Edit2, Check, X, Tag, Moon, Sun, Share2, CreditCard, Crown, Loader2, Clock } from 'lucide-react';

interface SettingsProps {
  categories: Category[];
  onUpdateCategories: (cats: Category[]) => void;
  showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
  currentTheme: 'dark' | 'light';
  toggleTheme: () => void;
  user: User;
  onSubscribe: () => void;
  isProcessingSubscription: boolean;
}

export default function Settings({ 
  categories, 
  onUpdateCategories, 
  showToast, 
  currentTheme, 
  toggleTheme,
  user,
  onSubscribe,
  isProcessingSubscription
}: SettingsProps) {
  const [activeTab, setActiveTab] = useState<'categories' | 'appearance' | 'subscription'>('categories');
  const [newCatName, setNewCatName] = useState('');
  const [newCatType, setNewCatType] = useState<'income' | 'expense'>('expense');
  const [editingCatId, setEditingCatId] = useState<string | null>(null);
  const [newSubName, setNewSubName] = useState('');

  const plan = getPlanConfig();

  const handleAddCategory = () => {
    if (!newCatName.trim()) return;
    const newCat: Category = {
      id: Math.random().toString(36).substr(2, 9),
      name: newCatName,
      type: newCatType,
      subCategories: []
    };
    onUpdateCategories([...categories, newCat]);
    setNewCatName('');
    showToast('Categoria criada com sucesso!', 'success');
  };

  const handleDeleteCategory = (id: string) => {
    if (confirm('Tem certeza? Isso pode afetar registros históricos.')) {
      onUpdateCategories(categories.filter(c => c.id !== id));
      showToast('Categoria removida', 'info');
    }
  };

  const handleAddSubCategory = (catId: string) => {
    if (!newSubName.trim()) return;
    const updatedCats = categories.map(c => {
      if (c.id === catId) {
        return {
          ...c,
          subCategories: [...c.subCategories, { id: Math.random().toString(36).substr(2, 9), name: newSubName }]
        };
      }
      return c;
    });
    onUpdateCategories(updatedCats);
    setNewSubName('');
  };

  const handleDeleteSubCategory = (catId: string, subId: string) => {
    const updatedCats = categories.map(c => {
      if (c.id === catId) {
        return { ...c, subCategories: c.subCategories.filter(s => s.id !== subId) };
      }
      return c;
    });
    onUpdateCategories(updatedCats);
  };

  const shareApp = () => {
      const url = window.location.href;
      const text = `Gerencie suas finanças com o ZenOS Finance! Instale agora: ${url}`;
      const whatsappUrl = `https://wa.me/?text=${encodeURIComponent(text)}`;
      window.open(whatsappUrl, '_blank');
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center gap-4 mb-6">
        <div className="bg-indigo-600 p-3 rounded-2xl shadow-lg shadow-indigo-600/20">
          <SettingsIcon className="w-6 h-6 text-white" />
        </div>
        <div>
           <h2 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Ajustes do Sistema</h2>
           <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Personalize sua experiência</p>
        </div>
      </div>

      <div className="bg-white dark:bg-[#0a0c14] border border-slate-200 dark:border-white/5 rounded-[2.5rem] overflow-hidden shadow-xl dark:shadow-none">
         <div className="flex border-b border-slate-200 dark:border-white/5 overflow-x-auto no-scrollbar">
            <button 
              onClick={() => setActiveTab('categories')}
              className={`flex-1 min-w-[100px] py-4 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'categories' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              Categorias
            </button>
            <button 
              onClick={() => setActiveTab('subscription')}
              className={`flex-1 min-w-[100px] py-4 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'subscription' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              Assinatura
            </button>
            <button 
              onClick={() => setActiveTab('appearance')}
              className={`flex-1 min-w-[100px] py-4 text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'appearance' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
            >
              Aparência
            </button>
         </div>

         <div className="p-4 md:p-8">
            {activeTab === 'categories' && (
              <div className="space-y-8">
                {/* Add New Category */}
                <div className="bg-slate-50 dark:bg-slate-900/50 p-6 rounded-3xl border border-slate-200 dark:border-white/5">
                   <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Nova Categoria</h3>
                   <div className="flex flex-col md:flex-row gap-4">
                      <input 
                        type="text" 
                        placeholder="Nome da categoria..."
                        className="flex-1 px-4 py-3 bg-white dark:bg-[#030712] border border-slate-200 dark:border-slate-800 rounded-xl text-slate-900 dark:text-white outline-none focus:ring-1 focus:ring-indigo-500 text-sm"
                        value={newCatName}
                        onChange={e => setNewCatName(e.target.value)}
                      />
                      <select 
                        className="px-4 py-3 bg-white dark:bg-[#030712] border border-slate-200 dark:border-slate-800 rounded-xl text-slate-900 dark:text-white outline-none focus:ring-1 focus:ring-indigo-500 text-sm"
                        value={newCatType}
                        onChange={e => setNewCatType(e.target.value as any)}
                      >
                        <option value="expense">Despesa</option>
                        <option value="income">Receita</option>
                      </select>
                      <button 
                        onClick={handleAddCategory}
                        className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black uppercase text-xs tracking-widest hover:bg-indigo-500 transition-all"
                      >
                        Criar
                      </button>
                   </div>
                </div>

                {/* List Categories */}
                <div className="space-y-4">
                   {categories.map(cat => (
                     <div key={cat.id} className="bg-slate-50 dark:bg-[#111827]/40 rounded-3xl border border-slate-200 dark:border-white/5 overflow-hidden">
                        <div className="p-4 flex items-center justify-between bg-white/50 dark:bg-white/5">
                           <div className="flex items-center gap-3">
                              <span className={`w-2 h-2 rounded-full ${cat.type === 'income' ? 'bg-emerald-400' : 'bg-rose-400'}`}></span>
                              <h4 className="font-bold text-slate-700 dark:text-slate-200">{cat.name}</h4>
                              <span className="text-[9px] font-black uppercase tracking-widest text-slate-500 dark:text-slate-600">{cat.type === 'income' ? 'Receita' : 'Despesa'}</span>
                           </div>
                           <div className="flex items-center gap-2">
                              <button onClick={() => setEditingCatId(editingCatId === cat.id ? null : cat.id)} className="p-2 text-slate-500 hover:text-indigo-400"><Tag className="w-4 h-4" /></button>
                              <button onClick={() => handleDeleteCategory(cat.id)} className="p-2 text-slate-500 hover:text-rose-500"><Trash2 className="w-4 h-4" /></button>
                           </div>
                        </div>

                        {/* Subcategories */}
                        {(editingCatId === cat.id) && (
                          <div className="p-4 bg-slate-100 dark:bg-black/20 animate-in slide-in-from-top-2">
                             <div className="flex flex-wrap gap-2 mb-4">
                                {cat.subCategories.map(sub => (
                                  <div key={sub.id} className="bg-indigo-500/10 border border-indigo-500/20 px-3 py-1.5 rounded-lg flex items-center gap-2">
                                     <span className="text-xs text-indigo-600 dark:text-indigo-300 font-bold">{sub.name}</span>
                                     <button onClick={() => handleDeleteSubCategory(cat.id, sub.id)} className="text-indigo-400 hover:text-rose-400"><X className="w-3 h-3" /></button>
                                  </div>
                                ))}
                             </div>
                             <div className="flex gap-2">
                                <input 
                                  placeholder="Nova subcategoria..."
                                  className="flex-1 px-3 py-2 bg-white dark:bg-[#030712] border border-slate-200 dark:border-slate-800 rounded-lg text-slate-900 dark:text-white text-xs outline-none"
                                  value={newSubName}
                                  onChange={e => setNewSubName(e.target.value)}
                                  onKeyDown={e => e.key === 'Enter' && handleAddSubCategory(cat.id)}
                                />
                                <button onClick={() => handleAddSubCategory(cat.id)} className="p-2 bg-indigo-600 rounded-lg text-white"><Plus className="w-4 h-4" /></button>
                             </div>
                          </div>
                        )}
                     </div>
                   ))}
                </div>
              </div>
            )}

            {activeTab === 'subscription' && (
              <div className="space-y-8">
                 <div className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-[2.5rem] p-8 text-white relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-full bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20"></div>
                    <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
                       <div>
                          <div className="flex items-center gap-3 mb-2">
                             <Crown className="w-6 h-6 text-amber-300" />
                             <h3 className="text-2xl font-black uppercase tracking-tighter">ZenOS Premium</h3>
                          </div>
                          <p className="text-indigo-100 text-sm font-medium max-w-sm mb-4">
                             Desbloqueie todo o poder da inteligência artificial, gestão ilimitada e relatórios avançados.
                          </p>
                          <div className="flex items-center gap-4">
                             <div className="bg-white/20 backdrop-blur-md px-4 py-2 rounded-xl">
                                <span className="text-[10px] font-bold uppercase tracking-widest text-indigo-200 block">Status</span>
                                <span className="font-black text-white uppercase flex items-center gap-2">
                                   {user.subscriptionStatus === 'active' ? (
