import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { User, Transaction, Jar, Debt, Budget, FinancialGoal, Category, FinancialData } from '../types';

// Configuração do Banco de Dados
// Se houver chaves no LocalStorage (configuradas via Admin) ou ENV, usa Supabase.
const SUPABASE_URL = localStorage.getItem('zen_sb_url') || ''; 
const SUPABASE_KEY = localStorage.getItem('zen_sb_key') || '';

let supabase: SupabaseClient | null = null;

if (SUPABASE_URL && SUPABASE_KEY) {
  try {
    supabase = createClient(SUPABASE_URL, SUPABASE_KEY);
    console.log("ZenOS: Conectado ao Supabase Cloud DB");
  } catch (e) {
    console.error("ZenOS: Falha ao conectar Supabase, usando LocalStorage", e);
  }
}

// Helpers para LocalStorage (Fallback)
const getLocal = <T>(key: string, def: T): T => {
  const s = localStorage.getItem(key);
  return s ? JSON.parse(s) : def;
};
const setLocal = (key: string, val: any) => localStorage.setItem(key, JSON.stringify(val));

export const db = {
  // --- USERS ---
  users: {
    get: async (email: string): Promise<User | undefined> => {
      if (supabase) {
        const { data } = await supabase.from('users').select('*').eq('email', email).single();
        return data as User;
      }
      return getLocal<User[]>('zen_users_db', []).find(u => u.email === email);
    },
    create: async (user: User): Promise<void> => {
      if (supabase) {
        await supabase.from('users').insert(user);
      } else {
        const users = getLocal<User[]>('zen_users_db', []);
        setLocal('zen_users_db', [...users, user]);
      }
    },
    update: async (user: User): Promise<void> => {
      if (supabase) {
        await supabase.from('users').update(user).eq('id', user.id);
      } else {
        const users = getLocal<User[]>('zen_users_db', []);
        setLocal('zen_users_db', users.map(u => u.id === user.id ? user : u));
      }
    }
  },

  // --- FINANCIAL DATA (Transactions, Potes, etc) ---
  // Carrega tudo de uma vez para performance no frontend
  getFinancialData: async (userId: string): Promise<FinancialData> => {
    if (supabase) {
      const [tx, potes, debts, budgets, goals, cats] = await Promise.all([
        supabase.from('transactions').select('*').eq('user_id', userId),
        supabase.from('potes').select('*').eq('user_id', userId),
        supabase.from('debts').select('*').eq('user_id', userId),
        supabase.from('budgets').select('*').eq('user_id', userId),
        supabase.from('goals').select('*').eq('user_id', userId),
        supabase.from('categories').select('*').eq('user_id', userId),
      ]);

      // Fallback para defaults se vazio e for primeira vez
      return {
        transactions: tx.data || [],
        potes: potes.data || [],
        debts: debts.data || [],
        budgets: budgets.data || [],
        goals: goals.data || [],
        categories: cats.data?.length ? cats.data : getLocal('zen_categories', [])
      };
    }

    // LocalStorage Mode
    return {
      transactions: getLocal('zen_transactions', []),
      potes: getLocal('zen_potes', []),
      debts: getLocal('zen_debts', []),
      budgets: getLocal('zen_budgets', []),
      goals: getLocal('zen_goals', []),
      categories: getLocal('zen_categories', [])
    };
  },

  // --- GENERIC SAVERS ---
  saveTransactions: async (userId: string, txs: Transaction[]) => {
    if (supabase) {
        // Full Sync Strategy (Simples para MVP) - Em prod, usar upsert/delta
        // Para evitar deletar tudo, vamos apenas inserir os novos no backend real, 
        // mas aqui simularemos persistencia completa do estado local p/ facilitar
        // NOTA: Em app real, backend gerencia IDs. Aqui, frontend gera IDs.

        // Upsert transactions
        const { error } = await supabase.from('transactions').upsert(txs.map(t => ({...t, user_id: userId})));
        if (error) console.error("DB Error", error);
    } else {
        setLocal('zen_transactions', txs);
    }
  },

  savePotes: async (userId: string, potes: Jar[]) => {
    if (supabase) await supabase.from('potes').upsert(potes.map(p => ({...p, user_id: userId})));
    else setLocal('zen_potes', potes);
  },

  saveDebts: async (userId: string, debts: Debt[]) => {
    if (supabase) await supabase.from('debts').upsert(debts.map(d => ({...d, user_id: userId})));
    else setLocal('zen_debts', debts);
  },

  saveBudgets: async (userId: string, budgets: Budget[]) => {
    if (supabase) await supabase.from('budgets').upsert(budgets.map(b => ({...b, user_id: userId})));
    else setLocal('zen_budgets', budgets);
  },

  saveGoals: async (userId: string, goals: FinancialGoal[]) => {
    if (supabase) await supabase.from('goals').upsert(goals.map(g => ({...g, user_id: userId})));
    else setLocal('zen_goals', goals);
  },

  saveCategories: async (userId: string, cats: Category[]) => {
    if (supabase) await supabase.from('categories').upsert(cats.map(c => ({...c, user_id: userId})));
    else setLocal('zen_categories', cats);
  }
};

