export const login = async (email: string, password: string): Promise<{ success: boolean, user?: User, message?: string }> => {
  const user = await db.users.get(email);

  if (!user || user.password !== password) {
    return { success: false, message: 'Credenciais inválidas.' };
  }

  if (user.status === 'blocked') {
    return { success: false, message: 'Conta bloqueada pelo administrador.' };
  }

  const updatedUser = await checkSubscriptionValidity(user);
  localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(updatedUser));

  return { success: true, user: updatedUser };
};

export const logout = () => {
  localStorage.removeItem(CURRENT_USER_KEY);
};

export const getCurrentUser = (): User | null => {
  const stored = localStorage.getItem(CURRENT_USER_KEY);
  if (!stored) return null;
  return JSON.parse(stored);
};

const checkSubscriptionValidity = async (user: User): Promise<User> => {
  if (user.subscriptionStatus === 'active' || user.role === 'admin') return user;

  const now = new Date();
  const trialEnd = new Date(user.trialEndsAt);

  if (now > trialEnd && user.subscriptionStatus === 'trial') {
    const updatedUser = { ...user, subscriptionStatus: 'expired' as const };
    await db.users.update(updatedUser);
    return updatedUser;
  }
  return user;
};

export const register = async (name: string, email: string, password: string): Promise<{ success: boolean, message?: string }> => {
  const existing = await db.users.get(email);
  if (existing) {
    return { success: false, message: 'E-mail já cadastrado.' };
  }

  const trialDate = new Date();
  trialDate.setDate(trialDate.getDate() + 7);

  const newUser: User = {
    id: Math.random().toString(36).substr(2, 9),
    name,
    email,
    password,
    role: 'user',
    status: 'active',
    subscriptionStatus: 'trial',
    trialEndsAt: trialDate.toISOString(),
    createdAt: new Date().toISOString()
  };

  await db.users.create(newUser);
  return { success: true };
};

export const getUsers = async (): Promise<User[]> => {
    // Hack para listar usuários no modo local/admin
    // Em modo real DB, isso seria uma query paginada
    if(localStorage.getItem('zen_sb_url')) return []; // Em modo cloud, não listamos todos por segurança aqui
    const stored = localStorage.getItem('zen_users_db');
    return stored ? JSON.parse(stored) : [];
};

export const updateUserStatus = async (userId: string, status: 'active' | 'blocked') => {
    const users = await getUsers();
    const user = users.find(u => u.id === userId);
    if(user) {
        user.status = status;
        await db.users.update(user);
        return true;
    }
    return false;
}

export const activateSubscription = async (userId: string) => {
    // Busca user local ou remoto
    // Simulação simplificada
    const users = await getUsers(); 
    const user = users.find(u => u.id === userId);
    if (user) {
        user.subscriptionStatus = 'active';
        await db.users.update(user);

        // Atualiza sessão
        const currentUser = getCurrentUser();
        if (currentUser && currentUser.id === userId) {
            currentUser.subscriptionStatus = 'active';
            localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(currentUser));
        }
        return true;
    }
    return false;
};

