export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // Data States (Loaded asynchronously)
  const [loadingData, setLoadingData] = useState(false);
  const [categories, setCategories] = useState<Category[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [potes, setPotes] = useState<Jar[]>([]);
  const [debts, setDebts] = useState<Debt[]>([]);
  const [budgets, setBudgets] = useState<Budget[]>([]);
  const [goals, setGoals] = useState<FinancialGoal[]>([]);

  // States for Paywall & Fab
  const [isProcessingPayment, setIsProcessingPayment] = useState(false);
  const [verifyingPayment, setVerifyingPayment] = useState(false);
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // 1. Initialize Auth & Load Data
  useEffect(() => {
    initializeAuth();
    const currentUser = getCurrentUser();

    if (currentUser) {
      setUser(currentUser);
      loadUserData(currentUser.id);
      checkPaymentCallback(currentUser);
    }
  }, []);

  const loadUserData = async (userId: string) => {
    setLoadingData(true);
    try {
        const data = await db.getFinancialData(userId);
        setTransactions(data.transactions);
        setPotes(data.potes.length ? data.potes : INITIAL_POTES);
        setDebts(data.debts);
        setBudgets(data.budgets);
        setGoals(data.goals);
        setCategories(data.categories.length ? data.categories : DEFAULT_CATEGORIES);
    } catch (e) {
        console.error("Failed to load data", e);
        showToast("Erro ao carregar dados do servidor.", "error");
    } finally {
        setLoadingData(false);
    }
  };

  const checkPaymentCallback = (currentUser: User) => {
      const params = new URLSearchParams(window.location.search);
      const status = params.get('status') || params.get('collection_status');
      const paymentId = params.get('payment_id') || params.get('collection_id');

      if (status === 'approved' && paymentId) {
         setVerifyingPayment(true);
         setTimeout(async () => {
            const plan = getPlanConfig();
            await activateSubscription(currentUser.id);
            registerPayment({
               id: paymentId,
               userId: currentUser.id,
               userName: currentUser.name,
               amount: plan.price,
               date: new Date().toISOString(),
               status: 'approved',
               method: 'credit_card',
               planName: plan.name
            });
            setUser(prev => prev ? ({ ...prev, subscriptionStatus: 'active' }) : null);
            setVerifyingPayment(false);
            window.history.replaceState({}, document.title, window.location.pathname);
            showToast("Pagamento Confirmado! Assinatura Ativa.", "success");
         }, 1500);
      } else if (status === 'failure' || status === 'rejected') {
         showToast("O pagamento não foi concluído.", "error");
         window.history.replaceState({}, document.title, window.location.pathname);
      }
  };

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // --- Processed Data (Derived State) ---
  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  // --- Handlers (Now calling DB) ---
  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    loadUserData(loggedInUser.id);
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = () => {
    logout();
    setUser(null);
    setTransactions([]);
    setView('dashboard');
  };

  const updateAndSave = async (
      updateFn: (prev: any) => any, 
      setter: React.Dispatch<any>, 
      saver: (uid: string, data: any) => Promise<void>
  ) => {
      if(!user) return;
      setter((prev: any) => {
          const newData = typeof updateFn === 'function' ? updateFn(prev) : updateFn;
          saver(user.id, newData).catch(err => console.error("Save failed", err));
          return newData;
      });
  };

  // --- Specific Action Handlers ---

  const handleAddTransaction = (t: Transaction) => {
    if(!user) return;
    const newTxs = [t, ...transactions];
    setTransactions(newTxs);
    db.saveTransactions(user.id, newTxs);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null);
  };

  const handleUpdateTransactions = (txs: Transaction[]) => {
      if(!user) return;
      setTransactions(txs);
      db.saveTransactions(user.id, txs);
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string, date: string) => {
    if(!user) return;
    const updatedDebts = debts.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    });
    setDebts(updatedDebts);
    db.saveDebts(user.id, updatedDebts as Debt[]);

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: date || new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  const handleMercadoPagoCheckout = async () => {
     if (!user) return;
     const plan = getPlanConfig();
     setIsProcessingPayment(true);
     try {
       const { initPoint } = await createMercadoPagoPreference(plan, user.id);
       window.location.href = initPoint;
     } catch (error) {
       console.error("Erro no checkout", error);
       showToast("Erro ao iniciar pagamento.", "error");
       setIsProcessingPayment(false);
     }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    showToast("Analisando imagem...", "info");
    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);
      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; 
  };

  const handleMicClick = async () => {
    if (isRecording) stopRecording(); else startRecording();
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (event) => { if (event.data.size > 0) audioChunksRef.current.push(event.data); };
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");
          const result = await analyzeAudioCommand(base64Audio);
          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };

  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard, section: 'PRINCIPAL' },
    { id: 'wallet', label: 'Carteira', icon: Wallet, section: 'PRINCIPAL' },
    { id: 'transactions', label: 'Finanças', icon: Receipt, section: 'FINANCEIRO' },
    { id: 'potes', label: 'Potes', icon: Archive, section: 'FINANCEIRO' },
    { id: 'budgets', label: 'Orçamentos', icon: Target, section: 'FINANCEIRO' },
    { id: 'debts', label: 'Dívidas', icon: AlertCircle, section: 'FINANCEIRO' },
    { id: 'goals', label: 'Metas', icon: Target, section: 'FINANCEIRO' },
    { id: 'settings', label: 'Ajustes', icon: SettingsIcon, section: 'SISTEMA' },
    { id: 'admin', label: 'Admin', icon: Shield, section: 'SISTEMA', adminOnly: true },
    { id: 'advisor', label: 'IA Advisor', icon: BrainCircuit, section: 'ZEN TOOLS' },
  ];

  const sections = ['PRINCIPAL', 'FINANCEIRO', 'SISTEMA', 'ZEN TOOLS'];

  // --- RENDERIZACAO ---

  if (verifyingPayment) {
     return (
        <div className="min-h-screen bg-slate-50 dark:bg-[#030712] flex items-center justify-center flex-col gap-6 text-[#212529] dark:text-white p-6">
           <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
           <div className="text-center">
              <h2 className="text-xl font-black uppercase tracking-tighter">Conectando...</h2>
              <p className="text-slate-500 text-sm mt-2">Sincronizando com o banco de dados.</p>
           </div>
        </div>
     );
  }

  if (!user) {
    return (
      <>
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        <Auth onLoginSuccess={handleLoginSuccess} />
      </>
    );
  }

  if (loadingData) {
      return (
        <div className="min-h-screen bg-slate-50 dark:bg-[#030712] flex items-center justify-center">
            <Loader2 className="w-10 h-10 text-indigo-600 animate-spin" />
        </div>
      );
  }

  // --- LOGICA DE BLOQUEIO DE ASSINATURA ---
  const isExpired = user.subscriptionStatus === 'expired';

  if (isExpired) {
    const plan = getPlanConfig();
    return (
       <div className="min-h-screen bg-slate-50 dark:bg-[#030712] flex items-center justify-center p-6 text-[#212529] dark:text-white">
          <div className="bg-white dark:bg-[#111827] rounded-[2.5rem] w-full max-w-md p-8 border border-slate-200 dark:border-white/5 shadow-2xl relative overflow-hidden">
             <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-rose-500 via-purple-500 to-indigo-500"></div>
             <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-600/20 blur-3xl rounded-full pointer-events-none"></div>
             <div className="flex flex-col items-center text-center space-y-6">
                <div className="w-20 h-20 bg-rose-500/10 rounded-full flex items-center justify-center mb-2 animate-bounce">
                   <Lock className="w-10 h-10 text-rose-500" />
                </div>
                <div>
                   <h2 className="text-2xl font-black uppercase tracking-tighter mb-2">Período de Teste Encerrado</h2>
                   <p className="text-slate-500 text-sm">Esperamos que você tenha aproveitado os 7 dias gratuitos do ZenOS Finance. Para continuar organizando sua vida financeira, ative o plano premium.</p>
                </div>
                <div className="w-full bg-slate-50 dark:bg-black/20 rounded-2xl p-6 border border-slate-200 dark:border-white/5">
                   <div className="flex justify-between items-center mb-4">
                      <span className="text-sm font-bold text-slate-600 dark:text-slate-400 uppercase tracking-widest">{plan.name}</span>
                      <span className="text-2xl font-black text-indigo-600 dark:text-indigo-400">R$ {plan.price.toFixed(2)}<span className="text-xs text-slate-400">/mês</span></span>
                   </div>
                   <ul className="space-y-3 text-left">
                      {plan.features.map((feat, idx) => (
                        <li key={idx} className="flex items-center gap-2 text-xs font-bold text-slate-600 dark:text-slate-300"><Check className="w-4 h-4 text-emerald-500" /> {feat}</li>
                      ))}
                   </ul>
                </div>
                <button onClick={handleMercadoPagoCheckout} disabled={isProcessingPayment} className="w-full py-4 bg-[#009EE3] text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl hover:bg-[#008ED0] transition-all flex items-center justify-center gap-2 relative overflow-hidden group">
                  <div className="absolute inset-0 w-full h-full bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:animate-[shimmer_1.5s_infinite]"></div>
                  {isProcessingPayment ? <Loader2 className="w-5 h-5 animate-spin" /> : <CreditCard className="w-5 h-5" />}
                  {isProcessingPayment ? 'Redirecionando...' : 'Pagar com Mercado Pago'}
                </button>
                <button onClick={handleLogout} className="text-xs text-slate-400 hover:text-rose-500 transition-colors">Sair da conta</button>
             </div>
          </div>
       </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-[#F8F9FA] dark:bg-[#030712] text-[#212529] dark:text-slate-100 font-sans overflow-hidden select-none transition-colors duration-300">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
      <input type="file" accept="image/*" capture="environment" ref={fileInputRef} className="hidden" onChange={handleFileChange} />
      {isProcessing && (
        <div className="fixed inset-0 z-[100] bg-white/80 dark:bg-black/80 backdrop-blur-sm flex items-center justify-center flex-col gap-4">
          <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          <p className="text-[#212529] dark:text-white font-bold animate-pulse">Consultando IA...</p>
        </div>
      )}

      {/* FAB */}
      <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end gap-3 safe-pb">
        {isFabOpen && (
          <div className="flex flex-col gap-3 animate-in slide-in-from-bottom-10 fade-in duration-200">
            <button onClick={handleCameraClick} className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"><Camera className="w-5 h-5" /></button>
            <button onClick={handleMicClick} className={`w-12 h-12 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform ${isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-white text-indigo-900'}`}>{isRecording ? <StopCircle className="w-6 h-6" /> : <Mic className="w-5 h-5" />}</button>
            <button onClick={() => { setView('transactions'); setPreFilledTx(null); setIsFabOpen(false); showToast("Modo manual", "info"); }} className="w-12 h-12 bg-white text-indigo-900 rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"><Receipt className="w-5 h-5" /></button>
          </div>
        )}
        <button onClick={() => { if (isRecording) stopRecording(); else setIsFabOpen(!isFabOpen); }} className={`w-14 h-14 rounded-full shadow-2xl shadow-indigo-600/40 flex items-center justify-center hover:scale-110 active:scale-90 transition-all group ${isRecording ? 'bg-rose-500' : 'bg-indigo-600'}`}>
          {isRecording ? <div className="w-4 h-4 bg-white rounded-sm animate-spin" /> : <Plus className={`w-7 h-7 text-white transition-transform duration-300 ${isFabOpen ? 'rotate-45' : ''}`} />}
        </button>
      </div>

      <div className={`fixed inset-0 bg-black/80 backdrop-blur-md z-[60] lg:hidden transition-opacity ${isSidebarOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`} onClick={() => setIsSidebarOpen(false)} />

      <aside className={`fixed lg:sticky top-0 left-0 h-screen z-[70] transition-all duration-300 ${isSidebarOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0 lg:w-20 xl:w-72'} bg-white dark:bg-[#0a0c14] border-r border-slate-200 dark:border-white/5 flex flex-col shadow-2xl lg:shadow-none`}>
        <div className="p-6 flex items-center justify-between xl:justify-start gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-600/20"><BrainCircuit className="w-6 h-6 text-white" /></div>
            <span className="text-xl font-black lg:hidden xl:block tracking-tighter text-[#212529] dark:text-white">ZenOS</span>
          </div>
          <button className="lg:hidden p-2 text-[#6C757D]" onClick={() => setIsSidebarOpen(false)}><X /></button>
        </div>
        <nav className="flex-1 px-3 mt-6 space-y-6 overflow-y-auto no-scrollbar">
          {sections.map(sectionName => {
             const items = navItems.filter(item => item.section === sectionName && (!item.adminOnly || user.role === 'admin'));
             if (items.length === 0) return null;
             return (
              <div key={sectionName} className="space-y-1">
                <h4 className="px-4 text-[8px] font-black text-[#6C757D] dark:text-slate-600 uppercase tracking-[0.3em] lg:hidden xl:block">{sectionName}</h4>
                <div className="space-y-1">
                  {items.map((item) => (
                    <button key={item.id} onClick={() => { setView(item.id); setIsSidebarOpen(false); }} className={`w-full flex items-center gap-4 px-4 py-3 rounded-2xl transition-all ${view === item.id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/10' : 'text-[#6C757D] dark:text-slate-500 hover:text-[#212529] dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800/40'}`}>
                      <item.icon className={`w-5 h-5 flex-shrink-0 ${view === item.id ? 'text-white' : ''}`} />
                      <span className="font-bold text-sm lg:hidden xl:block">{item.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </nav>
        <div className="px-4 py-2">
            <div className={`p-4 rounded-2xl border ${user.subscriptionStatus === 'trial' ? 'bg-amber-500/10 border-amber-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
                <p className={`text-[9px] font-black uppercase tracking-widest mb-1 ${user.subscriptionStatus === 'trial' ? 'text-amber-500' : 'text-emerald-500'}`}>{user.subscriptionStatus === 'trial' ? 'Período de Teste' : 'Assinatura Ativa'}</p>
                {user.subscriptionStatus === 'trial' && <p className="text-xs text-slate-500 dark:text-slate-400">Expira em: {new Date(user.trialEndsAt).toLocaleDateString()}</p>}
            </div>
        </div>
        <div className="p-4 border-t border-slate-200 dark:border-white/5">
          <button onClick={handleLogout} className="w-full flex items-center gap-4 px-4 py-3 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all">
            <LogOut className="w-5 h-5" /><span className="font-bold text-sm lg:hidden xl:block">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#F8F9FA] dark:bg-[#030712] transition-colors duration-300">
        <header className="h-16 glass sticky top-0 z-50 px-4 md:px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-slate-100 dark:bg-slate-900/50 rounded-xl text-indigo-600 dark:text-indigo-400"><Menu className="w-5 h-5" /></button>
            <h1 className="text-sm md:text-lg font-black uppercase tracking-widest truncate text-[#212529] dark:text-slate-100">{navItems.find(i => i.id === view)?.label}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="hidden sm:flex flex-col items-end">
                <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest">Usuário</span>
                <span className="text-xs font-black text-[#212529] dark:text-white truncate max-w-[100px]">{user.name}</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
                <span className="font-black text-indigo-600 dark:text-indigo-400">{user.name.charAt(0)}</span>
             </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <AnalyticsDashboard data={financialData} />}
            {view === 'wallet' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => updateAndSave((prev: Transaction[]) => prev.filter(t => t.id !== id), setTransactions, db.saveTransactions)}
                onEdit={(updated) => updateAndSave((prev: Transaction[]) => prev.map(t => t.id === updated.id ? updated : t), setTransactions, db.saveTransactions)}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                transactions={transactions}
                onAdd={(d) => updateAndSave((prev: Debt[]) => [...prev, d], setDebts, db.saveDebts)}
                onUpdate={(d) => updateAndSave((prev: Debt[]) => prev.map(item => item.id === d.id ? d : item), setDebts, db.saveDebts)}
                onEdit={(d) => updateAndSave((prev: Debt[]) => prev.map(item => item.id === d.id ? d : item), setDebts, db.saveDebts)}
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(newPotes) => {
                  const clean = newPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  updateAndSave(() => clean as Jar[], setPotes, db.savePotes);
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => updateAndSave(b, setBudgets, db.saveBudgets)} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => updateAndSave((prev: FinancialGoal[]) => [...prev, g], setGoals, db.saveGoals)}
                onUpdate={(newGoals) => updateAndSave(newGoals, setGoals, db.saveGoals)}
                onDeposit={handleGoalDeposit}
                onEdit={(g) => updateAndSave((prev: FinancialGoal[]) => prev.map(i => i.id === g.id ? g : i), setGoals, db.saveGoals)}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={(cats) => updateAndSave(cats, setCategories, db.saveCategories)}
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
                user={user}
                onSubscribe={handleMercadoPagoCheckout}
                isProcessingSubscription={isProcessingPayment}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Receipt, Target, BrainCircuit, Menu, X, Archive, 
  AlertCircle, Plus, Settings as SettingsIcon, Camera, Mic, Loader2, StopCircle, LogOut, Shield, Wallet, Lock, Crown, Check, CreditCard
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Budget, FinancialGoal, Category, User } from './types';
import Dashboard from './components/Dashboard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Settings from './components/Settings';
import AdminPanel from './components/AdminPanel';
import Auth from './components/Auth';
import Toast, { ToastType } from './components/Toast';
import { analyzeReceipt, analyzeAudioCommand } from './services/gemini';
import { initializeAuth, getCurrentUser, logout, activateSubscription } from './services/auth';
import { getPlanConfig, registerPayment, createMercadoPagoPreference } from './services/billing.ts';
import { db } from './services/db'; // New Database Service

// Default Constants (Fallback)
