        </div>
        <div className="p-4 border-t border-slate-200 dark:border-white/5">
          <button onClick={handleLogout} className="w-full flex items-center gap-4 px-4 py-3 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all">
            <LogOut className="w-5 h-5" /><span className="font-bold text-sm lg:hidden xl:block">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen relative bg-[#F8F9FA] dark:bg-[#030712] transition-colors duration-300">

        {/* Content Area - No Header */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 md:space-y-8 no-scrollbar pt-16 lg:pt-6">
          <div className="max-w-7xl mx-auto w-full">
            {view === 'dashboard' && <AnalyticsDashboard data={financialData} />}
            {view === 'wallet' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => updateAndSave((prev: Transaction[]) => prev.filter(t => t.id !== id), setTransactions, db.saveTransactions)}
                onEdit={(updated) => updateAndSave((prev: Transaction[]) => prev.map(t => t.id === updated.id ? updated : t), setTransactions, db.saveTransactions)}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                transactions={transactions}
                onAdd={(d) => updateAndSave((prev: Debt[]) => [...prev, d], setDebts, db.saveDebts)}
                onUpdate={(d) => updateAndSave((prev: Debt[]) => prev.map(item => item.id === d.id ? d : item), setDebts, db.saveDebts)}
                onEdit={(d) => updateAndSave((prev: Debt[]) => prev.map(item => item.id === d.id ? d : item), setDebts, db.saveDebts)}
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(newPotes) => {
                  const clean = newPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  updateAndSave(() => clean as Jar[], setPotes, db.savePotes);
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => updateAndSave(b, setBudgets, db.saveBudgets)} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => updateAndSave((prev: FinancialGoal[]) => [...prev, g], setGoals, db.saveGoals)}
                onUpdate={(newGoals) => updateAndSave(newGoals, setGoals, db.saveGoals)}
                onDeposit={handleGoalDeposit}
                onEdit={(g) => updateAndSave((prev: FinancialGoal[]) => prev.map(i => i.id === g.id ? g : i), setGoals, db.saveGoals)}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={(cats) => updateAndSave(cats, setCategories, db.saveCategories)}
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
                user={user}
                onSubscribe={handleMercadoPagoCheckout}
                isProcessingSubscription={isProcessingPayment}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { User, PlanConfig, PaymentRecord } from '../types';
import { getUsers, updateUserStatus, activateSubscription } from '../services/auth';
import { getPlanConfig, updatePlanConfig, getPayments } from '../services/billing.ts';
import { Shield, Search, UserCheck, UserX, Trash2, Crown, Clock, CreditCard, DollarSign, Settings, BarChart3, Save, ExternalLink, RefreshCw } from 'lucide-react';

export default function AdminPanel() {
  const [activeTab, setActiveTab] = useState<'users' | 'plans' | 'financial'>('users');
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(false);
  const [search, setSearch] = useState('');

  // Plan Config State
  const [planConfig, setPlanConfig] = useState<PlanConfig>(getPlanConfig());
  const [payments, setPayments] = useState<PaymentRecord[]>([]);

  useEffect(() => {
    loadData();
    // Real-time polling: Atualiza lista de usuários a cada 10 segundos
    const interval = setInterval(() => {
        if (activeTab === 'users') {
            refreshUsers();
        }
    }, 10000);
    return () => clearInterval(interval);
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    await refreshUsers();
    setPlanConfig(getPlanConfig());
    setPayments(getPayments());
    setLoading(false);
  };

  const refreshUsers = async () => {
      try {
          const userList = await getUsers();
          setUsers(userList);
      } catch (error) {
          console.error("Erro ao atualizar usuários:", error);
      }
  };

  const handleToggleStatus = async (userId: string, currentStatus: 'active' | 'blocked') => {
    const newStatus = currentStatus === 'active' ? 'blocked' : 'active';
    if (await updateUserStatus(userId, newStatus)) {
      await refreshUsers(); // Atualiza UI imediatamente
    } else {
      alert("Não é possível alterar o status deste usuário (pode ser um admin).");
    }
  };

  const handleActivateSubscription = async (userId: string) => {
    if (await activateSubscription(userId)) {
        await refreshUsers(); // Atualiza UI imediatamente
        alert("Assinatura ativada manualmente com sucesso.");
    }
  };

  const handleSavePlan = (e: React.FormEvent) => {
    e.preventDefault();
    updatePlanConfig(planConfig);
    alert("Configurações salvas com sucesso!");
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(search.toLowerCase()) || 
    u.email.toLowerCase().includes(search.toLowerCase())
  );

  const totalRevenue = payments.reduce((acc, p) => acc + p.amount, 0);

