            <Shield className="w-8 h-8 text-white" />
          </div>
          <div>
            <h2 className="text-2xl font-black uppercase tracking-tighter">Portal Admin</h2>
            <p className="text-indigo-200 text-xs font-bold uppercase tracking-widest">Gestão Global do Sistema</p>
          </div>
        </div>

        {/* Tabs de Navegação */}
        <div className="flex bg-indigo-800/50 p-1.5 rounded-2xl">
           <button 
             onClick={() => setActiveTab('users')}
             className={`px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-widest transition-all ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-md' : 'text-indigo-200 hover:bg-white/10'}`}
           >
             Usuários
           </button>
           <button 
             onClick={() => setActiveTab('plans')}
