import { PlanConfig, PaymentRecord } from '../types

export const DEFAULT_PLAN: PlanConfig = {
  planId: 'default',
  name: 'Default Plan',
  description: 'Basic plan with limited features.',
  price: 10,
  currency: 'USD',
  mercadoPagoPublicKey: 'APP_USR-9fcf61f6-7e45-4a0d-86d4-afca0ce47960',
  mercadoPagoAccessToken: 'APP_USR-3070912774531465-040600-85abb4ca8ae650eac74cdb6ba00b87a3-197163105'
};

export const createMercadoPagoPreference = async (plan: PlanConfig, userId: string, quantity: number = 1): Promise<any> => {
