export const createMercadoPagoPreference = async (plan: PlanConfig, userId: string) => {
  const currentUrl = window.location.href.split('?')[0];

  // 1. MODO REAL VIA API (Prioritário se Access Token existir)
  if (plan.mercadoPagoAccessToken) {
    try {
      const response = await fetch('https://api.mercadopago.com/checkout/preferences', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${plan.mercadoPagoAccessToken}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          items: [{
            title: plan.name,
            quantity: 1,
            currency_id: 'BRL',
            unit_price: plan.price
          }],
          external_reference: userId,
          back_urls: {
            success: currentUrl,
            failure: currentUrl,
            pending: currentUrl
          },
          auto_return: "approved"
        })
      });

      const data = await response.json();
      if (data.init_point) {
        return {
           preferenceId: data.id,
           initPoint: data.init_point
        };
      } else {
        console.error("MP API Error:", data);
        // Se falhar (ex: CORS em localhost), cai para o link estático ou simulação
      }
    } catch (e) {
      console.error("MP Fetch Error (Provavelmente CORS - Requer Backend/Proxy):", e);
    }
  }

  // 2. MODO LINK ESTÁTICO (Se configurado e API falhar ou não tiver token)
  if (plan.paymentLink && plan.paymentLink.startsWith('http')) {
     return {
        preferenceId: 'static_link',
        initPoint: plan.paymentLink
     };
  }

  // 3. MODO SIMULAÇÃO (Fallback final)
  await new Promise(r => setTimeout(r, 1500)); // Delay para sensação de processamento

  // Simula o comportamento do Mercado Pago redirecionando de volta com params
  return {
    preferenceId: `pref_${Math.random().toString(36).substr(2, 9)}`,
