                                 className="w-full px-4 py-3 bg-white dark:bg-black/20 border border-slate-200 dark:border-white/5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-mono"
                                 value={planConfig.mercadoPagoPublicKey || ''}
                                 onChange={e => setPlanConfig({...planConfig, mercadoPagoPublicKey: e.target.value})}
                             />
                          </div>
                          <div className="space-y-2">
                             <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 flex items-center gap-1"><Key className="w-3 h-3" /> Access Token</label>
                             <input 
                                 type="password" 
                                 placeholder="APP_USR-..."
                                 className="w-full px-4 py-3 bg-white dark:bg-black/20 border border-slate-200 dark:border-white/5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-mono"
                                 value={planConfig.mercadoPagoAccessToken || ''}
                                 onChange={e => setPlanConfig({...planConfig, mercadoPagoAccessToken: e.target.value})}
                             />
                          </div>

                          <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 flex items-center gap-1"><Lock className="w-3 h-3" /> Client ID</label>
                                <input 
                                    type="text" 
                                    className="w-full px-4 py-3 bg-white dark:bg-black/20 border border-slate-200 dark:border-white/5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-mono"
                                    value={planConfig.mercadoPagoClientId || ''}
                                    onChange={e => setPlanConfig({...planConfig, mercadoPagoClientId: e.target.value})}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 flex items-center gap-1"><Lock className="w-3 h-3" /> Client Secret</label>
                                <input 
                                    type="password" 
                                    className="w-full px-4 py-3 bg-white dark:bg-black/20 border border-slate-200 dark:border-white/5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-mono"
                                    value={planConfig.mercadoPagoClientSecret || ''}
                                    onChange={e => setPlanConfig({...planConfig, mercadoPagoClientSecret: e.target.value})}
                                />
                            </div>
                          </div>

                          <div className="space-y-2 pt-2 border-t border-emerald-500/20">
                             <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400">Link de Pagamento (Fallback)</label>
                             <input 
                                 type="url" 
                                 placeholder="https://mpago.la/..."
                                 className="w-full px-4 py-3 bg-white dark:bg-black/20 border border-slate-200 dark:border-white/5 rounded-xl outline-none focus:ring-2 focus:ring-emerald-500 text-xs font-mono"
                                 value={planConfig.paymentLink || ''}
                                 onChange={e => setPlanConfig({...planConfig, paymentLink: e.target.value})}
                             />
                          </div>
                       </div>
                    </div>

                    <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl hover:bg-indigo-500 transition-all flex items-center justify-center gap-2">
                        <Save className="w-4 h-4" /> Salvar Configurações
                    </button>
                </form>
             </div>

             <div className="bg-indigo-500/10 p-8 rounded-[2.5rem] border border-indigo-500/20 flex flex-col items-center justify-center text-center">
                 <CreditCard className="w-16 h-16 text-indigo-500 mb-4" />
                 <h3 className="text-xl font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-tighter">Preview do Plano</h3>
                 <p className="text-slate-500 dark:text-slate-400 text-sm mb-6 max-w-xs">
                     É assim que o usuário verá o plano na tela de pagamento.
                 </p>

                 <div className="bg-white dark:bg-[#0a0c14] p-6 rounded-3xl shadow-2xl w-full max-w-xs transform rotate-2">
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Assinatura</span>
                        <Crown className="w-5 h-5 text-amber-500" />
                    </div>
                    <h4 className="text-xl font-black text-[#212529] dark:text-white mb-1">{planConfig.name}</h4>
                    <p className="text-3xl font-black text-indigo-600 dark:text-indigo-400 tracking-tighter">
                        R$ {planConfig.price.toFixed(2)}<span className="text-xs text-slate-400 font-bold">/mês</span>
                    </p>
                 </div>

                 {planConfig.mercadoPagoAccessToken ? (
                    <div className="mt-6 flex items-center gap-2 text-[10px] font-bold text-emerald-600 dark:text-emerald-400 bg-emerald-500/10 px-3 py-1 rounded-full">
                       <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                       API Produção Ativa
                    </div>
                 ) : planConfig.paymentLink ? (
                    <div className="mt-6 flex items-center gap-2 text-[10px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-500/10 px-3 py-1 rounded-full">
                       <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></div>
                       Link Estático Ativo
                    </div>
                 ) : (
                    <div className="mt-6 flex items-center gap-2 text-[10px] font-bold text-amber-600 dark:text-amber-400 bg-amber-500/10 px-3 py-1 rounded-full">
                       <div className="w-2 h-2 rounded-full bg-amber-500"></div>
                       Modo Simulação
                    </div>
                 )}
             </div>
          </div>
      )}

      {/* TAB: FINANCEIRO */}
      {activeTab === 'financial' && (
          <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="bg-emerald-500/10 p-6 rounded-3xl border border-emerald-500/20">
                      <span className="text-[10px] font-black text-emerald-600 dark:text-emerald-400 uppercase tracking-widest block mb-2">Receita Total</span>
                      <p className="text-3xl font-black text-emerald-600 dark:text-white tracking-tighter">R$ {totalRevenue.toFixed(2)}</p>
                  </div>
                  <div className="bg-indigo-500/10 p-6 rounded-3xl border border-indigo-500/20">
                      <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest block mb-2">Vendas Totais</span>
                      <p className="text-3xl font-black text-indigo-600 dark:text-white tracking-tighter">{payments.length}</p>
                  </div>
                  <div className="bg-amber-500/10 p-6 rounded-3xl border border-amber-500/20">
                      <span className="text-[10px] font-black text-amber-600 dark:text-amber-400 uppercase tracking-widest block mb-2">Ticket Médio</span>
                      <p className="text-3xl font-black text-amber-600 dark:text-white tracking-tighter">
                          R$ {payments.length > 0 ? (totalRevenue / payments.length).toFixed(2) : '0.00'}
                      </p>
                  </div>
              </div>

              <div className="bg-white dark:bg-[#111827]/60 border border-slate-200 dark:border-white/5 rounded-[2.5rem] overflow-hidden shadow-xl">
                  <div className="p-6 border-b border-slate-200 dark:border-white/5 flex items-center gap-2">
                     <BarChart3 className="w-5 h-5 text-slate-500" />
                     <h3 className="text-sm font-black text-[#212529] dark:text-white uppercase tracking-widest">Histórico de Transações</h3>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-slate-50 dark:bg-black/20">
                            <tr>
                                <th className="px-6 py-4 text-left text-[9px] font-black uppercase text-slate-500">Data</th>
                                <th className="px-6 py-4 text-left text-[9px] font-black uppercase text-slate-500">Cliente</th>
                                <th className="px-6 py-4 text-left text-[9px] font-black uppercase text-slate-500">Método</th>
                                <th className="px-6 py-4 text-left text-[9px] font-black uppercase text-slate-500">Status</th>
                                <th className="px-6 py-4 text-right text-[9px] font-black uppercase text-slate-500">Valor</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-white/5">
                            {payments.map(p => (
                                <tr key={p.id} className="hover:bg-slate-50 dark:hover:bg-white/5">
                                    <td className="px-6 py-4 text-xs font-bold text-slate-600 dark:text-slate-400">
                                        {new Date(p.date).toLocaleDateString()}
                                    </td>
                                    <td className="px-6 py-4 text-xs font-bold text-[#212529] dark:text-white">
                                        {p.userName}
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className="px-2 py-1 rounded-lg bg-slate-100 dark:bg-white/10 text-[10px] font-black uppercase tracking-widest text-slate-500">
                                            {p.method === 'credit_card' ? 'Cartão' : p.method === 'pix' ? 'Pix' : 'Boleto'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${p.status === 'approved' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-amber-500/10 text-amber-500'}`}>
                                            {p.status === 'approved' ? 'Aprovado' : p.status}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-right text-xs font-black text-[#212529] dark:text-white">
                                        R$ {p.amount.toFixed(2)}
                                    </td>
                                </tr>
                            ))}
                            {payments.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="px-6 py-8 text-center text-xs text-slate-400 italic">Nenhuma transação registrada.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Receipt, Target, BrainCircuit, Menu, X, Archive, 
  AlertCircle, Plus, Settings as SettingsIcon, Camera, Mic, Loader2, StopCircle, LogOut, Shield, Wallet, Lock, Crown, Check, CreditCard
} from 'lucide-react';
import { AppView, Transaction, Jar, Debt, Budget, FinancialGoal, Category, User } from './types';
import Dashboard from './components/Dashboard';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import Transactions from './components/Transactions';
import Debts from './components/Debts';
import Potes from './components/Potes';
import AIAdvisor from './components/AIAdvisor';
import Budgets from './components/Budgets';
import Goals from './components/Goals';
import Settings from './components/Settings';
import AdminPanel from './components/AdminPanel';
import Auth from './components/Auth';
import Toast, { ToastType } from './components/Toast';
import { analyzeReceipt, analyzeAudioCommand } from './services/gemini';
import { initializeAuth, getCurrentUser, logout, activateSubscription } from './services/auth';
import { getPlanConfig, registerPayment, createMercadoPagoPreference } from './services/billing.ts';
import { db } from './services/db'; // New Database Service

// Default Constants (Fallback)
const INITIAL_POTES: Jar[] = [
  { id: '1', name: 'Operacional', percentage: 40, balance: 0 },
  { id: '2', name: 'Gastos Fixos', percentage: 40, balance: 0 },
  { id: '3', name: 'Investimento/Reserva', percentage: 20, balance: 0 },
];

const DEFAULT_CATEGORIES: Category[] = [
  { 
    id: 'c1', name: 'Moradia', type: 'expense', isDefault: true,
    subCategories: [{id: 's1', name: 'Aluguel'}, {id: 's2', name: 'Energia'}, {id: 's3', name: 'Internet'}, {id: 's4', name: 'Manutenção'}] 
  },
  { 
    id: 'c2', name: 'Alimentação', type: 'expense', isDefault: true,
    subCategories: [{id: 's5', name: 'Supermercado'}, {id: 's6', name: 'Restaurante'}, {id: 's7', name: 'Delivery'}] 
  },
  { 
    id: 'c3', name: 'Transporte', type: 'expense', isDefault: true,
    subCategories: [{id: 's8', name: 'Combustível'}, {id: 's9', name: 'Uber/Táxi'}, {id: 's10', name: 'Manutenção Veículo'}] 
  },
  { 
    id: 'c4', name: 'Saúde', type: 'expense', isDefault: true,
    subCategories: [{id: 's11', name: 'Farmácia'}, {id: 's12', name: 'Consultas'}, {id: 's13', name: 'Plano de Saúde'}] 
  },
  { 
    id: 'c5', name: 'Lazer', type: 'expense', isDefault: true,
    subCategories: [{id: 's14', name: 'Cinema/Streaming'}, {id: 's15', name: 'Viagem'}, {id: 's16', name: 'Hobbies'}] 
  },
  { 
    id: 'c6', name: 'Renda', type: 'income', isDefault: true,
    subCategories: [{id: 's17', name: 'Salário'}, {id: 's18', name: 'Freelance'}, {id: 's19', name: 'Dividendos'}] 
  }
];

interface NavItem {
  id: AppView;
  label: string;
  icon: any;
  section: string;
  adminOnly?: boolean;
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: ToastType } | null>(null);

  // Data States (Loaded asynchronously)
  const [loadingData, setLoadingData] = useState(false);
  const [categories, setCategories] = useState<Category[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [potes, setPotes] = useState<Jar[]>([]);
  const [debts, setDebts] = useState<Debt[]>([]);
  const [budgets, setBudgets] = useState<Budget[]>([]);
  const [goals, setGoals] = useState<FinancialGoal[]>([]);

  // States for Paywall & Fab
  const [isProcessingPayment, setIsProcessingPayment] = useState(false);
  const [verifyingPayment, setVerifyingPayment] = useState(false);
  const [isFabOpen, setIsFabOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [preFilledTx, setPreFilledTx] = useState<Partial<Transaction> | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // 1. Initialize Auth & Load Data
  useEffect(() => {
    initializeAuth();
    const currentUser = getCurrentUser();

    if (currentUser) {
      setUser(currentUser);
      loadUserData(currentUser.id);
      checkPaymentCallback(currentUser);
    }
  }, []);

  const loadUserData = async (userId: string) => {
    setLoadingData(true);
    try {
        const data = await db.getFinancialData(userId);
        setTransactions(data.transactions);
        setPotes(data.potes.length ? data.potes : INITIAL_POTES);
        setDebts(data.debts);
        setBudgets(data.budgets);
        setGoals(data.goals);
        setCategories(data.categories.length ? data.categories : DEFAULT_CATEGORIES);
    } catch (e) {
        console.error("Failed to load data", e);
        showToast("Erro ao carregar dados do servidor.", "error");
    } finally {
        setLoadingData(false);
    }
  };

  const checkPaymentCallback = (currentUser: User) => {
      const params = new URLSearchParams(window.location.search);
      const status = params.get('status') || params.get('collection_status');
      const paymentId = params.get('payment_id') || params.get('collection_id');

      if (status === 'approved' && paymentId) {
         setVerifyingPayment(true);
         setTimeout(async () => {
            const plan = getPlanConfig();
            await activateSubscription(currentUser.id);
            registerPayment({
               id: paymentId,
               userId: currentUser.id,
               userName: currentUser.name,
               amount: plan.price,
               date: new Date().toISOString(),
               status: 'approved',
               method: 'credit_card',
               planName: plan.name
            });
            setUser(prev => prev ? ({ ...prev, subscriptionStatus: 'active' }) : null);
            setVerifyingPayment(false);
            window.history.replaceState({}, document.title, window.location.pathname);
            showToast("Pagamento Confirmado! Assinatura Ativa.", "success");
         }, 1500);
      } else if (status === 'failure' || status === 'rejected') {
         showToast("O pagamento não foi concluído.", "error");
         window.history.replaceState({}, document.title, window.location.pathname);
      }
  };

  // Theme Management
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    return (localStorage.getItem('zen_theme') as 'dark' | 'light') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('zen_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  // --- Processed Data (Derived State) ---
  const processedPotes = useMemo(() => {
    let totalIncome = 0;
    const expenseByPote: Record<string, number> = {};

    transactions.forEach(t => {
      if (t.type === 'income') {
        totalIncome += t.amount;
      } else if (t.type === 'expense' && t.poteId) {
        expenseByPote[t.poteId] = (expenseByPote[t.poteId] || 0) + t.amount;
      }
    });

    return potes.map(pote => {
      const allocatedIncome = totalIncome * (pote.percentage / 100);
      const expenses = expenseByPote[pote.id] || 0;
      return { ...pote, balance: allocatedIncome - expenses };
    });
  }, [transactions, potes]);

  const financialData = useMemo(() => ({ 
    transactions, 
    potes: processedPotes, 
    debts, budgets, goals, categories
  }), [transactions, processedPotes, debts, budgets, goals, categories]);

  // --- Handlers (Now calling DB) ---
  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    setUser(loggedInUser);
    loadUserData(loggedInUser.id);
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = () => {
    logout();

    // Limpeza profunda do estado para evitar vazamento de dados entre usuários
    setUser(null);
    setTransactions([]);
    setPotes([]);
    setDebts([]);
    setBudgets([]);
    setGoals([]);
    setCategories([]);
    setView('dashboard');
    setIsSidebarOpen(false);
  };

  const updateAndSave = async (
      updateFn: any, 
      setter: React.Dispatch<any>, 
      saver: (uid: string, data: any) => Promise<void>
  ) => {
      if(!user) return;
      setter((prev: any) => {
          const newData = typeof updateFn === 'function' ? updateFn(prev) : updateFn;
          saver(user.id, newData).catch(err => console.error("Save failed", err));
          return newData;
      });
  };

  // --- Specific Action Handlers ---

  const handleAddTransaction = (t: Transaction) => {
    if(!user) return;
    const newTxs = [t, ...transactions];
    setTransactions(newTxs);
    db.saveTransactions(user.id, newTxs);
    showToast(`${t.type === 'income' ? 'Entrada' : 'Despesa'} registrada!`);
    setPreFilledTx(null);
  };

  const handleUpdateTransactions = (txs: Transaction[]) => {
      if(!user) return;
      setTransactions(txs);
      db.saveTransactions(user.id, txs);
  };

  const handleDebtPayment = (debt: Debt, amount: number, poteId: string, date: string) => {
    if(!user) return;
    const updatedDebts = debts.map(d => {
      if (d.id === debt.id) {
        const newRemaining = Math.max(0, d.remainingAmount - amount);
        return { ...d, remainingAmount: newRemaining, status: newRemaining <= 0 ? 'paid' : d.status };
      }
      return d;
    });
    setDebts(updatedDebts);
    db.saveDebts(user.id, updatedDebts as Debt[]);

    const paymentTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Pagamento: ${debt.name}`,
      amount: amount,
      category: 'Dívidas',
      date: date || new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência'
    };
    handleAddTransaction(paymentTx);
  };

  const handleGoalDeposit = (amount: number, poteId: string, goalName: string) => {
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description: `Aporte: ${goalName}`,
      amount: amount,
      category: 'Investimento',
      subCategory: 'Meta',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      poteId: poteId,
      paymentMethod: 'Transferência Interna'
    };
    handleAddTransaction(tx);
  };

  const handleMercadoPagoCheckout = async () => {
     if (!user) return;
     const plan = getPlanConfig();
     setIsProcessingPayment(true);
     try {
       const { initPoint } = await createMercadoPagoPreference(plan, user.id);
       window.location.href = initPoint;
     } catch (error) {
       console.error("Erro no checkout", error);
       showToast("Erro ao iniciar pagamento.", "error");
       setIsProcessingPayment(false);
     }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    showToast("Analisando imagem...", "info");
    const reader = new FileReader();
    reader.onload = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const result = await analyzeReceipt(base64String);
      setIsProcessing(false);
      if (result) {
        setView('transactions');
        setPreFilledTx(result);
        showToast("Dados extraídos do cupom!", "success");
      } else {
        showToast("Não foi possível ler o cupom.", "error");
      }
    };
    reader.readAsDataURL(file);
    e.target.value = ''; 
  };

  const handleMicClick = async () => {
    if (isRecording) stopRecording(); else startRecording();
    if (isRecording) setIsFabOpen(false);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (event) => { if (event.data.size > 0) audioChunksRef.current.push(event.data); };
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/mp3' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setIsProcessing(true);
          showToast("Processando comando...", "info");
          const result = await analyzeAudioCommand(base64Audio);
          setIsProcessing(false);
          if (result) {
            setView('transactions');
            setPreFilledTx(result);
            showToast(result.type === 'income' ? "Receita identificada!" : "Despesa identificada!", "success");
          } else {
            showToast("Não entendi o comando.", "error");
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
      showToast("Ouvindo... (toque novamente para parar)", "info");
    } catch (err) {
      console.error(err);
      showToast("Erro ao acessar microfone", "error");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsFabOpen(false);
    }
  };

  const handleCameraClick = () => {
    fileInputRef.current?.click();
    setIsFabOpen(false);
  };

  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Visão Geral', icon: LayoutDashboard, section: 'PRINCIPAL' },
