            {view === 'dashboard' && <AnalyticsDashboard data={financialData} />}
            {view === 'wallet' && <Dashboard data={financialData} />}
            {view === 'transactions' && (
              <Transactions 
                transactions={transactions} 
                potes={processedPotes} 
                categories={categories}
                onAdd={handleAddTransaction} 
                onDelete={(id) => updateAndSave((prev: Transaction[]) => prev.filter(t => t.id !== id), setTransactions, db.saveTransactions)}
                onEdit={(updated) => updateAndSave((prev: Transaction[]) => prev.map(t => t.id === updated.id ? updated : t), setTransactions, db.saveTransactions)}
                preFilledData={preFilledTx}
              />
            )}
            {view === 'debts' && (
              <Debts 
                debts={debts} 
                potes={processedPotes} 
                transactions={transactions}
                onAdd={(d) => updateAndSave((prev: Debt[]) => [...prev, d], setDebts, db.saveDebts)}
                onUpdate={(d) => updateAndSave((prev: Debt[]) => prev.map(item => item.id === d.id ? d : item), setDebts, db.saveDebts)}
                onEdit={(d) => updateAndSave((prev: Debt[]) => prev.map(item => item.id === d.id ? d : item), setDebts, db.saveDebts)}
                onPay={handleDebtPayment} 
              />
            )}
            {view === 'potes' && (
              <Potes 
                potes={processedPotes} 
                transactions={transactions}
                onUpdate={(newPotes) => {
                  const clean = newPotes.map(p => ({ id: p.id, name: p.name, percentage: p.percentage, balance: 0 }));
                  updateAndSave(() => clean as Jar[], setPotes, db.savePotes);
                }} 
              />
            )}
            {view === 'budgets' && <Budgets budgets={budgets} transactions={transactions} categories={categories} onUpdate={(b) => updateAndSave(b, setBudgets, db.saveBudgets)} />}
            {view === 'goals' && (
              <Goals 
                goals={goals} 
                potes={processedPotes}
                onAdd={(g) => updateAndSave((prev: FinancialGoal[]) => [...prev, g], setGoals, db.saveGoals)}
                onUpdate={(newGoals) => updateAndSave(newGoals, setGoals, db.saveGoals)}
                onDeposit={handleGoalDeposit}
                onEdit={(g) => updateAndSave((prev: FinancialGoal[]) => prev.map(i => i.id === g.id ? g : i), setGoals, db.saveGoals)}
              />
            )}
            {view === 'settings' && (
              <Settings 
                categories={categories} 
                onUpdateCategories={(cats) => updateAndSave(cats, setCategories, db.saveCategories)}
                showToast={showToast} 
                currentTheme={theme}
                toggleTheme={toggleTheme}
                user={user}
                onSubscribe={handleMercadoPagoCheckout}
                isProcessingSubscription={isProcessingPayment}
              />
            )}
            {view === 'admin' && user.role === 'admin' && <AdminPanel />}
            {view === 'advisor' && <AIAdvisor data={financialData} onTransactionCommand={handleAddTransaction} />}
          </div>
          <div className="h-24 lg:hidden"></div>
        </div>
      </main>
    </div>
  );
}

import React, { useMemo } from 'react';
import { Wallet, TrendingUp, Plus, PieChart as PieChartIcon, BarChart3, Activity, AlertTriangle, CheckCircle2 } from 'lucide-react';
import { FinancialData } from '../types';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, 
  BarChart, Bar, XAxis, YAxis, CartesianGrid 
} from 'recharts';

interface DashboardProps {
  data: FinancialData;
}

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f59e0b', '#10b981', '#06b6d4'];

export default function Dashboard({ data }: DashboardProps) {
  const { transactions, potes, debts } = data;
  const totalBalance = potes.reduce((acc, p) => acc + p.balance, 0);

  const now = new Date();
  const currentMonthIdx = now.getMonth();
  const currentYear = now.getFullYear();

  const monthIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === currentMonthIdx)
    .reduce((acc, t) => acc + t.amount, 0);

  // Cálculo de Dívidas do Mês (Pagamento vs Aberto)
  const debtSummary = useMemo(() => {
    let due = 0;
    let paid = 0;

    debts.forEach(debt => {
      const installmentValue = debt.totalAmount / (debt.installments || 1);

      // Projeção simples para ver se tem parcela neste mês
      for (let i = 0; i < (debt.installments || 1); i++) {
         const installmentDate = new Date(debt.dueDate);
         installmentDate.setMonth(installmentDate.getMonth() + i);
         installmentDate.setHours(0,0,0,0);

         if (installmentDate.getMonth() === currentMonthIdx && installmentDate.getFullYear() === currentYear) {
            // Verificar se esta parcela específica foi "paga" baseado no montante total pago
            const amountPaid = debt.totalAmount - debt.remainingAmount;
            const installmentsPaidCount = Math.floor((amountPaid + 0.01) / installmentValue);

            if (i < installmentsPaidCount) {
               paid += installmentValue;
            } else {
               due += installmentValue;
            }
         }
      }
    });
    return { due, paid };
  }, [debts, currentMonthIdx, currentYear]);

  const categoryData = useMemo(() => {
    const expenses = transactions.filter(t => t.type === 'expense');
    const categories: Record<string, number> = {};
    expenses.forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });
    return Object.entries(categories)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 6);
  }, [transactions]);

  const trendData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const monthIndex = d.getMonth();
      const year = d.getFullYear();
      const income = transactions
        .filter(t => t.type === 'income' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      const expense = transactions
        .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === monthIndex && new Date(t.date).getFullYear() === year)
        .reduce((acc, t) => acc + t.amount, 0);
      last6Months.push({ name: months[monthIndex], Entradas: income, Saídas: expense });
    }
    return last6Months;
  }, [transactions]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-white dark:bg-[#0f172a] border border-slate-200 dark:border-white/10 p-2 rounded-xl shadow-2xl backdrop-blur-md">
          <p className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest mb-0.5">{payload[0].name || payload[0].dataKey}</p>
          <p className="text-xs font-black text-[#212529] dark:text-white">R$ {payload[0].value.toLocaleString()}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-10">

      {/* 1. Saldo */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-900 p-5 md:p-6 rounded-3xl shadow-xl relative overflow-hidden group border border-white/10">
           <div className="absolute -top-4 -right-4 p-8 opacity-10 group-hover:scale-125 transition-transform duration-700"><Wallet className="w-16 h-16 md:w-24 text-white" /></div>
           <span className="text-indigo-100/60 text-[9px] font-black uppercase tracking-[0.2em] block mb-1">Saldo</span>
           <p className={`text-3xl md:text-5xl font-black tracking-tighter ${totalBalance < 0 ? 'text-rose-400' : 'text-white'}`}>
             R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
           <div className="mt-3 flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></div>
              <span className="text-[8px] text-indigo-200/50 font-black uppercase tracking-widest">Ativo</span>
           </div>
        </div>

        <div className="bg-white dark:bg-[#111827]/60 p-5 md:p-6 rounded-3xl border border-slate-200 dark:border-white/5 relative group overflow-hidden flex flex-col justify-center shadow-sm dark:shadow-none">
           <div className="absolute -top-4 -right-4 p-8 opacity-5"><TrendingUp className="w-16 h-16 md:w-24 text-[#212529] dark:text-white" /></div>
           <div className="flex items-center gap-2 mb-2">
              <div className="p-1.5 bg-emerald-500/10 rounded-lg"><TrendingUp className="w-4 h-4 text-emerald-600 dark:text-emerald-400" /></div>
              <span className="text-[#6C757D] dark:text-slate-500 text-[9px] font-black uppercase tracking-[0.2em]">Ganhos</span>
           </div>
           <p className="text-3xl md:text-5xl font-black text-emerald-600 dark:text-emerald-400 tracking-tighter">
             R$ {monthIncome.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
           </p>
        </div>
      </div>

      {/* 1.5 Dívidas do Mês (Novo) */}
      <div className="bg-slate-50 dark:bg-slate-900/40 p-5 rounded-3xl border border-slate-200 dark:border-white/5">
        <h3 className="text-[9px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-4">
           Compromissos do Mês
        </h3>
        <div className="grid grid-cols-2 gap-4">
            <div className="bg-rose-500/10 rounded-2xl p-4 border border-rose-500/20">
               <div className="flex items-center gap-2 mb-1">
                  <AlertTriangle className="w-3.5 h-3.5 text-rose-500" />
                  <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest">À Vencer</span>
               </div>
               <p className="text-2xl font-black text-rose-500 dark:text-rose-400">R$ {debtSummary.due.toLocaleString()}</p>
            </div>
            <div className="bg-emerald-500/10 rounded-2xl p-4 border border-emerald-500/20">
               <div className="flex items-center gap-2 mb-1">
                  <CheckCircle2 className="w-3.5 h-3.5 text-emerald-500" />
                  <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Pago</span>
               </div>
               <p className="text-2xl font-black text-emerald-500 dark:text-emerald-400">R$ {debtSummary.paid.toLocaleString()}</p>
            </div>
        </div>
      </div>

      {/* 2. Potes */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {potes.map((pote) => (
            <div key={pote.id} className="bg-white dark:bg-[#0a0c14] p-4 rounded-2xl border border-slate-200 dark:border-white/5 hover:border-indigo-500/40 transition-all group shadow-sm dark:shadow-none">
               <div className="flex justify-between items-center mb-2">
                  <span className="text-[8px] font-black text-[#6C757D] dark:text-slate-500 uppercase tracking-widest truncate">{pote.name}</span>
