import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { User, Transaction, Jar, Debt, Budget, FinancialGoal, Category, FinancialData } from '../types';

let supabase: SupabaseClient | null = null;

// Inicializa o Supabase se as credenciais existirem
export const initSupabase = (url?: string, key?: string) => {
  const sbUrl = url || localStorage.getItem('zen_sb_url');
  const sbKey = key || localStorage.getItem('zen_sb_key');

  if (sbUrl && sbKey) {
    try {
      supabase = createClient(sbUrl, sbKey);
      console.log("ZenOS: Conexão com Supabase inicializada.");
      return true;
    } catch (e) {
      console.error("ZenOS: Erro ao conectar Supabase", e);
      return false;
    }
  }
  return false;
};

// Tenta inicializar na carga do arquivo
initSupabase();

