// Helpers para LocalStorage (Fallback)
const getLocal = <T>(key: string, def: T): T => {
  const s = localStorage.getItem(key);
  return s ? JSON.parse(s) : def;
};
const setLocal = (key: string, val: any) => localStorage.setItem(key, JSON.stringify(val));

export const db = {
  get isConnected() { return !!supabase; },

  // --- USERS ---
  users: {
    get: async (email: string): Promise<User | undefined> => {
      if (supabase) {
        const { data, error } = await supabase.from('users').select('*').eq('email', email).maybeSingle();
        if (error) console.error("SB Error", error);
        return data ? mapUserFromDb(data) : undefined;
      }
      return getLocal<User[]>('zen_users_db', []).find(u => u.email === email);
    },
    listAll: async (): Promise<User[]> => {
      if (supabase) {
        const { data } = await supabase.from('users').select('*');
        return (data || []).map(mapUserFromDb);
      }
      return getLocal<User[]>('zen_users_db', []);
    },
    create: async (user: User): Promise<void> => {
      if (supabase) {
        const { error } = await supabase.from('users').insert(mapUserToDb(user));
        if (error) console.error("SB Create User Error", error);
      } else {
        const users = getLocal<User[]>('zen_users_db', []);
        setLocal('zen_users_db', [...users, user]);
      }
    },
    update: async (user: User): Promise<void> => {
      if (supabase) {
        await supabase.from('users').update(mapUserToDb(user)).eq('id', user.id);
      } else {
        const users = getLocal<User[]>('zen_users_db', []);
        setLocal('zen_users_db', users.map(u => u.id === user.id ? user : u));
      }
    }
  },

  // --- FINANCIAL DATA ---
  getFinancialData: async (userId: string): Promise<FinancialData> => {
    if (supabase) {
      const [tx, potes, debts, budgets, goals, cats] = await Promise.all([
        supabase.from('transactions').select('*').eq('user_id', userId),
        supabase.from('potes').select('*').eq('user_id', userId),
        supabase.from('debts').select('*').eq('user_id', userId),
        supabase.from('budgets').select('*').eq('user_id', userId),
        supabase.from('goals').select('*').eq('user_id', userId),
        supabase.from('categories').select('*').eq('user_id', userId),
      ]);

      return {
        transactions: (tx.data || []).map(mapTxFromDb),
        potes: (potes.data || []).map(p => ({...p})), // Potes mapping is simple 1:1 except snake_case handled by direct property access if needed, but here simple spread works if keys match or we map manually. 
        // Correction: Potes needs manual mapping too if keys differ? Jar has id, name, percentage, balance. DB has same.
        debts: (debts.data || []).map(mapDebtFromDb),
        budgets: (budgets.data || []).map(b => ({id: b.id, category: b.category, limit: b.limit, spent: b.spent})),
        goals: (goals.data || []).map(mapGoalFromDb),
        categories: (cats.data || []).map(mapCategoryFromDb)
      };
    }

    // LocalStorage Mode
    return {
      transactions: getLocal('zen_transactions', []),
      potes: getLocal('zen_potes', []),
      debts: getLocal('zen_debts', []),
      budgets: getLocal('zen_budgets', []),
      goals: getLocal('zen_goals', []),
      categories: getLocal('zen_categories', [])
    };
  },

  // --- GENERIC SAVERS (Upsert Logic) ---
  saveTransactions: async (userId: string, txs: Transaction[]) => {
    if (supabase) {
        // Warning: Supabase upsert requires unique keys. ID is primary key.
        // For sync simplicity in this demo, we upsert the whole list.
        const { error } = await supabase.from('transactions').upsert(txs.map(t => mapTxToDb(t, userId)));
        if (error) console.error("DB TX Error", error);
    } else {
        setLocal('zen_transactions', txs);
    }
  },

  savePotes: async (userId: string, potes: Jar[]) => {
    if (supabase) {
        // First delete old ones not in current list? Or just upsert.
        // For strict sync, typically we upsert.
        const { error } = await supabase.from('potes').upsert(potes.map(p => mapPoteToDb(p, userId)));
        if (error) console.error("DB Potes Error", error);
    }
    else setLocal('zen_potes', potes);
  },

  saveDebts: async (userId: string, debts: Debt[]) => {
    if (supabase) await supabase.from('debts').upsert(debts.map(d => mapDebtToDb(d, userId)));
    else setLocal('zen_debts', debts);
  },

  saveBudgets: async (userId: string, budgets: Budget[]) => {
    if (supabase) await supabase.from('budgets').upsert(budgets.map(b => mapBudgetToDb(b, userId)));
    else setLocal('zen_budgets', budgets);
  },

  saveGoals: async (userId: string, goals: FinancialGoal[]) => {
    if (supabase) await supabase.from('goals').upsert(goals.map(g => mapGoalToDb(g, userId)));
    else setLocal('zen_goals', goals);
  },

  saveCategories: async (userId: string, cats: Category[]) => {
    if (supabase) await supabase.from('categories').upsert(cats.map(c => mapCategoryToDb(c, userId)));
    else setLocal('zen_categories', cats);
  }
};

